BEGIN TRANSACTION;
CREATE TABLE canvas_concepts (
        id          INTEGER PRIMARY KEY AUTOINCREMENT,
        concept     TEXT NOT NULL,  -- "смерть", "реинкарнация", "Хукам", ...
        traditional TEXT,           -- традиционное/ведическое понимание
        ksd_meaning TEXT NOT NULL,  -- KSD/Nanak переопределение
        gurbani_ref TEXT,           -- ссылка на СГГС если есть
        source      TEXT
    );
   Пример: ਭਾਗੁ ਹੋਆ ਗੁਰਿ ਸੰਤੁ ਮਿਲਾਇਆ (СГГС 97) = "Удача улыбнулась, и я объединился со Святым Гуру (внутри)".

2. ਸੰਤ (mukta, множественное число) = обычные сикхи, искатели Оангкара (Создателя). "Достичь пыли стоп сантов" = осознать Хукам через бхагатов.

3. "Санты Бенареса" (ਬਾਨਾਰਸਿ ਕੇ ਠਗ, bukv. "аферисты Бенареса") — отдельная группа, которая сама называет себя сантами; прямо критикуется в Гурбани как мошенники. Кабир (СГГС 476): ਓਇ ਹਰਿ ਕੇ ਸੰਤ ਨ ਆਖੀਅਹਿ ਬਾਨਾਰਸਿ ਕੇ ਠਗ = "Они не могут зваться святыми Хара — они мошенники Бенареса".

4. ਸੰਤ ਧੂਰਿ (Sant Dhuur) = не "пыль со стоп", а "сообщения, приводящие к реализации Создателя" (Creator Connecting Messages). Dhuur = послания, содержащиеся в шабде; Sant происходит от Sat = стремление установить связь с Оангкаром. Sant Dhuur — это внутреннее содержание шабда, ведущее к реализации, а не указание следовать за каким-то бабой-сантом.','СГГС 97: ਭਾਗੁ ਹੋਆ ਗੁਰਿ ਸੰਤੁ ਮਿਲਾਇਆ — ਸੰਤੁ (aungkar) = Гуру/Создатель
СГГС 476 (Кабир): ਓਇ ਹਰਿ ਕੇ ਸੰਤ ਨ ਆਖੀਅਹਿ ਬਾਨਾਰਸਿ ਕੇ ਠਗ — ਬਾਨਾਰਸਿ ਕੇ ਠਗ = мошенники, присвоившие имя "сант"','word_sant_in_gurbani.txt; Karminder Singh Dhillon — Hijacking Of Sikhi (sikhivicharforum.org)');
CREATE TABLE grammar_rules (
        id          INTEGER PRIMARY KEY AUTOINCREMENT,
        category    TEXT,           -- "suffix", "ending", "case", "gender", ...
        pattern     TEXT,           -- aunkard / sihari / mukta / ...
        meaning     TEXT,           -- мужской род, единственное число, ...
        example_word TEXT,
        example_meaning TEXT,
        source      TEXT
    );
CREATE TABLE jap_bani_verses (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        section TEXT NOT NULL,
        pauri_num INTEGER,
        line_num INTEGER,
        ast_row INTEGER UNIQUE,
        gurmukhi TEXT,
        roman TEXT,
        ast_translation TEXT,
        has_blue INTEGER DEFAULT 0,
        has_underline INTEGER DEFAULT 0,
        word_analysis TEXT,
        ksd_translation TEXT,
        commentary TEXT
    );

