INSERT INTO "grammar_rules" VALUES(47,'tense','past_tense_ee_ending','прошедшее время (женский род, завершённое действие)','pavee','была спасена / спаслась (НЕ "будет спасена")','Упрощенное издание + Nanak Canvas + KSD принципы');
INSERT INTO "grammar_rules" VALUES(48,'tense','future_tense_ay_ending','будущее время / потенциальное','pavsee','будет спасена','Упрощенное издание + Nanak Canvas + KSD принципы');
INSERT INTO "grammar_rules" VALUES(49,'principle','tense_determines_meaning','Временная форма глагола кардинально меняет смысл — прошедшее ≠ будущее. Мейнстрим-переводы часто игнорируют временную форму, превращая прошедшее в будущее.','pavee (past, fem) vs pavsee (future)','Nanak Canvas: "и предки БЫЛИ спасены" (прошедшее) ≠ "и предки будут спасены" (будущее)','Упрощенное издание + Nanak Canvas + KSD принципы');
INSERT INTO "grammar_rules" VALUES(50,'principle','grammar_over_tradition','KSD-подход: грамматика + контекст Гурбани определяет смысл. Традиционные толкования и мейнстрим-переводы — не авторитет, если противоречат грамматике.','','Пример: Dhu = путеводная звезда (Punjab.com + логика строки), а не имя святого. Пример: временная форма "были спасены" vs "будут спасены".','Упрощенное издание + Nanak Canvas + KSD принципы');
INSERT INTO "grammar_rules" VALUES(51,'word_class','ਨਾਂਵ (Noun)','Слово, называющее живое существо, место или предмет (имя существительное)','ਮੋਹਨ, ਘਰ, ਕੁਰਸੀ, ਸੰਤ, ਮਨ','Mohan, ghar, kursi, sant, man','Гурбани грамматика.pdf (Gurbani Viakaran), стр. 6-15');
INSERT INTO "grammar_rules" VALUES(52,'word_class','ਪੜਨਾਂਵ (Pronoun)','Слово, заменяющее уже упомянутое существительное во избежание повтора','ਮੈਂ, ਅਸੀਂ, ਤੂੰ, ਤੁਸੀਂ, ਉਹ','Main, aseen, toon, tuseen, oh','Гурбани грамматика.pdf (Gurbani Viakaran), стр. 6-15');
INSERT INTO "grammar_rules" VALUES(53,'word_class','ਵਿਸ਼ੇਸ਼ਣ (Adjective)','Слово, описывающее признак существительного или местоимения','ਛੋਟਾ, ਮੋਟਾ, ਕਾਲਾ, ਮੈਲਾ','chota, mota, kala, maila','Гурбани грамматика.pdf (Gurbani Viakaran), стр. 6-15');
INSERT INTO "grammar_rules" VALUES(54,'word_class','ਕਿਰਿਆ (Verb)','Слово, обозначающее действие. Изменяется по числу, роду и времени (ਕਾਲ) — поэтому произношение требует особого внимания. Также выражает приказ, просьбу, желание.','ਬੈਠਣਾ, ਖਾਣਾ, ਸੁਣਨਾ','baithna, khana, sunna','Гурбани грамматика.pdf (Gurbani Viakaran), стр. 6-15');
INSERT INTO "grammar_rules" VALUES(55,'word_class','ਕਿਰਿਆ ਵਿਸ਼ੇਸ਼ਣ (Adverb)','Слово, уточняющее характеристику глагола (место, время, образ действия, степень)','ਤੇਜ਼ ਦੌੜਨਾ, ਸਵੇਰੇ ਜਾਗਣਾ','tez daurhna, savere jagana','Гурбани грамматика.pdf (Gurbani Viakaran), стр. 6-15');
INSERT INTO "grammar_rules" VALUES(56,'word_class','ਸਬੰਧਕ (Preposition)','Слово, связывающее существительное/местоимение с другими словами предложения','ਕਾ, ਕੇ, ਕੀ, ਦਾ, ਦੇ, ਦੀ, ਨੂੰ, ਨਾਲ, ਨੇੜੇ, ਦੂਰ','ka, ke, ki, da, de, di, nu, nal, nere, dur','Гурбани грамматика.pdf (Gurbani Viakaran), стр. 6-15');
INSERT INTO "grammar_rules" VALUES(57,'word_class','ਯੋਜਕ/ਕਾਰਕ (Conjunction)','Слово, соединяющее части предложения или предложения между собой','ਅਤੇ, ਪਰ, ਤਾਂ, ਕਿਉਂਕਿ, ਜੇਕਰ','ate, par, tan, kiunki, jekar','Гурбани грамматика.pdf (Gurbani Viakaran), стр. 6-15');
INSERT INTO "grammar_rules" VALUES(58,'word_class','ਸੰਬੋਧਕ (Exclamation/Vocative marker)','Слово-обращение к конкретному лицу. После него в письме ставится ''!''','ਮੋਹਨ!, ਅੰਧੇ!, ਮੁੜੇ!, ਜਿੰਦੜੀਏ!','Mohan!, Andhe!, Mure!','Гурбани грамматика.pdf (Gurbani Viakaran), стр. 6-15');
INSERT INTO "grammar_rules" VALUES(59,'gender','ਪੁਲਿੰਗ (Masculine)','Слово, обозначающее или относящееся к мужскому роду','ਲੜਕਾ, ਘੋੜਾ','ladka, ghora — мальчик, конь','Гурбани грамматика.pdf (Gurbani Viakaran), стр. 6-15');
INSERT INTO "grammar_rules" VALUES(60,'gender','ਇਸਤ੍ਰੀਲਿੰਗ (Feminine)','Слово, обозначающее или относящееся к женскому роду','ਲੜਕੀ, ਘੋੜੀ, ਕੁਰਸੀ, ਰਾਣੀ','ladki, ghori, kursi, rani','Гурбани грамматика.pdf (Gurbani Viakaran), стр. 6-15');
INSERT INTO "grammar_rules" VALUES(61,'person','ਉੱਤਮ ਪੁਰਖ (First Person)','Говорящий о себе: я, мы','ਮੈਂ, ਅਸੀਂ','Main, aseen','Гурбани грамматика.pdf (Gurbani Viakaran), стр. 6-15');
INSERT INTO "grammar_rules" VALUES(62,'person','ਮਧਮ ਪੁਰਖ (Second Person)','Говорящий обращается к другому: ты, вы','ਤੂੰ, ਤੁਸੀਂ','Toon, tuseen','Гурбани грамматика.pdf (Gurbani Viakaran), стр. 6-15');
INSERT INTO "grammar_rules" VALUES(63,'person','ਅਨਯ ਪੁਰਖ (Third Person)','Говорящий о ком-то третьем: он, она, они','ਉਹ, ਉਸ, ਉਹਨਾਂ','Oh, us, ohna','Гурбани грамматика.pdf (Gurbani Viakaran), стр. 6-15');
INSERT INTO "grammar_rules" VALUES(64,'case','ਕਾਰਕ (Case markers)','Слова, связывающие существительное/местоимение с глаголом в предложении. Определяют падежные отношения.','ਨੇ, ਨੂੰ, ਲਈ, ਵਾਸਤੇ, ਵਿੱਚ, ਤੋਂ, ਉੱਤੇ, ਕੋਲ, ਦੇ, ਦੀ, ਦੀਆਂ, ਦੁਆਰਾ','ne, nu, layi, vaste, vich, ton, utte, kol, de, di, dian, duara','Гурбани грамматика.pdf (Gurbani Viakaran), стр. 6-15');
INSERT INTO "grammar_rules" VALUES(65,'number','ਔਂਕੜ (aungkar) = Singular','Слова, оканчивающиеся на ਔਂਕੜ (aungkar, -u), как правило, являются единственным числом (ਇਕ-ਵਚਨ)','ਨੇਹੁ, ਤਾਪੁ, ਦੁਆਰੁ, ਜਨੁ, ਪਤੁ, ਵਾਰੁ','nehu, tapu, duaru, janu, patu, varu','Гурбани грамматика.pdf (Gurbani Viakaran), стр. 6-15');
INSERT INTO "grammar_rules" VALUES(66,'number','ਮੁਕਤਾ (mukta) = Plural (from aungkar noun)','Чтобы образовать множественное число от слова на ਔਂਕੜ — убирают ਔਂਕੜ с последней буквы (mukta). Правило: aungkar → убрать aungkar = plural.','ਨੇਹੁ→ਨੇਹ, ਤਾਪੁ→ਤਾਪ, ਜਨੁ→ਜਨ, ਪਤੁ→ਪਤ, ਵਾਰੁ→ਵਾਰ','nehu→neh, tapu→tap, janu→jan, patu→pat, varu→var','Гурбани грамматика.pdf (Gurbani Viakaran), стр. 6-15');
INSERT INTO "grammar_rules" VALUES(67,'number','Прилагательное (ਵਿਸ਼ੇਸ਼ਣ) мн.ч. = mukta','Прилагательное ко множественному существительному тоже принимает форму mukta (без ਔਂਕੜ на последней букве)','ਅਨਿਕ (мн.ч.), ਅਮੁਲ (мн.ч.)','Anik bilas karat manmohan; Amul gun amul vapar (Jap)','Гурбани грамматика.pdf (Gurbani Viakaran), стр. 6-15');
INSERT INTO "grammar_rules" VALUES(68,'gender','ਇਸਤ੍ਰੀਲਿੰਗ ਨਾਵਾਂ (Feminine Nouns) = НЕТ ਔਂਕੜ','Существительные женского рода оканчиваются на mukta (без ਔਂਕੜ на последнем согласном). Список типичных слов женского рода (mukta): ਵਿਖ, ਦੇਹ, ਵਾਤ, ਬਾਤ, ਧੋਖ, ਧਰਿ, ਪਿਆਸ, ਖੇਹ, ਸੇਵ, ਵੇਲ, ਘਾਲ, ਠਉਰ, ਗਣਤ, ਕਲਮ, ਵਾਟ, ਪੂਜ, ਭੁਖ, ਨੀਂਦ, ਕੰਧ, ਤਿਖ, ਪੀੜ, ਪੀਰ, ਬਾਹ, ਆਸ','vik, deh, vat, bat, dhokh...','Ik Vik Na Chaleh Sathi (Var Gauri M:5); Manu Tanu Deh Sukhali (Sorath M:5)','Гурбани грамматика.pdf (Gurbani Viakaran), стр. 6-15');
INSERT INTO "grammar_rules" VALUES(69,'gender','ਸਾਰ (feminine=mukta / masculine=aungkar)','Слово ਸਾਰ (khabar=новость/суть) — женского рода, mukta. НО ਸਾਰੁ (철/iron, essence/оригинал) — мужского рода, с aungkar. Контекст определяет род и форму.','ਕਮਲ ਕੀ ਸਾਰ ਨਹੀ ਮੁਲਿ ਪਾਈ (fem); ਨਾਨਕ ਕਥਨਾ ਕਰੜਾ ਸਾਰੁ (masc)','Kamal Ki Saar Nahi Mul Payi; Nanak Kathna Karha Saaru','Гурбани грамматика.pdf (Gurbani Viakaran), стр. 6-15');
INSERT INTO "grammar_rules" VALUES(70,'gender','ਵਾਰ (feminine со значением ''время/раз/черёд'')','ਵਾਰ в значении ''раз, черёд'' — женского рода (mukta). Когда ਵਾਰਿ = ''заграда/препятствие'' — sihari на ''ਰ''.','ਵਾਰਿਆ ਨ ਜਾਵਾ ਏਕ ਵਾਰ (Jap) — fem; ਸਾਚ ਧਰਮ ਕੀ ਕਰਿ ਦੀਨੀ ਵਾਰਿ (Asa M:5) — с sihari','Varia Na Java Ek Vaar; Saach Dharam Ki Kar Deeni Vaari','Гурбани грамматика.pdf (Gurbani Viakaran), стр. 6-15');
INSERT INTO "grammar_rules" VALUES(71,'gender','ਵਿਸ਼ੇਸ਼ਣ ਇਸਤ੍ਰੀਲਿੰਗ (Adj. for feminine) = mukta','Прилагательное к существительному женского рода также оканчивается на mukta (без ਔਂਕੜ)','ਫਕੜ (adj to fem ਜਾਤੀ), ਕਵਣ (adj to fem ਥਿਤਿ)','Fakar Jati Fakru Nao (M:1 Var Sri) — ਜਾਤੀ=fem→ਫਕੜ mukta; ਨਾਉ=masc sing→ਫਕੜੁ aungkar','Гурбани грамматика.pdf (Gurbani Viakaran), стр. 6-15');
INSERT INTO "grammar_rules" VALUES(72,'case','ਸੰਬੋਧਨ ਕਾਰਕ (Vocative Case) = mukta','Когда существительное стоит в звательном падеже (обращение «Эй, X!»), его последняя буква принимает форму mukta (теряет ਔਂਕੜ). ИСКЛЮЧЕНИЕ: если в звательном падеже обращаются к Создателю — сохраняется aungkar.','ਮਨ (voc) ← ਮਨੁ; ਨਾਨਕ (voc) ← ਨਾਨਕੁ','Gurmukh Namu Japhu Man Mere (ਮਨ=voc, ''O mind''); Nanak Pavhu Sukh Ghanere (ਨਾਨਕ=voc); Suni Mita Nanaku Binavanta (ਨਾਨਕੁ=subject nominative, НЕ voc)','Гурбани грамматика.pdf (Gurbani Viakaran), стр. 6-15');
INSERT INTO "grammar_rules" VALUES(73,'case','ਸੰਬੋਧਨ ਕਾਰਕ ਵਿਸ਼ੇਸ਼ਣ (Adjective for Vocative) = mukta','Прилагательное при существительном в звательном падеже тоже принимает форму mukta','ਪੂਰਨ (adj to voc ਪੁਰਖ), ਦਇਆਲ (adj to voc ਪ੍ਰਭ)','Tum Puran Purakh Bidhate (Gauri M:5); Nanak Kadh Lehu Prabh Diayal (Sukhmani)','Гурбани грамматика.pdf (Gurbani Viakaran), стр. 6-15');
INSERT INTO "grammar_rules" VALUES(74,'case','ਸੰਬੰਧ ਕਾਰਕ (Possessive Case) = mukta','В притяжательном падеже (мурккаб изафи) — у притяжательного существительного убирают ਔਂਕੜ (mukta), даже если послелог ''ਦਾ''/''ਕਾ'' не указан явно.','ਮੋਖ (= ਮੋਖ ਦਾ ਦੁਆਰ), ਜਗਦੀਸ (= ਜਗਦੀਸ ਦਾ ਇਕ ਨਾਮ)','Manne Paveh Mokh Duaru (Jap) = ਮੋਖ ਦਾ ਦੁਆਰ; Lakh Lakh Geda Akhiyeh Ek Namu Jagdisu (Jap) = ਜਗਦੀਸ ਦਾ ਇਕ ਨਾਮ','Гурбани грамматика.pdf (Gurbani Viakaran), стр. 6-15');
INSERT INTO "grammar_rules" VALUES(75,'case','ਗੁਰ = possessive (''Guru''s'') → mukta на ਰ','ਗੁਰੁ (base form) имеет aungkar на ਰ. Когда значение ''Гуру принадлежащий (da)'' — ਰ становится mukta. В словах ਗੁਰ ਸੰਗਤਿ, ਗੁਰਬਾਣੀ, ਗੁਰ ਸਿੱਖ — ਗੁਰ без ਔਂਕੜ.','ਗੁਰ ਪ੍ਰਸਾਦਿ = Guru''s Blessings; ਗੁਰ ਸੰਗਤਿ = Guru''s Sangat','Gur Persad, Gur Sanggat, Gurbani, Gur Sikh — all mukta on Rara','Гурбани грамматика.pdf (Gurbani Viakaran), стр. 6-15');
INSERT INTO "grammar_rules" VALUES(76,'case','КРИТИЧЕСКИ ВАЖНО: ਔਂਕੜ на слове ≠ possessive','Если слово оканчивается на ਔਂਕੜ — оно НЕ МОЖЕТ читаться как притяжательный падеж (''X ਦਾ''). Aungkar указывает на именительный падеж или прилагательное, но НЕ на possessive. Это устраняет целый класс ошибок мейнстрим-переводов.','ਨਿਰੰਜਨੁ ਹੋਇ → ਨਿਰੰਜਨੁ с aungkar = прилагательное к ਨਾਮੁ, НЕ ''ਨਿਰੰਜਨ ਦਾ''; ਨਾਨਕੁ ਨੀਚੁ ਕਹੈ ਵੀਚਾਰੁ → ਨੀਚੁ = прилагательное к ਨਾਨਕੁ, НЕ ''ਨਾਨਕ ਦਾ''','Esa Namu Niranjanu Hoe — Niranjanu(aungkar)=adj of Naamu; Nanaku Nichu Kahe Vicharu — Nichu=adj of Nanaku','Гурбани грамматика.pdf (Gurbani Viakaran), стр. 6-15');
INSERT INTO "grammar_rules" VALUES(77,'case','ਧਿਆਨ теряет ਔਂਕੜ перед словом ਕੀ','ਧਿਆਨ должно было бы иметь ਔਂਕੜ (как ਸੰਤੋਖੁ, ਸਰਮੁ рядом с ним), но предшествующее слово ਕੀ убирает ਔਂਕੜ.','ਮੁੰਡਾ ਸੰਤੋਖੁ ਸਰਮੁ ਪਤੁ ਝੋਲੀ ਧਿਆਨ ਕੀ ਕਰਹਿ ਬਿਭੂਤਿ (Jap)','Munda Santokhu Sarmu Patu Jholi Dhian Ki Kareh Bibhuti','Гурбани грамматика.pdf (Gurbani Viakaran), стр. 6-15');
INSERT INTO "grammar_rules" VALUES(78,'case','ਸੰਬੰਧਕੀ ਪਦ (Prepositions) — предшествующее слово = mukta','Существительные перед послелогами ਬਿਨੁ, ਵਿਟਹੁ, ਕਉ, ਸੇਤੀ, ਵਿੱਚ, ਮਹਿ, ਉਪਰਿ, ਤੇ, ਪਹਿ, ਪਾਸਿ — принимают mukta (последний согласный без ਔਂਕੜ).','ਮਹਿ, ਤੇ, ਪਹਿ, ਵਿੱਚਿ, ਮੰਧੇ','Sagal Udam Mahi Udamu Bhala (Sukhmani); Man Hi Te Manu Mania (Tukhari M:1); Tanu Manu Gur Pahi Vechia (Siri Rag M:1); Gun Vich Gun Lai Sari (Basant M:1)','Гурбани грамматика.pdf (Gurbani Viakaran), стр. 6-15');
INSERT INTO "grammar_rules" VALUES(79,'ending','ਮਹਿ (mahi) — preposition ''внутри, среди''','Послелог, означающий ''внутри, среди, в''. Существительное перед ним = mukta.','ਸਗਲ ਉਦਮ ਮਹਿ','Sagal Udam Mahi — среди всех усилий','Гурбани грамматика.pdf (Gurbani Viakaran), стр. 6-15');
INSERT INTO "grammar_rules" VALUES(80,'ending','ਤੇ (te) — preposition ''от, из''','Послелог ''от, из, с''. Существительное перед ним = mukta.','ਮਨ ਹੀ ਤੇ','Man Hi Te — из/от самого ума','Гурбани грамматика.pdf (Gurbani Viakaran), стр. 6-15');
INSERT INTO "grammar_rules" VALUES(81,'ending','ਪਹਿ (pahi) — preposition ''к, у''','Послелог ''к, у (кого-то)''. Существительное перед ним = mukta.','ਗੁਰ ਪਹਿ ਵੇਚਿਆ','Gur Pahi Vechia — отдал Гуру','Гурбани грамматика.pdf (Gurbani Viakaran), стр. 6-15');
INSERT INTO "grammar_rules" VALUES(82,'ending','ਵਿੱਚਿ (vichi) — preposition ''в, внутри''','Послелог ''в, внутри''. Существительное перед ним = mukta.','ਵਿਚਿ ਬੋਹਿਥ ਬੈਠਾ ਆਇ','Vich Bohith Baitha Aae','Гурбани грамматика.pdf (Gurbani Viakaran), стр. 6-15');
INSERT INTO "grammar_rules" VALUES(83,'number','ਕੰਨਾ (kenna, -aa ending) = Plural','Слова, оканчивающиеся на ਕੰਨਾ (-aa), являются множественным числом. ВНИМАНИЕ: конечный ਕੰਨਾ — признак множественного числа, а НЕ падежный маркер.','ਚੰਦਾ (мн.ч. от ਚੰਦ), ਰਸਾ (мн.ч. от ਰਸ), ਦਾਸਾ (мн.ч. от ਦਾਸ), ਬੰਧਨਾ, ਪੁਨਾ, ਵਾਦਾ','Je Sau Chanda Ugvahi (Asa Di Var) — ਚੰਦਾ = множественное от ਚੰਦ; Rang Rasa Jaise Supnaha (Asa M:5) — ਰਸਾ = мн. от ਰਸ; Anand Karhi Tere Dasa (Sorath M:5) — ਦਾਸਾ = мн. от ਦਾਸ','Гурбани грамматика.pdf (Gurbani Viakaran), стр. 16-30');
INSERT INTO "grammar_rules" VALUES(84,'vowel_mark','ਸਿਹਾਰੀ (sihari) = послелог ''в, внутри, через, посредством''','Сихари — прежде всего маркер послелога (preposition). ਵਿਚਿ, ਬਾਹਰਿ, ਉਪਰਿ и подобные — выражают отношение к другому слову: ''в, снаружи, над''. Сихари на последнем согласном существительного превращает его в инструментальный/локативный падеж: ''через X, посредством X, в X''.','ਵਿਚਿ, ਉਪਰਿ, ਹੇਠਿ, ਮਧਿ, ਬਾਹਰਿ, ਸੰਗਿ, ਸਾਥਿ, ਨਾਲਿ, ਪਾਸਿ, ਵਸਿ, ਨਜੀਕਿ, ਬਰਾਬਰਿ, ਗੈਲਿ, ਤੁਲਿ, ਸਰਿ, ਸਿਰਿ','Bhai Vich Suraju Bhai Vich Chanadu (Asa Di Var); Likhey Upari Hukamu Hoei (Salok M:2)','Гурбани грамматика.pdf (Gurbani Viakaran), стр. 16-30');
INSERT INTO "grammar_rules" VALUES(85,'ending','ਸਿਹਾਰੀ послелоги — полный список','Послелоги с сихари на последнем согласном: ਵਿਚਿ (в), ਉਪਰਿ (над), ਹੇਠਿ (под), ਮਧਿ/ਮੰਝਾਰਿ (в середине), ਬਾਹਰਿ (снаружи), ਸੰਗਿ/ਸਾਥਿ (вместе с), ਨਾਲਿ (с), ਪਾਸਿ (рядом/у), ਵਸਿ (во власти), ਨਜੀਕਿ (близко), ਬਰਾਬਰਿ (наравне), ਗੈਲਿ (с/рядом), ਤੁਲਿ (наравне/как), ਸਰਿ/ਸਿਰਿ (над/на голове), ਭੀਤਰਿ (внутри), ਬੀਚਿ (в середине), ਅੰਤਰਿ (внутри), ਮਹਿ/ਮਾਹਿ (в), ਨਿਕਟਿ (близко), ਅੰਤਿ (в конце), ਵਲਿ (в сторону), ਪਾਰਿ (за, на той стороне), ਭਰਿ (полностью)','ਭੀਤਰਿ, ਬੀਚਿ, ਅੰਤਰਿ, ਮੰਝਾਰਿ, ਮਹਿ, ਮਾਹਿ, ਨਿਕਟਿ, ਆਦਿ, ਅੰਤਿ, ਵਲਿ, ਪਾਰਿ, ਸਮਸਰਿ, ਭਰਿ','Full list from text','Гурбани грамматика.pdf (Gurbani Viakaran), стр. 16-30');
INSERT INTO "grammar_rules" VALUES(86,'vowel_mark','ਸਿਹਾਰੀ на существительном = ''через / посредством X''','Когда сихари стоит на последней букве существительного — оно становится инструментальным: ''через X'', ''посредством X'', ''в X''. Это меняет смысл переводов кардинально по сравнению с мейнстримом.','ਸਬਦਿ = через Шабад (НЕ ''Шабад'' как объект); ਧਰਮਿ = через дхарам; ਕਰਮਿ = через карам; ਦਰਸਨਿ = через даршан; ਰੂਪਿ = через форму; ਮਨਿ = в уме/через ум; ਮੁਖਿ = через уста','Sikhee Sikhia Gur Vichari. Nadri Karmi Langaye Pari (Asa Di Var) — ਕਰਮਿ = через карам (не ''кармой''); ਧਰਮਿ = через дхарам (не ''дхарму'')','Гурбани грамматика.pdf (Gurbani Viakaran), стр. 16-30');
INSERT INTO "grammar_rules" VALUES(87,'vowel_mark','ਸਬਦਿ (sihari) = ''через Шабад'' — НЕ ''Шабад''','ਸਬਦਿ с сихари = ''через Шабад / посредством Шабада''. Мейнстрим часто читает как именительный ''Шабад'', меняя смысл. Правильно: ''через Шабад Гуру'' — инструментальный падеж.','ਆਸ ਅੰਦੇਸੇ ਤੇ ਨਿਹਕੇਵਲੁ ਹਉਮੈ ਸਬਦਿ ਜਲਾਏ (Asa Di Var)','ਸਬਦਿ = ''через Шабад сжигает эго'' — НЕ ''сжигает слово-эго''; Satgur Kai Sabdi Haumai Bikh Mare (Sidh Gosht)','Гурбани грамматика.pdf (Gurbani Viakaran), стр. 16-30');
INSERT INTO "grammar_rules" VALUES(88,'vowel_mark','ਦਰਸਨਿ / ਰੂਪਿ (sihari) = послелог ''через даршан/форму''','Сихари на ਦਰਸਨਿ и ਰੂਪਿ делает их послелогами (''через''), а НЕ объектами действия. Мейнстрим-перевод ''Индусы хвалят даршан и красивую форму идолов'' — неверен. Правильно: ''хвалят Господа через даршан и форму''.','ਹਿੰਦੂ ਸਾਲਾਹੀ ਸਾਲਾਹਨਿ ਦਰਸਨਿ ਰੂਪਿ ਅਪਾਰੁ (Asa Di Var)','ਦਰਸਨਿ ਰੂਪਿ = ''через даршан и форму Безграничного'' (sihari = preposition); НЕ ''даршан и красивую форму (идолов)''','Гурбани грамматика.pdf (Gurbani Viakaran), стр. 16-30');
INSERT INTO "grammar_rules" VALUES(89,'vowel_mark','ਸੁਣਿ (sihari) = ''через слушание / посредством слушания''','ਸੁਣਿ с сихари = инструментальный: ''через состояние слушания'', ''посредством''. НЕ ''для слушания'' и НЕ именительный ''слушание''.','ਜੋਗੀ ਸੁਣਿ ਧਿਆਵਨਿ ਜੇਤੇ (Asa Di Var)','ਸੁਣਿ = ''через/посредством состояния слушания'' — НЕ ''для бездумного состояния''','Гурбани грамматика.pdf (Gurbani Viakaran), стр. 16-30');
INSERT INTO "grammar_rules" VALUES(90,'vowel_mark','ਗੁਣਿ (sihari) = ''через добродетели / благодаря добродетелям''','ਗੁਣਿ с сихари = ''посредством добродетелей, благодаря добродетелям''. НЕ именительный ''добродетели''.','ਨਾਨਕ ਇਹ ਗੁਣਿ ਨਾਮੁ ਸੁਖਮਨੀ (Sukhmani)','ਗੁਣਿ = ''благодаря этой добродетели — Naam Sukhmani''','Гурбани грамматика.pdf (Gurbani Viakaran), стр. 16-30');
INSERT INTO "grammar_rules" VALUES(91,'vowel_mark','ਮਨਿ = ''через ум / в уме''; ਮੁਖਿ = ''через уста''','ਮਨਿ с сихари = ''через ум, в уме''. ਮੁਖਿ с сихари = ''через уста, устами''. Противопоставление: ਮਨਮੁਖਿ (следующий уму-без-Гуру) vs ਗੁਰਮੁਖਿ (следующий устами Гуру).','ਮਨਿ ਮੁਖਿ ਸੁਚੇ ਜਾਣੀਅਹਿ ਗੁਰਮੁਖਿ ਜਿਨਾ ਗਿਆਣੁ (Sri Rag M:1)','ਮਨਿ = через ум; ਮੁਖਿ = через уста; ਗੁਰਮੁਖਿ = через уста Гуру; ਮਨਮੁਖਿ = через собственный ум (без Гуру)','Гурбани грамматика.pdf (Gurbani Viakaran), стр. 16-30');
INSERT INTO "grammar_rules" VALUES(92,'vowel_mark','ਭੰਡਿ (sihari) = ''через женщину / посредством женщины''','ਭੰਡੁ = существительное (женщина). ਭੰਡਿ с сихари = ''через женщину, посредством''. НЕ именительный падеж.','ਭੰਡੁ ਮੁਆ ਭੰਡੁ ਭਾਲੀਐ ਭੰਡਿ ਹੋਵੈ ਬੰਧਾਣੁ (Asa Di Var)','ਭੰਡਿ = ''через женщину создаётся связь'' — сихари = инструментальный','Гурбани грамматика.pdf (Gurbani Viakaran), стр. 16-30');
INSERT INTO "grammar_rules" VALUES(93,'vowel_mark','ਵਿਚਿ (sihari) = ''в, внутри X'' — sihari означает нахождение внутри','ਵਿਚਿ с сихари = ''в чём-то, внутри чего-то''. ਸਚਿ (ਸਚ+ਿ) = ''в Истине/Создателе''; ਮੁਖਿ ਵਿਚਿ = ''внутри/через уста''.','ਨਾਨਕ ਗੁਰ ਪਰਸਾਦੀ ਛੁਟੀਐ ਜੇ ਚਿਤੁ ਲਗੈ ਸਚਿ (M:3, Var Maru) — ਸਚਿ = в Сач','Nanak Gur Parsadi Chhutiyai Je Chit Lagai Sachi — Sachi = in Truth/Creator','Гурбани грамматика.pdf (Gurbani Viakaran), стр. 16-30');
INSERT INTO "grammar_rules" VALUES(94,'vowel_mark','ਸਿਹਾਰੀ ਸਥਾਨ — сихари с наречиями (ਕਿਰਿਆ-ਵਿਸ਼ੇਸ਼ਣ)','Сихари также появляется с наречиями, функционируя как послелог (preposition). Эти слова часто стоят без связанного существительного. Список: ਵਿਚਿ, ਅੰਤਰਿ, ਬਾਹਰਿ, ਸਾਥਿ, ਸੰਗਿ, ਨਾਲਿ, ਦੂਰਿ, ਮੰਝਿ, ਨੇੜਿ, ਫਿਰਿ, ਬਹੁੜਿ, ਤਲਿ, ਉਪਰਿ, ਬਾਹਰਿ ਵਾਰਿ, ਹਦੂਰਿ, ਉਰਵਾਰਿ, ਪਾਰਿ, ਵਲਿ, ਓੜਕਿ, ਆਦਿ, ਮਧਿ, ਅੰਤਿ, ਪਾਸਿ, ਨਿਦਾਨਿ, ਮੁਲਿ, ਵਖਿ, ਬੇਗਿ, ਹੁਣਿ, ਅਬਿ, ਕਦਿ','ਹਦੂਰਿ (в присутствии), ਉਰਵਾਰਿ (на этой стороне), ਪਾਰਿ (на той стороне), ਵਲਿ (в сторону)','Dekhai Sunai Haduri Sad Ghat Ghat Braham Ravind (Sri Rag M:5); Nanak Nam Vihunia Na Urvari Na Pari (M:3, Var Sorath)','Гурбани грамматика.pdf (Gurbani Viakaran), стр. 16-30');
INSERT INTO "grammar_rules" VALUES(95,'ending','ਹੁਣਿ (huni) = ''сейчас, теперь''','Наречие времени ਹੁਣਿ = ''сейчас''. Сихари здесь указывает на временной послелог.','ਥਾਉ ਨ ਹੋਵੀ ਪਉਦੀਈ, ਹੁਣਿ ਸੁਣੀਐ ਕਿਆ ਰੁਆਇਆ (Asa Di Var)','Thau Na Hovi Paudiyee, Huni Suniyai Kia Ruaia','Гурбани грамматика.pdf (Gurbani Viakaran), стр. 16-30');
INSERT INTO "grammar_rules" VALUES(96,'ending','ਬੇਗਿ (begi) = ''быстро, немедленно'' (=ਛੇਤੀ)','Наречие ਬੇਗਿ = ''быстро''. Сихари — показатель наречия.','ਜੋਂ ਕਰਿ ਪਾਚਨੁ ਬੇਗਿ ਨ ਪਾਵੈ, ਝਗਰੁ ਕਰੈ ਘਰ ਹਾਈ (Gauri Purbi Kabir)','Begi = quickly/soon','Гурбани грамматика.pdf (Gurbani Viakaran), стр. 16-30');
INSERT INTO "grammar_rules" VALUES(97,'ending','ਓੜਕਿ (orhki) = ''в конце концов, в итоге''','Наречие ਓੜਕਿ = ''в конце, в итоге''. Сихари — наречный маркер.','ਕੁੜ ਨਿਖੁਟੈ ਨਾਨਕਾ ਓੜਕਿ ਸਚਿ ਰਹੀ (M:1 Var Ramkali)','Orhki Sach Rahi — ''в итоге остаётся только Истина''','Гурбани грамматика.pdf (Gurbani Viakaran), стр. 16-30');
INSERT INTO "grammar_rules" VALUES(98,'ending','ਹਦੂਰਿ (haduri) = ''в присутствии, лицом к лицу''','Наречие/послелог ਹਦੂਰਿ = ''в присутствии, прямо перед''. Сихари — послелог.','ਦੇਖੈ ਸੁਣੈ ਹਦੂਰਿ ਸਦ ਘਟਿ ਘਟਿ ਬ੍ਰਹਮੁ ਰਵਿੰਦੁ (Sri Rag M:5)','Dekhai Sunai Haduri Sad — ''видит и слышит в присутствии, постоянно''','Гурбани грамматика.pdf (Gurbani Viakaran), стр. 16-30');
INSERT INTO "grammar_rules" VALUES(99,'ending','ਤੋਂ / ਥੋਂ (ton/thon) = ''от, из, с'' (ablative)','Послелоги ਤੋਂ / ਥੋਂ = ''от, из, с''. Существительное перед ними = mukta (без aungkar). Когда послелог явный — у существительного нет сихари на рааре.','ਧੁਰਿ ਕਰਮੁ ਜਿਨਾਂ ਕਉ ਤੁਧੁ ਪਾਇਆ (Asa Di Var); ਪੁਰਬਿ = ''от начала, с прошлого''','Dhuri Karm Jina Kau Tudhu Paia; Je Hovai Purabi Likhia (Asa Di Var) — ਪੁਰਬਿ = ''с прошлого''','Гурбани грамматика.pdf (Gurbani Viakaran), стр. 16-30');
INSERT INTO "grammar_rules" VALUES(100,'ending','ਨੂੰ / ਵਲਿ = направление ''к, в сторону''','Послелоги ਨੂੰ / ਵਲਿ указывают направление (''к, в сторону кого-то/чего-то''). Существительное перед ними = mukta.','ਨੰਗਾ ਦੋਜਕਿ ਚਾਲਿਆ ਤਾ ਦਿਸੈ ਖਰਾ ਡਰਾਵਣਾ (Asa Di Var) — ਦੋਜਕਿ ਨੂੰ','Nanga Dojaki Chalia — ਦੋਜਕਿ + направление = ''пошёл к аду''','Гурбани грамматика.pdf (Gurbani Viakaran), стр. 16-30');
INSERT INTO "grammar_rules" VALUES(101,'ending','ਲਈ / ਹੇਤ / ਨੂੰ = ''для, ради'' (с инфинитивом)','Послелоги ਲਈ, ਹੇਤ, ਨੂੰ с инфинитивом = ''для того чтобы, ради''. Сихари появляется на конце инфинитива (глагол-имя) при этих послелогах.','ਆਖਣਿ ਔਖਾ ਸਾਚਾ ਨਾਉ (Asa M:1) — ਆਖਣਿ = ''для произнесения, произнести''','Aakhan Aukha Sacha Nao — ਆਖਣਿ = инфинитив с sihari; Ant Na Karnai, Deon Na Ant (Jap Ji) — ਕਰਨੈ, ਦੇਣ с sihari','Гурбани грамматика.pdf (Gurbani Viakaran), стр. 16-30');
INSERT INTO "grammar_rules" VALUES(102,'vowel_mark','ਸਿਹਾਰੀ на инфинитиве (ਭਾਵਾਰਥ) = целевой послелог ''для того чтобы''','Сихари на конце инфинитивных форм (оканчивающихся на ਣੇ или ਨੇ) = целевой послелог. Смысл: ''для X-ния, ради X-ния''. Это НЕ именительный и НЕ прямой объект.','ਆਖਣਿ = для произнесения; ਕਰਨੈ = для совершения; ਮੰਗਣਿ = для просьбы','Jor Na Mangani Deon Na Jor (Jap Ji) — ਮੰਗਣਿ = ''для прошения/просьбы''; Ant Na Karnai = ''нет конца для совершения''','Гурбани грамматика.pdf (Gurbani Viakaran), стр. 16-30');
INSERT INTO "grammar_rules" VALUES(103,'ending','ਤੱਕ / ਤੋੜੀ = ''до, вплоть до''','Послелоги ਤੱਕ / ਤੋੜੀ = ''до, вплоть до''. Существительное перед ними = mukta.','ਅਸਮਾਨਿ ਕਿਆੜਾ ਢਿਕਿਓਨੁ (Var Sata Balvand) — ਅਸਮਾਨ ਤੱਕ','Asmani Kiara Dhikionu — ''до неба вытянул''','Гурбани грамматика.pdf (Gurbani Viakaran), стр. 16-30');
INSERT INTO "grammar_rules" VALUES(104,'ending','ਨਾਲ (nal) = ''с помощью, вместе с, посредством''','Послелог ਨਾਲ = ''с, вместе с, посредством''. Существительное перед ним = mukta.','ਝਖੜਿ ਵਾਉ ਨ ਡੋਲੇਈ ਪਰਬਤ ਮੇਰਾਣੁ (Var Sata Balvand) — ਝੱਖੜ ਨਾਲ','Zhakhari Vau Na Dolei — ''не колышется от урагана (ветра)''','Гурбани грамматика.pdf (Gurbani Viakaran), стр. 16-30');
INSERT INTO "grammar_rules" VALUES(105,'principle','ਸਿਹਾਰੀ меняет смысл — системная ошибка мейнстрим-переводов','Игнорирование сихари — источник многих неверных переводов. Мейнстрим читает слова с сихари как именительный, упуская инструментальный/локативный смысл. Примеры системных ошибок: ਸਬਦਿ → ''the Word'' вместо ''through the Word''; ਦਰਸਨਿ ਰੂਪਿ → ''the darshan and the form'' вместо ''through darshan and form''; ਕਰਮਿ → ''karma/deed'' вместо ''through grace/deed''; ਧਰਮਿ → ''religion'' вместо ''through dharam''.','ਧਰਮਿ, ਕਰਮਿ (sihari) — через дхарам/карам; ਹਿੰਦੂ ਸਾਲਾਹੀ ਸਾਲਾਹਨਿ ਦਰਸਨਿ ਰੂਪਿ ਅਪਾਰੁ','Sihari on ਦਰਸਨਿ & ਰੂਪਿ → prepositions. Correct: ''through His darshan and boundless form'' — NOT ''praise the darshan and beautiful form of idols''','Гурбани грамматика.pdf (Gurbani Viakaran), стр. 16-30');
INSERT INTO "grammar_rules" VALUES(106,'ending','ਵੇਲਾ (Vela, mukta) vs ਵੇਲੇ (Velee/Velei, kenna)','ਵੇਲਾ (без ਕੰਨਾ) = ОПРЕДЕЛЕНИЕ термина (''Амрит Вела — это...''). ਵੇਲੇ (с ਕੰਨਾ/sihari) = УКАЗАНИЕ НА ПЕРИОД ВРЕМЕНИ (''в течение Амрит Велы'', ''в момент Амрит Велы''). Аналог в русском: ''Вечер — это когда папа дома'' (определение) vs ''Папа приходит вечером'' (время). В Паури 4 Джап Бани — ਵੇਲਾ (без ਕੰਨਾ) → это определение, а НЕ указание на 3 часа ночи.','ਅੰਮ੍ਰਿਤ ਵੇਲਾ ਸਚੁ ਨਾਉ... (Jap Bani P.4) — mukta → определение; Sada Shyam Vela = ''вечер — это когда папа дома'' (определение); Syam Veley Bapu Ghar Aunda = ''папа приходит вечером'' (время)','Если бы речь шла о промежутке времени (3am), было бы ਅੰਮ੍ਰਿਤ ਵੇਲੇ, НЕ ਅੰਮ੍ਰਿਤ ਵੇਲਾ','Гурбани грамматика.pdf + KSD-анализ Амрит Вела (из комментариев пользователя)');
INSERT INTO "grammar_rules" VALUES(107,'principle','Принцип непротиворечивости СГГС (Gurbani interprets Gurbani)','Если перевод одного шабда противоречит другим шабдам того же Гуру или другого Гуру СГГС — перевод неверен. Гурбани самосогласована: один шабд объясняет другой. Алгоритм проверки: (1) найти все шабды с тем же ключевым словом; (2) если мейнстрим-перевод создаёт противоречие между ними — перевод неверен; (3) искать значение, при котором все шабды согласуются.','Амрит Вела: ''before dawn (3am)'' противоречит СГГС 422, 1084, 146, 540 — где ਵੇਲਾ = любой момент жизни с Создателем','SGGS 422: Vela Sach Parvan Shabad Pashhansi — ''Истинно то время, когда пробуждается к Слову'' (не ''только в 3am''); SGGS 1084: ''каждый момент сделай Велой'' — невозможно если Вела = 3am','KSD-анализ Амрит Вела (Паури 4 Джап Бани + кросс-ссылки СГГС)');
INSERT INTO "grammar_rules" VALUES(108,'vowel_mark','sihari_verb_adjective_list','sihari appears on adverbs/verb-adjectives of manner or repetition','ਫੇਰਿ, ਬਾਹੁਰਿ, ਬਹੁਰਿ, ਫੁਨਿ, ਕਿਟਿ, ਬੀਚਿ, ਮੰਝਾਰਿ, ਨਿਰੰਤਰਿ, ਭਿਨਿ, ਓੜਿ, ਉਪਰਿ, ਹੇਠਿ, ਹਜੂਰਿ, ਤਤਕਾਲਿ, ਆਸਿ ਪਾਸਿ','sihari marks these as verb-adjectives, not nouns','grammar_pdf_p31');
INSERT INTO "grammar_rules" VALUES(109,'vowel_mark','sihari_reduplicated_words','reduplicated verb-adjectives take sihari on both instances','ਝਿਮਿ ਝਿਮਿ, ਠਿਮਿ ਠਿਮਿ, ਮੁਸਿ ਮੁਸਿ, ਮਪਿ ਮਪਿ, ਵਲਿ ਵਲਿ, ਰਸਕਿ ਰਸਕਿ','reduplicated adverbs of manner','grammar_pdf_p31');
INSERT INTO "grammar_rules" VALUES(110,'word_form','ਬਾਹਰ_noun_vs_preposition','ਬਾਹਰ as noun: no sihari, uses ਕਾ as possessive marker; ਬਾਹਰਿ with sihari = preposition "outside of"','ਬਾਹਰ / ਬਾਹਰਿ','ਬਾਹਰ ਕਾ ਮਾਸੁ ਮੰਦਾ (noun) vs ਬਾਹਰੁ ਉਦਕਿ ਪਖਾਰੀਐ (noun direction)','grammar_pdf_p33');
INSERT INTO "grammar_rules" VALUES(111,'word_form','ਅੰਤਰਿ_vs_ਅੰਤਰੁ','ਅੰਤਰਿ with sihari = locative preposition "inside/within"; ਅੰਤਰੁ with aungkar = noun "different/separation"','ਅੰਤਰਿ / ਅੰਤਰੁ','ਤਨੁ ਮਨੁ ਦੇਇ ਨ ਅੰਤਰੁ ਰਾਖੈ (Suhi, Ravidas) — ਅੰਤਰੁ = separation','grammar_pdf_p34');
INSERT INTO "grammar_rules" VALUES(112,'word_form','ਓੜਕਿ_vs_ਓੜਕ','ਓੜਕਿ with sihari = adverb "forever/eternally"; ਓੜਕ without syllable = noun "end"','ਓੜਕਿ / ਓੜਕ','ਸੇਵਕ ਕੀ ਓੜਕਿ ਨਿਬਹੀ ਪ੍ਰੀਤਿ (Maru M:5, forever) vs ਓੜਕ ਓੜਕ ਭਾਲਿ ਥਕੇ (Jap Ji, end)','grammar_pdf_p35');
INSERT INTO "grammar_rules" VALUES(113,'word_form','ਅੰਤੁ_noun','ਅੰਤੁ with aungkar = noun "end/limit"; no sihari because it is a noun','ਅੰਤੁ','ਅਗਮ ਅਗੋਚਰਾ ਤੇਰਾ ਅੰਤੁ ਨ ਪਾਇਆ (Anand)','grammar_pdf_p35');
INSERT INTO "grammar_rules" VALUES(114,'word_form','ਸੰਗਿ_vs_ਸੰਗੁ','same word in one verse: ਸੰਗਿ with sihari = preposition "with"; ਸੰਗੁ with aungkar = noun "company/association"','ਸੰਗਿ / ਸੰਗੁ','ਤਿਨ ਸੰਗਿ ਸੰਗੁ ਨ ਕੀਚਈ (M:5, Var Gujari)','grammar_pdf_p35');
INSERT INTO "grammar_rules" VALUES(115,'word_form','ਵਿਚਿ_vs_ਵਿਚੁ','ਵਿਚਿ with sihari = preposition "in/inside"; ਵਿਚੁ with aungkar = noun "middle/intermediary"','ਵਿਚਿ / ਵਿਚੁ','ਹਉਮੈ ਮਨੁ ਅਸਥੁਲੁ ਹੈ ਕਿਉਂ ਕਰਿ ਵਿਚੁ ਦੇ ਜਾਇ (M:3, Var Gujari)','grammar_pdf_p36');
INSERT INTO "grammar_rules" VALUES(116,'word_form','ਫੇਰਿ_vs_ਫੇਰੁ','ਫੇਰਿ with sihari = adverb "again/then"; ਫੇਰੁ with aungkar = noun (name Pheru, or cycle/circle)','ਫੇਰਿ / ਫੇਰੁ','ਫੇਰਿ ਵਸਾਇਆ ਫੇਰੁ-ਆਣਿ ਸਤਿਗੁਰਿ ਖਡੂਰੁ (Var Sata Balvand)','grammar_pdf_p36');
INSERT INTO "grammar_rules" VALUES(117,'case','possessive_drops_aungkar','in possessive case (sambandh karak), aungkar is removed from last consonant whether preposition ਦਾ/ਕਾ appears or not','','','grammar_pdf_p33');
INSERT INTO "grammar_rules" VALUES(118,'word_class','conjunction_no_sihari','conjunctions (ਯੋਜਕ) connect two clauses and do NOT take sihari at end — they look like adverbs but are not','ਮਤੁ, ਜਬ, ਤਬ, ਅਬ, ਨਾਤੁਰ, ਸਣੁ, ਵਿਣੁ','conjunctions: no sihari expected','grammar_pdf_p37');
INSERT INTO "grammar_rules" VALUES(119,'word_form','ਮਤੁ_conjunction','ਮਤੁ = conjunction "lest / so that not"; no sihari — not an adverb','ਮਤੁ','ਮਤੁ ਕਿ ਜਾਪੈ ਸਾਹੁ ਆਵੈ ਕਿ ਨ ਆਵੈ ਰਾਮ (Bihagrа M:4)','grammar_pdf_p38');
INSERT INTO "grammar_rules" VALUES(120,'word_form','ਨਾਤੁਰ_conjunction','ਨਾਤੁਰ = conjunction "otherwise/or else" (= ਨਹੀਂ ਤਾਂ, ਵਰਨਾ); no sihari','ਨਾਤੁਰ','ਗੁਰ ਪ੍ਰਸਾਦਿ ਅਕਲਿ ਭਈ ਅਵਰੈ ਨਾਤੁਰ ਭਾ ਬੇਗਾਨਾ (Gauri Bairagan, Kabir)','grammar_pdf_p38');
INSERT INTO "grammar_rules" VALUES(121,'word_form','ਸਣੁ_conjunction','ਸਣੁ = conjunction "along with / and with" (= ਅਤੇ ਨਾਲੋਂ); no sihari','ਸਣੁ','ਚੁੜਾ ਭੰਨੁ ਪਲੰਗ ਸਿਉ ਮੁੰਢੇ ਸਣੁ ਬਾਹੀ ਸਣੁ ਬਾਹਾ (Vadhans M:1)','grammar_pdf_p38');
INSERT INTO "grammar_rules" VALUES(122,'word_form','ਵਿਣੁ_conjunction','ਵਿਣੁ = conjunction "without" connecting two clauses; no sihari','ਵਿਣੁ','ਵਿਣੁ ਪਾਰਸੈ ਪੁਜ ਨ ਹੋਵਈ ਵਿਣੁ ਮਨ ਪਰਚੇ ਅਵਰਾ ਸਮਝਾਏ (Gujari M:3)','grammar_pdf_p38');
INSERT INTO "grammar_rules" VALUES(123,'word_class','conjunctive_participle_sihari','conjunctive participle (ਪੂਰਬ-ਪੂਰਨ-ਕਾਰਦੰਤਕ): sihari on base verb = "having done [action]"; action completed before the main verb','ਛੋਡਿ, ਬੈਸਿ, ਧਰਿ, ਕਰਿ, ਭਣਿ, ਘੜਿ, ਬੀਜਿ, ਬੋਲਿ, ਭਖਿ','ਮਾਸੁ ਛੋਡਿ ਬੈਸਿ ਨਕੁ ਪਕੜਹਿ (M:1) | ਧਰਿ ਤਰਾਜੁ ਤੋਲੀਐ (Asa di Var) | ਕਰਿ ਕਿਰਪਾ ਜਿਸੁ ਆਪਿ ਬੁਝਾਇਆ (Sukhmani)','grammar_pdf_p39');
INSERT INTO "grammar_rules" VALUES(124,'principle','sihari_determines_parsing','absence of sihari where conjunctive participle is expected means the word is a noun — this changes sentence meaning entirely; critical for correct Gurbani parsing','ਸਾਜਨ / ਸਾਜਿ','ਸਾਜਨ ਚਲੇ ਪਿਆਰਿਆ (friends departing) — reading ਸਾਜ ਨ ਚਲੇ is wrong because ਸਾਜਿ (having adorned) would need sihari on ਜ which is absent','grammar_pdf_p40');
INSERT INTO "grammar_rules" VALUES(125,'principle','compound_noun_vs_conjunctive_participle','when sihari is absent on what looks like a conjunctive participle, the word forms a compound noun; determines correct parsing','ਬੋਲੁ-ਵਿਗਾੜੁ','ਜੇ ਕੋ ਆਖੈ ਬੋਲੁ ਵਿਗਾੜੁ (Jap Ji) = compound noun "corruptor of speech", NOT ਬੋਲਿ ਵਿਗਾੜੁ; confirmed by ਅਸੀ ਬੋਲ-ਵਿਗਾੜ ਵਿਗਾੜਹ ਬੋਲ (Siri Rag M:1)','grammar_pdf_p40');
INSERT INTO "grammar_rules" VALUES(126,'word_form','ਜਰਿ_vs_ਜਰ','ਜਰਿ (sihari) = conjunctive participle "having endured/burned away"; ਜਰ (no sihari) = noun "sword/gold" — opposite meanings','ਜਰਿ / ਜਰ','ਅਸ ਜਰਿ ਪਰ ਜਰਿ ਜਰਿ ਜਬ ਰਹੈ ਤਬ ਜਾਇ ਜੋਤਿ ਉਜਾਰਉ ਲਹੈ — burn away own and others desires (not "sword")','grammar_pdf_p41');
INSERT INTO "grammar_rules" VALUES(127,'word_class','participle_with_auxiliary_verb','participle (ਕਾਰਦੰਤਕ) combined with auxiliary verbs (ਆਣਾ, ਜਾਣਾ, ਬਹਿਣਾ, ਰਹਿਣਾ, ਸਕਣਾ) forming compound verbs: sihari on participle last consonant','ਬਨਿ, ਦੀਸਿ, ਜਿਣਿ, ਹਾਰਿ, ਛਡਿ, ਆਣਿ, ਭੇਜਿ, ਧੋਇ, ਲਿਖਿ, ਪੀੜਿ','ਸੇਵਕ ਕਉ ਸੇਵਾ ਬਨਿ ਆਈ (Sukhmani) | ਦੇ ਸਾਬੁਣੁ ਲਈਐ ਓਹੁ ਧੋਇ (Jap Ji)','grammar_pdf_p43');
INSERT INTO "grammar_rules" VALUES(128,'word_class','compound_verb_subject_sihari','in compound verbs: sihari on subject end means "this/for/the" (preposition role); differs from noun+sihari preposition case because here the subject IS the main verb','ਆਖਣਿ, ਪੜਣਿ','ਜੇ ਕੋ ਖਾਇਕੁ ਆਖਣਿ ਪਾਇ (Jap Ji) | ਲਗਾ ਪੜਣਿ ਸਲੋਕੁ (Asa di Var)','grammar_pdf_p44');
INSERT INTO "grammar_rules" VALUES(129,'word_class','imperative_mood_sihari','imperative mood (ਅਨੁਮਤਯਾਰਥ ਲਕਾਰ): command "you do this" — sihari sometimes appears on verb last consonant','ਜਪਿ, ਸਾਲਾਹਿ, ਸਿਮਰਿ, ਆਹਿ, ਲੇਹਿ, ਦੇਹਿ, ਸੁਣਿ, ਕਰਿ, ਧਰਿ','ਏਕੋ ਜਪਿ ਏਕੋ ਸਾਲਾਹਿ ਏਕੁ ਸਿਮਰਿ ਏਕੋ ਮਨ ਆਹਿ (Sukhmani)','grammar_pdf_p45');
INSERT INTO "grammar_rules" VALUES(130,'word_form','ਜਪਿ_vs_ਜਪੁ_vs_ਜਪ','ਜਪਿ (sihari) = imperative "You recite!" (command); ਜਪੁ (aungkar) = noun+verb-noun "recitation" (title of Jap Ji + command to activate); ਜਪ (no syllable) = plural','ਜਪਿ / ਜਪੁ / ਜਪ','ਜਪਿ ਜਨ ਸਦਾ ਦਿਨ ਰੈਣੀ (Sukhmani, imperative) | ਜਪੁ after Gur Prasaad = title + imperative | ਅਸੰਖ ਜਪ ਅਸੰਖ ਭਾਉ (Jap Ji, plural)','grammar_pdf_p45');
INSERT INTO "grammar_rules" VALUES(131,'word_form','imperative_examples_list','imperative mood examples: ਸਾਲਾਹਿ=praise (you), ਸਿਮਰਿ=remember (you), ਆਹਿ=desire (you), ਲੇਹਿ=take (you), ਦੇਹਿ=give (you), ਸੁਣਿ=listen (you), ਕਰਿ=do (you), ਧਰਿ=hold/place (you)','ਸਾਲਾਹਿ / ਸਿਮਰਿ / ਆਹਿ / ਲੇਹਿ / ਦੇਹਿ / ਸੁਣਿ / ਕਰਿ / ਧਰਿ','ਮਨ ਮੇਰੇ ਤਿਨ ਕੀ ਓਟ ਲੇਹਿ, ਮਨੁ ਤਨੁ ਅਪਨਾ ਤਿਨ ਜਨ ਦੇਹਿ (Sukhmani)','grammar_pdf_p47');
INSERT INTO "grammar_rules" VALUES(132,'word_class','subordinate_clause_structure','subordinate clause (ਅਧੀਨ ਵਾਕੰਸ): two words — (1) noun with sihari on last consonant + (2) verb ending with dulava; means "by [noun-action], [main result]"','ਨਾਮਿ ਸਲਾਹਿਐ, ਸਤਿਗੁਰਿ ਮਿਲਿਐ, ਧਾਨਿ ਖਾਧੈ, ਪਾਰਸਿ ਪਰਸਿਐ','ਨਾਨਕ ਨਾਮਿ ਸਲਾਹਿਐ ਮਨੁ ਤਨੁ ਸੀਤਲੁ ਹੋਇ (M:5) | ਸਤਿਗੁਰਿ ਮਿਲਿਐ ਸਚੁ ਪਾਇਆ (Asa di Var)','grammar_pdf_p48');
INSERT INTO "grammar_rules" VALUES(133,'principle','subordinate_clause_noun_only','sihari in subordinate clause appears on NOUN only, not on pronoun; when subject is a pronoun, sihari is absent','','ਸਤਿਗੁਰ ਵਿਟਹੁ ਵਾਰਿਆ ਜਿਤੁ ਮਿਲਿਐ ਖਸਮੁ ਸਮਾਲਿਆ (Asa di Var) — ਜਿਤੁ is pronoun, no sihari','grammar_pdf_p49');
INSERT INTO "grammar_rules" VALUES(134,'word_form','ਜੋਬਨਿ_subordinate_clause','ਜੋਬਨਿ (sihari) = subordinate clause noun "by/through [act of] youth [squandered]"; NOT "old age comes, youth is lost" — sihari marks it as cause, not sequence','ਜੋਬਨਿ','ਜਰੁ ਆਈ ਜੋਬਨਿ ਹਾਰਿਆ (Asa di Var) = old age arrived by [the body] losing youth through evil desires — subordinate clause, not temporal sequence','grammar_pdf_p49');
INSERT INTO "grammar_rules" VALUES(135,'word_form','subordinate_clause_examples','subordinate clause examples: ਨਾਮਿ ਸਲਾਹਿਐ=by praising the Naam, ਧਾਨਿ ਖਾਧੈ=by eating this grain, ਸਤਿਗੁਰਿ ਮਿਲਿਐ=by meeting the Satguru, ਪਿੰਡਿ ਮੁਐ=by dying of body, ਮੁਖਿ ਜੋਰਿਐ=by joining mouths','ਨਾਮਿ / ਧਾਨਿ / ਸਤਿਗੁਰਿ / ਪਾਰਸਿ / ਲੋਕਿ / ਜੋਬਨਿ / ਪਿੰਡਿ / ਮੁਖਿ','ਪਿੰਡਿ ਮੁਐ ਜੀਉ ਕਿਹ ਘਰਿ ਜਾਤਾ (Gauri Kabir) = by the body dying, where does the soul go?','grammar_pdf_p49');
INSERT INTO "grammar_rules" VALUES(136,'tense','present_imperfect_3rd_plural_ni','present imperfect verb (ਸਮਾਨ ਵਰਤਮਾਨ) in 3rd person plural (ਬਹੁਵਚਨ ਅਨਯ ਪੁਰਖ): verb ends with ਨਿ (ਨ + sihari) = "they are [doing/singing/etc.]"','ਗਾਵਨਿ, ਜਾਣਨਿ, ਵਾਇਨਿ, ਨਚਨਿ, ਹਲਾਇਨਿ, ਫੇਰਨਿ, ਚੁਗਨਿ, ਵਸਨਿ, ਛੋਡਨਿ','ਗਾਵਨਿ ਤੁਧਨੋ ਚਿਤ੍ਰ ਗੁਪਤੁ ਲਿਖਿ ਜਾਣਨਿ (Sodar Asa M:1) = they sing to You, Chitr Gupt who writes knows','grammar_pdf_p50');
INSERT INTO "grammar_rules" VALUES(137,'word_form','ਸਾਲਾਹਨਿ_vs_ਸਾਲਾਹਣ','ਸਾਲਾਹਨਿ (sihari on ਨ) = "they praise" (3rd person plural); ਸਾਲਾਹਣ (no sihari) = verb-noun "praise-worthy/deserving praise"','ਸਾਲਾਹਨਿ / ਸਾਲਾਹਣ','ਸੁਣਿਐ ਮੁਖ ਸਾਲਾਹਣ ਮੰਦੁ (Jap Ji) = "Whoever listened, even the wicked became praise-worthy" — NOT "wicked ones praise with their mouth"','grammar_pdf_p51');
INSERT INTO "grammar_rules" VALUES(138,'word_form','ਮਰਨਿ_vs_ਮਰਨੁ','ਮਰਨਿ (sihari on ਨ) = "they die" (3rd person plural present imperfect); ਮਰਨੁ (aungkar) = noun "death"','ਮਰਨਿ / ਮਰਨੁ','ਮਰਨਿ ਮੁਨਸਾ ਸੁਰਿਆ ਹਕੁ ਹੈ ਜੋ ਹੋਇ ਮਰਨਿ ਪਰਵਾਣੋ (Vadhans M:1) = those die who have been approved to die','grammar_pdf_p51');
INSERT INTO "grammar_rules" VALUES(139,'tense','future_tense_3rd_plural_sni','future tense (ਭਵਿਖੱਤ ਕਾਲ) 3rd person plural: verb ending in ਸ+ਨ takes sihari on final ਨ = "they will [do]"','ਪਉਸਨਿ, ਜਾਸਨਿ, ਸਿੰਘਾਪਸਨਿ, ਬਹਸਨਿ','ਤਲਬਾ ਪਉਸਨਿ ਆਕੀਆ ਬਾਕੀ ਜਿਨਾ ਰਹੀ (M:1, Var Ramkali) = rebels will be summoned who still owe a balance','grammar_pdf_p52');
INSERT INTO "grammar_rules" VALUES(140,'tense','present_tense_3rd_plural_hi','present tense (ਵਰਤਮਾਨ ਕਾਲ) 3rd person plural: verb ending in ਹ takes sihari = "they [do]"','ਮਾਰਹਿ, ਲੁਟਹਿ','ਮਾਰਹਿ ਲੁਟਹਿ ਨੀਤ ਨੀਤ (Gauri M:1) = they kill, they loot, again and again','grammar_pdf_p53');
INSERT INTO "grammar_rules" VALUES(141,'tense','present_tense_2nd_singular_hi','present tense 2nd person singular (ਇਕ-ਵਚਨ ਮੱਧਮ ਪੁਰਖ): same -ਹਿ ending as 3rd plural; context determines person','ਜੋਹਿ, ਰਹੀਏਹਿ, ਹੋਈਅਹਿ','ਵੇਲਿ ਪਰਾਈ ਜੋਹਿ ਜੀਅੜੇ (Gauri M:1) = you spy on others opportunity | ਰਹੀਏਹਿ = you are left behind','grammar_pdf_p53');
INSERT INTO "grammar_rules" VALUES(142,'vowel_mark','original_sihari_inherited','original/inherent sihari (ਮੂਲਿਕ ਸਿਹਾਰੀ): words borrowed from Sanskrit/Persian/Arabic that bring sihari from source language — it remains permanently regardless of grammatical function','ਹਰਿ, ਨਾਰਿ, ਜੁਗਤਿ, ਧੁਨਿ, ਭੂਮਿ, ਧਰਤਿ, ਪ੍ਰੀਤਿ, ਆਦਿ, ਸਿਮ੍ਰਿਤਿ, ਸ਼ਕਤਿ, ਰੈਣਿ, ਰਾਤਿ, ਰੁਤਿ, ਸ੍ਰਿਸਟਿ, ਕੀਰਤਿ, ਜੋਤਿ, ਰੀਤਿ, ਅਤਿ, ਸਰਣਿ, ਨਿਧਿ, ਰਿਧਿ, ਸਿਧਿ, ਜੋਨਿ, ਸੁਰਤਿ, ਮੁਨਿ, ਤ੍ਰਿਪਤਿ, ਚਿੰਤਾਮਣਿ','these always carry sihari — do not confuse with grammatical sihari endings','grammar_pdf_p54');
INSERT INTO "grammar_rules" VALUES(143,'word_form','ਭਗਤਿ_vs_ਭਗਤੁ','ਭਗਤਿ (original sihari) = devotion/bhakti (abstract noun); ਭਗਤੁ (aungkar) = singular devotee (person); ਭਗਤ (no syllable) = plural devotees','ਭਗਤਿ / ਭਗਤੁ / ਭਗਤ','ਮੁਕਤਿ ਭੁਗਤਿ ਜੁਗਤਿ ਤੇਰੀ ਸੇਵਾ (Suhi M:5) | ਤੇਰੀ ਭਗਤਿ ਤੇਰੀ ਭਗਤਿ ਭੰਡਾਰ ਜੀ (Asa M:4)','grammar_pdf_p54');
INSERT INTO "grammar_rules" VALUES(144,'word_form','ਮੁਕਤਿ_vs_ਮੁਕਤੁ','ਮੁਕਤਿ (original sihari) = liberation (abstract noun); ਮੁਕਤੁ (aungkar) = liberated one (person)','ਮੁਕਤਿ / ਮੁਕਤੁ','ਇਹ ਜੀਉ ਸਦਾ ਮੁਕਤੁ ਹੈ (M:3 Var Gujari) — ਮੁਕਤੁ = liberated being (person)','grammar_pdf_p54');
INSERT INTO "grammar_rules" VALUES(145,'word_form','ਗਤਿ_vs_ਗਤੁ','ਗਤਿ (original sihari) = state/condition/spiritual state; ਗਤੁ/ਗਤ = "gone/past/happened" (different word entirely)','ਗਤਿ / ਗਤੁ / ਗਤ','ਨਾਮੋ ਗਤਿ ਨਾਮੋ ਪਤਿ ਜਨ ਕੀ (Dhanasari M:5) | ਅਪਿਓ ਪੀਓ ਗਤੁ ਭੀਓ ਭਰਮਾ (Jetsari M:5) = delusion is gone','grammar_pdf_p54');
INSERT INTO "grammar_rules" VALUES(146,'word_form','ਬੁਧਿ_vs_ਬੁਧੁ','ਬੁਧਿ (original sihari) = intellect/wisdom (abstract); ਬੁਧੁ = the wise one (person); ਸਿਧਿ = spiritual power (abstract); ਸਿਧੁ = siddha/adept (person)','ਬੁਧਿ / ਬੁਧੁ / ਸਿਧਿ / ਸਿਧੁ','ਰਿਧਿ ਬੁਧਿ ਸਿਧਿ ਗਿਆਨੁ ਸਦਾ ਸੁਖੁ ਹੋਇ (M:1 Var Malar) | ਭੈ ਵਿਚਿ ਸਿਧ ਬੁਧ ਸੁਰ ਨਾਥ (Asa di Var) = siddhas, wise ones, gods','grammar_pdf_p55');
INSERT INTO "grammar_rules" VALUES(147,'word_form','ਮਤਿ_vs_ਮੱਤ','ਮਤਿ (original sihari) = intellect/mind/reasoning (abstract noun); ਮੱਤ (no sihari, different root) = "drunk/intoxicated" or compound word element','ਮਤਿ / ਮੱਤ','ਮਤਿ ਥੋੜੀ ਸੇਵ ਗਵਾਈਐ (Asa di Var) = by little intellect, service is lost | ਮਨੁ ਮੈ ਮਤੁ ਮੈਗਲ ਮਿਕਦਾਰਾ (Dhanasari M:3) = mind drunk like an elephant','grammar_pdf_p55');
INSERT INTO "grammar_rules" VALUES(148,'word_form','ਪਤਿ_vs_ਪਤੁ_vs_ਪਤ','ਪਤਿ (original sihari) = husband OR honor/respect (two meanings, context dependent); ਪਤੁ (aungkar) = honor as abstract; ਪਤ (no syllable) = leaf/paper OR yogis begging bowl','ਪਤਿ / ਪਤੁ / ਪਤ','ਜਹ ਨਿਰਮਲ ਪੁਰਖੁ ਪੁਰਖ-ਪਤਿ ਹੋਤਾ (Sukhmani) = husband | ਮੁਰਖ ਅੰਧੈ ਪਤਿ ਗਵਾਈ (Asa di Var) = honor lost | ਫਲ ਫਿਕੇ ਫੁਲ ਬਕਬਕੇ ਕੰਮਿ ਨ ਆਵਹਿ ਪਤ (Asa di Var) = leaves (of no use)','grammar_pdf_p55');
INSERT INTO "grammar_rules" VALUES(149,'word_form','ਮਿਤਿ_vs_ਮਿਤੁ','ਮਿਤਿ (original sihari) = extent/measure/limit; ਮਿਤੁ (aungkar) = friend/companion','ਮਿਤਿ / ਮਿਤੁ','ਕਰਤੇ ਕੀ ਮਿਤਿ ਕਰਤਾ ਜਾਣੈ (Dakhni Oankar) = only Creator knows Creator extent | ਮਿਟੀ ਪਈ ਅਤੋਲਵੀ ਕੋਇ ਨ ਹੋਸੀ ਮਿਤੁ (Salok Farid) = no friend will come','grammar_pdf_p56');
INSERT INTO "grammar_rules" VALUES(150,'word_form','ਸਤਿ_adjective_vs_ਸਤੁ_noun','ਸਤਿ (adjective, original sihari) = True/Eternal (divine attribute, e.g. Sat Naam); ਸਤੁ (aungkar, noun) = charity/essence/purity/truth as quality','ਸਤਿ / ਸਤੁ','ਚਰਨ ਸਤਿ ਸਤਿ ਪਰਸਨਹਾਰ (Sukhmani) = True feet | ਸੁਣਿਐ ਸਤੁ ਸੰਤੋਖੁ ਗਿਆਨੁ (Jap Ji) = essence/charity heard | ਪਤਿ ਵਿਣੁ ਪੂਜਾ ਸਤ ਵਿਣੁ ਸੰਜਮ (Ramkali M:1) = without charity, restraint is futile','grammar_pdf_p56');
INSERT INTO "grammar_rules" VALUES(151,'word_form','ਕਲਿ_vs_ਕਲ','ਕਲਿ (sihari) = Kali Yuga (current age) OR mental distress/worry/anxiety; ਕਲ (no sihari) = skill/art/ability/power (no sihari when meaning skill)','ਕਲਿ / ਕਲ','ਕਲਿ ਕਲੇਸ ਮਿਟੰਤ ਸਿਮਰਣਿ ਕਾਟਿ ਜਮਦੂਤ ਵਾਸ (Gujari M:5) = distress of Kali Yuga | ਆਪੇ ਹੀ ਕਰਨਾ ਕੀਓ ਕਲ ਆਪੇ ਹੀ ਤੈ ਧਾਰੀਐ (Asa di Var) = ਕਲ = skill/power','grammar_pdf_p57');
INSERT INTO "grammar_rules" VALUES(152,'word_form','ਕੋਟਿ_vs_ਕੋਟੁ','ਕੋਟਿ (original sihari) = ten million/crore (number); ਕੋਟੁ (aungkar) = fort/castle','ਕੋਟਿ / ਕੋਟੁ','ਕੋਟਿ ਕੋਟਿ ਭਾਲਿ ਥਕੇ (Jap Ji) = millions searched | contrast with ਕੋਟੁ as fort','grammar_pdf_p59');
INSERT INTO "grammar_rules" VALUES(153,'word_form','ਹਸਤਿ_vs_ਹਸਤੁ','ਹਸਤਿ/ਹਸਤੀ (sihari/bihari) = elephant; ਹਸਤੁ/ਹਸਤ (aungkar/no syllable) = hand OR "happens/laughed"','ਹਸਤਿ / ਹਸਤੁ','sihari/bihari marks elephant meaning; aungkar/mukta marks hand or verb form','grammar_pdf_p59');
INSERT INTO "grammar_rules" VALUES(154,'word_form','ਸੁਧਿ_vs_ਸੁਧੁ','ਸੁਧਿ (sihari) = awareness/realization/consciousness; ਸੁਧੁ (aungkar) = corrected/purified','ਸੁਧਿ / ਸੁਧੁ','sihari = state of awareness; aungkar = adjective "corrected"','grammar_pdf_p59');
INSERT INTO "grammar_rules" VALUES(155,'word_form','ਮੂਰਤਿ_vs_ਮੂਰਤੁ','ਮੂਰਤਿ (original sihari) = idol/form/image (murti); ਮੂਰਤੁ (aungkar) = auspicious moment/muhurat','ਮੂਰਤਿ / ਮੂਰਤੁ','Akaal Murat = ਅਕਾਲ ਮੂਰਤਿ = Beyond-Time Form (sihari = original)','grammar_pdf_p59');
INSERT INTO "grammar_rules" VALUES(156,'gender','feminine_sihari_ni_ending','sihari marks feminine gender on nouns ending in -ਣਿ or -ਨਿ; list of common feminine nouns with inherent sihari','ਭੰਡਾਰਣਿ, ਸੋਹਾਗਣਿ, ਪਰਦੇਸਣਿ, ਕਲਾਲਣਿ, ਮਾਲਿਣਿ, ਭੈਰਾਗਣਿ, ਸਾਹਣਿ, ਸਾਪਣਿ, ਸਰਪਣਿ, ਜਲਣਿ, ਦਾਮਣਿ, ਵਰਤਣਿ, ਪੜੋਸਣਿ, ਸਉਕਣਿ, ਗੀਹਣਿ, ਘਾਣਿ, ਕਾਣਿ, ਪਾਣਿ','sihari on -ਣਿ/-ਨਿ ending = feminine noun','grammar_pdf_p59');
INSERT INTO "grammar_rules" VALUES(157,'word_form','ਕਾਮਣਿ_vs_ਕਾਮਣ','ਕਾਮਣਿ (sihari) = woman/wife (feminine noun); ਕਾਮਣ (no sihari) = magic charm/spell (different meaning)','ਕਾਮਣਿ / ਕਾਮਣ','ਗੁਣਿ ਕਾਮਣ ਕਾਮਣਿ ਕਰੈ ਤਉ ਪਿਆਰੇ ਕਉ ਪਾਵੈ (Tilang M:1) — both in one line: charm and woman','grammar_pdf_p60');
INSERT INTO "grammar_rules" VALUES(158,'word_form','ਤਰੁਣਿ_vs_ਤਰਣੁ','ਤਰੁਣਿ (sihari, feminine) = young woman; ਤਰਣੁ (aungkar) = to swim/cross over — common misreading in Gurbani','ਤਰੁਣਿ / ਤਰਣੁ','ਜੋਸੀ ਤਰੁਣਿ ਭਤਾਰ ਉੜਜੀ (Asa M:5) = the young woman whose husband has left | ਤਰਣੁ ਦੁਹੇਲਾ ਭਇਆ ਖਿਨ ਮਹਿ (Asa M:5) = crossing over became difficult in a moment — NOT a woman','grammar_pdf_p60');
INSERT INTO "grammar_rules" VALUES(159,'gender','feminine_adjective_as_noun_sihari','adjectives used as feminine nouns take sihari; same adjective without sihari is masculine','ਸੁੰਦਰਿ, ਸੁਜਾਣਿ, ਚਤੁਰਿ, ਚੰਚਲਿ, ਸੁਘਰਿ, ਨਿਰਗੁਣਿ, ਪਰਧਾਨਿ, ਕਰੂਪਿ, ਸਰੂਪਿ, ਬੇਪੀਰਿ, ਕੁੜਿਆਰਿ, ਸੇਵਕਿ','ਸੁੰਦਰਿ ਸੁਜਾਣਿ ਚਤੁਰਿ ਬੇਟੀ (Ramkali M:5) = beautiful wise clever daughter | vs ਸੁੰਦਰ ਸੁਘਰ ਸਰੂਪ ਸਿਆਣੇ (Asa M:5, masculine)','grammar_pdf_p61');
INSERT INTO "grammar_rules" VALUES(160,'word_form','ਸੇਵਕਿ_feminine','ਸੇਵਕਿ (sihari) = female servant (feminine form); ਸੇਵਕੁ (aungkar) = male servant','ਸੇਵਕਿ / ਸੇਵਕੁ','ਹਿਰਦੈ ਹਰਿ ਹਰਿ ਨਾਮ ਰਸੁ ਕਵਲਾ ਸੇਵਕਿ ਤਿਸੁ (M:3, Var Bilaval) = Lakshmi is servant of that one','grammar_pdf_p61');
INSERT INTO "grammar_rules" VALUES(161,'gender','arabic_feminine_ti_ending','Arabic-origin feminine nouns ending in ਤ take sihari = -ਤਿ ending; large category of Arabic loanwords in Gurbani','ਕੁਦਰਤਿ, ਸਿਫਤਿ, ਹਿਕਮਤਿ, ਹੁਰਮਤਿ, ਕੀਮਤਿ, ਸਲਾਮਤਿ, ਦਉਲਤਿ, ਮਿੰਨਤਿ, ਨਿਆਮਤਿ, ਸੁਨਤਿ, ਮੁਹਬਤਿ, ਤਰੀਕਤਿ, ਨੀਅਤਿ, ਹੈਰਤਿ, ਜਰੂਰਤਿ, ਉਮਤਿ','all Arabic feminine words in Gurbani end in -ਤਿ (sihari on ਤ)','grammar_pdf_p62');
INSERT INTO "grammar_rules" VALUES(162,'word_form','ਇਕਿ_indefinite_plural','ਇਕ (no sihari) = singular "one"; ਇਕਿ (sihari) = indefinite plural pronoun/adjective "some/certain ones"','ਇਕ / ਇਕਿ','ਇਕਿ ਘਰਿ ਆਵਹਿ ਆਪਣੈ ਇਕਿ ਮਿਲਿ ਮਿਲਿ ਪੁਛਹਿ ਸੁਖੁ (Asa M:1) = some come home, some ask about wellbeing','grammar_pdf_p63');
INSERT INTO "grammar_rules" VALUES(163,'word_form','ਹਿਕਿ_vs_ਹਿਕੁ','ਹਿਕੁ (aungkar) = singular "one"; ਹਿਕਿ (sihari) = plural "some/ones" (Punjabi dialect form of ਇਕ)','ਹਿਕੁ / ਹਿਕਿ','ਬਨਿ ਭੀਆਵਲੇ ਹਿਕੁ ਸਾਥੀ ਲਧਮੁ (M:5 Var Gujari) = singular | ਹਿਕ ਦੂੰ ਹਿਕਿ ਚਾੜੇ ਅਨਿਕ ਪਿਆਰੇ (Jetsari M:5) = plural','grammar_pdf_p64');
INSERT INTO "grammar_rules" VALUES(164,'word_form','ਹੋਰਿ_vs_ਹੋਰੁ','ਹੋਰੁ/ਹੋਰ (aungkar/no syllable) = singular "another/other"; ਹੋਰਿ (sihari on ਰ) = plural "others"','ਹੋਰੁ / ਹੋਰਿ','ਧਰਤੀ ਹੋਰੁ ਪਰੈ ਹੋਰੁ ਹੋਰੁ (Jap Ji) = singular | ਹੋਰਿ ਕੇਤੇ ਗਾਵਨਿ ਸੇ ਮੈ ਚਿਤਿ ਨ ਆਵਨਿ (Jap Ji) = plural others','grammar_pdf_p65');
INSERT INTO "grammar_rules" VALUES(165,'word_form','ਅਵਰਿ_vs_ਅਵਰੁ','ਅਵਰੁ (aungkar) = singular "another/other one"; ਅਵਰਿ (sihari) = plural "others/all other means"','ਅਵਰੁ / ਅਵਰਿ','ਕਹੈ ਪ੍ਰਭੁ ਅਵਰੁ ਅਵਰੁ ਕਿਛੁ ਕੀਜੈ (Bilaval M:4) = singular | ਅਵਰਿ ਉਪਾਵ ਸਭਿ ਤਿਆਗਿਆ (Bilaval M:5) = all other means','grammar_pdf_p65');
INSERT INTO "grammar_rules" VALUES(166,'word_class','demonstrative_gender_marking','demonstrative pronouns/adjectives (ਇਹੁ, ਏਹੁ, ਓਹੁ): masculine singular = aungkar on ਹ; feminine singular = sihari on ਹ; plural = sihari on ਹ','ਇਹੁ/ਇਹਿ, ਏਹੁ/ਏਹਿ, ਓਹੁ/ਓਹਿ','ਜਿਨਿ ਏਹਿ ਲਿਖੇ ਤਿਸੁ ਸਿਰਿ ਨਾਹਿ (Jap Ji) = ਏਹਿ plural (these) | ਨਾ ਓਹਿ ਮਰਹਿ ਨ ਠਾਗੇ ਜਾਹਿ (Jap Ji) = ਓਹਿ plural (they)','grammar_pdf_p66');
INSERT INTO "grammar_rules" VALUES(167,'tense','past_tense_agent_sihari','past tense: sihari on the agent/subject marks who performed the past action; sihari also lengthens pronunciation (ਕਿ sounds like ਕੇ, ਤਿ like ਤੇ)','ਗੁਰਿ, ਪ੍ਰਭਿ, ਪੁਰਖਿ, ਪਰਮੇਸੁਰਿ, ਸਤਿਗੁਰਿ, ਬਾਪਿ, ਪਿਰਿ, ਮੁਰਖਿ, ਜਿਨਿ, ਤਿਨਿ, ਆਪਿ','ਗੁਰਿ ਹਾਥੁ ਧਰਿਓ ਮੇਰੈ ਮਾਥਾ (Jetsari M:4) = Guru placed hand | ਸਰਬ ਕਲਿਆਣ ਪ੍ਰਭਿ ਕੀਨੇ (Sorath M:5) = Prabh did','grammar_pdf_p67');
INSERT INTO "grammar_rules" VALUES(168,'word_form','past_agent_contraction','past agent marker can contract: ਸੁਲਤਾਣੇ = ਸੁਲਤਾਣਿ ਦੇ ("by the Sultan"); ਕਰਤਾਰੇ = ਕਰਤਾਰਿ ਦੇ ("by the Creator") — oblique agentive contraction','ਸੁਲਤਾਣੇ / ਕਰਤਾਰੇ','ਨਾਮਾ ਸੁਲਤਾਣੇ ਬਾਧਿਲਾ (Bhairo Namdev) | ਠਾਵਿ ਪਾਈ ਕਰਤਾਰੇ (Sorath M:5)','grammar_pdf_p67');
INSERT INTO "grammar_rules" VALUES(169,'word_form','ਜਿਨਿ_creator_vs_ਜਿਨ_pronoun','ਜਿਨਿ (sihari) = past agent "Creator/Almighty who did [action]"; ਜਿਨ (no sihari) = relative pronoun "those who / whoever"','ਜਿਨਿ / ਜਿਨ','ਜਿਨਿ ਹਰਿ ਪਾਇਓ ਤਿਨਹਿ ਛਪਾਇਓ (Todi Namdev) = Creator found/hid | ਜਿਨ ਮਨਿ ਪ੍ਰੀਤਿ ਲਗੀ ਹਰਿ ਕੇਰੀ (Jetsari M:4) = those whose minds are attached','grammar_pdf_p68');
INSERT INTO "grammar_rules" VALUES(170,'word_form','ਤਿਨਿ_creator_vs_ਤਿਨ_pronoun','ਤਿਨਿ (sihari) = past agent "Creator" OR number three (3); ਤਿਨ (no sihari) = pronoun "those/they"','ਤਿਨਿ / ਤਿਨ','ਜਿਸਕਾ ਸਾ ਤਿਨਿ ਲੀਆ ਮਿਲਾਇ (Sukhmani) = Creator united | ਤਿਣਿ ਚੇਲੇ ਪਰਵਾਣੁ (Jap Ji) = three disciples (number 3) | ਤਿਨ ਹੋਵਤ ਆਤਮ ਪਰਗਾਸ (Sukhmani) = those who (pronoun)','grammar_pdf_p69');
INSERT INTO "grammar_rules" VALUES(171,'word_form','ਆਪਿ_creator_and_being','ਆਪਿ (sihari) = Creator/Almighty as past agent OR "the being/self" (sihari used because being and Creator are one — theological point)','ਆਪਿ','ਜਿਨ ਕਉ ਆਪਿ ਦੇਇ ਵਡਿਆਈ (M:4 Var Gauri) = Creator gives | ਆਪਿ ਜਪਹੁ ਅਵਰਾ ਨਾਮੁ ਜਪਾਵਹੁ (Sukhmani) = the being (sihari: being = Creator)','grammar_pdf_p70');
INSERT INTO "grammar_rules" VALUES(172,'word_form','ਆਪਿ_vs_ਆਪੁ','ਆਪਿ (sihari) = Creator as past agent / "the Being" whose self IS Creator; ਆਪੁ (aungkar) = the individual self/ego "himself/herself"','ਆਪਿ / ਆਪੁ','ਆਪਿ ਕਰੇ ਕਿਸੁ ਆਖੀਐ (Creator acts) | ਆਪੁ ਗਵਾਇ ਸੇਵਾ ਕਰੇ (efface your ego-self)','grammar_pdf_p71');
INSERT INTO "grammar_rules" VALUES(173,'principle','nirgun_sargun_distinction','Nirgun (ਨਿਰਗੁਣ) = Creator without attributes, beyond creation; Sargun (ਸਰਗੁਣ) = Creator manifest in creation with attributes — same One, two aspects; ਆਪਿ used for both because the Being is Creator','ਨਿਰਗੁਣ / ਸਰਗੁਣ','ਆਪੇ ਨਿਰਗੁਣੁ ਆਪੇ ਸਰਗੁਣੁ (M:5) — Creator is both; theological foundation for ਆਪਿ covering both states','grammar_pdf_p72');
INSERT INTO "grammar_rules" VALUES(174,'word_form','ਖੁਦਿ_creator_agent','ਖੁਦਿ (sihari) = Arabic/Persian "Khud" (self/God) as past agent marker — equivalent to ਆਪਿ; Creator performed the action','ਖੁਦਿ','ਖੁਦਿ ਕੁਦਰਤਿ ਕੀਮਤਿ ਕਰੇ (Creator himself sets the value of His creation)','grammar_pdf_p72');
INSERT INTO "grammar_rules" VALUES(175,'vowel_mark','sihari_replacing_bihari_meter','Section 19.0: sihari replaces bihari (ੀ) for poetic meter needs — meaning unchanged, both forms valid; Guru Granth uses shorter sihari to fit poetic rhythm (ਕਾਵਿ-ਰਚਨਾ)','ਚੇਰਿ=ਚੇਰੀ, ਪੰਖਿ=ਪੰਖੀ, ਦਰਬਾਰਿ=ਦਰਬਾਰੀ, ਸੁਆਮਿ=ਸੁਆਮੀ, ਪ੍ਰੀਤਿ=ਪ੍ਰੀਤੀ, ਰਜਾਇ=ਰਜ਼ਾਈ','ਚੇਰਿ ਕਹਾਵਉ ਸੁਆਮਿ ਤੁਮਾਰੀ (Suhi M:4) = I am called servant of my Master | ਪੰਖਿ ਨ ਚੁਕਾ (bird — meter form)','grammar_pdf_p73');
INSERT INTO "grammar_rules" VALUES(176,'word_form','ਦਰਬਾਰਿ_bihari_meter','ਦਰਬਾਰਿ (sihari) = ਦਰਬਾਰੀ "of the Court / courtly" — bihari replaced by sihari for meter; NOT the locative "in the Court" (which uses different grammar)','ਦਰਬਾਰਿ / ਦਰਬਾਰੀ','ਦਰਬਾਰਿ ਸੋਭਾ ਪਾਵਹਿ (obtain glory at/of the Court) — sihari=bihari meter form','grammar_pdf_p73');
INSERT INTO "grammar_rules" VALUES(177,'vowel_mark','sihari_replacing_lava_meter','sihari also replaces ਲਾਵਾਂ (other vowel markers) for poetic meter: ਨੇਰਿ=ਨੇੜੇ (near), ਚਾਰਿ=ਚਾਰੇ (all four), ਤਲਿ=ਤਲੇ (below/under)','ਨੇਰਿ / ਚਾਰਿ / ਤਲਿ','ਸਦਾ ਨੇਰਿ ਦੂਰਿ ਨ ਜਾਹੁ (always near — ਨੇਰਿ=ਨੇੜੇ) | ਚਾਰਿ ਪਦਾਰਥ (the four gifts — ਚਾਰਿ=ਚਾਰੇ)','grammar_pdf_p74');
INSERT INTO "grammar_rules" VALUES(178,'word_form','ਧੰਨਿ_short_form','ਧੰਨਿ = short poetic form of ਧੰਨਾ/ਧੰਨੁ "blessed/praise be"; sihari is meter contraction — same meaning as full form','ਧੰਨਿ','ਧੰਨਿ ਸੁ ਦੇਸੁ ਜਹਾ ਤੂੰ ਵਸਿਆ (Tukhari M:5) = blessed is that land where You dwell','grammar_pdf_p74');
INSERT INTO "grammar_rules" VALUES(179,'vowel_mark','bihari_plural_preposition','Section 20.1: bihari (ੀ) on noun = plural preposition form — "with the [plural noun]s / by the [plural noun]s / to the [plural noun]s"; equivalent to ਾਂ ਨੇ/ਨੂੰ/ਨਾਲ','ਸਿਖੀ=ਸਿੱਖਾਂ ਨੇ, ਅਖੀ=ਅੱਖਾਂ ਨੂੰ, ਉਪਾਵੀ=ਉਪਾਵਾਂ ਨਾਲ, ਅਖਰੀ=ਅੱਖਰਾਂ ਨਾਲ','ਸਿਖੀ ਸਿਖਿਆ ਗੁਰ ਵੀਚਾਰਿ (Jap Ji) = the Sikhs, through Guru''s teaching, contemplate | ਅਖੀ ਬਾਝਹੁ ਵੇਖਣਾ (without eyes seeing)','grammar_pdf_p75');
INSERT INTO "grammar_rules" VALUES(180,'word_form','ਅਖੀ_plural_preposition','ਅਖੀ (bihari) = plural preposition "with/through the eyes" (ਅੱਖਾਂ ਨਾਲ/ਨੂੰ); ਅਖੁ (aungkar) = noun singular "eye"','ਅਖੀ / ਅਖੁ','ਅਖੀ ਬਾਝਹੁ ਵੇਖਣਾ ਵਿਣੁ ਕੰਨਾ ਸੁਣਣਾ (Anand Sahib) = to see without eyes, hear without ears','grammar_pdf_p75');
INSERT INTO "grammar_rules" VALUES(181,'tense','bihari_first_person_verb','Section 20.2: bihari (ੀ) on verb = 1st person singular "I [do/will do]" (ਮੈਂ ਕਰਾਂ); present/future tense self-reference','ਸੋਚੀ=ਮੈਂ ਸੋਚਾਂ, ਕਰੀ=ਮੈਂ ਕਰਾਂ, ਦੇਖੀ=ਮੈਂ ਦੇਖਾਂ, ਵਣਜੀ=ਮੈਂ ਵਣਜ ਕਰਾਂ','ਸੋਚੀ ਸੋਚਿ ਨ ਹੋਵਈ (Jap Ji) = even if I think and think [it cannot be known] | ਕਿਆ ਕਰੀ ਕਿਛੁ ਕਹਣੁ ਨ ਜਾਇ (what shall I do/say)','grammar_pdf_p76');
INSERT INTO "grammar_rules" VALUES(182,'vowel_mark','bihari_replacing_sihari','Section 20.3: bihari (ੀ) replaces sihari for poetic meter — same grammatical meaning; ਲਹਨੀ=ਲਹਨਿ (3rd plural "they receive"), ਜਾਣੀ=ਜਾਣਿ (conjunctive/preposition)','ਲਹਨੀ=ਲਹਨਿ, ਜਾਣੀ=ਜਾਣਿ','ਲਹਨੀ ਦਾਤਿ ਸੰਤੋਖੁ (they receive the gift of contentment) — bihari=sihari meter | ਜਾਣੀ ਜਾਣੁ ਨ ਦੇਵਉ (having known, I will not give up)','grammar_pdf_p76');
INSERT INTO "grammar_rules" VALUES(183,'vowel_mark','bihari_as_preposition','bihari (ੀ) on noun = instrumental preposition "by means of / through / with" (ਨਾਲ); ਨਦਰੀ=ਨਦਰ ਨਾਲ, ਵਿਜੋਗੀ=ਵਿਜੋਗ ਨਾਲ','ਨਦਰੀ / ਵਿਜੋਗੀ','ਨਦਰੀ ਨਦਰਿ ਨਿਹਾਲ (Jap Ji) = by the Glance of Grace, blissful | ਵਿਜੋਗੀ ਦੁਖੁ ਪਾਇਆ (by separation, pain is found)','grammar_pdf_p76');
INSERT INTO "grammar_rules" VALUES(184,'vowel_mark','aungkar_singular_marker','Section 21.0: aungkar (ੁ) marks singular on BOTH noun and its adjective — both take aungkar together; this is the fundamental singular agreement rule','ਸੱਚਾ ਸਾਹਿਬੁ, ਮਹਾਨੁ ਕਰਤਾਰੁ','ਸੱਚਾ ਸਾਹਿਬੁ ਸਾਚੁ ਨਾਇ (Jap Ji) = True is the Master, True the Name — both noun+adjective take aungkar','grammar_pdf_p77');
INSERT INTO "grammar_rules" VALUES(185,'tense','past_tense_nu_ending','Section 22.0: past tense singular verb ending -ਨੁ (ਨ + aungkar) = "he/she/Creator did [action to plural objects]"; subject is singular, objects are plural','ਬਖਸਿਅਨੁ, ਕੀਤਨੁ, ਦਿੱਤਨੁ','ਬਖਸਿਅਨੁ ਨਾਮ ਨਿਧਾਨੁ (M:5) = He (singular) bestowed the treasure of Naam [plural blessings] | -ਨੁ marks singular agent doing plural action','grammar_pdf_p77');
INSERT INTO "grammar_rules" VALUES(186,'tense','past_tense_nu_vs_ni','past tense contrast: -ਨੁ (aungkar) = singular agent "he examined/did"; -ਨਿ (sihari) = plural "they examined/did"','ਪਰਖਿਅਨੁ / ਪਰਖੀਅਨਿ','ਪਰਖਿਅਨੁ (he alone examined) vs ਪਰਖੀਅਨਿ (they examined) — aungkar=singular, sihari=plural agent','grammar_pdf_p78');
INSERT INTO "grammar_rules" VALUES(187,'word_class','imperative_aungkar','Section 23.0: aungkar (ੁ) on verb = imperative "You [singular, respectful] do this!" — formal command directed to one person; differs from sihari imperative (less formal)','ਦੇਹੁ, ਚਲੁ, ਪਰੁ, ਸੁਣਹੁ, ਮਿਲਹੁ','ਦੇਹੁ ਦਰਸਨੁ ਹੋਇ ਦਇਆਲੁ (M:5) = Give [Your] darshan, be merciful | ਸੁਣਹੁ ਬਿਨੰਤੀ ਮੇਰੀ ਹਰਿ ਜੀਉ (hear my prayer)','grammar_pdf_p78');
INSERT INTO "grammar_rules" VALUES(188,'vowel_mark','original_aungkar_words','Section 24.0: some words carry original/inherited aungkar from Sanskrit/Arabic — permanent, not grammatical number marker; must be recognized to avoid misreading as masculine singular','ਕਿਤੁ, ਬਿਨੁ, ਬਹੁਤੁ, ਬਿੰਦੁ, ਸੁਤੁ, ਜੰਤੁ','ਕਿਤੁ ਦਰਵਾਜੈ ਰਖਾ (Anand) = at which door shall I keep [watch]? — ਕਿਤੁ is original aungkar, not singular marker','grammar_pdf_p79');
INSERT INTO "grammar_rules" VALUES(189,'gender','feminine_original_aungkar','some feminine nouns carry original aungkar — they are feminine despite the aungkar which normally marks masculine; reader must know these by recognition','ਧਾਤੁ=substance/metal (f), ਭਿਖੁ=begging (f), ਰਤੁ=blood (f), ਮਲੁ=filth (f), ਮਸੁ=ink (f)','ਰਤੁ ਪੀਣੇ ਮਾਣਸ ਤੇ ਕੁੰਗੂ (Asa M:1) = those who drink blood [feminine noun ਰਤੁ] | ਮਸੁ ਕਰਿ ਮੇਘ ਵਰਸਾਵਉ (if I make ink of clouds)','grammar_pdf_p79');
INSERT INTO "grammar_rules" VALUES(190,'word_form','ਬਿਨੁ_original_aungkar','ਬਿਨੁ = "without" — conjunction/preposition with original aungkar; NOT singular marker; always written with aungkar on ਨ','ਬਿਨੁ','ਬਿਨੁ ਸਤਿਗੁਰ ਕਿਨੈ ਨ ਪਾਇਓ (without the Satguru none has found) — original aungkar, not grammatical','grammar_pdf_p79');
INSERT INTO "grammar_rules" VALUES(191,'vowel_mark','hu_subject_case','Section 25.0: single ਹੁ (ਹ + aungkar, no nasal) after word = nominative/subject case marker "the Creator/subject"; marks the main agent','ਸਤਿਗੁਰਹੁ, ਪ੍ਰਭਹੁ','ਮੇਰੇ ਸਤਿਗੁਰਹੁ ਕਿਰਪਾ ਕਰੀ (M:4) = My Satguru showed grace — ਹੁ marks subject/nominative','grammar_pdf_p80');
INSERT INTO "grammar_rules" VALUES(192,'case','hahu_ablative_case','double ਹਹੁ (two ਹ with aungkar) = ablative case "from / out of / away from"; distinguishes direction away from subject','ਰਾਹੁ vs ਰਾਹਹੁ, ਕਹੁ vs ਕਹਹੁ','ਰਾਹੁ (the path) vs ਰਾਹਹੁ (from the path) | ਕਹੁ (say — imperative) vs ਕਹਹੁ (from saying / because of saying) — single vs double ਹ distinguishes case','grammar_pdf_p80');
INSERT INTO "grammar_rules" VALUES(193,'vowel_mark','dulangkar_noun_before_preposition','Section 26.0-26.1: dulangkar (ੁ, aungkar) on noun when followed by a preposition word; marks noun as object/base for preposition','ਵਸਤੁ, ਜਿੰਦੁ, ਖਾਕੁ, ਸਸੁ, ਪੀਯੁ','ਵਸਤੁ ਅੰਦਰਿ ਵਸਤੁ ਸਮਾਵੈ (Asa di Var) | ਸਾਹੇ ਲਿਖੇ ਨ ਚਲਨੀ ਜਿੰਦੁ ਕੂੰ ਸਮਝਾਇ (Salok Farid) | ਸਸੁ ਤੇ ਪਿਰਿ ਕੀਨੀ ਵਾਖਿ (Asa M:5)','grammar_pdf_p81');
INSERT INTO "grammar_rules" VALUES(194,'vowel_mark','dulangkar_as_preposition','Section 26.2: dulangkar used as preposition meaning "in/within" — word with aungkar itself functions as locative (ਵਿਚ)','ਖੇਹੁ=ਖੇਹ ਵਿਚ','ਖੇਹੁ ਖੇਹ ਰਲਾਈਏ (Siri Ragu M:1) = merged into dust [ਖੇਹੁ = in dust]','grammar_pdf_p82');
INSERT INTO "grammar_rules" VALUES(195,'vowel_mark','dulangkar_replacing_hora','Section 26.3: dulangkar replaces hora (ੋ) for poetic meter — meaning identical to hora form; ਜਿਦੂ=ਜਿਦੋਂ (from which), ਤਿਦੂ=ਤਿਦੋਂ (from then), ਕੂ=ਕੋ','ਜਿਦੂ=ਜਿਦੋਂ, ਤਿਦੂ=ਤਿਦੋਂ, ਕੂ=ਕੋ, ਅਸਲੂ=ਅਸਲੋਂ','ਜਿਦੂ ਕਿਛੁ ਗੁਝਾ ਨ ਹੋਇ (Var Gauri M:4) = from which nothing is hidden | ਮਾਸ ਨ ਤਿਦੂ ਖਾਹਿ (Salok Farid) | ਦੁਖ ਮੁਝ ਕੂ (to me)','grammar_pdf_p82');
INSERT INTO "grammar_rules" VALUES(196,'vowel_mark','laan_replacing_sihari','Section 27.0: laa''n (ਾ, lavan) replaces sihari for poetic meter — same grammatical meaning; forms are interchangeable','ਪੜੇ=ਪੜਿ, ਮੁਹੇ=ਮੁਹਿ, ਕੁੜੇ=ਕੁੜਿ, ਦਰੇ=ਦਰਿ, ਸੰਸਾਰੇ=ਸੰਸਾਰਿ, ਸੰਗੇ=ਸੰਗਿ, ਸਾਥੇ=ਸਾਥਿ, ਧੁਰੇ=ਧੁਰਿ, ਉਪਰੇ=ਉਪਰਿ, ਅੰਤੇ=ਅੰਤਿ','ਕਬਿਤ ਪੜੇ ਪੜਿ ਕਬਿਤਾ ਮੁਏ (Sorath Kabir) — same line uses both forms | ਸੰਤੋਖੁ ਭਇਆ ਸੰਸਾਰੇ (=ਸੰਸਾਰਿ, Sorath M:5) | ਨਾਨਕ ਪ੍ਰਭੁ ਮੇਰੈ ਸਾਥੇ (=ਸਾਥਿ, Sorath M:5)','grammar_pdf_p82');
INSERT INTO "grammar_rules" VALUES(197,'word_form','laan_sihari_same_line','same verse can use both laa''n and sihari forms of same word — confirms they are stylistic variants, not grammatically distinct','ਦਰੇ=ਦਰਿ','ਹਰਿ ਦਰੇ ਹਰਿ ਦਰਿ ਸੋਹਨਿ ਤੇਰੇ ਭਗਤ ਪਿਆਰੇ ਰਾਮ (Asa M:5) — ਦਰੇ and ਦਰਿ in same tuk','grammar_pdf_p83');
INSERT INTO "grammar_rules" VALUES(198,'vowel_mark','dulaava_place_preposition','Section 28.0-28.1: dulaava (ੈ) marks locative/place preposition "in/at/on/with" — used with place nouns, nouns of location, and relational nouns','ਦੂਜੈ=ਦੂਜੇ ਨਾਲ, ਰਿਦੈ=ਰਿਦੇ ਵਿਚ, ਮੰਦੈ=ਮੰਦ ਵਿਚ, ਰੈਨਡੀਏ=ਰੈਨ ਵਿਚ, ਚਉਕੈ, ਮਥੈ, ਪੇੜੈ, ਅਗੈ, ਤਲੈ, ਪਿਛੈ','ਸਭੋ ਸੁਤਕੁ ਭਰਮੁ ਹੈ ਦੂਜੈ ਲਗੈ ਜਾਇ (Asa di Var) | ਸਚੁ ਤਾ ਪਰੁ ਜਾਣੀਐ ਜਾ ਰਿਦੈ ਸਚਾ ਹੋਇ (Asa di Var)','grammar_pdf_p83');
INSERT INTO "grammar_rules" VALUES(199,'vowel_mark','dulaava_noun_preposition','Section 28.2: dulaava (ੈ) on noun = locative "in/to/of the [noun]" where a preposition word follows; parallels sihari but for different case contexts','ਘਰੈ, ਨਾਵੈ','ਘਰੈ ਅੰਦਰਿ ਸਭੁ ਵਥੁ ਹੈ (Asa M:3) = within the house everything exists | ਸਭ ਨਾਵੈ ਨੋ ਲੋਚਦੀ (Asa M:3) = all long for the Name','grammar_pdf_p84');
INSERT INTO "grammar_rules" VALUES(200,'vowel_mark','dulaava_adjective_agreement','Section 28.3: when noun carries sihari or dulaava, its adjective must also take dulaava (ੈ) — agreement in oblique case; dulaava replaces laa''n on adjective','ਅੰਧੈ, ਪੂਰੈ, ਭੀੜੈ, ਭੀਹਾਵਲੈ, ਮੇਰੈ, ਤੇਰੈ, ਪਰਾਇਓ, ਕਚੈ, ਪਹਿਲੈ','ਗੁਰਿ ਪੂਰੈ ਮਿਹਰਵਾਨਿ (M:4) = by the Perfect Guru, merciful — ਗੁਰਿ (sihari) → ਪੂਰੈ (dulaava) | ਮੁਰਖਿ ਅੰਧੈ ਪਤਿ ਗਵਾਈ (Asa di Var)','grammar_pdf_p84');
INSERT INTO "grammar_rules" VALUES(201,'principle','terai_mani_bhavde_correct_reading','ਭਗਤ ਤੇਰੈ ਮਨਿ ਭਾਵਦੇ (Asa di Var) = "devotees are pleasing to Your mind" NOT "devotees are pleasing Your mind"; ਤੇਰੈ = locative "to Your [mind]", ਮਨਿ = dative; subject is ਭਗਤ','ਤੇਰੈ ਮਨਿ','ਭਗਤ ਤੇਰੈ ਮਨਿ ਭਾਵਦੇ — devotees are beloved in Your heart (not: devotees love Your mind)','grammar_pdf_p85');
INSERT INTO "grammar_rules" VALUES(202,'vowel_mark','dulaava_verb_causal','Section 28.4: dulaava on verb-noun = causal "by means of [verb action]"; ਸੁਣਿਓ = ਸੁਣਨ ਕਰਕੇ "by hearing" — same pattern as sihari on verb (rule 14 cross-reference)','ਸੁਣਿਓ=ਸੁਣਨ ਕਰਕੇ','dulaava on verb-noun marks the action as the cause/instrument of the main clause result','grammar_pdf_p86');
INSERT INTO "grammar_rules" VALUES(203,'case','kenora_ablative_preposition','Section 29.0: kenora (ੈਂ / ਹੈਂ) used as ablative preposition "from / away from / out of" on locative nouns; ਆਪੈਂ=ਆਪ ਥੋਂ (from oneself), ਮੁਹੈਂ=ਮੁੰਹ ਤੋਂ (from the mouth)','ਆਪੈਂ=ਆਪ ਥੋਂ, ਮੁਹੈਂ=ਮੁੰਹ ਤੋਂ, ਜੀਭੌਂ=ਜੀਭ ਤੋਂ','ਨਾਨਕ ਜੇ ਕੋ ਆਪੈਂ ਜਾਣੈ ਅਗੈ ਗਇਆ ਨ ਸੋਹੈ (Jap Ji) = one who thinks himself above [from oneself outward] will not look good ahead | ਮੁਹੈਂ ਕਿ ਬੋਲਣੁ ਬੋਲੀਐ (Jap Ji)','grammar_pdf_p86');
INSERT INTO "grammar_rules" VALUES(204,'vowel_mark','original_sihari_extended_list','Section 30.1: extended list of original/inherited sihari words — sihari is permanent, comes from source language (Sanskrit/Arabic); cannot be removed or replaced by aungkar','ਹਰਿ, ਨਾਰਿ, ਰਾਸਿ, ਜੁਗਤਿ, ਧੁਨਿ, ਭੂਮਿ, ਧਰਤਿ, ਪ੍ਰੀਤਿ, ਦ੍ਰਿਸਟਿ, ਸਿਮ੍ਰਿਤਿ, ਨਾਭਿ, ਸ਼ਕਤਿ, ਰੈਣਿ, ਰਾਤਿ, ਰੁਤਿ, ਸ੍ਰਿਸਟਿ, ਕੀਰਤਿ, ਰਵਿ, ਅਗਨਿ, ਸਮਾਧਿ, ਮਰਤਿ, ਜਤਿ, ਜੋਤਿ, ਰੀਤਿ, ਅਤਿ, ਸਰਣਿ, ਨਿਧਿ, ਰਿਧਿ, ਬਿਧਿ, ਜੋਨਿ, ਸੁਰਤਿ, ਧੁਰਿ, ਮੁਨਿ, ਤ੍ਰਿਪਤਿ, ਉਪਾਧਿ, ਚਿੰਤਾਮਣਿ','ਰਿਧਿ ਬੁਧਿ ਸਿਧਿ ਗਿਆਨੁ ਸਦਾ ਸੁਖੁ ਹੋਇ (M:1 Var Malar) — all three have original sihari','grammar_pdf_p88');
INSERT INTO "grammar_rules" VALUES(205,'word_form','bhagti_vs_bhagtu','ਭਗਤਿ (original sihari) = devotion/bhakti (abstract noun); ਭਗਤੁ (aungkar) = devotee singular (person); ਭਗਤ (mukta) = devotees plural','ਭਗਤਿ / ਭਗਤੁ / ਭਗਤ','ਤੇਰੀ ਭਗਤਿ ਤੇਰੀ ਭਗਤਿ ਭੰਡਾਰ ਜੀ (Asa M:4) = Your devotion [abstract] | ਤੇਰੇ ਭਗਤ ਸਲਾਹਨਿ ਤੁਧੁ ਜੀ (plural devotees)','grammar_pdf_p88');
INSERT INTO "grammar_rules" VALUES(206,'word_form','mukti_vs_muktu','ਮੁਕਤਿ (original sihari) = liberation/mukti (abstract noun); ਮੁਕਤੁ (aungkar) = liberated one (person); ਮੁਕਤ (mukta) = liberated plural','ਮੁਕਤਿ / ਮੁਕਤੁ / ਮੁਕਤ','ਮੁਕਤਿ ਭੁਗਤਿ ਜੁਗਤਿ ਤੇਰੀ ਸੇਵਾ (Suhi M:5) = liberation, sustenance, unity — through Your service | ਇਹ ਜੀਉ ਸਦਾ ਮੁਕਤੁ ਹੈ (M:3 Var Gujari) = this soul is always liberated (person)','grammar_pdf_p88');
INSERT INTO "grammar_rules" VALUES(207,'word_form','gati_vs_gatu','ਗਤਿ (original sihari) = spiritual state/condition (abstract); ਗਤੁ (aungkar) = went/departed/passed (verb form meaning "became gone")','ਗਤਿ / ਗਤੁ','ਨਾਮੋ ਗਤਿ ਨਾਮੋ ਪਤਿ ਜਨ ਕੀ (Dhanasari M:5) = Name is the state, Name is the honor | ਅਪਿਓ ਪੀਓ ਗਤੁ ਭੀਓ ਭਰਮਾ (Jetsari M:5) = drank nectar, delusion departed','grammar_pdf_p89');
INSERT INTO "grammar_rules" VALUES(208,'word_form','budhi_vs_budhu','ਬੁਧਿ (original sihari) = intellect/wisdom (abstract noun); ਬੁਧੁ (aungkar) = Buddha/wise person (masculine singular); ਬੁਧ ਸਿਧ (mukta) = plural wise ones','ਬੁਧਿ / ਬੁਧੁ / ਬੁਧ','ਰਿਧਿ ਬੁਧਿ ਸਿਧਿ ਗਿਆਨੁ ਸਦਾ ਸੁਖੁ ਹੋਇ (M:1) = spiritual powers, wisdom, siddhis | ਤੈ ਵਿਚਿ ਸਿਧ ਬੁਧ ਸੁਰ ਨਾਥ (Asa di Var) = plural persons','grammar_pdf_p89');
INSERT INTO "grammar_rules" VALUES(209,'word_form','mati_vs_matu','ਮਤਿ (original sihari) = intellect/understanding (abstract); ਮਤੁ (aungkar) = drunk/intoxicated (adjective/verb form = ਮੱਤਾ ਹੋਇਆ)','ਮਤਿ / ਮਤੁ','ਮਤਿ ਥੋੜੀ ਸੇਵ ਗਵਾਈਐ (Asa di Var) = through little intellect, service is wasted | ਮਨੁ ਮੈ ਮਤੁ ਮੈਗਲ ਮਿਕਦਾਰਾ (Dhanasari M:3) = mind drunk like intoxicated elephant','grammar_pdf_p89');
INSERT INTO "grammar_rules" VALUES(210,'word_form','pati_vs_patu','ਪਤਿ (original sihari) = husband OR honor/dignity (abstract); ਪਤੁ (aungkar/mukta) = leaf/petal (noun) OR Jogi''s ਪੱਟਾ (begging cloth)','ਪਤਿ / ਪਤੁ / ਪਤ','ਜਹ ਨਿਰਮਲ ਪੁਰਖੁ ਪੁਰਖ-ਪਤਿ ਹੋਤਾ (Sukhmani) = husband/lord | ਮੁਰਖਿ ਅੰਧੈ ਪਤਿ ਗਵਾਈ = honor lost | ਫਲ ਫਿਕੇ ਫੁਲ ਬਕਬਕੇ ਕੰਮਿ ਨ ਆਵਹਿ ਪਤ (Asa di Var) = leaves [no sihari, noun]','grammar_pdf_p90');
INSERT INTO "grammar_rules" VALUES(211,'word_form','miti_vs_mitu','ਮਿਤਿ (original sihari) = measure/extent/limit (abstract); ਮਿਤੁ (aungkar) = friend (masculine noun)','ਮਿਤਿ / ਮਿਤੁ','ਕਰਤੇ ਕੀ ਮਿਤਿ ਕਰਤਾ ਜਾਣੈ (Dakhni Omkar) = Creator alone knows His own extent | ਮਿਟੀ ਪਈ ਅਟੋਲਵੀ ਕੋਇ ਨ ਹੋਸੀ ਮਿਤੁ (Salok Farid) = no one will be a friend','grammar_pdf_p90');
INSERT INTO "grammar_rules" VALUES(212,'word_form','sati_vs_satu','ਸਤਿ (original sihari) = True/Truth as adjective (eternal attribute of Creator); ਸਤੁ (aungkar/mukta) = truth/virtue/reality as noun','ਸਤਿ / ਸਤੁ','ਚਰਨ ਸਤਿ, ਸਤਿ ਪਰਸਨਹਾਰ | ਆਪਿ ਸਤਿ, ਸਤਿ ਸਭ ਧਾਰੀ (Sukhmani) = True the feet, True the worship | ਸਤੁ ਸੰਤੋਖੁ ਪਤੁ ਕਰਿ ਝੋਲੀ (Ramkali M:3) = make truth and contentment your begging-bag [noun]','grammar_pdf_p90');
INSERT INTO "grammar_rules" VALUES(213,'word_form','satu_virtue_noun','ਸਤੁ (aungkar) = virtue/chastity/giving as concrete noun (act of purity, charity); distinct from ਸਤਿ (adjective "True")','ਸਤੁ / ਸਤ','ਸੁਣਿਐ ਸਤੁ ਸੰਤੋਖੁ ਗਿਆਣੁ (Jap Ji) = truth-virtue, contentment, wisdom | ਸਤੁ ਸੀਗਾਰ ਭਉ ਅੰਜਨੁ ਪਾਇਆ (Suhi M:5) = virtue-chastity as adornment | ਪਤਿ ਵਿਣੁ ਪੂਜਾ ਸਤ ਵਿਣੁ ਸੰਜਮ (Ramkali M:1) = without virtue, discipline is empty','grammar_pdf_p91');
INSERT INTO "grammar_rules" VALUES(214,'word_form','kali_vs_kal','ਕਲਿ (sihari) = Kalyug (dark age) OR anxiety/mental anguish; ਕਲ (no sihari) = art/skill/power/plan — no sihari when meaning is craft or creative power','ਕਲਿ / ਕਲ','ਕਲਿ ਕਲੇਸ ਮਿਟੰਤ ਸਿਮਰਣਿ (Gujari M:5) = anxieties of Kalyug removed | ਆਪੇ ਹੀ ਕਰਣਾ ਕੀਓ ਕਲ ਆਪੇ ਹੀ ਤੈ ਧਾਰੀਓ (Asa di Var) = You Yourself created the art/power — ਕਲ=skill, no sihari','grammar_pdf_p91');
INSERT INTO "grammar_rules" VALUES(215,'word_form','sathi_number_vs_fool','ਸਠਿ (sihari) = 68 (number, from Sanskrit ਸ਼ਾਸ਼ਟਿ); ਸਠੀ = older form of the same; ਸਠ (mukta) = fool/stubborn','ਸਠਿ / ਸਠੀ / ਸਠ','ਸੁਣਿਐ ਅਠਸਠਿ ਕਾ ਇਸਨਾਣੁ (Jap Ji) = hearing [equals bathing at] 68 pilgrimage sites | ਸਠ ਕਠੋਰੁ ਕੁਲਹੀਣੁ ਬਿਆਪਤ ਮੋਹੁ ਕੀਚੁ (Asa M:5) = stubborn fool','grammar_pdf_p93');
INSERT INTO "grammar_rules" VALUES(216,'word_form','koti_million_vs_kot_fort','ਕੋਟਿ (sihari on ਟ) = ten million/crore (number); ਕੋਟੁ/ਕੋਟ (aungkar/mukta) = fort/fortress','ਕੋਟਿ / ਕੋਟੁ','ਕੋਟਿ = ten million (cardinal number, original sihari) | ਕੋਟੁ = fort — no sihari when meaning is fort','grammar_pdf_p93');
INSERT INTO "grammar_rules" VALUES(217,'word_form','hasti_elephant_vs_hast','ਹਸਤਿ/ਹਸਤੀ (sihari/bihari) = elephant; ਹਸਤੁ/ਹਸਤ (aungkar/mukta) = happen, hand, or laughing — opposite meanings, same spelling root','ਹਸਤਿ / ਹਸਤੁ','ਹਸਤਿ (elephant) takes sihari/bihari | when meaning is "to happen" or "hand" or "laughter" then aungkar or mukta','grammar_pdf_p93');
INSERT INTO "grammar_rules" VALUES(218,'word_form','sudhi_vs_sudhu','ਸੁਧਿ (sihari) = realization/awareness/consciousness; ਸੁਧੁ (aungkar) = corrected/purified/set right','ਸੁਧਿ / ਸੁਧੁ','ਸੁਧਿ = spiritual awareness (abstract noun, original sihari) | ਸੁਧੁ = one who is corrected (adjective/noun)','grammar_pdf_p93');
INSERT INTO "grammar_rules" VALUES(219,'word_form','murti_vs_murtu','ਮੂਰਤਿ (sihari) = idol/image/form (original sihari, from Sanskrit ਮੂਰ੍ਤਿ); ਮੂਰਤੁ (aungkar) = auspicious time/muhurat (ਮੁਹੂਰਤ)','ਮੂਰਤਿ / ਮੂਰਤੁ','ਮੂਰਤਿ = idol/divine form (sihari permanent) | ਮੂਰਤੁ = muhurat/auspicious moment (aungkar, different word)','grammar_pdf_p93');
INSERT INTO "grammar_rules" VALUES(220,'gender','feminine_agent_noun_ni_ending','Section 30.2: feminine agent/role nouns end in -ਣਿ (ਣ + sihari); masculine counterpart has -ਣ/ਣੁ; these are professional/relational feminine nouns','ਭੰਡਾਰਣਿ, ਸੋਹਾਗਣਿ, ਪਰਦੇਸਣਿ, ਕਲਾਲਣਿ, ਬੈਰਣਿ, ਮਾਲਣਿ, ਬਨਜਾਰਣਿ, ਸਾਹਣਿ, ਸਾਪਣਿ, ਸਰਪਣਿ, ਜਲਣਿ, ਦਾਮਣਿ, ਵਰਤਣਿ, ਪੜੋਸਣਿ, ਸਉਕਣਿ, ਗੀਹਣਿ, ਤਾਜਣਿ, ਘਾਣਿ, ਕਾਣਿ, ਆਣਿ, ਪਾਣਿ','ਸੋਹਾਗਣਿ = fortunate/married woman | ਕਲਾਲਣਿ = wine-seller woman | ਦਾਮਣਿ = lightning | ਪੜੋਸਣਿ = neighbor woman','grammar_pdf_p94');
INSERT INTO "grammar_rules" VALUES(221,'word_form','kaman_charm_vs_kamani_woman','ਕਾਮਣ (mukta) = charm/spell/love-talisman; ਕਾਮਣਿ (sihari) = woman — same root, opposite roles in same verse','ਕਾਮਣ / ਕਾਮਣਿ','ਗੁਣਿ ਕਾਮਣ ਕਾਮਣਿ ਕਰੈ ਤਉ ਪਿਆਰੇ ਕਉ ਪਾਵੈ (Tilang M:1) = the woman (ਕਾਮਣਿ) makes a charm (ਕਾਮਣ) of virtues [and] obtains her beloved groom','grammar_pdf_p94');
INSERT INTO "grammar_rules" VALUES(222,'word_form','taruni_vs_taranu_vs_tarun','ਤਰੁਣਿ (sihari) = young woman; ਤਰਣੁ (aungkar on ਣ) = swimming/crossing over (verbal noun); ਤਰੁਣ (mukta) = youth/adolescence — three distinct meanings from similar forms','ਤਰੁਣਿ / ਤਰਣੁ / ਤਰੁਣ','ਜੈਸੀ ਤਰੁਣਿ ਭਤਾਰ ਉਰਝੀ (Asa M:5) = woman attached to husband | ਤਰਣੁ ਦੁਹੇਲਾ ਭਇਆ ਖਿਨ ਮਹਿ ਖਸਮੁ ਚਿਤਿ ਨ ਆਇਓ (Asa M:5) = crossing [over] became difficult — ਤਰਣੁ is verb-noun NOT woman despite ਖਸਮੁ in same line','grammar_pdf_p95');
INSERT INTO "grammar_rules" VALUES(223,'principle','context_determines_gender_not_neighboring_words','do not assign gender based on neighboring words in verse; ਤਰਣੁ is wrongly read as "woman" because ਖਸਮੁ (husband) appears in same line — grammar (aungkar on ਣ) determines meaning, not context of surrounding nouns','ਤਰਣੁ misread as woman','ਤਰਣੁ ਦੁਹੇਲਾ ਭਇਆ ਖਿਨ ਮਹਿ ਖਸਮੁ ਚਿਤਿ ਨ ਆਇਓ (Asa M:5) — ਤਰਣੁ (aungkar)=crossing, not woman; ਤਰੁਣਿ (sihari) would mean woman','grammar_pdf_p95');
INSERT INTO "grammar_rules" VALUES(224,'gender','feminine_sihari_additional_list','additional feminine words with original/permanent sihari: ਬੇਲਿ/ਵੇਲਿ, ਦਾਲਿ, ਭਾਲਿ, ਭੀਤਿ, ਕਰਤੂਤਿ, ਦਾਤਿ, ਤਪਤਿ, ਮਸੀਤਿ, ਹਟਤਾਰਿ, ਲਬਧਿ, ਨਦਰਿ, ਖਬਰਿ, ਡੋਰਿ, ਵਾਰਿ/ਵਾੜਿ, ਅਰਦਾਸਿ, ਫੁਰਮਾਇਸਿ, ਸਾਬਾਸਿ, ਰਹਰਾਸਿ, ਰਾਸਿ','ਭੀਤਿ=wall(f), ਕਰਤੂਤਿ=deed(f), ਦਾਤਿ=gift(f), ਨਦਰਿ=grace(f), ਖਬਰਿ=news(f), ਅਰਦਾਸਿ=prayer(f), ਰਹਰਾਸਿ=evening prayer(f)','all these feminine nouns carry permanent sihari regardless of grammatical position','grammar_pdf_p95');
INSERT INTO "grammar_rules" VALUES(225,'gender','arabic_feminine_ti_extended_list','Section 30.4: extended list of Arabic-origin feminine nouns ending in -ਤਿ; all take permanent sihari on ਤ','ਕੁਦਰਤਿ, ਸਿਫਤਿ, ਹਿਕਮਤਿ, ਹੁਜਤਿ, ਮਿਹਰਾਮਤਿ, ਸਰੀਅਤਿ, ਹੁਰਮਤਿ, ਗੈਰਤਿ, ਕਰਮਾਤਿ, ਸਲਾਮਤਿ, ਕੀਮਤਿ, ਮੁਸਕਤਿ, ਮੁਹਲਤਿ, ਨਉਬਤਿ, ਨੀਅਤਿ, ਹੈਰਤਿ, ਜਰੂਰਤਿ, ਖਿਜਮਤਿ, ਦਉਲਤਿ, ਮਿੰਨਤਿ, ਖਸਲਤਿ, ਨਿਆਮਤਿ, ਸੁਨਤਿ, ਮੁਹਬਤਿ, ਤਰੀਕਤਿ, ਮਸਲਤਿ, ਉਮਤਿ','all Arabic feminine words ending in -ਤ take permanent sihari = -ਤਿ; this is a large category of loanwords','grammar_pdf_p97');
INSERT INTO "grammar_rules" VALUES(226,'word_form','eki_plural_count','ਏਕਿ (sihari) = indefinite plural "some/certain ones" (parallel to ਇਕਿ); ਏਕੁ (aungkar) = singular "one/the One"','ਏਕਿ / ਏਕੁ','ਏਕਿ ਨਚਾਵਹਿ ਏਕਿ ਭਵਾਵਹਿ ਇਕਿ ਆਇ ਜਾਇ ਹੋਇ ਧੂਰਾ (Ramkali M:5) = some He makes dance, some He makes wander','grammar_pdf_p97');
INSERT INTO "grammar_rules" VALUES(227,'principle','count_words_sihari_plural_aungkar_singular','systematic pattern for count/numeral words: aungkar or mukta = singular; sihari = indefinite plural — applies to ਇਕਿ/ਇਕੁ, ਹਿਕਿ/ਹਿਕੁ, ਏਕਿ/ਏਕੁ, ਹੋਰਿ/ਹੋਰੁ, ਅਵਰਿ/ਅਵਰੁ','ਹੋਰਿ/ਹੋਰੁ, ਅਵਰਿ/ਅਵਰੁ pattern','ਧਰਤੀ ਹੋਰੁ ਪਰੈ ਹੋਰੁ ਹੋਰੁ (Jap Ji) = singular | ਹੋਰਿ ਕੇਤੇ ਗਾਵਨਿ ਸੇ ਮੈ ਚਿਤਿ ਨ ਆਵਨਿ (Jap Ji) = plural | ਅਵਰਿ ਉਪਾਵ ਸਭਿ ਤਿਆਗਿਆ (Bilaval M:5) = all other means [plural]','grammar_pdf_p99');
INSERT INTO "grammar_rules" VALUES(228,'principle','sihari_determines_ik_meaning','if ਇਕ means "some" (indefinite plural pronoun) then ਕ must have sihari = ਇਕਿ; if sihari absent and word ਪਤਿ follows, ਪਤਿ means honor (with sihari) — absence of sihari on ਇਕ forces different reading of whole verse','ਇਕਿ vs ਇਕ — determines meaning of entire verse','"ਇਕ ਆਪੀਨੈ ਪਤਲੀ ਸਹ ਕੇਰੇ ਬੋਲਾ" — if ਇਕ = "some", ਕ needs sihari; ਪਤਲੀ is Urdu (not Farid''s language); correct reading from old sakhi: one woman is weak, Master''s commands are hard on her','grammar_pdf_p98');
INSERT INTO "grammar_rules" VALUES(229,'word_class','demonstrative_sihari_plural_masculine','Section 32.0: demonstrative pronouns ਇਹੁ/ਏਹੁ/ਓਹੁ — aungkar on ਹ = masculine singular; sihari on ਹ = feminine singular OR plural (including masculine plural); sihari overrides gender to mark plurality','ਇਹੁ/ਇਹਿ, ਏਹੁ/ਏਹਿ, ਓਹੁ/ਓਹਿ/ਓਇ','ਸਹਸਾ ਇਹੁ ਸੰਸਾਰੁ ਹੈ (masculine sg) | ਪ੍ਰਭੁ ਮਿਲਣੈ ਕੀ ਏਹ ਨੀਸਾਣੀ (feminine sg) | ਜਿਨਿ ਏਹਿ ਲਿਖੇ ਤਿਸੁ ਸਿਰਿ ਨਾਹਿ (Jap Ji) = ਏਹਿ plural, sihari on masculine word','grammar_pdf_p102');
INSERT INTO "grammar_rules" VALUES(230,'word_form','ohi_oie_plural','ਓਹੁ (aungkar) = singular "that one/He"; ਓਹਿ/ਓਇ (sihari) = plural "those/they"','ਓਹੁ / ਓਹਿ / ਓਇ','ਨਾਨਕ ਓਹੁ ਪੁਰਖੁ ਕਹੀਐ ਜੀਵਨ ਮੁਕਤਿ (Sukhmani) = singular | ਨਾ ਓਹਿ ਮਰਹਿ ਨ ਠਾਗੇ ਜਾਹਿ (Jap Ji) = plural | ਓਇ ਮਨੁਖ ਮੁੜ ਅਗਿਆਨੀ ਕਹੀਅਹਿ (Todi M:4) = plural variant ਓਇ','grammar_pdf_p102');
INSERT INTO "grammar_rules" VALUES(231,'tense','past_agent_extended_examples','Section 33.0: extended list of past tense agent markers with sihari — sihari prolongs the vowel (ਕਿ sounds like ਕੇ, ਤਿ like ਤੇ); covers Guru names, divine titles, and human agents','ਗੁਰਿ, ਪਰਮੇਸੁਰਿ, ਪ੍ਰਭਿ, ਪੁਰਖਿ, ਸਤਿਗੁਰਿ, ਬਾਪਿ, ਪਿਰਿ, ਮੁਰਖਿ, ਜਿਨਿ, ਤਿਨਿ, ਆਪਿ','ਹਾਥ ਦੇਇ ਰਾਖੇ ਪਰਮੇਸੁਰਿ ਸਗਲਾ ਦੁਰਤੁ ਮਿਟਾਇਆ (Gujari M:5) | ਕਰਤੈ ਪੁਰਖਿ ਤਾਲੁ ਦਿਵਾਇਆ (Sorath M:5) | ਬਾਪਿ ਦਿਲਾਸਾ ਮੇਰੋ ਕੀਨਾ (Asa Kabir) = Father gave comfort','grammar_pdf_p103');
INSERT INTO "grammar_rules" VALUES(232,'word_form','bapi_past_agent_father','ਬਾਪਿ (sihari) = father as past agent "Father did [action]"; ਬਾਪ (mukta) = father as noun object — both in same verse','ਬਾਪਿ / ਬਾਪ','ਬਾਪਿ ਦਿਲਾਸਾ ਮੇਰੋ ਕੀਨਾ। ਸੇਜ ਸੁਖਾਲੀ ਮੁਖਿ ਅੰਮ੍ਰਿਤੁ ਦੀਨਾ। ਤਿਸੁ ਬਾਪ ਕਉ ਕਿਉ ਮਨਹੁ ਵਿਸਾਰੀ (Asa Kabir) = ਬਾਪਿ (agent), ਬਾਪ (object of ਕਉ)','grammar_pdf_p104');
INSERT INTO "grammar_rules" VALUES(233,'word_form','jini_agent_vs_jin_relative','ਜਿਨਿ (sihari) = Creator as past agent "Creator who did"; ਜਿਨ (no sihari) = relative pronoun "those who/whoever" referring to humans','ਜਿਨਿ / ਜਿਨ','ਜਿਨਿ ਹਰਿ ਪਾਇਓ ਤਿਨਹਿ ਛਪਾਇਓ (Todi Namdev) = Creator who found [Hari] hid it | ਜਿਨ ਮਨਿ ਪ੍ਰੀਤਿ ਲਗੀ ਹਰਿ ਕੇਰੀ ਤਿਨ ਧੁਰਿ ਭਾਗ ਪੁਰਾਣਾ (Jetsari M:4) = those whose minds [human plural, no sihari]','grammar_pdf_p104');
INSERT INTO "grammar_rules" VALUES(234,'word_form','tini_creator_vs_tin_pronoun_vs_number','ਤਿਨਿ (sihari on ਨ) = Creator as past agent OR number three (3); ਤਿਨ (no sihari) = pronoun "those/they" (human, plural)','ਤਿਨਿ / ਤਿਨ','ਜਿਸਕਾ ਸਾ ਤਿਨਿ ਲੀਆ ਮਿਲਾਇ (Sukhmani) = Creator united | ਤਿਣਿ ਚੇਲੇ ਪਰਵਾਣੁ (Jap Ji) = three disciples [number] | ਤਿਨ ਹੋਵਤ ਆਤਮ ਪਰਗਾਸ (Sukhmani) = those who [pronoun, no sihari]','grammar_pdf_p105');
INSERT INTO "grammar_rules" VALUES(235,'word_form','aapi_apu_aap_full_disambiguation','three forms: ਆਪਿ (sihari) = Creator as past agent OR Being (whose self is one with Creator); ਆਪੁ (aungkar) = ego-self / His own self; ਆਪ (mukta) = reflexive "himself/itself"','ਆਪਿ / ਆਪੁ / ਆਪ','ਜਬ ਆਪਨ ਆਪੁ ਆਪਿ ਉਰਿ ਧਾਰੈ (Sukhmani) = ਆਪਿ=Creator, ਆਪੁ=Himself | ਸਤਿਗੁਰਿ ਮਿਲਿਐ ਸਚੁ ਪਾਇਆ ਜਿਨੀ ਵਿਚਹੁ ਆਪੁ ਗਵਾਇਆ = ਆਪੁ=ego | ਸਭ ਪਵੈ ਪੈਰੀ ਸਤਿਗੁਰੁ ਕੇਰੀ ਜਿਥੈ ਗੁਰੁ ਆਪ ਰਖਿਆ = ਆਪ=reflexive himself','grammar_pdf_p106');
INSERT INTO "grammar_rules" VALUES(236,'principle','aapinai_aap_correct_reading','"ਆਪੀਨੈ ਆਪੁ ਸਾਜਿਓ ਆਪੀਨੈ ਰਚਿਓ ਨਾਉ" (Asa di Var) is misread as "Creator created the world Himself and created names for beings" — wrong; ਆਪੁ = reflexive "He Himself" (not world-creation); correct: He Himself, appearing in both Nirgun and Sargun forms, no other created Him','ਆਪੀਨੈ ਆਪੁ ਸਾਜਿਓ','ਆਪਨਾ ਆਪੁ ਉਪਾਇਓਨੁ, ਤਦਹੁ ਹੋਰੁ ਨ ਕੋਈ (Gujari di Var M:3) — before creation He was alone; this confirms ਆਪੁ=His own self, no other created Him','grammar_pdf_p107');
INSERT INTO "grammar_rules" VALUES(237,'vowel_mark','sihari_for_greater_matr_bihari_substitution','Section 34.0: sihari replaces bihari (and other long vowels) when poem requires shorter matra count; full list of bihari→sihari substitutions in Gurbani verse','ਚਾਲਿਸ=ਚਾਲਸੀ, ਹੋਵਿਗ=ਹੋਵੇਗੀ, ਵਜਿਗ=ਵੱਜੇਗੀ, ਆਵਿਗ=ਆਵੇਗੀ, ਬਾਣਿ=ਬਾਣੀ, ਸਭਿ=ਸਭੀ, ਲੇਖਣਿ=ਲੇਖਣੀ, ਮੇਦਨਿ=ਮੇਦਨੀ, ਬਲਿ=ਬਲੀ, ਭਿ=ਭੀ, ਜਨਨਿ=ਜਨਨੀ, ਮਣਿ=ਮਣੀ, ਦੁਬਲਿ=ਦੁਬਲੀ','sihari is the "short" form of bihari for metrical purposes; meaning is identical','grammar_pdf_p108');
INSERT INTO "grammar_rules" VALUES(238,'word_form','suri_muni_sihari_for_bihari','ਸੁਰਿ (sihari) = ਸੁਰੀ = deity/divine one; ਮੁਨਿ (sihari) = ਮੁਨੀ = sage/hermit — sihari replaces bihari for meter; both are adjectives for persons','ਸੁਰਿ / ਮੁਨਿ','ਆਖਿ ਸੁਰਿ ਨਰ ਮੁਨਿ ਜਨ ਸੇਵ (Jap Ji) = deities say, men and sages serve | ਸੁਣਿਐ ਸਿਧ ਪੀਰ ਸੁਰਿ ਨਾਥ (Jap Ji) = ਸੁਰਿ=deity','grammar_pdf_p109');
INSERT INTO "grammar_rules" VALUES(239,'word_form','chari_four_vs_char','ਚਾਰਿ (sihari or laa''n) = ਚਾਰੇ "all four" (stressed numeral with emphasis); ਚਾਰ (no syllable) = "four" (unstressed, simple count)','ਚਾਰਿ / ਚਾਰ','ਪੰਡਿਤ ਮੈਲੁ ਨ ਚੁਕਈ ਜੇ ਵੇਦ ਪੜਹਿ ਜੁਗ ਚਾਰਿ (M:3) = all four ages | ਇਹ ਮਾਇਆ ਕੀ ਸੋਭਾ ਚਾਰਿ ਦਿਹਾੜੇ ਜਾਦੀ (Asa M:3) = lasts only four days [emphatic] | ਚਾਰ ਪਦਾਰਥ ਜੇ ਕੋ ਮਾਗੈ (Sukhmani) = four gifts [simple count, no stress]','grammar_pdf_p110');
INSERT INTO "grammar_rules" VALUES(240,'word_form','kinni_how_many','ਕਿੰਨਿ (sihari) = ਕਿੰਨੇ "how many/where" — sihari replaces laa''n for meter','ਕਿੰਨਿ / ਕਿੰਨੇ','ਜਿਮੀ ਪੁਛੈ ਅਸਮਾਨ ਫਰੀਦਾ ਖੇਵਟ ਕਿੰਨਿ ਗਏ (Asa) = earth asks sky: the ferryman, how many have gone?','grammar_pdf_p110');
INSERT INTO "grammar_rules" VALUES(241,'vowel_mark','bihari_plural_preposition_restatement','Section 35.1/4.1: bihari (ੀ) on end of plural noun = preposition meaning "to/by/with/from the [plurals]" — bihari marks the plural noun as taking a case relationship','ਸਿਖੀ, ਅਖੀ, ਉਪਾਵੀ, ਅਖਰੀ','bihari gives preposition meaning to plural nouns: ਸਿਖੀ=ਸਿੱਖਾਂ ਨੇ, ਅਖੀ=ਅੱਖਾਂ ਨੂੰ, ਉਪਾਵੀ=ਉਪਾਵਾਂ ਨਾਲ — this is the core plural preposition function of bihari','grammar_pdf_p110');
INSERT INTO "grammar_rules" VALUES(242,'vowel_mark','bihari_plural_preposition_extended','Section 35.1: extended examples of bihari (ੀ) on plural noun = preposition "to/by/with/from"; each noun+bihari encodes specific case relationship','ਪੁੱਤ੍ਰੀ=ਪੁੱਤ੍ਰਾਂ ਨੇ, ਕੰਨੀ=ਕੰਨਾਂ ਨੂੰ, ਨੇਤ੍ਰੀ=ਨੇਤ੍ਰਾਂ ਨਾਲ, ਥਣੀ=ਥਣਾਂ ਕਰਕੇ, ਅਵਤਾਰੀ=ਅਵਤਾਰਾਂ ਵਿਚ','ਪੁੱਤ੍ਰੀ ਕਉਲੁ ਨ ਪਾਲਿਓ (Var Sata) = sons did not keep word | ਕੰਨੀ ਸੁਤਕੁ ਕੰਨਿ ਪੈ ਲਾਇਤਬਾਰੀ ਖਾਹਿ (Asa di Var) = ears hear slander | ਕਿਸਨੁ ਸਦਾ ਅਵਤਾਰੀ ਰੂਪਾ (Vadahans M:3) = Krishna always among incarnations','grammar_pdf_p111');
INSERT INTO "grammar_rules" VALUES(243,'tense','bihari_first_person_verb_extended','Section 35.2: bihari (ੀ) on verb = 1st person singular "I [do]" — additional examples beyond ਸੋਚੀ/ਕਰੀ','ਠਗੀ=ਮੈਂ ਠੱਗਦਾ ਹਾਂ, ਤੋਲੀ=ਮੈਂ ਤੋਲਾਂ','ਹਉ ਠਗਵਾੜਾ ਠਗੀ ਦੇਸੁ (Siri Ragu M:1) = I am a cheater who cheats the land | ਘਟ ਹੀ ਭੀਤਰਿ ਸੋ ਸਹੁ ਤੋਲੀ (Suhi M:1) = within this very vessel I weigh that Husband','grammar_pdf_p112');
INSERT INTO "grammar_rules" VALUES(244,'vowel_mark','bihari_replacing_sihari_3pl_instrumental','Section 35.3: bihari replaces sihari in two roles: (1) 3rd person plural verb "they do" (=ਨਿ ending); (2) instrumental preposition "by means of / with" — same form, context distinguishes','ਲਹਨੀ=ਲਹਨਿ ਲੈਂਦੇ, ਜਾਣੀ=ਜਾਣਨਿ, ਚੇਤਨੀ=ਚੇਤਨਿ, ਚਲਨੀ=ਚਲਨਿ; ਨਦਰੀ=ਨਦਰ ਨਾਲ, ਵਿਜੋਗੀ=ਵਿਜੋਗ ਨਾਲ, ਬੇਬਾਣੀ=ਬੇਬਾਣ ਵਿਚ','ਨਾਨਕ ਕਰਮਾਂ ਬਾਹਰੇ ਦਰਿ ਢੋਅ ਨ ਲਹਨੀ ਢਾਵਦੇ (Asa di Var) = graceless ones get no support at the door | ਨਦਰੀ ਮੋਖ ਦੁਆਰੁ (Jap Ji) = by the Glance of Grace, the door of liberation | ਰਹੈ ਬੇਬਾਣੀ ਮੜੀ ਮਸਾਣੀ (Asa di Var) = dwells in wilderness of cremation ground','grammar_pdf_p112');
INSERT INTO "grammar_rules" VALUES(245,'tense','past_tense_nu_extended_examples','Past tense -ਨੁ (singular agent, plural objects) extended examples: verb-stem + ਿਅਨੁ or ਿਓਨੁ = "he/Creator did [to many]"','ਬਖਸਿਅਨੁ, ਉਤਾਰਿਅਨੁ, ਰਖਿਅਨੁ, ਰਿੜਕਿਓਨੁ, ਲਇਅਨੁ, ਨਿਕਾਲਿਅਨੁ','ਕਉਣ ਕਉਣ ਅਪਰਾਧੀ ਬਖਸਿਅਨੁ (M:5) = which sinners did He forgive? | ਚਉਦਹ ਰਤਨ ਨਿਕਾਲਿਅਨੁ ਕੀਤੋਨੁ ਚਾਨਾਣੁ (Var Sata) = He brought out 14 gems and created light | ਮਾਧਾਣਾ ਪਰਬਤੁ ਕਰਿ ਸਬਦਿ ਰਿੜਕਿਓਨੁ (Var Sata) = He churned [the ocean] by the Word','grammar_pdf_p114');
INSERT INTO "grammar_rules" VALUES(246,'tense','parkhiani_plural_vs_parkhianu_singular','ਪਰਖੀਅਨਿ (sihari on ਨ) = plural past "they examined/were examined"; ਪਰਖਿਅਨੁ (aungkar on ਨ) = singular past "He examined" — sihari/aungkar on ਨ determines number of agent','ਪਰਖੀਅਨਿ / ਪਰਖਿਅਨੁ','ਖੋਟੇ ਖਰੇ ਸਭਿ ਪਰਖੀਅਨਿ ਤਿਤੁ ਸਚੈ ਕੈ ਦਰਬਾਰਾ ਰਾਮ (Vadahans M:3) = all the counterfeit and genuine were examined [plural passive] — sihari = plural','grammar_pdf_p114');
INSERT INTO "grammar_rules" VALUES(247,'vowel_mark','original_aungkar_comprehensive','Section 38.0: original/inherited aungkar words — permanent, not grammatical singular marker; includes both masculine and feminine nouns','ਕਿਤੁ, ਸਭਤੁ, ਬਿਨੁ, ਬਹੁਤੁ, ਇਕਤੁ, ਬਿੰਦੁ (neuter/masculine); ਧਾਤੁ, ਭਿਖੁ, ਰਤੁ, ਮਲੁ, ਮਸੁ, ਵਥੁ, ਰੇਣੁ, ਢੇਣੁ, ਕਲਤੁ (feminine)','ਧਾਤੁ ਮਿਲੈ ਫੁਨਿ ਧਾਤੁ ਕਉ (Siri Ragu M:1) = metal meets metal again | ਭਿਖੁ ਕੀ ਕਾਰ ਕਮਾਵਣੀ ਭਿਖੁ ਹੀ ਮਾਹਿ ਸਮਾਹਿ (Siri Ragu M:3) = the task of begging [feminine noun ਭਿਖੁ]','grammar_pdf_p115');
INSERT INTO "grammar_rules" VALUES(248,'case','hu_single_vs_hahu_double_comprehensive','Section 39.0: single ਹੁ (one ਹ + aungkar, no nasal) = (1) on nouns: nominative/subject case singular; (2) on verbs: future tense 2nd person singular imperative; double ਹਹੁ (two ਹ + aungkar) = (1) on nouns: ablative case singular "from"; (2) on verbs: future tense 2nd person plural imperative','Nouns: ਰਾਹੁ/ਰਾਹਹੁ, ਸਿਆਹੁ/ਸਿਆਹਹੁ, ਸਾਹੁ/ਸਾਹਹੁ; Verbs: ਕਹੁ/ਕਹਹੁ, ਬਹੁ/ਬਹਹੁ, ਰਹੁ/ਰਹਹੁ, ਸਹੁ/ਸਹਹੁ','ਕਹੁ (you singular, say!) vs ਕਹਹੁ (you plural, say!) | ਰਾਹੁ (the path, nominative) vs ਰਾਹਹੁ (from the path, ablative) — single vs double ਹ is the grammatical distinction','grammar_pdf_p117');
INSERT INTO "grammar_rules" VALUES(249,'word_form','gur_parsadi_bihari_instrumental','ਗੁਰ ਪਰਸਾਦੀ (bihari) = ਗੁਰੂ ਦੇ ਪਰਸਾਦਿ ਨਾਲ "by Guru''s grace" — bihari as instrumental preposition on noun','ਗੁਰ ਪਰਸਾਦੀ','ਕਹੈ ਨਾਨਕੁ ਗੁਰ ਪਰਸਾਦੀ ਸਹਜੁ ਉਪਜੈ... (Anand) = by Guru''s grace, equipoise arises','grammar_pdf_p113');
INSERT INTO "grammar_rules" VALUES(250,'principle','vowel_mark_master_parsing_key','master parsing key: same word changes meaning based on vowel mark — aungkar (ੁ)=singular noun/masculine OR imperative OR original; sihari (ਿ)=preposition/locative/agent/feminine/plural/conjunctive participle/imperative OR original; bihari (ੀ)=plural preposition/1st person verb/replaces sihari; dulangkar/dulaava (ੁ/ੈ)=case markers; context + vowel together determine meaning','systematic guide to all vowel marks','no single rule: each vowel mark has 3-7 possible functions; grammar + theological context together determine correct reading of Gurbani','grammar_pdf_p123');
