INSERT INTO "ksd_examples" VALUES(1,NULL,3,'','','','[{"roman": "kooray", "literal": "Неосознающими, не-реализующими внутри (состояние)", "ksd_meta": "противоположно Sachiara"}, {"roman": "haumai", "literal": "эго", "ksd_meta": "что я существую"}]','Творец не может быть реализован внутри посредством ритуальной практики физического безмолвия, даже если я полностью сосредоточусь на внешнем молчании (внешнее молчание не эквивалентно внутреннему молчанию).  | Творец не может быть реализован внутри с помощью ритуальной практики устранения (исполнений), даже если я в состоянии исполнить мои прошлые, настоящие, и будущие желания.  | Он не может быть реализован внутри через религиозные знания, независимо от того, насколько у них высокий порядок или насколько они множественны. Такое знание не поддержало бы духовное путешествие внутреннего освобождения.  | Как же тогда я могу стать Богореализованным существом внутри себя? Как я могу устранить препятствие моего нереализованного состояния (мое внутреннее неведение Творца) ?  | Путь к осознанию Творца внутри состоит в том, чтобы оставаться в пределах границ (потока Творца) и пребывать в Сехедже (принятии) его Хукама, содержащегося внутри нас II1II  | Мое человеческое существование основано на Его Хукаме, даже если весь Его Хукам не может быть постигнут. | То, что я жив, является честью в пределах / рамках / контексте его Хукама.  | Последствия - радости и печали - моих действий (выборов) - хороших и плохих - согласуются с Хукамом Творца / Находятся в нём.  | Творец благословляет некоторых внутренней реализацией. В то время как множество остаётся в заблуждении и в постоянном внешнем поиске.  | Творец реализуется внутри - всеми. Никто не может осознать Творца вне пределов Его полномочий (внутри нас).  | Нанак, при осознании Творца внутри, осознание того, что я существую вне Его Хукама, перестаёт существовать II2II','','[1, 2, 3]','jbani_v2');
INSERT INTO "ksd_examples" VALUES(2,NULL,1,'','','','[{"roman": "gavai", "literal": "Петь", "ksd_meta": "Воспринимать Хукам Творца как что-либо."}, {"roman": "ko & kissey", "literal": "множество (Koee)", "ksd_meta": "например множество людей"}, {"roman": "gavai", "literal": "Петь", "ksd_meta": "Воспринимать Хукам Творца как что-либо."}, {"roman": "nesaan", "literal": "петь", "ksd_meta": "индикатор, знак"}, {"roman": "gavai", "literal": "Петь", "ksd_meta": "Воспринимать Хукам Творца как что-либо."}, {"roman": "gavai", "literal": "Петь", "ksd_meta": "Воспринимать Хукам Творца как что-либо."}, {"roman": "vidiya", "literal": "обучение", "ksd_meta": "знание, просветлённость"}, {"roman": "vikhum", "literal": "трудный", "ksd_meta": "за пределами возможностей человеческого интеллекта"}, {"roman": "gavai", "literal": "Петь", "ksd_meta": "Воспринимать Хукам Творца как что-либо."}, {"roman": "karey", "literal": "сила, стоящая за действием", "ksd_meta": "сила, предшествующая действию"}, {"roman": "tunn", "literal": "тело", "ksd_meta": "физические существа"}, {"roman": "kheh", "literal": "пепел", "ksd_meta": "разрушает (idiom)"}, {"roman": "gavai", "literal": "Петь", "ksd_meta": "Воспринимать Хукам Творца как что-либо."}, {"roman": "gavai", "literal": "Петь", "ksd_meta": "Воспринимать Хукам Творца как что-либо."}, {"roman": "dissey", "literal": "видел", "ksd_meta": "зная. пенджабская идиома."}, {"roman": "duur", "literal": "далеко", "ksd_meta": "вне досягаемости"}, {"roman": "gavai", "literal": "Петь", "ksd_meta": "Воспринимать Хукам Творца как что-либо."}, {"roman": "vekhey", "literal": "Знающий", "ksd_meta": "Понимать"}, {"roman": "na avey toat", "literal": "не иначе", "ksd_meta": "неограниченный"}, {"roman": "kotee", "literal": "0.1 миллиона", "ksd_meta": "неисчислимый"}, {"roman": "dey", "literal": "Даёт", "ksd_meta": "поддерживает творение"}, {"roman": "khahee", "literal": "потребляется", "ksd_meta": "пропитание"}, {"roman": "chalaye", "literal": "драйв, движущая сила", "ksd_meta": "в его Хукаме; это сила внутри"}, {"roman": "rah", "literal": "направление", "ksd_meta": "творение"}, {"roman": "vigsey", "literal": "действует (в отношение чего-либо) (Lit)", "ksd_meta": ""}, {"roman": "veparvah", "literal": "без забот", "ksd_meta": "несмотря на"}, {"roman": "bhakhiya", "literal": "язык", "ksd_meta": "команда"}, {"roman": "deh deh", "literal": "Дай!", "ksd_meta": "бесконечная отдача / “давание”"}, {"roman": "dataar", "literal": "Дающий", "ksd_meta": "Создатель"}, {"roman": "agey", "literal": "впереди", "ksd_meta": "раньше; Задача"}, {"roman": "rakheay", "literal": "располагать, хранить, предлагать", "ksd_meta": "Установить, определить."}, {"roman": "darbar", "literal": "Двора Творца", "ksd_meta": "Его Хукама"}, {"roman": "muhon", "literal": "изо рта", "ksd_meta": "полный, дискурс"}, {"roman": "dhare pyaar", "literal": "люби меня", "ksd_meta": "привести к осознанию Творца"}, {"roman": "amrit", "literal": "Mrit (смерть) A (нет) + Mrit (смерть)- бессмертие", "ksd_meta": "Гурбани, Наам, Шабд."}, {"roman": "vela", "literal": "Время", "ksd_meta": "определение/создание времени/описательное (нет фиксированного времени! Не предрассветные часы!); Человеческая жизнь, Хьюман Лайфтайм."}, {"roman": "avey", "literal": "достигнут", "ksd_meta": "реализован"}, {"roman": "kapraa", "literal": "ткань", "ksd_meta": "усердие (Sift Saram Ka Kapra)"}, {"roman": "mokh", "literal": "свобода от рабства", "ksd_meta": "свобода"}, {"roman": "duar", "literal": "Дверь", "ksd_meta": "Путь"}, {"roman": "gaveay", "literal": "Петь", "ksd_meta": "(процесс); принимать"}, {"roman": "gaveay", "literal": "Петь", "ksd_meta": "Принимать"}, {"roman": "suneay", "literal": "Слушать", "ksd_meta": "принять, адаптировать в себе"}, {"roman": "nadang", "literal": "звук", "ksd_meta": "повествование"}, {"roman": "vedang", "literal": "знание", "ksd_meta": "просветление"}, {"roman": "raheya samayee", "literal": "проживает", "ksd_meta": "resides, пребывает, погруженный, содержащийся внутри"}, {"roman": "esar", "literal": "Шивджи", "ksd_meta": "принцип разрушения"}, {"roman": "gorakh", "literal": "управитель (йогического) знания", "ksd_meta": "для Сикхов в этом контексте, принцип знания, просветлённости"}, {"roman": "brahma", "literal": "(Lit)", "ksd_meta": "творение"}, {"roman": "ek daata", "literal": "Одному дающему", "ksd_meta": "Поддерживающий бытие; Хукам"}, {"roman": "viser na jayee", "literal": "разделять, не забывать", "ksd_meta": "освобождать, отправлять восвояси (куда подальше)"}, {"roman": "vich", "literal": "Внутри", "ksd_meta": "Интернализировать, усвоить."}, {"roman": "ek daata", "literal": "Одному дающему", "ksd_meta": "Поддерживающий бытие; Хукам"}, {"roman": "viser na jayee", "literal": "разделять, не забывать", "ksd_meta": "освобождать, отправлять восвояси (куда подальше)"}, {"roman": "jug charey", "literal": "четыре века (психических состояния)", "ksd_meta": "Расширенный"}, {"roman": "navaan khandaan", "literal": "Девять континентов", "ksd_meta": "вдоль и поперек, повсюду."}, {"roman": "laye", "literal": "получает", "ksd_meta": "зарабатывает"}, {"roman": "tiss", "literal": "Его", "ksd_meta": "Создателя"}, {"roman": "nadar", "literal": "Великолепние", "ksd_meta": "Благословения; Просветление"}, {"roman": "keeta andar keet", "literal": "Червь среди червей, низкий", "ksd_meta": "бесполезный"}, {"roman": "sujhayee", "literal": "Знать", "ksd_meta": "Вникать"}, {"roman": "dhaval", "literal": "Бык поддерживающий землю", "ksd_meta": "Законы природы, Хукам"}, {"roman": "poh", "literal": "Коснуться", "ksd_meta": "Производить эффект"}, {"roman": "esar", "literal": "божество Шива", "ksd_meta": "Уничтожение"}, {"roman": "bharma", "literal": "божество Брахма", "ksd_meta": "Порождение"}, {"roman": "ind", "literal": "Божество Индра", "ksd_meta": "Поддержка, управление процессами бытия."}, {"roman": "salahan", "literal": "Хвала", "ksd_meta": "Признательность"}, {"roman": "mund", "literal": "Плохой", "ksd_meta": "Отрицание Создателя (противоположность Salahan)"}, {"roman": "jog", "literal": "Союз", "ksd_meta": "Божественная реализация"}, {"roman": "jugat", "literal": "Методы", "ksd_meta": "Ориентация"}, {"roman": "tunn", "literal": "Тело", "ksd_meta": "Физический"}, {"roman": "bheyd", "literal": "Внутренняя работа", "ksd_meta": "Чувства (органы чувств)"}, {"roman": "sat", "literal": "Создатель", "ksd_meta": "Божественный"}, {"roman": "athsath", "literal": "68", "ksd_meta": "Teeraths; места духовного паломничества (Тираты)."}, {"roman": "sara", "literal": "Океан", "ksd_meta": "неограниченный, полный"}, {"roman": "gah", "literal": "Поиск", "ksd_meta": "Преследование"}, {"roman": "andhey", "literal": "Слепой", "ksd_meta": "Невежество"}, {"roman": "pavey", "literal": "Получить", "ksd_meta": "Обнаружить"}, {"roman": "rah", "literal": "Путь", "ksd_meta": "Просветление (как обнаружение направления Хукама, в данном контексте)."}, {"roman": "haath", "literal": "Рука", "ksd_meta": "В руках. В пределах досягаемости."}, {"roman": "hovey", "literal": "Становится", "ksd_meta": "места."}, {"roman": "asgah", "literal": "Глубокий океан", "ksd_meta": "Духовная жизнь."}]','Множество духовных искателей воспринимают Хукам Творца как силу своего существования / жизни | Множество людей воспринимают дары Творца как индикаторы его Хукама | Множество людей воспринимают Хукам Творца как достоинства (атрибуты) безмерной божественной красоты | Просветлённость / духовное знание воспринимается многими как Хукам Творца; исчерпывающее знание того, что Творец вне дискурса.  | Многие воспринимают Хукам Творца как силу, стоящую за физическим творением и его разрушением. | Многие воспринимают Хукам Творца как отнятие жизни после того, как она была дана. | Многие воспринимают Хукам Творца как реализацию того, что Он недосягаем.  | Многие воспринимают Хукам Творца как осознание того, что Он вездесущ.  | Рассказы о восприятиях Хукама Творца - безграничны (Хукам сам собой - безграничен) | Даже если эти повествования о Хукаме Творца были рассказаны бесчисленными способами бесчисленными искателями, ставящими в своих рассказах бесчисленные акценты на то, или другое | Хукам Творца - поддерживает Творение. Его творение истощается в своём получении поддержки (потребляя жизненную силу) - согласно его Хукаму. (Сначала приходит приток жизненных ресурсов, затем их потребление через проживание жизни)  | Эта поддержка благодаря Хукаму Творца беспрепятственно продолжалась в течение многих периодов времени, веков.  | Хукам Творца - это сила, находящаяся в Его творении. | Нанак, сам Творец управляет своим собственным Хукамом II3II  | Хукам творца существует (постоянно), как и Сам Творец. Он командует своим Творением через безграничную заботу и любовь.  | С таким Хукамом и безмерной любовью Творец бесконечно дает дары пропитания своему Творению | Что же тогда я должен определить как свою духовную цель, благодаря чему может произойти реализация его Хукама? | Какой дискурс мне следует предпринять в моём духовном путешествии? Благодаря совершенству / добродетели какой любви может произойти реализация (любовная) его Хукама? | Духовная цель состоит в том, чтобы сделать мою жизнь (Vela) наполненной Шабдом (Амритой), который является интериоризацией (Vichar) добродетелей Единого Создателя, который есть Вечное Существование, является Хукми (Нао), и превыше всего (Vadeayee). | Путь к осознанию Творца внутри лежит через усердие в получение его Милости | Нанак говорит, вышеизложенное - это путь к реализации Творца внутри себя через обретение божественных добродетелей I4II  | Его Хукам не может быть создан и контролироваться / изменяться его Творением и Творениями (людьми, существами, феноменами)  | Его Хукам создан и управляется Им. Он остаётся необусловленным Творением. | Тот, кто живёт в следовании воле Творца, Хукама (интернализируя его), получает Честь, путём принятия союза с ним.  | Нанак, усвоить (интернализировать) его Хукам - означает принять его безграничные добродетели. | Интернализируйте (усвойте) Хукам через его принятие, усвоение (адаптацию) и прививание любви к нему в своём разуме.  | Благодаря усвоению Хукама, духовная агония (от разлуки) рассеивается (т.к. каждое действие протекает в его Хукаме, и является выражением и укреплением этого союза), и духовное блаженство поселяется в доме нашей атмы. | Шабд, сошедший с уст Гуру, содержит внутри звук высшей мелодии, высшее знание, и приводит к полному и окончательному растворению себя в Хукаме.  | Шабд содержит в себе эссенцию просветлённости, в отношении всех процессов разрушения (Ищар), процессов мистического познания (Горакх), в отношении всего бытия (Брахма), творческих процессов (Парвати) и поддержки / заботы о чём-либо в бытии (Майи - знание, почему что-то существует и расцветает, и имеет удачу, поддержку).  | Сущность Хукама можно осознать и реализовать, но о ней нельзя рассказать (словами. но можно рассказать своей реализацией его) | Шабд - Гуру обеспечивает мне удовлетворяющую реализованность. | Удовлетворящую реализованость того, что есть Один Хукам, поддерживающий всех и всё, и я - не исключение. В виду такой реализованности, я это не забуду (всё о нём напоминает), не разделюсь с ним II5II  | Зачем предпринимать Духовность Тиратов (ритуальных паломничеств), если это не входит в сферу его Хукама, поскольку сфера Хукама - не относится к географическим местам? (Не удовлетворяет запрос Хукама реализоваться во мне. Основной посыл - духовность вне тех или иных территорий) | Во всем духовном мире ничего не может быть реализовано, осознанно, без благословления Просветления твоим Хукамом (Только когда следуешь Хукаму, духовные истины реализуются). | Интернализация этого Одного бесценного послания моего Гуру делает мою духовность основанной на благочестивой Добродетели. Это делает нашу духовность GOD-Based.  | Шабд - Гуру обеспечивает (обеспечивающий) мне удовлетворяющую реализованность. | Удовлетворящую реализованость того, что есть Один Хукам, поддерживающий всех и всё, и я - не исключение. В виду такой реализованности, я это не забуду (всё о нём напоминает), не разделюсь с ним II6II    | Если продлить возраст (мой) до четырёх Юг и ещё в десять раз больше | Если кто-то получит мировую славу и сделает последователем каждого человека  | Если кто-то создаст себе репутацию и заслужит похвалу в духовном социуме | Без благословения просвещением твоего Хукама - я духовно бесполезен.  | В анти-хукамских практиках, я виновен в том, что запятнал свою духовность бесполезностью.  | Нанак, реализация Хукама создаёт наполненную добродетелью духовную жизнь, поскольку Ниргун (Бог, лишенный качеств) являеется источником всех Добродетелей. | Я не могу постичь равного существа как источника всех Добродетелей, чья Реализация Хукама создаёт наполненную Добродетелью ДуховностьII7II  | Через процесс духовного слушания (интернализации) Шабда слушающий возвышается к высотам Сидхов, Пиров, Суров, Натхов.  | Интернализация Шабда рождает пробужденность относительно Хукама Творца для нашей планеты, законов мироздания и всей Вселенной.  | Интернализация Шабда создает осознание Хукама Творца, относящегося к Солнцу, небесным телам и космосу. | Интернализация Шабда устраняет страх смерти.  | Нанак, духовность интернализации Шабда - благословенна.  | Интернализация Шабда избавляет от грехов и печалей II8II  | Интернализация Шабда создаёт осознание относительно силы Творца разрушать, создавать и поддерживать что-либо в бытии. | Интернализация Шабда превращает отрицание Творца в признание Творца. | Интернализация Шабда ориентирует наши физические чувства на божественную реализацию. | Интернализация Шабда позволяет оценить ведические тексты (на предмет их ценности)  | Нанак, духовность интернализации Шабда - благословенна.  | Интернализация Шабда избавляет от грехов и печалей II9II  | Интернализация шабда приносит божественную удовлетворённость и просветление. | Интернализация Шабда позволяет оценить реальность очищения в (68-ми) местах духовных паломничеств. | Интернализация Шабда придаёт ценность непрерывному чтению (чтение без Интернализации - бесполезно).  | Интернализация Шабда рождает постоянно-естественный фокус на Творце.  | Нанак, духовность интернализации Шабда - благословенна.  | Интернализация Шабда избавляет от грехов и печалей II10II  | Интернализация Шабда - это стремление к Совершенному Творцу.  | Интернализация Шабда позволяет оценить учения ведущих мусульманских священнослужителей.  | Интернализация Шабда перенаправляет невежество в просветление. | Интернализация Шабда делает доступным погружение в глубины духовной жизни. | Нанак, духовность интернализации Шабда - благословенна.  | Интернализация Шабда избавляет от грехов и печалей II11II ','','[1, 2, 3]','jbani_v2');
INSERT INTO "ksd_examples" VALUES(3,NULL,12,'','','','[{"roman": "gutt", "literal": "Состояние", "ksd_meta": "Духовное состояние"}, {"roman": "pichey", "literal": "Позади", "ksd_meta": "Последствие"}, {"roman": "likhanhaar", "literal": "Писатель", "ksd_meta": "Писательская способность"}, {"roman": "sagal", "literal": "Целый", "ksd_meta": "Завершенный"}, {"roman": "sudh", "literal": "Пробужденность", "ksd_meta": "Просветлённость"}, {"roman": "jumm", "literal": "Солдаты смерти", "ksd_meta": "Пороки (переопределено в Гурбани)"}, {"roman": "jaye", "literal": "Продолжить", "ksd_meta": "проведенный"}, {"roman": "marag", "literal": "Пути", "ksd_meta": "Духовное путешествие к осознанию Творца"}, {"roman": "chaley", "literal": "Путешествие", "ksd_meta": "следование, пересечение"}, {"roman": "dharm", "literal": "Законы, правила, регуляции - делай то, не делай то.", "ksd_meta": "Хукам - это закон."}, {"roman": "mokh", "literal": "Свобода от препятствий, (от слова Mukt)", "ksd_meta": "Окончательный"}, {"roman": "duar", "literal": "Дверь", "ksd_meta": "тропа"}, {"roman": "parvarey", "literal": "Семья", "ksd_meta": "Семья в отношении ума, манаса- (5 чувств/каналов восприятия)"}, {"roman": "trey", "literal": "Переплыть через", "ksd_meta": "Духовная задача"}, {"roman": "tarey", "literal": "Заставить переплыть", "ksd_meta": "Обеспечить духовную задачу"}, {"roman": "gur", "literal": "Гуру", "ksd_meta": "Шабд"}, {"roman": "sikh", "literal": "от Sikhiya", "ksd_meta": "сообщение, совет, руководство"}, {"roman": "bhikh", "literal": "от Bhaykh", "ksd_meta": "Претенциозный, поддельный."}, {"roman": "parwaan", "literal": "Стать принятым / одобренным / достойным", "ksd_meta": "Соответствовать. Fit"}, {"roman": "pavey", "literal": "Receive", "ksd_meta": "Become"}, {"roman": "dargah", "literal": "Суд совести/ высшего разума", "ksd_meta": "справедливость"}, {"roman": "rajaan", "literal": "Король", "ksd_meta": "Создатель (как Высший авторитет моей духовности)"}, {"roman": "ek", "literal": "Одного", "ksd_meta": "Создатель"}, {"roman": "kartey", "literal": "Создатель", "ksd_meta": "Сознание, в контексте Паури"}, {"roman": "dhaol", "literal": "Белый", "ksd_meta": "Чистый"}, {"roman": "dhaol dhrm", "literal": "Чистый", "ksd_meta": "Божественная духовность (в отличие от мирской / претенциозной / фальшивой религии)"}, {"roman": "dhavley", "literal": "то, что является белым", "ksd_meta": "Чистый, божественный."}, {"roman": "upar", "literal": "Над / Наверху", "ksd_meta": "на нём (сверху на чём-то, как груз"}, {"roman": "bhaar", "literal": "Весt", "ksd_meta": "Груз"}, {"roman": "dhartee", "literal": "Hirdey Dhartee", "ksd_meta": "- Совесть как Центр, Корень и Источник нашей духовной жизни"}, {"roman": "hor", "literal": "From Hor Dee Hor- Что-то другое", "ksd_meta": "отклоняющееся."}, {"roman": "bhaar", "literal": "Вес", "ksd_meta": "груз, бремя"}, {"roman": "ranga", "literal": "цветной", "ksd_meta": "проникнутой; пронизанной"}, {"roman": "taan", "literal": "Сил", "ksd_meta": "Добродетелей (Духовная сила заключается в добродетелях)"}, {"roman": "sualeho", "literal": "Тот, кто даёт ответы", "ksd_meta": "Достойный"}, {"roman": "lakh", "literal": "Сто тысяч", "ksd_meta": "неисчислимое"}, {"roman": "bhalee", "literal": "Хорошо", "ksd_meta": "Позитивно, применимо."}]','Такова природа божественных Добродетелей - существо, осознающее Творца, становится Добродетелями.  | Духовное состояние превращения себя в божественные Добродетели не поддается описанию. Последствием попытки описания является сожаление, раскаяние.  | Духовное состояние превращения себя в божественные добродетели выходит за рамки человеческих способностей к описанию. | Медитативная беседа о духовном состоянии становления божественными добродетелями раскрывает семя просветление, предыдущих и последующих стихов. | Такова природа божественных Добродетелей - существо, осознающее Творца, становится Добродетелями.  | Духовное состояние становления божественными добродетелями относится к Сознанию [единобытия], охватывающему манас (ум, который оперирует 5-ю органами чувств) и буддхи (интеллект, волевое начало, управляющее вниманием). Такое духовное состояние относится к принятию божественных добродетелей на всех уровнях разума (манаса), интеллекта (буддхи), сознания, подсознания).  | Духовное состояние становления божественными добродетелями - есть полное, окончательное просветление духовной вселенной (universe of spirituality). Бог присутствует везде во вселенной. Маннэ - объективная духовность для всей вселенной.  | Духовное состояние становления божественными добродетелями сводит на нет опасности не-просветления. | Духовное состояние становления божественными добродетелями устраняет “духовность”, имевшую завязку на нашей греховности. | Такова природа божественных Добродетелей - существо, осознающее Творца, становится Добродетелями.  | Духовное состояние становления божественными добродетелями устраняет препятствия с пути реализации Творца.  | Духовное состояние становления божественными добродетелями протекает через духовное достоинство, определяемыми “глазами” Гуру..  | Духовное состояние становления божественными добродетелями исключает прохождение предписанных путей и религий. | Духовное состояние становления божественными добродетелями - это состояние связи с Хукамом.  | Такова природа божественных Добродетелей - существо, осознающее Творца, становится Добродетелями.  | Духовное состояние становления божественными добродетелями - это реализация абсолютной духовности, Мокши.  | Духовное состояние становления божественными добродетелями состоит в том, чтобы укоренить в этих добродетелях свои пять чувств, подобных внутренней семье.  | Духовное состояние становления божественными добродетелями - это духовная цель, что следует из послания Гуру (Шабда).  | Нанак, духовное состояние становления божественными добродетелями освобождает меня от путаницы претенциозных (фэйковых) путей.  | Такова природа божественных Добродетелей - существо, осознающее Творца, становится Добродетелями.  | Мои пять чувств принимаются моим сознанием как достойные того, чтобы руководить моим духовным путешествием.  | Мои пять чувств достойно стоят перед судом моей совести. | Мои пять чувств теперь изящно стоят на пути осознания моего Творца.  | Мои пять чувств сосредоточены на Едином Творце. | Должен ли кто-то повествовать дискурс о пяти чувствах, сосредоточенных на Едином Творце? | Благочестивая духовность является ребёнком Сочувствия [к себе]. | Ребёнок Сочувствия - это духовное удовлетворение, которое закрепляет и связывает пять Чувств . | Принять решение о том, что Сочувствие и Духовное Удовлетворение необходимо постоянно закреплять в чувствах, означает стать Существом, осознавшим Творца.  | Представьте себе бремя совести, лишенной Сочувствия и Духовного Удовлетворения, возложенное на наш духовный путь.  | Бремя заключается в том, что Сознание, лишенное Сочувствия, переходит из одного “отклоненного” состояния в другое. | Как бремя этого постоянного отклонения легло на мою совесть? | Моя совесть (через мои 5 чувств) прониклась атрибутами временного.  | Все они (мои пронизанные чувства) непрерывно писали мою духовную судьбу. | Если бы я знал, как написать свою духовную судьбу (правильным образом) | Какую (духовную) судьбу я бы написал? | Насколько достойной, добродетельной и красивой будет моя (духовная) судьба? | Обильные благословения для моей духовной судьбы были бы неоценимы.  | Когда повеление Единого Творца действует в пространстве моего сознания | Из такой сознания в мою (духовную) жизнь текут реки Добродетелей.  | Беседа о благочестивом сознании выше моих сил | Моя неспособность такова, что я не могу ни разу выразить свою преданность (в полной мере соответствующе) | Я принимаю всё, что Ты прикажешь мне, исходя из моей совести.  | Твоё вечное бесформенное Я - является опорой, кормильцем моей Совести II16II','','[1, 2, 3]','jbani_v2');
INSERT INTO "ksd_examples" VALUES(4,NULL,16,'','','','[{"roman": "asankh", "literal": "Sankh- Считать", "ksd_meta": "A + Sankh- Неисчислимый, неизмеряемый, безлимитный, бесконечный."}, {"roman": "tup", "literal": "Покаяние, аскеза", "ksd_meta": "интенсивная форма ритуальной практики"}, {"roman": "bhakh", "literal": "Есть", "ksd_meta": "Потреблять, терпеть"}, {"roman": "saar", "literal": "Железо", "ksd_meta": "Проблемы, испытания"}, {"roman": "moaan", "literal": "Тишина", "ksd_meta": "(также - стон или молчание); Свободный от отвлечения внимания"}, {"roman": "bhalee", "literal": "Хорошо", "ksd_meta": "Позитивно, применимо."}]','Я точу и оттачиваю своё сознание на камне Твоих Добродетелей. Внутри меня шафран - это цвет, пропитанный Твоими Добродетелями. | Интернализация божественных добродетелей является Вечным / Духовным / Внутренним Тапасом (Аскезой). | Если я усвою хотя бы одну каплю послания Шабда / Гуру в своем сознании, величие этого сознания будет за пределами исчислений (его достоинств).  | Я принимаю всё, что Ты прикажешь мне, исходя из моей просветлённой совести.  | Моя просветлённая совесть Творит неисчислимую Реализацию неисчислимой Любви Творца.   | Моя просветлённая Совесть проводит безграничное почитание Бесконечному Превосходству (Творца).  | Моя просветлённая Совесть - это (эквивалентно) рецитации бесчисленных священных писаний и Вед. | Моё просветлённая Совесть создаёт не имеющий границ союз с Творцом в состоянии внутреннего отречения.  | Моё просветлённая Совесть есть дискурс безмерной вовлечённости и просветления в отношении Божественных Добродетелей.  | Моя просветлённая совесть (безгранично удовлетворённая) приносит мне безмерное удовлетворение от безграничной дающей способности Творца (то, что даёт творец нам, когда мы реализуем нашу просветлённую совесть).  | Моя просветлённая совесть позволяет мне в случае столкновения с несоизмеримыми (духовными) препятствиями и преодолевать их. | Моё просветлённая совесть - это целеустремлённая не отвлекающая сосредоточенность на Творце (нет блуждания внимания, отчего оно неизмеримо т.к. едино, и этим единством превосходит любую множественность, поскольку Творец за пределами исчислений). | Беседа о благочестивой совести выше моих способностей. | Моя неспособность такова, что я не могу ни разу адекватно выразить свою преданность и признательность (в полной мере соответствующе).  | Я принимаю всё, что Ты прикажешь мне, изнутри моей совести.  | Ты, Вечный, Бесформенный - Основа Моей Совести II17II | Должен ли кто-то повествовать дискурс о пяти чувствах, сосредоточенных на Едином Творце? | Духовные достижения Совести, управляющей пятью чувствами, объектом сосредоточения которых является Единый Творец, не поддаются исчислению. Nahi Sumaar! ','','[1, 2, 3]','jbani_v2');
INSERT INTO "ksd_examples" VALUES(5,NULL,3,'','','','[{"roman": "kooray", "literal": "Неосознающими, не-реализующими внутри (состояние)", "ksd_meta": "противоположно Sachiara"}, {"roman": "haumai", "literal": "эго", "ksd_meta": "что я существую"}]','Творец не может быть реализован внутри посредством ритуальной практики физического безмолвия, даже если я полностью сосредоточусь на внешнем молчании (внешнее молчание не эквивалентно внутреннему молчанию).  | Творец не может быть реализован внутри с помощью ритуальной практики устранения (исполнений), даже если я в состоянии исполнить мои прошлые, настоящие, и будущие желания.  | Он не может быть реализован внутри через религиозные знания, независимо от того, насколько у них высокий порядок или насколько они множественны. Такое знание не поддержало бы духовное путешествие внутреннего освобождения.  | Как же тогда я могу стать Богореализованным существом внутри себя? Как я могу устранить препятствие моего нереализованного состояния (мое внутреннее неведение Творца) ?  | Путь к осознанию Творца внутри состоит в том, чтобы оставаться в пределах границ (потока Творца) и пребывать в Сехедже (принятии) его Хукама, содержащегося внутри нас II1II  | Мое человеческое существование основано на Его Хукаме, даже если весь Его Хукам не может быть постигнут. | То, что я жив, является честью в пределах / рамках / контексте его Хукама.  | Последствия - радости и печали - моих действий (выборов) - хороших и плохих - согласуются с Хукамом Творца / Находятся в нём.  | Творец благословляет некоторых внутренней реализацией. В то время как множество остаётся в заблуждении и в постоянном внешнем поиске.  | Творец реализуется внутри - всеми. Никто не может осознать Творца вне пределов Его полномочий (внутри нас).  | Нанак, при осознании Творца внутри, осознание того, что я существую вне Его Хукама, перестаёт существовать II2II','','[1, 2, 3]','jbani_v1');
INSERT INTO "ksd_examples" VALUES(6,NULL,1,'','','','[{"roman": "gavai", "literal": "Петь", "ksd_meta": "Воспринимать Хукам Творца как что-либо."}, {"roman": "ko & kissey", "literal": "множество (Koee)", "ksd_meta": "например множество людей"}, {"roman": "gavai", "literal": "Петь", "ksd_meta": "Воспринимать Хукам Творца как что-либо."}, {"roman": "nesaan", "literal": "петь", "ksd_meta": "индикатор, знак"}, {"roman": "gavai", "literal": "Петь", "ksd_meta": "Воспринимать Хукам Творца как что-либо."}, {"roman": "gavai", "literal": "Петь", "ksd_meta": "Воспринимать Хукам Творца как что-либо."}, {"roman": "vidiya", "literal": "обучение", "ksd_meta": "знание, просветлённость"}, {"roman": "vikhum", "literal": "трудный", "ksd_meta": "за пределами возможностей человеческого интеллекта"}, {"roman": "gavai", "literal": "Петь", "ksd_meta": "Воспринимать Хукам Творца как что-либо."}, {"roman": "karey", "literal": "сила, стоящая за действием", "ksd_meta": "сила, предшествующая действию"}, {"roman": "tunn", "literal": "тело", "ksd_meta": "физические существа"}, {"roman": "kheh", "literal": "пепел", "ksd_meta": "разрушает (idiom)"}, {"roman": "gavai", "literal": "Петь", "ksd_meta": "Воспринимать Хукам Творца как что-либо."}, {"roman": "gavai", "literal": "Петь", "ksd_meta": "Воспринимать Хукам Творца как что-либо."}, {"roman": "dissey", "literal": "видел", "ksd_meta": "зная. пенджабская идиома."}, {"roman": "duur", "literal": "далеко", "ksd_meta": "вне досягаемости"}, {"roman": "gavai", "literal": "Петь", "ksd_meta": "Воспринимать Хукам Творца как что-либо."}, {"roman": "vekhey", "literal": "Знающий", "ksd_meta": "Понимать"}, {"roman": "na avey toat", "literal": "не иначе", "ksd_meta": "неограниченный"}, {"roman": "kotee", "literal": "0.1 миллиона", "ksd_meta": "неисчислимый"}, {"roman": "dey", "literal": "Даёт", "ksd_meta": "поддерживает творение"}, {"roman": "khahee", "literal": "потребляется", "ksd_meta": "пропитание"}, {"roman": "chalaye", "literal": "драйв, движущая сила", "ksd_meta": "в его Хукаме; это сила внутри"}, {"roman": "rah", "literal": "направление", "ksd_meta": "творение"}, {"roman": "vigsey", "literal": "действует (в отношение чего-либо) (Lit)", "ksd_meta": ""}, {"roman": "veparvah", "literal": "без забот", "ksd_meta": "несмотря на"}, {"roman": "bhakhiya", "literal": "язык", "ksd_meta": "команда"}, {"roman": "deh deh", "literal": "Дай!", "ksd_meta": "бесконечная отдача / “давание”"}, {"roman": "dataar", "literal": "Дающий", "ksd_meta": "Создатель"}, {"roman": "agey", "literal": "впереди", "ksd_meta": "раньше; Задача"}, {"roman": "rakheay", "literal": "располагать, хранить, предлагать", "ksd_meta": "Установить, определить."}, {"roman": "darbar", "literal": "Двора Творца", "ksd_meta": "Его Хукама"}, {"roman": "muhon", "literal": "изо рта", "ksd_meta": "полный, дискурс"}, {"roman": "dhare pyaar", "literal": "люби меня", "ksd_meta": "привести к осознанию Творца"}, {"roman": "amrit", "literal": "Mrit (смерть) A (нет) + Mrit (смерть)- бессмертие", "ksd_meta": "Гурбани, Наам, Шабд."}, {"roman": "vela", "literal": "Время", "ksd_meta": "определение/создание времени/описательное (нет фиксированного времени! Не предрассветные часы!); Человеческая жизнь, Хьюман Лайфтайм."}, {"roman": "avey", "literal": "достигнут", "ksd_meta": "реализован"}, {"roman": "kapraa", "literal": "ткань", "ksd_meta": "усердие (Sift Saram Ka Kapra)"}, {"roman": "mokh", "literal": "свобода от рабства", "ksd_meta": "свобода"}, {"roman": "duar", "literal": "Дверь", "ksd_meta": "Путь"}, {"roman": "gaveay", "literal": "Петь", "ksd_meta": "(процесс); принимать"}, {"roman": "gaveay", "literal": "Петь", "ksd_meta": "Принимать"}, {"roman": "suneay", "literal": "Слушать", "ksd_meta": "принять, адаптировать в себе"}, {"roman": "nadang", "literal": "звук", "ksd_meta": "повествование"}, {"roman": "vedang", "literal": "знание", "ksd_meta": "просветление"}, {"roman": "raheya samayee", "literal": "проживает", "ksd_meta": "resides, пребывает, погруженный, содержащийся внутри"}, {"roman": "esar", "literal": "Шивджи", "ksd_meta": "принцип разрушения"}, {"roman": "gorakh", "literal": "управитель (йогического) знания", "ksd_meta": "для Сикхов в этом контексте, принцип знания, просветлённости"}, {"roman": "brahma", "literal": "(Lit)", "ksd_meta": "творение"}, {"roman": "ek daata", "literal": "Одному дающему", "ksd_meta": "Поддерживающий бытие; Хукам"}, {"roman": "viser na jayee", "literal": "разделять, не забывать", "ksd_meta": "освобождать, отправлять восвояси (куда подальше)"}, {"roman": "vich", "literal": "Внутри", "ksd_meta": "Интернализировать, усвоить."}, {"roman": "ek daata", "literal": "Одному дающему", "ksd_meta": "Поддерживающий бытие; Хукам"}, {"roman": "viser na jayee", "literal": "разделять, не забывать", "ksd_meta": "освобождать, отправлять восвояси (куда подальше)"}, {"roman": "jug charey", "literal": "четыре века (психических состояния)", "ksd_meta": "Расширенный"}, {"roman": "navaan khandaan", "literal": "Девять континентов", "ksd_meta": "вдоль и поперек, повсюду."}, {"roman": "laye", "literal": "получает", "ksd_meta": "зарабатывает"}, {"roman": "tiss", "literal": "Его", "ksd_meta": "Создателя"}, {"roman": "nadar", "literal": "Великолепние", "ksd_meta": "Благословения; Просветление"}, {"roman": "keeta andar keet", "literal": "Червь среди червей, низкий", "ksd_meta": "бесполезный"}, {"roman": "sujhayee", "literal": "Знать", "ksd_meta": "Вникать"}, {"roman": "dhaval", "literal": "Бык поддерживающий землю", "ksd_meta": "Законы природы, Хукам"}, {"roman": "poh", "literal": "Коснуться", "ksd_meta": "Производить эффект"}, {"roman": "esar", "literal": "божество Шива", "ksd_meta": "Уничтожение"}, {"roman": "bharma", "literal": "божество Брахма", "ksd_meta": "Порождение"}, {"roman": "ind", "literal": "Божество Индра", "ksd_meta": "Поддержка, управление процессами бытия."}, {"roman": "salahan", "literal": "Хвала", "ksd_meta": "Признательность"}, {"roman": "mund", "literal": "Плохой", "ksd_meta": "Отрицание Создателя (противоположность Salahan)"}, {"roman": "jog", "literal": "Союз", "ksd_meta": "Божественная реализация"}, {"roman": "jugat", "literal": "Методы", "ksd_meta": "Ориентация"}, {"roman": "tunn", "literal": "Тело", "ksd_meta": "Физический"}, {"roman": "bheyd", "literal": "Внутренняя работа", "ksd_meta": "Чувства (органы чувств)"}, {"roman": "sat", "literal": "Создатель", "ksd_meta": "Божественный"}, {"roman": "athsath", "literal": "68", "ksd_meta": "Teeraths; места духовного паломничества (Тираты)."}, {"roman": "sara", "literal": "Океан", "ksd_meta": "неограниченный, полный"}, {"roman": "gah", "literal": "Поиск", "ksd_meta": "Преследование"}, {"roman": "andhey", "literal": "Слепой", "ksd_meta": "Невежество"}, {"roman": "pavey", "literal": "Получить", "ksd_meta": "Обнаружить"}, {"roman": "rah", "literal": "Путь", "ksd_meta": "Просветление (как обнаружение направления Хукама, в данном контексте)."}, {"roman": "haath", "literal": "Рука", "ksd_meta": "В руках. В пределах досягаемости."}, {"roman": "hovey", "literal": "Становится", "ksd_meta": "места."}, {"roman": "asgah", "literal": "Глубокий океан", "ksd_meta": "Духовная жизнь."}]','Множество духовных искателей воспринимают Хукам Творца как силу своего существования / жизни | Множество людей воспринимают дары Творца как индикаторы его Хукама | Множество людей воспринимают Хукам Творца как достоинства (атрибуты) безмерной божественной красоты | Просветлённость / духовное знание воспринимается многими как Хукам Творца; исчерпывающее знание того, что Творец вне дискурса.  | Многие воспринимают Хукам Творца как силу, стоящую за физическим творением и его разрушением. | Многие воспринимают Хукам Творца как отнятие жизни после того, как она была дана. | Многие воспринимают Хукам Творца как реализацию того, что Он недосягаем.  | Многие воспринимают Хукам Творца как осознание того, что Он вездесущ.  | Рассказы о восприятиях Хукама Творца - безграничны (Хукам сам собой - безграничен) | Даже если эти повествования о Хукаме Творца были рассказаны бесчисленными способами бесчисленными искателями, ставящими в своих рассказах бесчисленные акценты на то, или другое | Хукам Творца - поддерживает Творение. Его творение истощается в своём получении поддержки (потребляя жизненную силу) - согласно его Хукаму. (Сначала приходит приток жизненных ресурсов, затем их потребление через проживание жизни)  | Эта поддержка благодаря Хукаму Творца беспрепятственно продолжалась в течение многих периодов времени, веков.  | Хукам Творца - это сила, находящаяся в Его творении. | Нанак, сам Творец управляет своим собственным Хукамом II3II  | Хукам творца существует (постоянно), как и Сам Творец. Он командует своим Творением через безграничную заботу и любовь.  | С таким Хукамом и безмерной любовью Творец бесконечно дает дары пропитания своему Творению | Что же тогда я должен определить как свою духовную цель, благодаря чему может произойти реализация его Хукама? | Какой дискурс мне следует предпринять в моём духовном путешествии? Благодаря совершенству / добродетели какой любви может произойти реализация (любовная) его Хукама? | Духовная цель состоит в том, чтобы сделать мою жизнь (Vela) наполненной Шабдом (Амритой), который является интериоризацией (Vichar) добродетелей Единого Создателя, который есть Вечное Существование, является Хукми (Нао), и превыше всего (Vadeayee). | Путь к осознанию Творца внутри лежит через усердие в получение его Милости | Нанак говорит, вышеизложенное - это путь к реализации Творца внутри себя через обретение божественных добродетелей I4II  | Его Хукам не может быть создан и контролироваться / изменяться его Творением и Творениями (людьми, существами, феноменами)  | Его Хукам создан и управляется Им. Он остаётся необусловленным Творением. | Тот, кто живёт в следовании воле Творца, Хукама (интернализируя его), получает Честь, путём принятия союза с ним.  | Нанак, усвоить (интернализировать) его Хукам - означает принять его безграничные добродетели. | Интернализируйте (усвойте) Хукам через его принятие, усвоение (адаптацию) и прививание любви к нему в своём разуме.  | Благодаря усвоению Хукама, духовная агония (от разлуки) рассеивается (т.к. каждое действие протекает в его Хукаме, и является выражением и укреплением этого союза), и духовное блаженство поселяется в доме нашей атмы. | Шабд, сошедший с уст Гуру, содержит внутри звук высшей мелодии, высшее знание, и приводит к полному и окончательному растворению себя в Хукаме.  | Шабд содержит в себе эссенцию просветлённости, в отношении всех процессов разрушения (Ищар), процессов мистического познания (Горакх), в отношении всего бытия (Брахма), творческих процессов (Парвати) и поддержки / заботы о чём-либо в бытии (Майи - знание, почему что-то существует и расцветает, и имеет удачу, поддержку).  | Сущность Хукама можно осознать и реализовать, но о ней нельзя рассказать (словами. но можно рассказать своей реализацией его) | Шабд - Гуру обеспечивает мне удовлетворяющую реализованность. | Удовлетворящую реализованость того, что есть Один Хукам, поддерживающий всех и всё, и я - не исключение. В виду такой реализованности, я это не забуду (всё о нём напоминает), не разделюсь с ним II5II  | Зачем предпринимать Духовность Тиратов (ритуальных паломничеств), если это не входит в сферу его Хукама, поскольку сфера Хукама - не относится к географическим местам? (Не удовлетворяет запрос Хукама реализоваться во мне. Основной посыл - духовность вне тех или иных территорий) | Во всем духовном мире ничего не может быть реализовано, осознанно, без благословления Просветления твоим Хукамом (Только когда следуешь Хукаму, духовные истины реализуются). | Интернализация этого Одного бесценного послания моего Гуру делает мою духовность основанной на благочестивой Добродетели. Это делает нашу духовность GOD-Based.  | Шабд - Гуру обеспечивает (обеспечивающий) мне удовлетворяющую реализованность. | Удовлетворящую реализованость того, что есть Один Хукам, поддерживающий всех и всё, и я - не исключение. В виду такой реализованности, я это не забуду (всё о нём напоминает), не разделюсь с ним II6II    | Если продлить возраст (мой) до четырёх Юг и ещё в десять раз больше | Если кто-то получит мировую славу и сделает последователем каждого человека  | Если кто-то создаст себе репутацию и заслужит похвалу в духовном социуме | Без благословения просвещением твоего Хукама - я духовно бесполезен.  | В анти-хукамских практиках, я виновен в том, что запятнал свою духовность бесполезностью.  | Нанак, реализация Хукама создаёт наполненную добродетелью духовную жизнь, поскольку Ниргун (Бог, лишенный качеств) являеется источником всех Добродетелей. | Я не могу постичь равного существа как источника всех Добродетелей, чья Реализация Хукама создаёт наполненную Добродетелью ДуховностьII7II  | Через процесс духовного слушания (интернализации) Шабда слушающий возвышается к высотам Сидхов, Пиров, Суров, Натхов.  | Интернализация Шабда рождает пробужденность относительно Хукама Творца для нашей планеты, законов мироздания и всей Вселенной.  | Интернализация Шабда создает осознание Хукама Творца, относящегося к Солнцу, небесным телам и космосу. | Интернализация Шабда устраняет страх смерти.  | Нанак, духовность интернализации Шабда - благословенна.  | Интернализация Шабда избавляет от грехов и печалей II8II  | Интернализация Шабда создаёт осознание относительно силы Творца разрушать, создавать и поддерживать что-либо в бытии. | Интернализация Шабда превращает отрицание Творца в признание Творца. | Интернализация Шабда ориентирует наши физические чувства на божественную реализацию. | Интернализация Шабда позволяет оценить ведические тексты (на предмет их ценности)  | Нанак, духовность интернализации Шабда - благословенна.  | Интернализация Шабда избавляет от грехов и печалей II9II  | Интернализация шабда приносит божественную удовлетворённость и просветление. | Интернализация Шабда позволяет оценить реальность очищения в (68-ми) местах духовных паломничеств. | Интернализация Шабда придаёт ценность непрерывному чтению (чтение без Интернализации - бесполезно).  | Интернализация Шабда рождает постоянно-естественный фокус на Творце.  | Нанак, духовность интернализации Шабда - благословенна.  | Интернализация Шабда избавляет от грехов и печалей II10II  | Интернализация Шабда - это стремление к Совершенному Творцу.  | Интернализация Шабда позволяет оценить учения ведущих мусульманских священнослужителей.  | Интернализация Шабда перенаправляет невежество в просветление. | Интернализация Шабда делает доступным погружение в глубины духовной жизни. | Нанак, духовность интернализации Шабда - благословенна.  | Интернализация Шабда избавляет от грехов и печалей II11II ','','[1, 2, 3]','jbani_v1');
INSERT INTO "ksd_examples" VALUES(7,NULL,12,'','','','[{"roman": "gutt", "literal": "Состояние", "ksd_meta": "Духовное состояние"}, {"roman": "pichey", "literal": "Позади", "ksd_meta": "Последствие"}, {"roman": "likhanhaar", "literal": "Писатель", "ksd_meta": "Писательская способность"}, {"roman": "sagal", "literal": "Целый", "ksd_meta": "Завершенный"}, {"roman": "sudh", "literal": "Пробужденность", "ksd_meta": "Просветлённость"}, {"roman": "jumm", "literal": "Солдаты смерти", "ksd_meta": "Пороки (переопределено в Гурбани)"}, {"roman": "jaye", "literal": "Продолжить", "ksd_meta": "проведенный"}, {"roman": "marag", "literal": "Пути", "ksd_meta": "Духовное путешествие к осознанию Творца"}, {"roman": "chaley", "literal": "Путешествие", "ksd_meta": "следование, пересечение"}, {"roman": "dharm", "literal": "Законы, правила, регуляции - делай то, не делай то.", "ksd_meta": "Хукам - это закон."}, {"roman": "mokh", "literal": "Свобода от препятствий, (от слова Mukt)", "ksd_meta": "Окончательный"}, {"roman": "duar", "literal": "Дверь", "ksd_meta": "тропа"}, {"roman": "parvarey", "literal": "Семья", "ksd_meta": "Семья в отношении ума, манаса- (5 чувств/каналов восприятия)"}, {"roman": "trey", "literal": "Переплыть через", "ksd_meta": "Духовная задача"}, {"roman": "tarey", "literal": "Заставить переплыть", "ksd_meta": "Обеспечить духовную задачу"}, {"roman": "gur", "literal": "Гуру", "ksd_meta": "Шабд"}, {"roman": "sikh", "literal": "от Sikhiya", "ksd_meta": "сообщение, совет, руководство"}, {"roman": "bhikh", "literal": "от Bhaykh", "ksd_meta": "Претенциозный, поддельный."}, {"roman": "parwaan", "literal": "Стать принятым / одобренным / достойным", "ksd_meta": "Соответствовать. Fit"}, {"roman": "pavey", "literal": "Receive", "ksd_meta": "Become"}, {"roman": "dargah", "literal": "Суд совести/ высшего разума", "ksd_meta": "справедливость"}, {"roman": "rajaan", "literal": "Король", "ksd_meta": "Создатель (как Высший авторитет моей духовности)"}, {"roman": "ek", "literal": "Одного", "ksd_meta": "Создатель"}, {"roman": "kartey", "literal": "Создатель", "ksd_meta": "Сознание, в контексте Паури"}, {"roman": "dhaol", "literal": "Белый", "ksd_meta": "Чистый"}, {"roman": "dhaol dhrm", "literal": "Чистый", "ksd_meta": "Божественная духовность (в отличие от мирской / претенциозной / фальшивой религии)"}, {"roman": "dhavley", "literal": "то, что является белым", "ksd_meta": "Чистый, божественный."}, {"roman": "upar", "literal": "Над / Наверху", "ksd_meta": "на нём (сверху на чём-то, как груз"}, {"roman": "bhaar", "literal": "Весt", "ksd_meta": "Груз"}, {"roman": "dhartee", "literal": "Hirdey Dhartee", "ksd_meta": "- Совесть как Центр, Корень и Источник нашей духовной жизни"}, {"roman": "hor", "literal": "From Hor Dee Hor- Что-то другое", "ksd_meta": "отклоняющееся."}, {"roman": "bhaar", "literal": "Вес", "ksd_meta": "груз, бремя"}, {"roman": "ranga", "literal": "цветной", "ksd_meta": "проникнутой; пронизанной"}, {"roman": "taan", "literal": "Сил", "ksd_meta": "Добродетелей (Духовная сила заключается в добродетелях)"}, {"roman": "sualeho", "literal": "Тот, кто даёт ответы", "ksd_meta": "Достойный"}, {"roman": "lakh", "literal": "Сто тысяч", "ksd_meta": "неисчислимое"}, {"roman": "bhalee", "literal": "Хорошо", "ksd_meta": "Позитивно, применимо."}]','Такова природа божественных Добродетелей - существо, осознающее Творца, становится Добродетелями.  | Духовное состояние превращения себя в божественные Добродетели не поддается описанию. Последствием попытки описания является сожаление, раскаяние.  | Духовное состояние превращения себя в божественные добродетели выходит за рамки человеческих способностей к описанию. | Медитативная беседа о духовном состоянии становления божественными добродетелями раскрывает семя просветление, предыдущих и последующих стихов. | Такова природа божественных Добродетелей - существо, осознающее Творца, становится Добродетелями.  | Духовное состояние становления божественными добродетелями относится к Сознанию [единобытия], охватывающему манас (ум, который оперирует 5-ю органами чувств) и буддхи (интеллект, волевое начало, управляющее вниманием). Такое духовное состояние относится к принятию божественных добродетелей на всех уровнях разума (манаса), интеллекта (буддхи), сознания, подсознания).  | Духовное состояние становления божественными добродетелями - есть полное, окончательное просветление духовной вселенной (universe of spirituality). Бог присутствует везде во вселенной. Маннэ - объективная духовность для всей вселенной.  | Духовное состояние становления божественными добродетелями сводит на нет опасности не-просветления. | Духовное состояние становления божественными добродетелями устраняет “духовность”, имевшую завязку на нашей греховности. | Такова природа божественных Добродетелей - существо, осознающее Творца, становится Добродетелями.  | Духовное состояние становления божественными добродетелями устраняет препятствия с пути реализации Творца.  | Духовное состояние становления божественными добродетелями протекает через духовное достоинство, определяемыми “глазами” Гуру..  | Духовное состояние становления божественными добродетелями исключает прохождение предписанных путей и религий. | Духовное состояние становления божественными добродетелями - это состояние связи с Хукамом.  | Такова природа божественных Добродетелей - существо, осознающее Творца, становится Добродетелями.  | Духовное состояние становления божественными добродетелями - это реализация абсолютной духовности, Мокши.  | Духовное состояние становления божественными добродетелями состоит в том, чтобы укоренить в этих добродетелях свои пять чувств, подобных внутренней семье.  | Духовное состояние становления божественными добродетелями - это духовная цель, что следует из послания Гуру (Шабда).  | Нанак, духовное состояние становления божественными добродетелями освобождает меня от путаницы претенциозных (фэйковых) путей.  | Такова природа божественных Добродетелей - существо, осознающее Творца, становится Добродетелями.  | Мои пять чувств принимаются моим сознанием как достойные того, чтобы руководить моим духовным путешествием.  | Мои пять чувств достойно стоят перед судом моей совести. | Мои пять чувств теперь изящно стоят на пути осознания моего Творца.  | Мои пять чувств сосредоточены на Едином Творце. | Должен ли кто-то повествовать дискурс о пяти чувствах, сосредоточенных на Едином Творце? | Благочестивая духовность является ребёнком Сочувствия [к себе]. | Ребёнок Сочувствия - это духовное удовлетворение, которое закрепляет и связывает пять Чувств . | Принять решение о том, что Сочувствие и Духовное Удовлетворение необходимо постоянно закреплять в чувствах, означает стать Существом, осознавшим Творца.  | Представьте себе бремя совести, лишенной Сочувствия и Духовного Удовлетворения, возложенное на наш духовный путь.  | Бремя заключается в том, что Сознание, лишенное Сочувствия, переходит из одного “отклоненного” состояния в другое. | Как бремя этого постоянного отклонения легло на мою совесть? | Моя совесть (через мои 5 чувств) прониклась атрибутами временного.  | Все они (мои пронизанные чувства) непрерывно писали мою духовную судьбу. | Если бы я знал, как написать свою духовную судьбу (правильным образом) | Какую (духовную) судьбу я бы написал? | Насколько достойной, добродетельной и красивой будет моя (духовная) судьба? | Обильные благословения для моей духовной судьбы были бы неоценимы.  | Когда повеление Единого Творца действует в пространстве моего сознания | Из такой сознания в мою (духовную) жизнь текут реки Добродетелей.  | Беседа о благочестивом сознании выше моих сил | Моя неспособность такова, что я не могу ни разу выразить свою преданность (в полной мере соответствующе) | Я принимаю всё, что Ты прикажешь мне, исходя из моей совести.  | Твоё вечное бесформенное Я - является опорой, кормильцем моей Совести II16II','','[1, 2, 3]','jbani_v1');
INSERT INTO "ksd_examples" VALUES(8,NULL,16,'','','','[{"roman": "asankh", "literal": "Sankh- Считать", "ksd_meta": "A + Sankh- Неисчислимый, неизмеряемый, безлимитный, бесконечный."}, {"roman": "tup", "literal": "Покаяние, аскеза", "ksd_meta": "интенсивная форма ритуальной практики"}, {"roman": "bhakh", "literal": "Есть", "ksd_meta": "Потреблять, терпеть"}, {"roman": "saar", "literal": "Железо", "ksd_meta": "Проблемы, испытания"}, {"roman": "moaan", "literal": "Тишина", "ksd_meta": "(также - стон или молчание); Свободный от отвлечения внимания"}, {"roman": "bhalee", "literal": "Хорошо", "ksd_meta": "Позитивно, применимо."}]','Я точу и оттачиваю своё сознание на камне Твоих Добродетелей. Внутри меня шафран - это цвет, пропитанный Твоими Добродетелями. | Интернализация божественных добродетелей является Вечным / Духовным / Внутренним Тапасом (Аскезой). | Если я усвою хотя бы одну каплю послания Шабда / Гуру в своем сознании, величие этого сознания будет за пределами исчислений (его достоинств).  | Я принимаю всё, что Ты прикажешь мне, исходя из моей просветлённой совести.  | Моя просветлённая совесть Творит неисчислимую Реализацию неисчислимой Любви Творца.   | Моя просветлённая Совесть проводит безграничное почитание Бесконечному Превосходству (Творца).  | Моя просветлённая Совесть - это (эквивалентно) рецитации бесчисленных священных писаний и Вед. | Моё просветлённая Совесть создаёт не имеющий границ союз с Творцом в состоянии внутреннего отречения.  | Моё просветлённая Совесть есть дискурс безмерной вовлечённости и просветления в отношении Божественных Добродетелей.  | Моя просветлённая совесть (безгранично удовлетворённая) приносит мне безмерное удовлетворение от безграничной дающей способности Творца (то, что даёт творец нам, когда мы реализуем нашу просветлённую совесть).  | Моя просветлённая совесть позволяет мне в случае столкновения с несоизмеримыми (духовными) препятствиями и преодолевать их. | Моё просветлённая совесть - это целеустремлённая не отвлекающая сосредоточенность на Творце (нет блуждания внимания, отчего оно неизмеримо т.к. едино, и этим единством превосходит любую множественность, поскольку Творец за пределами исчислений). | Беседа о благочестивой совести выше моих способностей. | Моя неспособность такова, что я не могу ни разу адекватно выразить свою преданность и признательность (в полной мере соответствующе).  | Я принимаю всё, что Ты прикажешь мне, изнутри моей совести.  | Ты, Вечный, Бесформенный - Основа Моей Совести II17II | Должен ли кто-то повествовать дискурс о пяти чувствах, сосредоточенных на Едином Творце? | Духовные достижения Совести, управляющей пятью чувствами, объектом сосредоточения которых является Единый Творец, не поддаются исчислению. Nahi Sumaar! ','','[1, 2, 3]','jbani_v1');
INSERT INTO "ksd_examples" VALUES(9,13,1,'ਕੈਸੀ ਆਰਤੀ ਹੋਇ ॥ ਭਵਖੰਡਨਾ ਤੇਰੀ ਆਰਤੀ ॥','kaisī āratī hoe || bhavkhaṇḍnā tērī āratī ||','ਕੈਸੀ ਆਰਤੀ ਹੋਇ','[{"roman": "kaisi", "literal": "какая / что за", "ksd_meta": "вопрос-Рахао: «Что ж тогда есть...?»"}, {"roman": "arati", "literal": "обряд с лампадами (ритуальный)", "ksd_meta": "истинная Арати — не ритуал, а состояние внутреннего созерцания"}, {"roman": "bhav", "literal": "бытие", "ksd_meta": "смещённое/иллюзорное восприятие (bhav); страх как следствие"}, {"roman": "khandana", "literal": "разрушение", "ksd_meta": "устранение, разрушение иллюзии"}]','Что ж тогда [[является истинной]] Арати? || [[Разрушение иллюзорного восприятия (bhav) —]] вот Твоя Арати!','Предыдущие строки описывают внешние арати (луна/звёзды/ветер как лампады). Рахао-вопрос обнуляет их: «И что же тогда настоящая Арати?». Структура: перечисление → опровержение → ответ.','[1, 2, 3, 9]','manual_ksd_sodar');
INSERT INTO "ksd_examples" VALUES(10,NULL,35,'ਕੇਤਿਆ ਕਰਮ ਭੂਮਿ ਮੇਰ ਕੇਤੇ ਕੇਤੇ ਧੂ ਉਪਦੇਸ ॥','Keytia Karam Bhumi Mer Kaytay Kaytay Dhu Updes',NULL,'[{"roman": "Keytia", "literal": "множества (женский род)"}, {"roman": "Karam", "literal": "дела, поступки"}, {"roman": "Bhumi", "literal": "(букв.) земля; метафора: низкий"}, {"roman": "Mer", "literal": "(букв.) горы; метафора: высокий, высший"}, {"roman": "Kaytay", "literal": "множество (мужской род)"}, {"roman": "Dhu", "literal": "(букв.) путеводная звезда; метафора: ведение, фиксированное направление движения"}, {"roman": "Updes", "literal": "взгляды, интерпретации, оценки, утверждения, наставления"}]','Бесчисленны учения (упдеш), подобные землям, горам и путеводным звёздам — и осознание того, что существовало множество ведущих утверждений (кетей дху упдеш), основанных на множестве низких и возвышенных поступков (кетиа карам: бхуми, кете).','Мейнстрим-перевод: "Дхрува" = индуистский святой, преданный Вишну. KSD: Dhu = ਧੂ = путеводная звезда. Логическая прогрессия в строке: земля (низкое) → горы (высокое) → звёзды (ещё выше). Введение имени собственного разрушало бы этот ряд. Следующее слово "упдеш" завершает мысль: бесчисленны наставления-ориентиры.','[1, 3]','Упрощенное издание (2).docx, Паури 35; punjabi.com');
INSERT INTO "ksd_examples" VALUES(11,NULL,4,'ਅੰਮ੍ਰਿਤ ਵੇਲਾ ਸਚੁ ਨਾਉ ਵਡਿਆਈ ਵੀਚਾਰੁ ॥','Anmrit Vela Sach Nao Vadiayi Vichar',NULL,'[{"roman": "Anmrit (Amrit)", "literal": "бессмертный (А+Мрит), Нерождённое — не ''нектар''"}, {"roman": "Vela (mukta, без kenna)", "literal": "определение/описание термина — НЕ указание на период времени"}, {"roman": "Sach", "literal": "Создатель / Вечносуществующий (не просто ''Истина'')"}, {"roman": "Nao (=Hukmee)", "literal": "Хукам / Имя / Источник провидения"}, {"roman": "Vadiayi", "literal": "Величие / превыше всего"}, {"roman": "Vichar", "literal": "исследование, реализация (через изучение)"}]','Амрит Вела — это определение: жизнь, наполненная Бессмертным (Ооангкаром). Амрит Вела Сач Нао Вадиаии Вичар = ''Амрит Вела — это превращение моей жизни в жизнь, наполненную Шабдом: исследование и реализация Добродетелей Единого Творца, который есть Бытие (Сач), который есть Источник Провидения (Нао=Хукмии), и который превыше всего (Вадаии).''','ПРОТИВОРЕЧИЕ МЕЙНСТРИМА: перевод ''chant in the ambrosial hours before dawn (3am)'' — противоречит СГГС 422 (Гуру Нанак: ''истинно то время, когда пробуждается к Слову''), СГГС 1084 (''каждый момент сделай временем Создателя''), СГГС 146 (''все 8 пахар = 24 часа прожиты с пользой''). ГРАММАТИКА: ਵੇਲਾ (mukta, без kenna) = определение термина, а НЕ указание на период. Если бы имелось в виду ''3 часа ночи'' — была бы форма ਵੇਲੇ (с kenna). ВЕЛА = человеческая жизнь как возможность (СГГС 28, 35, 435, 520, 540, 1090). Кросс-ссылки: [{"sggs": 422, "line": "ਵੇਲਾ ਸਚੁ ਪਰਵਾਣੁ ਸਬਦੁ ਪਛਾਣਸੀ", "meaning": "Истинно то время, в котором пробуждается внимание к Его Слову (Гуру Нанак)"}, {"sggs": 1084, "line": "ਸਭੇ ਵਖਤ ਸਭੇ ਕਰਿ ਵੇਲਾ — ਖਾਲਕੁ ਯਾਦਿ ਦਿਲੈ ਮਹਿ ਮਉਲਾ", "meaning": "Каждый момент (вакт и вела) сделай временем памятования Создателя"}, {"sggs": 146, "line": "ਸਭੇ ਵੇਲਾ ਵਖਤ ਸਭਿ ਜੇ ਅਠੀ ਭਉ ਹੋਇ", "meaning": "Все 8 пахар (24 часа) прожиты с пользой, если прожиты в благоговении"}, {"sggs": 540, "line": "ਸਾ ਵੇਲਾ ਸੋ ਮੂਰਤੁ... ਜਿਤੁ ਹਰਿ ਮੇਰਾ ਚਿਤਿ ਆਵੈ", "meaning": "То время плодотворно, когда в сознании присутствует Вездесущий (Гуру Рам Дас)"}, {"sggs": 520, "line": "ਸਾ ਵੇਲਾ ਪਰਵਾਣੁ ਜਿਤੁ ਸਤਿਗੁਰੁ ਭੇਟਿਆ", "meaning": "Приемлемо то время, когда встретился с Создателем внутри (Гуру Арджан)"}, {"sggs": 35, "line": "ਜੇ ਵੇਲਾ ਵਖਤੁ ਵੀਚਾਰੀਐ ਤਾ ਕਿਤੁ ਵੇਲਾ ਭਗਤਿ ਹੋਇ", "meaning": "Каково подходящее время для Бхагти? (Гуру Амар Дас) — вопрос показывает, что нет фиксированного часа"}, {"sggs": 28, "line": "ਓਹ ਵੇਲਾ ਹਥਿ ਨ ਆਵਈ ਅੰਤਿ ਗਇਆ ਪਛੁਤਾਇ", "meaning": "Эта возможность (жизнь) не вернётся — ушёл сожалея"}]','[1, 2, 3]','KSD-анализ Амрит Вела (Паури 4 Джап Бани + кросс-ссылки СГГС)');
INSERT INTO "ksd_examples" VALUES(12,1,1,'','Sochey Soch Na Hovayee Jey Sochee Lakh Vaar II | Chupey Chup Na Hovayee Jey Laye Rhaan Liv Taar II | Bhukiya Bhukh Na Utree Jey Banna Pureeah Bhaar II | Sehes Sianpa Lakh Hohe Ta Ek Na Chale Naal II | Kiv Sachiara Hoyey Kiv Kooray Tootey Paal II | Hukam Rajayee Chalnaa Nanak Likhiya Naal II 1 II','','[{"roman": "sochey", "literal": "ритуальные омовения/купания в “особых”, духовных местах", "ksd_meta": ""}, {"roman": "soch", "literal": "практики/процессы удаления грязи с тела не удаляют грязь с ума. Речь идёт о “чистках”, омовениях, очищения - Sukhmani SGGS 265", "ksd_meta": ""}, {"roman": "na hovayee", "literal": "Не будет реализован", "ksd_meta": ""}, {"roman": "jey sochee (nasal)", "literal": "Если я очищу себя", "ksd_meta": ""}, {"roman": "lakh vaar", "literal": "Более сотни раз", "ksd_meta": ""}, {"roman": "chupey", "literal": "ритуалы молчания / не-говорения (сдерживания в речи) в течение долгого периода времени. Внешняя тишина.", "ksd_meta": ""}, {"roman": "chup", "literal": "Внутрення тишина.", "ksd_meta": ""}, {"roman": "na hovayee", "literal": "Не будет реализована (достигнута).", "ksd_meta": ""}, {"roman": "laye rahaan", "literal": "Я держу свой фокус / концентрация.", "ksd_meta": ""}, {"roman": "bhukh", "literal": "желание, жадность", "ksd_meta": ""}, {"roman": "na utree", "literal": "Не выбывает / Не устраняется", "ksd_meta": ""}, {"roman": "banna (nasal)", "literal": "завязывать (буквально)", "ksd_meta": "собирать"}, {"roman": "pureeah", "literal": "Прошлое, настоящее, будущее.", "ksd_meta": ""}, {"roman": "bhaar", "literal": "Коллекция", "ksd_meta": ""}, {"roman": "sianpa", "literal": "Религиозные знания", "ksd_meta": ""}, {"roman": "ek na", "literal": "Нет / Никто", "ksd_meta": ""}, {"roman": "kiv", "literal": "Как тогда", "ksd_meta": ""}, {"roman": "sachiara", "literal": "(от слова Sach/Creator-) Существом Реализовавшим Бога", "ksd_meta": ""}, {"roman": "hoyey", "literal": "Мы становимся", "ksd_meta": ""}, {"roman": "kooray", "literal": "Неосознающими, не-реализующими внутри (состояние)", "ksd_meta": "противоположно Sachiara"}]','Творец не может быть реализован во мне через ритуальное очищение / омовение в местах паломничества, даже если я омоюсь сто тысяч раз. | Творец не может быть реализован внутри посредством ритуальной практики физического безмолвия, даже если я полностью сосредоточусь на внешнем молчании (внешнее молчание не эквивалентно внутреннему молчанию). | Творец не может быть реализован внутри с помощью ритуальной практики устранения (исполнений), даже если я в состоянии исполнить мои прошлые, настоящие, и будущие желания. | Он не может быть реализован внутри через религиозные знания, независимо от того, насколько у них высокий порядок или насколько они множественны. Такое знание не поддержало бы духовное путешествие внутреннего освобождения. | Как же тогда я могу стать Богореализованным существом внутри себя? Как я могу устранить препятствие моего нереализованного состояния (мое внутреннее неведение Творца) ? | Путь к осознанию Творца внутри состоит в том, чтобы оставаться в пределах границ (потока Творца) и пребывать в Сехедже (принятии) его Хукама, содержащегося внутри нас II1II','','[1, 2, 3, 4, 5, 6, 7, 8]','jbani_v2_blocks');
INSERT INTO "ksd_examples" VALUES(13,1,2,'','Hukmee Hovan Jee Hukam Miley Vadeayee II | Hukmee Utam Neech Hukam Likh Dukh Sukh Payeaeh II | Ekna Hukmee Bakhsish Ek Hukmee Sada Bhaveayeah II | Hukmey Andur Sabh Ko Bahur Hukam Na Koye II | Nanak Hukmey Jey Bujhey Ta Haumai Kahey Na Koye II 2 II | Hukmee Utam Neech Hukam Likh Dukh Sukh Payeaeh II | Hukmee Hovan Jee Hukam Miley Vadeayee II | Hukmee Hovan Akaar Hukam Na Khayea Jayee II','','[{"roman": "hukmee", "literal": "Создатель", "ksd_meta": ""}, {"roman": "hovan", "literal": "Случаться, происходить", "ksd_meta": ""}, {"roman": "akaar", "literal": "Физическое существование", "ksd_meta": ""}, {"roman": "hukam", "literal": "Воля Творца", "ksd_meta": ""}, {"roman": "na kaheya jayee", "literal": "Невозможно выразить полностью", "ksd_meta": ""}, {"roman": "hukmee", "literal": "Создатель", "ksd_meta": ""}, {"roman": "hovan", "literal": "Происходит/ Есть / Существует", "ksd_meta": ""}, {"roman": "jee", "literal": "Жизнь", "ksd_meta": ""}, {"roman": "hukam (sihari)", "literal": "по его Хукаму", "ksd_meta": ""}, {"roman": "miley", "literal": "Приобратается / Получается", "ksd_meta": ""}, {"roman": "vadeaye", "literal": "Честь", "ksd_meta": ""}, {"roman": "hukmee", "literal": "Создатель", "ksd_meta": ""}, {"roman": "utam neech (lit)", "literal": "Высоко и низко. Хорошие и плохие дела.", "ksd_meta": ""}, {"roman": "likh", "literal": "Lekha- Результаты, исходы, последствия", "ksd_meta": ""}, {"roman": "dukh sukh", "literal": "Радости и печали", "ksd_meta": ""}, {"roman": "payeaeh", "literal": "Получать", "ksd_meta": ""}, {"roman": "ekna", "literal": "Некоторые", "ksd_meta": ""}, {"roman": "hukmee", "literal": "Создатель", "ksd_meta": ""}, {"roman": "bakhsheesh", "literal": "Благословлены", "ksd_meta": ""}, {"roman": "ek", "literal": "Множества", "ksd_meta": ""}]','Мое человеческое существование основано на Его Хукаме, даже если весь Его Хукам не может быть постигнут. | То, что я жив, является честью в пределах / рамках / контексте его Хукама. | Последствия - радости и печали - моих действий (выборов) - хороших и плохих - согласуются с Хукамом Творца / Находятся в нём. | Творец благословляет некоторых внутренней реализацией. В то время как множество остаётся в заблуждении и в постоянном внешнем поиске. | Творец реализуется внутри - всеми. Никто не может осознать Творца вне пределов Его полномочий (внутри нас). | Нанак, при осознании Творца внутри, осознание того, что я существую вне Его Хукама, перестаёт существовать II2II |  |  |  | ','','[1, 2, 3, 4, 5, 6, 7, 8]','jbani_v2_blocks');
INSERT INTO "ksd_examples" VALUES(14,1,3,'','Nanak Hukmey Jey Bujhey Ta Haumai Kahey Na Koye II 2 II | Gavai Ko Taan Hovai Kissey Taan II | Gavai Ko Daat Janei Nesaan II | Gavai Ko Gunn Vadeayeea Chaar II | Gavai Ko Vidiya Vikhum Vichaar II | Gavai Ko Saaj Karey Tunn Kheh II | Gavai Ko Japai Disey Duur II | Gavai Ko Vekhey Hadraa Hadoor II','','[{"roman": "gavai", "literal": "Петь(Lit)", "ksd_meta": "Воспринимать Хукам Творца как что-либо."}, {"roman": "ko & kissey", "literal": "множество (Koee)", "ksd_meta": "например множество людей"}, {"roman": "taan", "literal": "мощь, сила", "ksd_meta": ""}, {"roman": "hovey", "literal": "существование", "ksd_meta": ""}, {"roman": "gavai", "literal": "Петь(Lit)", "ksd_meta": "Воспринимать Хукам Творца как что-либо."}, {"roman": "ko", "literal": "множество, многие", "ksd_meta": ""}, {"roman": "daat (sihari)", "literal": "в подарках, внутри даров", "ksd_meta": ""}, {"roman": "janei", "literal": "представлять, распознавать", "ksd_meta": ""}, {"roman": "nesaan", "literal": "петь (Lit)", "ksd_meta": "индикатор, знак"}, {"roman": "gavai", "literal": "Петь(Lit)", "ksd_meta": "Воспринимать Хукам Творца как что-либо."}, {"roman": "ko", "literal": "Множества", "ksd_meta": ""}, {"roman": "gunn", "literal": "Добродетели (Наам), атрибуты (божественные)", "ksd_meta": "paramatma de gunn paramatma de naam. Это в частности то, что описано в преамбуле - 7 добродетелей. Также есть 5 паап, пороков - каам, кродх, ахамкар, лабх, лобх и т.д."}, {"roman": "vadeayeea", "literal": "Огромный (Vadda)", "ksd_meta": ""}, {"roman": "char (aungkar", "literal": "окончание на u)-  единственное число (красота - 1шт), или прилагательное мужского рода, означающее красоту (красивый)", "ksd_meta": ""}, {"roman": "char (mukht", "literal": "без окончания) - множественное число (красоты, красивые, и т.д.), или прилагательное женского рода - красота, красивая и т.д.", "ksd_meta": ""}, {"roman": "char (sihari)", "literal": "Четыри (буквально число - как 4 ножки у стула)", "ksd_meta": ""}, {"roman": "char", "literal": "(в данном контексте) красота, женственность", "ksd_meta": ""}, {"roman": "gavai", "literal": "Петь(Lit)", "ksd_meta": "Воспринимать Хукам Творца как что-либо."}, {"roman": "ko", "literal": "множество, многие", "ksd_meta": ""}, {"roman": "vidiya", "literal": "обучение (Lit)", "ksd_meta": "знание, просветлённость"}]',' | Множество духовных искателей воспринимают Хукам Творца как силу своего существования / жизни | Множество людей воспринимают дары Творца как индикаторы его Хукама | Множество людей воспринимают Хукам Творца как достоинства (атрибуты) безмерной божественной красоты | Просветлённость / духовное знание воспринимается многими как Хукам Творца; исчерпывающее знание того, что Творец вне дискурса. | Многие воспринимают Хукам Творца как силу, стоящую за физическим творением и его разрушением. | Многие воспринимают Хукам Творца как отнятие жизни после того, как она была дана. | Многие воспринимают Хукам Творца как реализацию того, что Он недосягаем. | Многие воспринимают Хукам Творца как осознание того, что Он вездесущ. | Рассказы о восприятиях Хукама Творца - безграничны (Хукам сам собой - безграничен) | Даже если эти повествования о Хукаме Творца были рассказаны бесчисленными способами бесчисленными искателями, ставящими в своих рассказах бесчисленные акценты на то, или другое | Хукам Творца - поддерживает Творение. Его творение истощается в своём получении поддержки (потребляя жизненную силу) - согласно его Хукаму. (Сначала приходит приток жизненных ресурсов, затем их потребление через проживание жизни) | Эта поддержка благодаря Хукаму Творца беспрепятственно продолжалась в течение многих периодов времени, веков. | Хукам Творца - это сила, находящаяся в Его творении. | Нанак, сам Творец управляет своим собственным Хукамом II3II','','[1, 2, 3, 4, 5, 6, 7, 8]','jbani_v2_blocks');
INSERT INTO "ksd_examples" VALUES(15,1,4,'','Sacha Sahib Sach Naye Bhakhiya Bhau Apaar II | Akhey Mangey Deh Deh Daat Kare Dataar II | Faer Ke Agey Rakheay Jitt Dissey Darbar II | Muhon Ke Bolen Boliay Jitt Sunn Dhare Pyaar II | Amrit Vela Sach Nao Vadeayee Vichar II | Karmee Avey Kapraa Nadree Mokh Duar II | Nanak Evey Janeay Sabh Apey Sachiar II 4 II | Anmrith Vaelaa Sach Naao Vaddiaaee Veechaar','','[{"roman": "sacha", "literal": "В существовании", "ksd_meta": ""}, {"roman": "sahib", "literal": "Мастер, создатель", "ksd_meta": ""}, {"roman": "sach", "literal": "В существовании", "ksd_meta": ""}, {"roman": "naye", "literal": "от Niyem- Приказ, Закон - Хукам", "ksd_meta": ""}, {"roman": "bhakhiya", "literal": "язык (Lit)", "ksd_meta": "команда"}, {"roman": "bhau", "literal": "Любовь", "ksd_meta": ""}, {"roman": "apaar", "literal": "Безграничный", "ksd_meta": ""}, {"roman": "akhey mangey", "literal": "Просить и запрашивать", "ksd_meta": ""}, {"roman": "deh deh", "literal": "Дай! (Lit)", "ksd_meta": "бесконечная отдача / “давание”"}, {"roman": "daat", "literal": "подарок (Lit)", "ksd_meta": ""}, {"roman": "karey", "literal": "даёт", "ksd_meta": ""}, {"roman": "dataar", "literal": "Дающий", "ksd_meta": "Создатель"}, {"roman": "faer ke", "literal": "Что тогда", "ksd_meta": ""}, {"roman": "agey", "literal": "впереди (Lit), раньше", "ksd_meta": "Задача"}, {"roman": "rakheay", "literal": "располагать, хранить, предлагать (Lit)", "ksd_meta": "Установить, определить."}, {"roman": "jitt dissey", "literal": "благодаря совершенству какого знания / реализации происходит познание", "ksd_meta": ""}, {"roman": "darbar", "literal": "Двора Творца (Lit)", "ksd_meta": "Его Хукама"}, {"roman": "muhon", "literal": "изо рта(Lit)", "ksd_meta": "полный, дискурс"}, {"roman": "ke bolan", "literal": "какие высказывания  (Lit)", "ksd_meta": ""}, {"roman": "boleiay", "literal": "говорить", "ksd_meta": ""}]','Хукам творца существует (постоянно), как и Сам Творец. Он командует своим Творением через безграничную заботу и любовь. | С таким Хукамом и безмерной любовью Творец бесконечно дает дары пропитания своему Творению | Что же тогда я должен определить как свою духовную цель, благодаря чему может произойти реализация его Хукама? | Какой дискурс мне следует предпринять в моём духовном путешествии? Благодаря совершенству / добродетели какой любви может произойти реализация (любовная) его Хукама? | Духовная цель состоит в том, чтобы сделать мою жизнь (Vela) наполненной Шабдом (Амритой), который является интериоризацией (Vichar) добродетелей Единого Создателя, который есть Вечное Существование, является Хукми (Нао), и превыше всего (Vadeayee). | Путь к осознанию Творца внутри лежит через усердие в получение его Милости | Нанак говорит, вышеизложенное - это путь к реализации Творца внутри себя через обретение божественных добродетелей I4II','','[1, 2, 3, 4, 5, 6, 7, 8]','jbani_v2_blocks');
INSERT INTO "ksd_examples" VALUES(16,1,5,'','Thapeya Na Jaye Keeta Na Hoye II | Apey Aap Niranjan Soey II | Jin Seyweya Tinn Payea Maan II | Nanak Gaveay Gunee Nidhan II | Gaveay Suneay Munn Rakheay Bhao II | Dukh Parhar Sukh Ghar Lae Jaye II | Gurmukh Nadang Gurmukh Vedang Gurmukh Raheya Samayee II | Gur Esar Gur Gorakh Brahma Gur Parbatee Mayee II','','[{"roman": "thapeya", "literal": "Придумано, Создано, Установлено", "ksd_meta": ""}, {"roman": "nan jaye", "literal": "Не может быть", "ksd_meta": ""}, {"roman": "keeta na hoey", "literal": "Управление не возможно", "ksd_meta": ""}, {"roman": "apey", "literal": "Его собственный", "ksd_meta": ""}, {"roman": "aap", "literal": "Сам", "ksd_meta": ""}, {"roman": "niranjan soey", "literal": "Незапятнанный Творением", "ksd_meta": ""}, {"roman": "jin", "literal": "Кто", "ksd_meta": ""}, {"roman": "seyweya", "literal": "Восприятие служения как следования Хукаму", "ksd_meta": ""}, {"roman": "tinn", "literal": "Тот", "ksd_meta": ""}, {"roman": "payea", "literal": "Получает, достигает", "ksd_meta": ""}, {"roman": "maan", "literal": "Честь", "ksd_meta": ""}, {"roman": "gaveay", "literal": "Петь(Lit) (процесс)", "ksd_meta": "принимать"}, {"roman": "gunee", "literal": "добродетели, божественные атрибуты", "ksd_meta": ""}, {"roman": "nidhan", "literal": "неисчислимо", "ksd_meta": ""}, {"roman": "gaveay", "literal": "Петь (Lit)", "ksd_meta": "Принимать"}, {"roman": "suneay", "literal": "Слушать (Lit)", "ksd_meta": "принять, адаптировать в себе"}, {"roman": "munn", "literal": "Разум", "ksd_meta": ""}, {"roman": "rakheay", "literal": "Держивать, прививать", "ksd_meta": ""}, {"roman": "bhao", "literal": "Любовь", "ksd_meta": ""}, {"roman": "dukh", "literal": "духовная агония", "ksd_meta": ""}]','Его Хукам не может быть создан и контролироваться / изменяться его Творением и Творениями (людьми, существами, феноменами) | Его Хукам создан и управляется Им. Он остаётся необусловленным Творением. | Тот, кто живёт в следовании воле Творца, Хукама (интернализируя его), получает Честь, путём принятия союза с ним. | Нанак, усвоить (интернализировать) его Хукам - означает принять его безграничные добродетели. | Интернализируйте (усвойте) Хукам через его принятие, усвоение (адаптацию) и прививание любви к нему в своём разуме. | Благодаря усвоению Хукама, духовная агония (от разлуки) рассеивается (т.к. каждое действие протекает в его Хукаме, и является выражением и укреплением этого союза), и духовное блаженство поселяется в доме нашей атмы. | Шабд, сошедший с уст Гуру, содержит внутри звук высшей мелодии, высшее знание, и приводит к полному и окончательному растворению себя в Хукаме. | Шабд содержит в себе эссенцию просветлённости, в отношении всех процессов разрушения (Ищар), процессов мистического познания (Горакх), в отношении всего бытия (Брахма), творческих процессов (Парвати) и поддержки / заботы о чём-либо в бытии (Майи - знание, почему что-то существует и расцветает, и имеет удачу, поддержку). | Сущность Хукама можно осознать и реализовать, но о ней нельзя рассказать (словами. но можно рассказать своей реализацией его) | Шабд - Гуру обеспечивает мне удовлетворяющую реализованность. | Удовлетворящую реализованость того, что есть Один Хукам, поддерживающий всех и всё, и я - не исключение. В виду такой реализованности, я это не забуду (всё о нём напоминает), не разделюсь с ним II5II','','[1, 2, 3, 4, 5, 6, 7, 8]','jbani_v2_blocks');
INSERT INTO "ksd_examples" VALUES(17,1,6,'','Teerath Navah Jay Tes Bhavan Vinn Bhannet Ke Nhaye Karee II | Jaytee Sireth Upayee Vekha Vinn Karma Kay Miley Layee II | Mutt Vich Ratunn Javahar Manik Jay Ek Gur Kee Sikh Sunee II | Gura Ek Deh Bujhayee II | Sabhna Jeea Ka Ek Daata So Mein Viser Na Jayee II 6 II','','[{"roman": "teerath (sihari)", "literal": "В местах паломничества", "ksd_meta": ""}, {"roman": "navah", "literal": "Купаться, очищаться (водой)", "ksd_meta": ""}, {"roman": "jay", "literal": "“Если” или “Когда”", "ksd_meta": ""}, {"roman": "tes", "literal": "Его (Hukmee)", "ksd_meta": ""}, {"roman": "bhavan", "literal": "Принимается в рамках Хукама", "ksd_meta": ""}, {"roman": "vinn", "literal": "без, вовне", "ksd_meta": ""}, {"roman": "bhanney", "literal": "В cфере Хукама", "ksd_meta": ""}, {"roman": "kay", "literal": "Почему", "ksd_meta": ""}, {"roman": "nhaye", "literal": "Очищаться, мыть, купаться", "ksd_meta": ""}, {"roman": "karee", "literal": "Делать, предпринимать", "ksd_meta": ""}, {"roman": "jaytee", "literal": "Столько же сколько, целиком", "ksd_meta": ""}, {"roman": "sireth", "literal": "Мир, духовный мир.", "ksd_meta": ""}, {"roman": "upayee", "literal": "Создаётся, существует.", "ksd_meta": ""}, {"roman": "vekhan", "literal": "Видеть. Осознавать.", "ksd_meta": ""}, {"roman": "vinn karma", "literal": "Без благословения", "ksd_meta": ""}, {"roman": "kay", "literal": "Что-либо", "ksd_meta": ""}, {"roman": "miley layee", "literal": "Достичь, реализовать.", "ksd_meta": ""}, {"roman": "mutt (sihari)", "literal": "Разум", "ksd_meta": "Духовность (место, где она проявляется)"}, {"roman": "vich", "literal": "Внутри", "ksd_meta": "Интернализировать, усвоить."}, {"roman": "ratunn jawahar manik", "literal": "рубины, бриллианты, жемчуг (лит). Бесценный. Божественные добродетели.", "ksd_meta": ""}]','Зачем предпринимать Духовность Тиратов (ритуальных паломничеств), если это не входит в сферу его Хукама, поскольку сфера Хукама - не относится к географическим местам? (Не удовлетворяет запрос Хукама реализоваться во мне. Основной посыл - духовность вне тех или иных территорий) | Во всем духовном мире ничего не может быть реализовано, осознанно, без благословления Просветления твоим Хукамом (Только когда следуешь Хукаму, духовные истины реализуются). | Интернализация этого Одного бесценного послания моего Гуру делает мою духовность основанной на благочестивой Добродетели. Это делает нашу духовность GOD-Based. | Шабд - Гуру обеспечивает (обеспечивающий) мне удовлетворяющую реализованность. | Удовлетворящую реализованость того, что есть Один Хукам, поддерживающий всех и всё, и я - не исключение. В виду такой реализованности, я это не забуду (всё о нём напоминает), не разделюсь с ним II6II','','[1, 2, 3, 4, 5, 6, 7, 8]','jbani_v2_blocks');
INSERT INTO "ksd_examples" VALUES(18,1,7,'','Jay Jug Charey Aarja Hor Dasunee Hoey II | Navaan Khandan Vich Janeay Naal Chaley Sabh Koey II | Changa Nao Rakhaye Kay Juss Keerat Jugg Laye II | Jay Tiss Nadar Na Aavayee Ta Vaat Na Puchey Kay II | Keeta Andar Keet Kar Dosee Dose Dharey II | Nanak Nirgun Gunn Karey Gunvantean Gunn Dey II | Teha Koey Na Sujhayee Jay Tiss Gunn Koey Karey II 7 II | wordly','','[{"roman": "jay", "literal": "Если", "ksd_meta": ""}, {"roman": "jug charey", "literal": "четыре века (психических состояния) (Lit)", "ksd_meta": "Расширенный"}, {"roman": "aarja", "literal": "Возраст", "ksd_meta": ""}, {"roman": "hor", "literal": "Даже больше (расширенный)", "ksd_meta": ""}, {"roman": "dasunee", "literal": "Десять раз", "ksd_meta": ""}, {"roman": "hoey", "literal": "Становится", "ksd_meta": ""}, {"roman": "navaan khandaan", "literal": "Девять континентов (Lit)", "ksd_meta": "вдоль и поперек, повсюду."}, {"roman": "jaaneeay", "literal": "Известные. Знаменитные.", "ksd_meta": ""}, {"roman": "naal challey", "literal": "Последователи", "ksd_meta": ""}, {"roman": "sabh koey", "literal": "Каждый", "ksd_meta": ""}, {"roman": "changa nao", "literal": "доброе имя, репутацию", "ksd_meta": ""}, {"roman": "rakhaye kay", "literal": "устанавливает", "ksd_meta": ""}, {"roman": "juss keerat", "literal": "хвалит, молится", "ksd_meta": ""}, {"roman": "jugg", "literal": "Духовный мир", "ksd_meta": ""}, {"roman": "laye", "literal": "получает", "ksd_meta": "зарабатывает"}, {"roman": "jay", "literal": "Если", "ksd_meta": ""}, {"roman": "tiss", "literal": "Его", "ksd_meta": "Создателя"}, {"roman": "nadar", "literal": "Великолепние", "ksd_meta": "Благословения; Просветление"}, {"roman": "na aavayee", "literal": "не приходит", "ksd_meta": ""}, {"roman": "vaat na puchey key", "literal": "бесполезно (idiomatic)", "ksd_meta": ""}]','Если продлить возраст (мой) до четырёх Юг и ещё в десять раз больше | Если кто-то получит мировую славу и сделает последователем каждого человека | Если кто-то создаст себе репутацию и заслужит похвалу в духовном социуме | Без благословения просвещением твоего Хукама - я духовно бесполезен. | В анти-хукамских практиках, я виновен в том, что запятнал свою духовность бесполезностью. | Нанак, реализация Хукама создаёт наполненную добродетелью духовную жизнь, поскольку Ниргун (Бог, лишенный качеств) являеется источником всех Добродетелей. | Я не могу постичь равного существа как источника всех Добродетелей, чья Реализация Хукама создаёт наполненную Добродетелью ДуховностьII7II','','[1, 2, 3, 4, 5, 6, 7, 8]','jbani_v2_blocks');
INSERT INTO "ksd_examples" VALUES(19,1,8,'','Pauree 8 | Suney Sidh Peer Sur Naath II | Suney Dharat Dhaval Akaas II | Suney Deep Loa Pataal II | Suney Poh Na Sakey Kaal II | Nanak Bhagtan Sada Vigas II | Suney Dookh Paap Ka Naas II 8 II','','[{"roman": "suney", "literal": "Через духовное слушание (через процесс) / созерцание / интернализация", "ksd_meta": ""}, {"roman": "sidh", "literal": "Возвышенные Йогин, Сиддх", "ksd_meta": ""}, {"roman": "peer", "literal": "Возвышенные Суфии, Суфийские учителя, Пиры", "ksd_meta": ""}, {"roman": "sur", "literal": "Суры, знатоки Вед, познающие тайны мироздания", "ksd_meta": ""}, {"roman": "naath", "literal": "Йогические лидеры, Натхи", "ksd_meta": ""}, {"roman": "dharat", "literal": "Земля", "ksd_meta": ""}, {"roman": "dhaval", "literal": "Бык поддерживающий землю (Lit)", "ksd_meta": "Законы природы, Хукам"}, {"roman": "akaas", "literal": "Вселенная", "ksd_meta": ""}, {"roman": "deep", "literal": "Солнце", "ksd_meta": ""}, {"roman": "loa", "literal": "Небесные тела", "ksd_meta": ""}, {"roman": "pataal", "literal": "Небесные пространства", "ksd_meta": ""}, {"roman": "poh", "literal": "Коснуться (Lit)", "ksd_meta": "Производить эффект"}, {"roman": "kaal", "literal": "Смерть, время", "ksd_meta": ""}, {"roman": "bhagtan", "literal": "Духовность интернализации Шабда", "ksd_meta": ""}, {"roman": "sada", "literal": "Постоянный, вечный", "ksd_meta": ""}, {"roman": "vigas", "literal": "Удовольствие, благословение", "ksd_meta": ""}, {"roman": "dookh", "literal": "Печали", "ksd_meta": ""}, {"roman": "paap", "literal": "Грех", "ksd_meta": ""}, {"roman": "naas", "literal": "Уничтожены, устранены", "ksd_meta": ""}]','Через процесс духовного слушания (интернализации) Шабда слушающий возвышается к высотам Сидхов, Пиров, Суров, Натхов. | Интернализация Шабда рождает пробужденность относительно Хукама Творца для нашей планеты, законов мироздания и всей Вселенной. | Интернализация Шабда создает осознание Хукама Творца, относящегося к Солнцу, небесным телам и космосу. | Интернализация Шабда устраняет страх смерти. | Нанак, духовность интернализации Шабда - благословенна. | Интернализация Шабда избавляет от грехов и печалей II8II','','[1, 2, 3, 4, 5, 6, 7, 8]','jbani_v2_blocks');
INSERT INTO "ksd_examples" VALUES(20,1,9,'','Suney Esar Bharma Ind II | Suney Mukh Salahan Mund II | Suney Jog Jugat Tunn Bheyd II | Suney Sasat Simret Ved II | Nanak Bhagtan Sada Vigas II | Suney Dookh Paap Ka Naas II 9 II','','[{"roman": "esar", "literal": "божество Шива (Lit)", "ksd_meta": "Уничтожение"}, {"roman": "bharma", "literal": "божество Брахма (Lit)", "ksd_meta": "Порождение"}, {"roman": "ind", "literal": "Божество Индра (Lit)", "ksd_meta": "Поддержка, управление процессами бытия."}, {"roman": "mukh (sihari)", "literal": "Высказываться", "ksd_meta": ""}, {"roman": "salahan", "literal": "Хвала", "ksd_meta": "Признательность"}, {"roman": "mund", "literal": "Плохой (Lit)", "ksd_meta": "Отрицание Создателя (противоположность Salahan)"}, {"roman": "jog", "literal": "Союз", "ksd_meta": "Божественная реализация"}, {"roman": "jugat", "literal": "Методы", "ksd_meta": "Ориентация"}, {"roman": "tunn", "literal": "Тело (Lit)", "ksd_meta": "Физический"}, {"roman": "bheyd", "literal": "Внутренняя работа", "ksd_meta": "Чувства (органы чувств)"}, {"roman": "sasat", "literal": "Шастры", "ksd_meta": ""}, {"roman": "simrat", "literal": "Симриты", "ksd_meta": ""}, {"roman": "ved", "literal": "Веды", "ksd_meta": ""}, {"roman": "bhagtan", "literal": "Духовность интернализации Шабда", "ksd_meta": ""}, {"roman": "sada", "literal": "Постоянный, вечный", "ksd_meta": ""}, {"roman": "vigas", "literal": "Удовольствие, благословение", "ksd_meta": ""}, {"roman": "dookh", "literal": "Печали", "ksd_meta": ""}, {"roman": "paap", "literal": "Грех", "ksd_meta": ""}, {"roman": "naas", "literal": "Уничтожены, устранены", "ksd_meta": ""}]','Интернализация Шабда создаёт осознание относительно силы Творца разрушать, создавать и поддерживать что-либо в бытии. | Интернализация Шабда превращает отрицание Творца в признание Творца. | Интернализация Шабда ориентирует наши физические чувства на божественную реализацию. | Интернализация Шабда позволяет оценить ведические тексты (на предмет их ценности) | Нанак, духовность интернализации Шабда - благословенна. | Интернализация Шабда избавляет от грехов и печалей II9II','','[1, 2, 3, 4, 5, 6, 7, 8]','jbani_v2_blocks');
INSERT INTO "ksd_examples" VALUES(21,1,10,'','Suney Sat Santokh Gyan II | Sache Sahiba Kya Nahi Ghar Teray | Suney Athsath Ka Eshnan II | Suney Parh Parh Pavey Maan II | Suney Lagey Sehaj Dhyaan II | Nanak Bhagtan Sada Vigas II | Suney Dookh Paap Ka Naas II 10 II','','[{"roman": "sat", "literal": "Создатель", "ksd_meta": "Божественный"}, {"roman": "santokh", "literal": "Глубинное удовлетворение (исчерпывающее).", "ksd_meta": ""}, {"roman": "gyan", "literal": "Знание, просветление.", "ksd_meta": ""}, {"roman": "athsath", "literal": "68 (Lit)", "ksd_meta": "Teeraths; места духовного паломничества (Тираты)."}, {"roman": "eshnan", "literal": "Омовения, купания (Ишнан).", "ksd_meta": ""}, {"roman": "parh parh", "literal": "Непрерывное чтение", "ksd_meta": ""}, {"roman": "pavey", "literal": "Получить", "ksd_meta": ""}, {"roman": "maan", "literal": "Честь, достоинство, ценность", "ksd_meta": ""}, {"roman": "lagey", "literal": "Достигать, приносить", "ksd_meta": ""}, {"roman": "sehej", "literal": "Естественный, постоянный", "ksd_meta": ""}, {"roman": "dhyaan", "literal": "Созерцание, Фокус, Дхьяна", "ksd_meta": ""}, {"roman": "bhagtan", "literal": "Духовность интернализации Шабда", "ksd_meta": ""}, {"roman": "sada", "literal": "Постоянный, вечный", "ksd_meta": ""}, {"roman": "vigas", "literal": "Удовольствие, благословение", "ksd_meta": ""}, {"roman": "dookh", "literal": "Печали", "ksd_meta": ""}, {"roman": "paap", "literal": "Грех", "ksd_meta": ""}, {"roman": "naas", "literal": "Уничтожены, устранены", "ksd_meta": ""}]','Интернализация шабда приносит божественную удовлетворённость и просветление. | Интернализация Шабда позволяет оценить реальность очищения в (68-ми) местах духовных паломничеств. | Интернализация Шабда придаёт ценность непрерывному чтению (чтение без Интернализации - бесполезно). | Интернализация Шабда рождает постоянно-естественный фокус на Творце. | Нанак, духовность интернализации Шабда - благословенна. | Интернализация Шабда избавляет от грехов и печалей II10II','','[1, 2, 3, 4, 5, 6, 7, 8]','jbani_v2_blocks');
INSERT INTO "ksd_examples" VALUES(22,1,11,'','Suney Sara Gunna Kay Gah II | Suney Sheikh Peer Paatshah II | Suney Andhey Pavey Rah II | Suney Hath Hovey Asgah II | Nanak Bhagtan Sada Vigas II | Suney Dookh Paap Ka Naas II 11 II','','[{"roman": "sara", "literal": "Океан(Lit)", "ksd_meta": "неограниченный, полный"}, {"roman": "gunna", "literal": "Добродетели, божественные атрибуты", "ksd_meta": ""}, {"roman": "sara gunna", "literal": "Создатель", "ksd_meta": ""}, {"roman": "gah", "literal": "Поиск (Lit)", "ksd_meta": "Преследование"}, {"roman": "sheikh", "literal": "Мусульманский сановник, Шейх", "ksd_meta": ""}, {"roman": "peer", "literal": "Святой человек, имеющий последователей, Пир", "ksd_meta": ""}, {"roman": "paatshah", "literal": "Король. Верховный, ведущий.", "ksd_meta": ""}, {"roman": "andhey", "literal": "Слепой(Lit)", "ksd_meta": "Невежество"}, {"roman": "pavey", "literal": "Получить (Lit)", "ksd_meta": "Обнаружить"}, {"roman": "rah", "literal": "Путь (Lit)", "ksd_meta": "Просветление (как обнаружение направления Хукама, в данном контексте)."}, {"roman": "haath", "literal": "Рука (Lit)", "ksd_meta": "В руках. В пределах досягаемости."}, {"roman": "hovey", "literal": "Становится", "ksd_meta": "места."}, {"roman": "asgah", "literal": "Глубокий океан(Lit)", "ksd_meta": "Духовная жизнь."}, {"roman": "bhagtan", "literal": "Духовность интернализации Шабда", "ksd_meta": ""}, {"roman": "sada", "literal": "Постоянный, вечный", "ksd_meta": ""}, {"roman": "vigas", "literal": "Удовольствие, благословение", "ksd_meta": ""}, {"roman": "dookh", "literal": "Печали", "ksd_meta": ""}, {"roman": "paap", "literal": "Грех", "ksd_meta": ""}, {"roman": "naas", "literal": "Уничтожены, устранены", "ksd_meta": ""}]','Интернализация Шабда - это стремление к Совершенному Творцу. | Интернализация Шабда позволяет оценить учения ведущих мусульманских священнослужителей. | Интернализация Шабда перенаправляет невежество в просветление. | Интернализация Шабда делает доступным погружение в глубины духовной жизни. | Нанак, духовность интернализации Шабда - благословенна. | Интернализация Шабда избавляет от грехов и печалей II11II','','[1, 2, 3, 4, 5, 6, 7, 8]','jbani_v2_blocks');
INSERT INTO "ksd_examples" VALUES(23,1,12,'','Pauree 12 | Hukum- Pauree 1-7 | Aisa Naam Niranjun Hoey II | Jay Ko Munn Janey Mun Koey II | Maney Kee Gutt Kahee Na Jaye II Jey Ko Kahey Pichey Pachtaye II | Kagad Kalam Na Likhanhaar II | Manney Ka Beh Karn Vichar II | Aisa Naam Niranjun Hoey II Jay Ko Maan Janey Maan Koey II 12 II','','[{"roman": "hukum", "literal": "Pauree 1-7", "ksd_meta": ""}, {"roman": "aisa", "literal": "Такой, такая", "ksd_meta": ""}, {"roman": "hoey", "literal": "является (природа)", "ksd_meta": ""}, {"roman": "naam niranjan", "literal": "Божественных Добродетелей (Параматма Гуна)", "ksd_meta": ""}, {"roman": "jay ko", "literal": "Существо, которое", "ksd_meta": ""}, {"roman": "munn koey", "literal": "Становится им", "ksd_meta": ""}, {"roman": "janey mun", "literal": "Осознает внутри", "ksd_meta": ""}, {"roman": "maney kee", "literal": "Становящийся Божественными Добродетелями", "ksd_meta": ""}, {"roman": "gutt", "literal": "Состояние", "ksd_meta": "Духовное состояние"}, {"roman": "kahee na jaye", "literal": "Вне описаний", "ksd_meta": ""}, {"roman": "jey ko kahey", "literal": "Попытка описания", "ksd_meta": ""}, {"roman": "pichey", "literal": "Позади (Lit)", "ksd_meta": "Последствие"}, {"roman": "pachtaye", "literal": "Сожаление, раскаяние", "ksd_meta": ""}, {"roman": "kagad", "literal": "Бумага (Lit)", "ksd_meta": ""}, {"roman": "kalam (lit)", "literal": "Пишущий инструмент", "ksd_meta": ""}, {"roman": "likhanhaar", "literal": "Писатель (Lit)", "ksd_meta": "Писательская способность"}, {"roman": "manney ka", "literal": "Становление (принадлежность становления духовному состоянию)", "ksd_meta": ""}, {"roman": "beh", "literal": "Сидеть (Lit). “Давай сядем и поговорим?” .  сосредоточенное усилие", "ksd_meta": ""}, {"roman": "karn vichar", "literal": "Созерцательная, медитативная беседа", "ksd_meta": ""}]',' |  | Такова природа божественных Добродетелей - существо, осознающее Творца, становится Добродетелями. | Духовное состояние превращения себя в божественные Добродетели не поддается описанию. Последствием попытки описания является сожаление, раскаяние. | Духовное состояние превращения себя в божественные добродетели выходит за рамки человеческих способностей к описанию. | Медитативная беседа о духовном состоянии становления божественными добродетелями раскрывает семя просветление, предыдущих и последующих стихов. | Такова природа божественных Добродетелей - существо, осознающее Творца, становится Добродетелями.','','[1, 2, 3, 4, 5, 6, 7, 8]','jbani_v2_blocks');
INSERT INTO "ksd_examples" VALUES(24,1,13,'','Munney Surt Hovey Mun Budh II | Munney Sagal Bhavan Kee Sudh II | Munney Moh Chota(n) Na Khaye II | Munney Jumm Kei Saath Na Jaye II | Aisa Naam Niranjun Hoey II Jay Ko Maan Janey Maan Koey II 13 II','','[{"roman": "munney", "literal": "Состояние становления божественным добродетелем (или добродетелями)", "ksd_meta": ""}, {"roman": "surt", "literal": "Сознание", "ksd_meta": ""}, {"roman": "hovey", "literal": "Случается(Lit)", "ksd_meta": ""}, {"roman": "mun", "literal": "Разум (Манас)", "ksd_meta": ""}, {"roman": "budh", "literal": "Интеллект (Буддхи)", "ksd_meta": ""}, {"roman": "munney", "literal": "Состояние становления божественными добродетелями", "ksd_meta": ""}, {"roman": "sagal", "literal": "Целый", "ksd_meta": "Завершенный"}, {"roman": "bhavan", "literal": "Вселенная (Lit)", "ksd_meta": ""}, {"roman": "sudh", "literal": "Пробужденность (Lit)", "ksd_meta": "Просветлённость"}, {"roman": "munney", "literal": "Состояние становления божественными добродетелями", "ksd_meta": ""}, {"roman": "moh", "literal": "Лицо (Lit)", "ksd_meta": ""}, {"roman": "chota(n) khaye", "literal": "получать побои (Lit)", "ksd_meta": "страдать от последствий (idiomatic)"}, {"roman": "munney", "literal": "Состояние становления божественными добродетелями", "ksd_meta": ""}, {"roman": "jumm", "literal": "Солдаты смерти (Lit)", "ksd_meta": "Пороки (переопределено в Гурбани)"}, {"roman": "kei saath", "literal": "Ассоциация с", "ksd_meta": ""}, {"roman": "jaye", "literal": "Продолжить", "ksd_meta": "проведенный"}]','Духовное состояние становления божественными добродетелями относится к Сознанию [единобытия], охватывающему манас (ум, который оперирует 5-ю органами чувств) и буддхи (интеллект, волевое начало, управляющее вниманием). Такое духовное состояние относится к принятию божественных добродетелей на всех уровнях разума (манаса), интеллекта (буддхи), сознания, подсознания). | Духовное состояние становления божественными добродетелями - есть полное, окончательное просветление духовной вселенной (universe of spirituality). Бог присутствует везде во вселенной. Маннэ - объективная духовность для всей вселенной. | Духовное состояние становления божественными добродетелями сводит на нет опасности не-просветления. | Духовное состояние становления божественными добродетелями устраняет “духовность”, имевшую завязку на нашей греховности. | Такова природа божественных Добродетелей - существо, осознающее Творца, становится Добродетелями.','','[1, 2, 3, 4, 5, 6, 7, 8]','jbani_v2_blocks');
INSERT INTO "ksd_examples" VALUES(25,1,14,'','Munney Marag Thaak Na Paye II | Munney Patt Sion Pargat Jaye II | Munney Mugg Na Chaley Panth II | Munney Dharm Seytee Sunbundh II | Aisa Naam Niranjun Hoey II Jay Ko Maan Janey Maan Koey II 14 II','','[{"roman": "munney", "literal": "Духовное состояние становления божественными добродетелями", "ksd_meta": ""}, {"roman": "marag", "literal": "Пути (Lit)", "ksd_meta": "Духовное путешествие к осознанию Творца"}, {"roman": "thaak", "literal": "Препятствия", "ksd_meta": ""}, {"roman": "paye", "literal": "Сталкиваться (Lit)", "ksd_meta": ""}, {"roman": "munney", "literal": "Духовное состояние становления божественными добродетелями", "ksd_meta": ""}, {"roman": "patt", "literal": "Духовное достоинство (в глазах Гуру)", "ksd_meta": ""}, {"roman": "pargat jaye", "literal": "Исходит", "ksd_meta": ""}, {"roman": "munney", "literal": "Духовное состояние становления божественными добродетелями", "ksd_meta": ""}, {"roman": "mugg", "literal": "Путь", "ksd_meta": ""}, {"roman": "chaley", "literal": "Путешествие (Lit)", "ksd_meta": "следование, пересечение"}, {"roman": "panth", "literal": "Предписанные пути . Религии.", "ksd_meta": ""}, {"roman": "munney", "literal": "Духовное состояние становления божественными добродетелями", "ksd_meta": ""}, {"roman": "dharm", "literal": "Законы, правила, регуляции - делай то, не делай то. (Lit)", "ksd_meta": "Хукам - это закон."}, {"roman": "seytee", "literal": "С, из", "ksd_meta": ""}, {"roman": "sunbundh", "literal": "Ассоциация, отношения", "ksd_meta": ""}, {"roman": "munney", "literal": "имеет мирское и духовное значение", "ksd_meta": ""}]','Духовное состояние становления божественными добродетелями устраняет препятствия с пути реализации Творца. | Духовное состояние становления божественными добродетелями протекает через духовное достоинство, определяемыми “глазами” Гуру.. | Духовное состояние становления божественными добродетелями исключает прохождение предписанных путей и религий. | Духовное состояние становления божественными добродетелями - это состояние связи с Хукамом. | Такова природа божественных Добродетелей - существо, осознающее Творца, становится Добродетелями.','','[1, 2, 3, 4, 5, 6, 7, 8]','jbani_v2_blocks');
INSERT INTO "ksd_examples" VALUES(26,1,15,'','Munney Paveh Mokh Duar II | Munney Parvarey Sadhaar II | Munney Trey Tarey Gur Sikh II | Munney Nanak Bhaveh Na Bhikh II | Aisa Naam Niranjun Hoey II Jay Ko Maan Janey Maan Koey II 15 II','','[{"roman": "munney", "literal": "Духовное состояние становления божественными добродетелями", "ksd_meta": ""}, {"roman": "paveh", "literal": "Реализация (осознание, претворенное в действие)", "ksd_meta": ""}, {"roman": "mokh", "literal": "Свобода от препятствий, (от слова Mukt)", "ksd_meta": "Окончательный"}, {"roman": "duar", "literal": "Дверь (Lit)", "ksd_meta": "тропа"}, {"roman": "munney", "literal": "Духовное состояние становления божественными добродетелями", "ksd_meta": ""}, {"roman": "parvarey", "literal": "Семья (Lit)", "ksd_meta": "Семья в отношении ума, манаса- (5 чувств/каналов восприятия)"}, {"roman": "sadhaar", "literal": "Основа, якорь, корень (от слова adhaar)", "ksd_meta": ""}, {"roman": "munney", "literal": "Духовное состояние становления божественными добродетелями", "ksd_meta": ""}, {"roman": "trey", "literal": "Переплыть через (Lit)", "ksd_meta": "Духовная задача"}, {"roman": "tarey", "literal": "Заставить переплыть (Lit)", "ksd_meta": "Обеспечить духовную задачу"}, {"roman": "gur", "literal": "Гуру", "ksd_meta": "Шабд"}, {"roman": "sikh", "literal": "от Sikhiya", "ksd_meta": "сообщение, совет, руководство"}, {"roman": "munney", "literal": "Духовное состояние становления божественными добродетелями", "ksd_meta": ""}, {"roman": "bhaveh", "literal": "Бродить, запутаться", "ksd_meta": ""}, {"roman": "na", "literal": "Отрицательная частица", "ksd_meta": ""}, {"roman": "bhikh", "literal": "от Bhaykh", "ksd_meta": "Претенциозный, поддельный."}]','Духовное состояние становления божественными добродетелями - это реализация абсолютной духовности, Мокши. | Духовное состояние становления божественными добродетелями состоит в том, чтобы укоренить в этих добродетелях свои пять чувств, подобных внутренней семье. | Духовное состояние становления божественными добродетелями - это духовная цель, что следует из послания Гуру (Шабда). | Нанак, духовное состояние становления божественными добродетелями освобождает меня от путаницы претенциозных (фэйковых) путей. | Такова природа божественных Добродетелей - существо, осознающее Творца, становится Добродетелями.','','[1, 2, 3, 4, 5, 6, 7, 8]','jbani_v2_blocks');
INSERT INTO "ksd_examples" VALUES(27,1,16,'','Panch Parwaan Panch Pardhaan II | Panchey Pavey Dargah Maan II | Panchey- The five senses | Panchey Sohey Dar Rajaan II | Panchaan Ka Gur Ek Dhiyaan II | Jay Ko Khaey Kraey Vichar II | Kartey Kaey Karney Nahi Sumaar II | Dhaol Dhrm Dya Ka Poot II','','[{"roman": "panch", "literal": "Пять чувств", "ksd_meta": ""}, {"roman": "parwaan", "literal": "Стать принятым / одобренным / достойным", "ksd_meta": "Соответствовать. Fit"}, {"roman": "pardhaan", "literal": "Вести, Ведение (управление - lead, leader)", "ksd_meta": ""}, {"roman": "panchey", "literal": "The five senses", "ksd_meta": ""}, {"roman": "pavey", "literal": "Receive", "ksd_meta": "Become"}, {"roman": "dargah", "literal": "Суд совести/ высшего разума", "ksd_meta": "справедливость"}, {"roman": "maan", "literal": "Достоинство", "ksd_meta": ""}, {"roman": "panchey", "literal": "Пять чувств", "ksd_meta": ""}, {"roman": "sohey", "literal": "красиво, изящно", "ksd_meta": ""}, {"roman": "dar (with sihari)", "literal": "дверной проём", "ksd_meta": "путь"}, {"roman": "rajaan", "literal": "Король (буквально), Создатель (как Высший авторитет моей духовности)", "ksd_meta": ""}, {"roman": "panchaan", "literal": "Пять чувств", "ksd_meta": ""}, {"roman": "ka", "literal": "из", "ksd_meta": ""}, {"roman": "gur", "literal": "Эссенции", "ksd_meta": ""}, {"roman": "ek", "literal": "Одного", "ksd_meta": "Создатель"}, {"roman": "dhiyaan", "literal": "Фокус", "ksd_meta": ""}, {"roman": "jay", "literal": "если, должен", "ksd_meta": ""}, {"roman": "ko", "literal": "один, кто-то", "ksd_meta": ""}, {"roman": "khaey", "literal": "Рассказать", "ksd_meta": ""}, {"roman": "kraey", "literal": "Делай, бери", "ksd_meta": ""}]','Мои пять чувств принимаются моим сознанием как достойные того, чтобы руководить моим духовным путешествием. | Мои пять чувств достойно стоят перед судом моей совести. | Мои пять чувств теперь изящно стоят на пути осознания моего Творца. | Мои пять чувств сосредоточены на Едином Творце. | Должен ли кто-то повествовать дискурс о пяти чувствах, сосредоточенных на Едином Творце? | Духовные достижения совести, управляющей пятью чувствами, сущностью которых является Единый Творец (поскольку Творец стоит в центре 5 чувств), не поддаются исчислению. | Благочестивая духовность является ребёнком Сочувствия [к себе]. | Ребёнок Сочувствия - это духовное удовлетворение, которое закрепляет и связывает пять Чувств . | Принять решение о том, что Сочувствие и Духовное Удовлетворение необходимо постоянно закреплять в чувствах, означает стать Существом, осознавшим Творца. | Представьте себе бремя совести, лишенной Сочувствия и Духовного Удовлетворения, возложенное на наш духовный путь. | Бремя заключается в том, что Сознание, лишенное Сочувствия, переходит из одного “отклоненного” состояния в другое. | Как бремя этого постоянного отклонения легло на мою совесть? | Моя совесть (через мои 5 чувств) прониклась атрибутами временного. | Все они (мои пронизанные чувства) непрерывно писали мою духовную судьбу. | Если бы я знал, как написать свою духовную судьбу (правильным образом) | Какую (духовную) судьбу я бы написал? | Насколько достойной, добродетельной и красивой будет моя (духовная) судьба? | Обильные благословения для моей духовной судьбы были бы неоценимы. | Когда повеление Единого Творца действует в пространстве моего сознания | Из такой сознания в мою (духовную) жизнь текут реки Добродетелей. | Беседа о благочестивом сознании выше моих сил | Моя неспособность такова, что я не могу ни разу выразить свою преданность (в полной мере соответствующе) | Я принимаю всё, что Ты прикажешь мне, исходя из моей совести. | Твоё вечное бесформенное Я - является опорой, кормильцем моей Совести II','','[1, 2, 3, 4, 5, 6, 7, 8]','jbani_v2_blocks');
INSERT INTO "ksd_examples" VALUES(28,1,17,'','Jo Tudh Bhavey Sayee Bhalee Kaar II | Asankh Jup Asankh Bhao II | Asankh Puja Asankh Tup Tao II | Asankh Granth Mukh Ved Paath II | Asankh Jog Munn Rahey Udaas II | Asankh Bhagat Gunn Gyaan Vichaar II | Asankh Satee Asankh Dataar II | Asankh Soor Muh Bhakh Saar II','','[{"roman": "asankh", "literal": "Sankh- Считать", "ksd_meta": "A + Sankh- Неисчислимый, неизмеряемый, безлимитный, бесконечный."}, {"roman": "jup", "literal": "Реализация", "ksd_meta": ""}, {"roman": "bhao", "literal": "Любовь", "ksd_meta": ""}, {"roman": "asankh", "literal": "Неисчислимый, безлимитный, бесконечный", "ksd_meta": ""}, {"roman": "puja", "literal": "Пуджа, ритуальное почитание", "ksd_meta": ""}, {"roman": "tup", "literal": "Покаяние, аскеза (Lit)", "ksd_meta": "интенсивная форма ритуальной практики"}, {"roman": "tao", "literal": "Верховный, высший", "ksd_meta": ""}, {"roman": "asankh", "literal": "Неисчислимый, безлимитный, бесконечный", "ksd_meta": ""}, {"roman": "granth", "literal": "Грантхи, Писания (Сири Гуру Грантх Сахиб)", "ksd_meta": ""}, {"roman": "mukh", "literal": "Повторения, рецитации", "ksd_meta": ""}, {"roman": "ved", "literal": "Веды", "ksd_meta": ""}, {"roman": "paath", "literal": "Чтения", "ksd_meta": ""}, {"roman": "asankh", "literal": "Неисчислимый, безлимитный, бесконечный", "ksd_meta": ""}, {"roman": "jog", "literal": "Союз", "ksd_meta": ""}, {"roman": "munn", "literal": "Разум, внутренний", "ksd_meta": ""}, {"roman": "rahey", "literal": "Оставаться, состояние", "ksd_meta": ""}, {"roman": "udaas", "literal": "Отречение, Удаси", "ksd_meta": ""}, {"roman": "asankh", "literal": "Неисчислимый, безлимитный, бесконечный", "ksd_meta": ""}, {"roman": "bhagat", "literal": "Бхагаты, следующие Хукаму", "ksd_meta": ""}, {"roman": "gunn", "literal": "Качества", "ksd_meta": ""}]','Я принимаю всё, что Ты прикажешь мне, исходя из моей просветлённой совести. | Моя просветлённая совесть Творит неисчислимую Реализацию неисчислимой Любви Творца. | Моя просветлённая Совесть проводит безграничное почитание Бесконечному Превосходству (Творца). | Моя просветлённая Совесть - это (эквивалентно) рецитации бесчисленных священных писаний и Вед. | Моё просветлённая Совесть создаёт не имеющий границ союз с Творцом в состоянии внутреннего отречения. | Моё просветлённая Совесть есть дискурс безмерной вовлечённости и просветления в отношении Божественных Добродетелей. | Моя просветлённая совесть (безгранично удовлетворённая) приносит мне безмерное удовлетворение от безграничной дающей способности Творца (то, что даёт творец нам, когда мы реализуем нашу просветлённую совесть). | Моя просветлённая совесть позволяет мне в случае столкновения с несоизмеримыми (духовными) препятствиями и преодолевать их. | Моё просветлённая совесть - это целеустремлённая не отвлекающая сосредоточенность на Творце (нет блуждания внимания, отчего оно неизмеримо т.к. едино, и этим единством превосходит любую множественность, поскольку Творец за пределами исчислений). | Беседа о благочестивой совести выше моих способностей. | Моя неспособность такова, что я не могу ни разу адекватно выразить свою преданность и признательность (в полной мере соответствующе). | Я принимаю всё, что Ты прикажешь мне, изнутри моей совести. | Ты, Вечный, Бесформенный - Основа Моей Совести II17II | Должен ли кто-то повествовать дискурс о пяти чувствах, сосредоточенных на Едином Творце? | Духовные достижения Совести, управляющей пятью чувствами, объектом сосредоточения которых является Единый Творец, не поддаются исчислению. Nahi Sumaar!','','[1, 2, 3, 4, 5, 6, 7, 8]','jbani_v2_blocks');
INSERT INTO "ksd_examples" VALUES(29,1,18,'','Asunkh Moorakh Andh Ghoar II | Asunkh Chor Haramkhor II | Asunkh Amar Kar Jahe Jor II | Asunkh Gulvadh Hatiya Kamahey II | Asunkh Papi Pap Kar Jahey II | Vedic | Kaam Krodh Maya Meh Cheet. Jhooth Vikaar Jagey Hett Cheet II Poonji Paap Lobh Kee Keet II Tat Taree Mun Naam Sucheet II | Asunkh Kureeaar Kurreey Firahey II','','[{"roman": "asankh", "literal": "Sankh- Считать", "ksd_meta": "A + Sankh- Неисчислимый, неизмеряемый, безлимитный, бесконечный."}, {"roman": "moorakh", "literal": "Не-просветленный.", "ksd_meta": ""}, {"roman": "andh", "literal": "Абсолютный", "ksd_meta": ""}, {"roman": "ghoar", "literal": "Тьма", "ksd_meta": ""}, {"roman": "chor", "literal": "Вор (Lit), Обман", "ksd_meta": ""}, {"roman": "haramkhor", "literal": "Неблагодарный", "ksd_meta": ""}, {"roman": "amar kar", "literal": "A+ Mar = То, что не умирает", "ksd_meta": "Стать бессмертным."}, {"roman": "jahe", "literal": "Результат, исход.", "ksd_meta": ""}, {"roman": "jor", "literal": "Мощность, сила, команда.", "ksd_meta": ""}, {"roman": "gulvadh", "literal": "(Lit) Обезглавить", "ksd_meta": "устранить - в духовном смысле, применительно к внутреннему процессу. принудить к молчанию."}, {"roman": "hatiya", "literal": "(Lit) Убить", "ksd_meta": ""}, {"roman": "kamahe", "literal": "(Lit) Совершать, выполнять, делать.", "ksd_meta": ""}, {"roman": "papi", "literal": "Тот, кто совершает преступление(juram", "ksd_meta": "временное)/ грех(paap; совершенное умом); Наполненный пороками разум."}, {"roman": "paap", "literal": "Действовать под влиянием пороков.", "ksd_meta": ""}, {"roman": "kar", "literal": "Совершить, закрепить", "ksd_meta": ""}, {"roman": "jahey", "literal": "Продолжить, Go on", "ksd_meta": ""}, {"roman": "poonji", "literal": "Collection, Summation", "ksd_meta": "Vikar- Vices SGGS 153"}, {"roman": "kureear", "literal": "Отрицание Творца", "ksd_meta": ""}, {"roman": "kurrey", "literal": "Действия, связанные с отрицанием Творца (действия отрицания Творца)", "ksd_meta": ""}, {"roman": "firahey", "literal": "Циклы, циклические, повторяющиеся", "ksd_meta": ""}]','Моя просветленная совесть приносит осознание моего безмерного состояния непросветленности и полнейшей (внутренней) тьмы. | Моё просветленное сознание создает осознание моего безмерного состояния обмана и неблагодарности. | Моя просветленная совесть создает реализацию моих бесчисленных попыток стать бессмертным и командовать (над другими) | Моя просветлённая совесть создает осознание моих бесчисленных поступков, которые обезглавливают меня. | Моё просветленное сознание создает осознание бесчисленных действий, совершенных моим наполненным пороками разумом, направленными на уничтожение/умолкание моего сознания и моей совести. | Моё просветлённое сознание и совесть создают осознание моих бесчисленных и повторяющихся отрицаний Творца. | Моё просветлённое сознание и совесть создают осознание моей безмерной склонности к негативным и неблагочестивым мыслям. | Mоё просветленное сознание и совесть создают осознание моих бесчисленных актов отрицания Творца, отягощающих мою духовность. | Нанак, я произношу речь моего скромного духовного достоинства. | Беседа о благочестивом сознании выше моих сил | Моя неспособность такова, что я не могу ни разу выразить свою преданность (в полной мере соответствующе) | Я принимаю всё, что Ты прикажешь мне, исходя из моей совести. | Твоё вечное бесформенное Я - Поддерживающее Моё Сознание II18II','','[1, 2, 3, 4, 5, 6, 7, 8]','jbani_v2_blocks');
INSERT INTO "ksd_examples" VALUES(30,1,19,'','Asunkh Naav Asunkh Thaav II | Agum Agum Asunkh Loe II | Asa Mehla 1 | Apar Apaar Agum Agochar Kehney Keem Na PayeeII 634 | Asunkh Kahey Sirr Bhaar Hoey II | Akhree Naam Akhree Salahh II | Eternal Rag Gauri Purbi Bavan Akhree Kabeer Jio Ki | Akhree Gyaan Geet Gun Gah II','','[{"roman": "asankh", "literal": "Sankh- Считать", "ksd_meta": "A + Sankh- Неисчислимый, неизмеряемый, безлимитный, бесконечный."}, {"roman": "naav", "literal": "From Niyam, структура, процедура", "ksd_meta": "Хукам; Приказ"}, {"roman": "thaav", "literal": "(Lit) место", "ksd_meta": "юрисдикция (в контексте Naav)"}, {"roman": "agum", "literal": "за гранью понимания", "ksd_meta": "Все досягаемости чувств. Описание Создателя."}, {"roman": "asankh", "literal": "Sankh- Считать", "ksd_meta": "A + Sankh- Неисчислимый, неизмеряемый, безлимитный, бесконечный."}, {"roman": "loe", "literal": "(Lit) свет", "ksd_meta": "просветление"}, {"roman": "sirr (w/ sihari)", "literal": "внутри разума", "ksd_meta": ""}, {"roman": "bhaar", "literal": "(Lit) груз, бремя", "ksd_meta": "Пробуждение (in the context of discourse)"}, {"roman": "hoey", "literal": "служит причиной для, приносит с целью чего-то", "ksd_meta": ""}, {"roman": "akhree", "literal": "1) Алфавит (буквы)", "ksd_meta": "2) Произведено как слово с приставкой A + Khr; нерушимый; вечный;"}, {"roman": "naam", "literal": "Божественные атрибуты", "ksd_meta": ""}, {"roman": "salahh", "literal": "(Lit) восхваление", "ksd_meta": "величие"}, {"roman": "akhree", "literal": "1) Алфавит (буквы)", "ksd_meta": "2) Произведено как слово с приставкой A + Khr; нерушимый; постоянный;"}, {"roman": "eternal gyaan", "literal": "Просветление.", "ksd_meta": ""}, {"roman": "geet", "literal": "(Lit) Песня, idiomatic: разразиться песней (быть прерванным вдохновенным потоком песни)", "ksd_meta": "наполняет меня молитвой; ревербация, отражение."}, {"roman": "gun", "literal": "Качества, Добродетели", "ksd_meta": ""}, {"roman": "gah", "literal": "(Lit) Океан, Неограниченность", "ksd_meta": ""}, {"roman": "akhree", "literal": "1) Алфавит (буквы)", "ksd_meta": "2) Произведено как слово с приставкой A + Khr; нерушимый; вечный;"}, {"roman": "bolunn", "literal": "(Lit) Speak", "ksd_meta": ""}, {"roman": "baan", "literal": "(Lit) Utter", "ksd_meta": ""}]','Моя просветленная совесть создает осознание бесконечности Хукама Творца и его бесконечной юрисдикции. | Моя просветленная совесть создает безмерное осознание Бесконечного Творца. | Моя просветленная совесть создает огромный внутренний дискурс в разуме, относящийся к духовному осознанию. | Моя просветленная совесть создает безмерное созерцание и осознание Вечных Божественных Добродетелей и нерушимый Авторитет Его Величия во мне. | Моя просветлённая совесть создает Просветление относительно Вечного, наполняя меня Безграничными Божественными Добродетелями. | В результате этого я становлюсь Добродетелями Вечного. | Становление Добродетелями Вечного позволяет бесконечно принять Вечного Творца в моем разуме. | Становясь этими (Божественными) Добродетелями, я отказываюсь от своего мнения об их отвержении. | Следовательно, мой разум следует всему, что велит моя совесть, моё просветленное сознание. | Мой разум теперь осознает, что все, что создано моей просветлённой совестью, находится в пределах Хукама Творца. |  | Беседа о благочестивой совести выше моих сил | Моя неспособность такова, что я не могу ни разу выразить свою преданность (в полной мере соответствующе) | Я принимаю всё, что Ты прикажешь мне, исходя из моей совести. | Твоё вечное бесформенное Я - Поддерживающее Моё Сознание II19II','','[1, 2, 3, 4, 5, 6, 7, 8]','jbani_v2_blocks');
INSERT INTO "ksd_examples" VALUES(31,1,20,'','Bhareay Hath Paer Tunn Deh II Panee Dhotey Utras Kheh II | Moot Pleete Kaparr Hoey II Dey Sabun Laeay Oh Dhoey II | Bhareay Mutt Paapa Ke Sang II | Oh Dhopey Navey Kaey Rung II | Punee Papi Akhan Nahe II | Kar Kar Karna Likh Ley Jah II | Apey Beej Apey Hee Khah II | Nanak Hukmee Aveh Jah II 20 II','','[{"roman": "bhareah", "literal": "загрязнённый", "ksd_meta": ""}, {"roman": "hath paer tunn deh", "literal": "Физически", "ksd_meta": ""}, {"roman": "panee", "literal": "Вода", "ksd_meta": ""}, {"roman": "dhotey", "literal": "Очищение", "ksd_meta": ""}, {"roman": "utras", "literal": "Удалить, стереть", "ksd_meta": ""}, {"roman": "kheh", "literal": "Пятно", "ksd_meta": ""}, {"roman": "moot pleete", "literal": "Загрязненный (moot = моча, урина", "ksd_meta": "pleete - нечистоты)"}, {"roman": "kaparr", "literal": "Одежда", "ksd_meta": ""}, {"roman": "sabun", "literal": "Мыло", "ksd_meta": ""}, {"roman": "laeay", "literal": "Использовать", "ksd_meta": ""}, {"roman": "dhoey", "literal": "Чистить, очищать", "ksd_meta": ""}, {"roman": "bhareay", "literal": "Загрязненный", "ksd_meta": ""}, {"roman": "mutt", "literal": "Интеллект", "ksd_meta": ""}, {"roman": "paapa", "literal": "(Lit) грехи, пороки, оступки", "ksd_meta": ""}, {"roman": "ke sang", "literal": "В пределах", "ksd_meta": ""}, {"roman": "oh", "literal": "Этот, который", "ksd_meta": ""}, {"roman": "dhopey", "literal": "Очищен", "ksd_meta": ""}, {"roman": "navey", "literal": "Божественные атрибуты, качества", "ksd_meta": ""}, {"roman": "rung", "literal": "(Lit) Цвет", "ksd_meta": "Наполнять, проявлять."}, {"roman": "punee", "literal": "Наполненный добродетелью", "ksd_meta": ""}]','Вода очищает меня, когда моё тело запятнано. | Мыло очищает мою грязную одежду. | Помимо запятнанности моего тела, и загрязненности моей одежды, мой интеллект запятнан пороками. | Очищение этого интеллекта происходит путём наполнения его добродетелями Творца. | Очищение запятнанного пороками интеллекта до наполненного добродетелями осуществляется не (просто) духовным дискурсом. | Очищение осуществляется путём духовного усвоения Добродетелей посредством постоянных поступков. | Духовность усвоения добродетелей посредством устойчивых поступков пробуждает Меня осознавать - пожну так, как посею. | Нанак, пожнешь, как посеешь - это Хукам Творца, относящийся к моему циклу духовности. II20II','','[1, 2, 3, 4, 5, 6, 7, 8]','jbani_v2_blocks');
INSERT INTO "ksd_examples" VALUES(32,1,21,'','Teerath Tupp Dya Dut Daan II | Jay Ko Pavey Til Ka Maan II | Suneya Maneya Mun Keeta Bhao II | Anturgat Teerath Mull Nao II | Sabh Gunn Teyre Mein Nahi Koey II | Venn Gunn Keetey Bhagat Na Hoey II | Suasth Aath Banni Barmao II | Kavann So Vela Vakhat Kavann Kavann Thit Kavann Vaar II','','[{"roman": "teerath (w/aungkar)", "literal": "Паломничество", "ksd_meta": ""}, {"roman": "tupp (w/aungkar)", "literal": "Тапас, аскеза", "ksd_meta": ""}, {"roman": "dya", "literal": "От дарения от глагола Deyna (verb)", "ksd_meta": ""}, {"roman": "dut (w/aungkar)", "literal": "Отречение, отказ, сдача", "ksd_meta": ""}, {"roman": "daan (w/aungkar)", "literal": "Милостыня, подаяние", "ksd_meta": ""}, {"roman": "jay ko", "literal": "Один, тот который", "ksd_meta": ""}, {"roman": "pavey", "literal": "Получать", "ksd_meta": "зарабатывать"}, {"roman": "til ka", "literal": "(Lit) Кунжутное семя", "ksd_meta": "миниатюрный; временной"}, {"roman": "maan", "literal": "Хвала как награда", "ksd_meta": ""}, {"roman": "til ka maan", "literal": "idiomatic: временное и незначительное. Это относится к кунжутному семени, но можно заменить на любое другое :)", "ksd_meta": ""}, {"roman": "suneya", "literal": "(Lit) Слушать", "ksd_meta": "Интернализировать"}, {"roman": "maneya", "literal": "(Lit) Верить, принимать", "ksd_meta": "Становиться"}, {"roman": "mun", "literal": "Разум", "ksd_meta": ""}, {"roman": "keeta bhao", "literal": "Любовь", "ksd_meta": ""}, {"roman": "anturgat", "literal": "Внутри, внутри разума.", "ksd_meta": ""}, {"roman": "teerath (w/sihari)", "literal": "(Lit) Паломничество", "ksd_meta": "Ритуальное очищение"}, {"roman": "mull", "literal": "Нечистоты, примеси (ритуальные)", "ksd_meta": "Пороки"}, {"roman": "nao", "literal": "Божественные Добродетели", "ksd_meta": ""}, {"roman": "sabh gunn", "literal": "Все Качества (Добродетели)", "ksd_meta": ""}, {"roman": "teyre", "literal": "Принадлежащие создателю", "ksd_meta": ""}]','Совершение паломничеств, аскез, ритуалов, раздача милостыни в своей практике духовности… | …не приносит ничего, кроме временной похвалы. | С любовью усваивая и становясь Добродетелями Творца… | Я совершаю внутреннее очищение Божественной Добродетелью. | Все Качества принадлежат Создателю, а вовсе не мне. | Духовность не материализуется без усвоения этих Добродетелей. | Шабд - убежище, а Добродетели - щит моей духовности. | Это прекрасное прибежище Шабда и щит добродетелей Творца создаем в моём разуме вечное блаженство и реализацию. | Вечное блаженство реализации в моем уме не зависит от определенного периода, времени, недели или дня | Возникновение Вечного блаженства и осознания в моём уме не зависит от определенного времени года или месяца. | Возникновение Вечного Блаженства Реализации в моем сознании достигается не через знание, содержащееся в Пуранах. | Возникновение Вечного Блаженства Реализации в моём сознании не достигается через знание, записанное Исламским духовенством в Коран. | Возникновение Вечного Блаженства Реализации в моём сознании вовсе не достигается с помощью Йогических знаний, относящихся к сезону, месяцу, неделе и дню. | Сознание Творца, создавшее во мне Состояние Вечного Блаженства Реализации, знает это. | Состояние Вечного Блаженства Реализации внутри меня не поддается описанию, рассказыванию или восхвалению. | Нанак (остановка, т.к. нет аункар; запятая, пауза), полное повествование о Состоянии Вечного Блаженства Реализации внутри меня таково (за пределами описания, повествования и восхваления), потому что каждое из моих чувств - Пробуждено. | Это происходит в результате становления величественными Добродетелями великолепного Создателя. | Нанак, заниматься само-направленной духовностью (в отличие от духовности, сосредоточенной на Добродетели) означает направлять её к недостойной цели II21II | Моя просветлённая совесть заставляет мой разум колебаться между бесчисленными темными мыслями и высокопросвещенными. | В этих колебаниях, в этих изнурител','','[1, 2, 3, 4, 5, 6, 7, 8]','jbani_v2_blocks');
INSERT INTO "ksd_examples" VALUES(33,1,23,'','Salahi Salah Eti Surt Na Payeea II | Nadiya Atey Vah Pveh Samund Na Janneah II | Samund Shah Sultan Girha Seytee Mal Dhan II | Kirri Tul Na Hovni Je Tis Mnoh Na Visreh II 23 II','','[{"roman": "salahi", "literal": "(Lit) Восхваление Добродетелей", "ksd_meta": ""}, {"roman": "salahi salah", "literal": "непрерывное восхваление", "ksd_meta": "непрерывное признание ценности; реализация"}, {"roman": "eti surt", "literal": "Такой тип мышление", "ksd_meta": ""}, {"roman": "na payeea", "literal": "не достигнуто", "ksd_meta": ""}, {"roman": "nadiya atey vah", "literal": "(Lit) в реках и водоемах течёт вода", "ksd_meta": "метафора разума и чувств, стремящихся к месту назначения. Здесь Нанак хочет усилить послание. Усилить идею о том, что разум и чувства должны двигаться в определённом направлении."}, {"roman": "pveh samund", "literal": "(Lit)", "ksd_meta": "впадать в океан; течь в океан божественных добродетелей; метафора становления, маннэ; река (из чувств и разума) втекает в океан (божественных добродетелей)"}, {"roman": "na janneah", "literal": "(Lit) незнание", "ksd_meta": "отсутствие отдельной идентичности; слияние. когда ты сливаешься, тогда нет отдельной идентичности."}, {"roman": "samund", "literal": "(Lit) Океан", "ksd_meta": "неизмеримой величины. (человек - океан добродетелей;)"}, {"roman": "shah sultan", "literal": "(Lit)", "ksd_meta": "Шах, Султан, царь царей. Возвышенный."}, {"roman": "girha", "literal": "(Lit) гора", "ksd_meta": "метафора для обозначения чего-то непоколебимого."}, {"roman": "seytee", "literal": "(Lit) подобно,сопоставимо", "ksd_meta": "тот, который"}, {"roman": "mal dhan", "literal": "(Lit) Богатство", "ksd_meta": "ценность."}, {"roman": "kirri", "literal": "(Lit) муравей", "ksd_meta": "незначительный (в духовном значении)"}, {"roman": "tul na hovni", "literal": "(Lit) несравненный, вне возможности проводить параллели", "ksd_meta": ""}, {"roman": "je", "literal": "если, пока", "ksd_meta": ""}, {"roman": "tis", "literal": "божественные добродетели", "ksd_meta": ""}, {"roman": "mnoh na visreh", "literal": "(Lit) Не удалено из моего ума", "ksd_meta": "не забыто; отказываться"}]','Моё (уравновешенное - контекст 21-22 паури) мышление не может быть достигнуто без осознания Божественных Добродетелей. | К такой реализации потоки моего разума и чувств слились, чтобы стать Океаном Божественных Добродетелей. | Становление Божественными Добродетелями сделало мою духовность бесценной, неизмеримой, непоколебимой и возвышенной. | Моя  идентичность остаётся несравненной, бесценной, неизмеримой, непоколебимой и возвышенной до тех пор, пока я не отказываюсь от Божественных Добродетелей II23II','','[1, 2, 3, 4, 5, 6, 7, 8]','jbani_v2_blocks');
INSERT INTO "ksd_examples" VALUES(34,1,24,'','Aant Na Sifti Kehnn Na Aant II | Aant Na Karnney Denn Na Aant II | Aant Na Vekhan Sunnen Na Aant II | Aant Na Japey Kya Mun Munt II | Aant Na Japey Kita Akaar II | Aant Na Japey Paravar II | Antt Karann Keytey Bil-lahey II | Ta Kay Aant Na Paey Jahe II','','[{"roman": "aant na", "literal": "Бесконечны, безлимитны", "ksd_meta": ""}, {"roman": "sifti", "literal": "(Lit) восхваления", "ksd_meta": "добродетели"}, {"roman": "kehnn", "literal": "дискурс", "ksd_meta": ""}, {"roman": "na aant", "literal": "бесконечны, безлимитны", "ksd_meta": ""}, {"roman": "karnney", "literal": "(Lit) делать, совершать действия", "ksd_meta": ""}, {"roman": "denn", "literal": "(Lit) вносить вклад", "ksd_meta": "отдавать."}, {"roman": "vekhan", "literal": "(Lit) видя", "ksd_meta": "интернализация"}, {"roman": "sunnen", "literal": "(Lit) слушая", "ksd_meta": "становление"}, {"roman": "japey", "literal": "понимая", "ksd_meta": ""}, {"roman": "kya", "literal": "что, что такое", "ksd_meta": ""}, {"roman": "mun (w/sihari)", "literal": "внутри моего знания", "ksd_meta": "внутри"}, {"roman": "munt", "literal": "руководство (корень: Mantar (мантар, а не мантра), совет к реализации не может использоваться как объект для повторения", "ksd_meta": "он должен использоваться как наставление к реализации; послания не предназначены для повторений; наставления не достигаются через чантинг)"}, {"roman": "japey", "literal": "осознание", "ksd_meta": ""}, {"roman": "kita", "literal": "(Lit) деятельность, действия", "ksd_meta": "поступки"}, {"roman": "akaar", "literal": "(Lit) форма, характер (природа) поступков", "ksd_meta": ""}, {"roman": "japey", "literal": "Осознание", "ksd_meta": ""}, {"roman": "paravar", "literal": "(Lit) эта сторона и та сторона", "ksd_meta": "обычно это метафора водоёма, который ты хочешь пересечь."}, {"roman": "antt karann keytey bil", "literal": "lahey II", "ksd_meta": ""}, {"roman": "antt", "literal": "Предел, лимит (Note: противоположность Antt Na в предыдущих стихах)", "ksd_meta": ""}, {"roman": "karann", "literal": "из-за, по какой причине (ты не общаешься со мной, и т.д.)", "ksd_meta": ""}]','Божественные Добродетели  - безграничны, как дискурс о них. | Действия, совершаемые Божественными Добродетелями (через меня) - неоценимы своим вкладом (в мою реальность). | Моё усвоение Божественных Добродетелей - безгранично (имеет природу безграничности), также как и моё становление Ими. | Безгранично то внутреннее руководство, вызванное моим осознанием божественных добродетелей. | Характер моих деяний, происходящих из осознания божественных добродетелей, безграничен. | Безграничны Границы моего осознания божественных добродетелей. | Неисчислимые страдания причиняются стремлением к духовности существ, у которых есть предел. | Никакое осознание не достигается путём такого стремления к духовности ограниченных сущностей / к духовности сущностей с ограниченными возможностями. | Такая реализация Безграничного (так, как объяснено начиная с 1-го паури) осуществляется Исключительными (людьми). | Повествование о Безграничном (исключительном) осознании тоже становится безграничным. | Возвышен мой Мастер и возвышена моя внутренняя Совесть (как Его Обитель). | Превыше всего на Возвышенности моей Совести пребывают Великолепные Добродетели Творца. | Моя Совесть возвышается таким образом (в Добродетелях Творца) | Таков путь к реализации Творца. | Моя внутренняя реализация также возвышена, как Божественные Добродетели Творца. | Нанак, моя реализация внутри - это благословение от Творца II24II','','[1, 2, 3, 4, 5, 6, 7, 8]','jbani_v2_blocks');
INSERT INTO "ksd_examples" VALUES(35,1,25,'','Nanak Pind Bhaksis Ka Kabhu Nekhutes Nahe II SGGS 358 | Bahuta Karam Likhiya, Na Jaye II | Vadda Data Til Na Tamaye II | Kaytey Manghey Jodh Apar II | Jup Banee Twenty Four | Kaytia Gannut Nahi Vichar | Kaytey Khup Tuttey Veykar II | Kaytey Ley Ley Mukhr Pahe II','','[{"roman": "bahuta", "literal": "неизмеримый", "ksd_meta": "обильный"}, {"roman": "likhiya", "literal": "(Lit) записано в", "ksd_meta": "предоставленный"}, {"roman": "na jaye", "literal": "(Lit) не уходит", "ksd_meta": "вечный"}, {"roman": "vadda", "literal": "Великолепный", "ksd_meta": ""}, {"roman": "data", "literal": "Создатель (дающий)", "ksd_meta": ""}, {"roman": "til", "literal": "(Lit) кунжутное семя", "ksd_meta": "частичка"}, {"roman": "tamaye", "literal": "желание", "ksd_meta": ""}, {"roman": "kaytey", "literal": "множество", "ksd_meta": ""}, {"roman": "manghey", "literal": "(Lit) спрашивать", "ksd_meta": "усваивать"}, {"roman": "jodh", "literal": "(Lit) воин", "ksd_meta": "храбрость"}, {"roman": "apar", "literal": "Изобилие", "ksd_meta": ""}, {"roman": "kaytia", "literal": "множество", "ksd_meta": ""}, {"roman": "gannut", "literal": "считать", "ksd_meta": ""}, {"roman": "nahi", "literal": "(Lit) вне", "ksd_meta": "за пределами"}, {"roman": "vichar", "literal": "повествование", "ksd_meta": ""}, {"roman": "kaytey", "literal": "множество", "ksd_meta": ""}, {"roman": "khup tuttey", "literal": "(Lit) истощение", "ksd_meta": "Устранён; выбывание после изнурительной битвы;"}, {"roman": "veykar", "literal": "Пороки", "ksd_meta": ""}, {"roman": "kaytey", "literal": "множество, бесчисленность", "ksd_meta": ""}, {"roman": "ley", "literal": "то что находится в ритме", "ksd_meta": "в регулярности (ley и tal - два компонента музыкальной композиции) ритма;"}]','Благословения Творца, дарованные мне, обильны и постоянны. | В таких благословениях великолепного Подателя у меня нет ни капли желания к чему-либо другому. | Благодаря таким благословением, я приобрёл огромное мужество, чтобы бороться со своими многочисленными пороками. | С моими пороками, которым нет счёта и описания. | Такими благословениями множество моих пороков - устранено (из моей изнурительной битвы). | В таких благословениях, я приобрёл постоянство в устранении своих бесчисленных пороков. | Пороки, поглотившие меня бесчисленными непросветлёнными желаниями | Эти благословения - призыв избавиться от моих бесчисленных печалей, связанных с желаниями. | Это призывание также является твоим благословением для меня, Творец. | Освобождение от рабства желаний (также) происходит в Твоих благословениях. | Я не могу приписать это ничему, кроме Твоего благословения. | Приписывать это (освобождение) чему-либо, кроме Твоих благословений, значит быть непросвещенным. | Рассмотрение таких верований является оскорблением Твоих благословений. | Осознание Твоих благословений заставило меня отказаться от таких оскорблений. | Так говорят и мои чувства (вместе с моим разумом) | Кого ни благословишь, о Создатель… | Нанак, тот достигает высшую из вершин духовности II25II','','[1, 2, 3, 4, 5, 6, 7, 8]','jbani_v2_blocks');
INSERT INTO "ksd_examples" VALUES(36,1,26,'','Amul Gunn Amul Vapar II | Gunn- Divine Virtues | Amul Vapareay Amul Bhandar II | Amul Aveh Amul Ley Jahe II | Amul Bhaye Amula Smahe II | Amul Dharam Amul Diban II | Amul Tul Amul Parvann II | Amul Bakhsis Amul Nisann II','','[{"roman": "amul", "literal": "A + Mul", "ksd_meta": "- бесценное; то, что не может иметь ценности (слишком ценное)"}, {"roman": "gunn", "literal": "Divine Virtues", "ksd_meta": ""}, {"roman": "vapar", "literal": "(Lit) относится к торговле (отдача чего-то, получение чего-то), обмену", "ksd_meta": "практика"}, {"roman": "amul", "literal": "бесценное", "ksd_meta": "то, что не может иметь ценности (слишком ценное)"}, {"roman": "vapareay", "literal": "(Lit) торговцы, те кто реализуют в мир добродетели получив их от Творца", "ksd_meta": "“практикующий торговлю добродетелями”"}, {"roman": "bhandar", "literal": "(Lit) коллекция,наполненность", "ksd_meta": "становление"}, {"roman": "amul", "literal": "бесценное", "ksd_meta": "то, что не может иметь ценности (слишком ценное)"}, {"roman": "aveh", "literal": "(Lit)  приход (чего-то)", "ksd_meta": "достижение"}, {"roman": "ley", "literal": "в ритме, ритмично, регулярно", "ksd_meta": ""}, {"roman": "jahe", "literal": "(Lit) идти", "ksd_meta": "последствие, результат (идущий вслед…)"}, {"roman": "amul", "literal": "бесценное", "ksd_meta": "то, что не может иметь ценности (слишком ценное)"}, {"roman": "bhaye", "literal": "любовь", "ksd_meta": ""}, {"roman": "smahe", "literal": "наполнение", "ksd_meta": ""}, {"roman": "amul", "literal": "бесценное", "ksd_meta": "то, что не может иметь ценности (слишком ценное)"}, {"roman": "dharam", "literal": "(Lit) правила и законы (органические)", "ksd_meta": "Хукам"}, {"roman": "diban", "literal": "(Lit) суд, суждения (как в суде, судебные решения)", "ksd_meta": ""}, {"roman": "amul", "literal": "бесценное", "ksd_meta": "то, что не может иметь ценности (слишком ценное)"}, {"roman": "tul", "literal": "(Lit) тула, весы для взвешивания", "ksd_meta": "такари на панджаби"}, {"roman": "parvann", "literal": "(Lit) весовой камень, который мы опускаем на одну сторону весов (а то, что должен быть взвешено, опускается на другую сторону)", "ksd_meta": ""}, {"roman": "tul & parvann", "literal": "идиоматический оборот про вынесение суждений", "ksd_meta": ""}]','Для достижения вершин духовности - бесценны божественные добродетели и бесценна их практика (реализация их в миру). | Бесценны практикующие Божественные Добродетели и бесценно наполнение себя ими (добродетелями). | Бесценно обретение божественных добродетелей  и бесценна полученная регулярность (моей духовности). | Бесценна любовь к божественным добродетелям и бесценно наполнение (себя - ими) | Бесценны решения, принятые в соответствии с бесценным Хукамом. | Бесценен ум (манас - чувствилище) и бесценен интеллект, который пребывает в Хукаме | Бесценны Его благословения, дарованные под его бесценным авторитетом. | Бесценны Его благословения, дарованные Его бесценным Хукамом. | Благословения Творца бесценны и за пределами описаний | Единственное достойное повествование о бесценных благах — это проникнуться божественными добродетелями. | Пропитанный благодатью Творца, я способен оценить содержание духовных текстов (описывающих благодать) | Проникнувшись благословением Творца, я оцениваю повествование тех, кто читает и обсуждает эти тексты (на предмет ценности) | Проникнувшись благословениями Ооангкара, я оцениваю повествование текстов, относящихся к Брахме и Индре (на предмет ценности) | Наполненный благословениями Творца, я оцениваю повествование текстов, относящихся к гопи и их кормильцу. | Проникнувшись благословениями Творца, я оцениваю повествование текстов, касающихся сидхов и их лидера | Проникнувшись благословениями Ооангкара, я оцениваю содержание текстов, относящихся к множеству рожденных духовных озарений (которые описывают или обсуждают люди) | Проникнувшись благословениями Творца, я оцениваю повествование текстов о добре и зле | Проникнувшись благословением Творца, я оцениваю повествование текстов о духовных людях, их лидерах и последователях. | Проникнувшись благословениями Ооангкара, я оцениваю повествование текстов, относящихся к бесчисленному множеству тех, кто обрёл достойную способность повествования (тех, кто понял, что способ описать - это реализова','','[1, 2, 3, 4, 5, 6, 7, 8]','jbani_v2_blocks');
INSERT INTO "ksd_examples" VALUES(37,1,29,'','Bhugat Gyan Dya Bhandaran Ghat Ghat Vajey Nad II | Aap Nath Nathi Sabh Ja Ke Ridh Sidh Avra Saad II | Sanjog Vijog Doey Kar Chalaveh Lekhey Avey Bhag II | Adeys Tisey Adeys II Aad Anil Anad Anahat Jug Jug Eko Veis II 29 II | Eka Mayi Jugt Viayi Tin Chayley Parvann II | Ek Sansari Ek Bhandari Ek Laye Dibann II | Jiv Tis Bhavey Tivei Chalavey Jiv Hovei Furmann II | Oh Vekhei Una Nadar Na Avei Bhauta Eh Vidann II','','[{"roman": "bhugat", "literal": "from Bhogna- наслаждаться, наслаждение", "ksd_meta": ""}, {"roman": "gyan", "literal": "просветлённое знание", "ksd_meta": ""}, {"roman": "dya", "literal": "сострадание", "ksd_meta": ""}, {"roman": "bhandaran", "literal": "(from Bhandar- сокровищница, торговая лавка) (Lit) владелец", "ksd_meta": "носитель"}, {"roman": "ghat ghat", "literal": "внутри “внутреннего”", "ksd_meta": ""}, {"roman": "vajey", "literal": "(Lit) играть на инструменте", "ksd_meta": "резонировать"}, {"roman": "nad", "literal": "(Lit) звучать, духовная команда", "ksd_meta": ""}, {"roman": "aap", "literal": "Относится к нашему “я”", "ksd_meta": ""}, {"roman": "nath", "literal": "Мастер (учитель), Владыка, Ооангкар", "ksd_meta": ""}, {"roman": "nathi", "literal": "в пределах потока “повеления”, команды", "ksd_meta": ""}, {"roman": "sabh ja ke", "literal": "все, кого …", "ksd_meta": "кем …"}, {"roman": "ridh sidh", "literal": "(Lit) магические занятия", "ksd_meta": "анти-хукам практики"}, {"roman": "avra", "literal": "нечто иное", "ksd_meta": "отклоняющиеся, девиантные"}, {"roman": "saad", "literal": "1.  Эссенция, сущность (божественные добродетели должны быть реализованы в уме и в совести", "ksd_meta": "люди, не следующие духовности шабда, не смогут осознать этого принципа) SGGS 644 2. Принцип и его философия, манмукскхая садхана SGGS 1058 & 116 3. Удовлетворенность SGGS 474 4) Разрушение на санскрите"}, {"roman": "sggs 474", "literal": "https://khojgurbani.org/shabad/474/1214 читая постоянно и постоянно одно и то же, многие не в состоянии осознать то, что написано", "ksd_meta": "но удовольствие от Гуру не было получено."}, {"roman": "sanjog", "literal": "союз, присоединение, слияние", "ksd_meta": "реализация Ооангкара"}, {"roman": "vijog", "literal": "разделение", "ksd_meta": ""}, {"roman": "doey", "literal": "оба", "ksd_meta": ""}, {"roman": "kar chalaveh", "literal": "вести дела, определять (вести дела - либо в союзе, либо в разделённости)", "ksd_meta": ""}, {"roman": "lekhey avey", "literal": "писания, принадлежащие … (кому-либо)", "ksd_meta": ""}]','Мой разум наслаждается просветлением; мой разум стал носителем сострадания и резонирует (как музыкальный инструмент) с повелением Ооангкара [внутри самого “внутреннего” во мне]. | Внутреннее просветление состоит в том, что Он Сам является хозяином положения, а анти-хукамные занятия ума являются девиантными и разрушительными. | Просветление внутри состоит в том, что мысли, ведущие к соединению и разделению с Ооангкаром - определяют написание моей духовной судьбы. | Я подчиняюсь в знак почтения только - Единому, Неизменному, Вечному и Безупречному (незапятнанному) Ооангкару, который проявляется голосом моей совести внутри II29II | Духовность просветления создаёт приемлемые для неё результаты в моём едином разуме. | Один результат в моем уме относится к миру добродетелей, другой к самому владельцу добродетелей (Ооангкару), и один присутствует в суждении о пороке и добродетели. | Просветленный разум ведет себя согласно команде своего суждения о пороке и добродетели. | Мой разум оценивает: в Благодати Просветления пороки перестают существовать, поэтому такого величия сей акт (Милости) | Я подчиняюсь в знак почтения только - Единому, Неизменному, Вечному и Безупречному (незапятнанному) Ооангкару, который проявляется голосом моей совести внутриII30II','','[1, 2, 3, 4, 5, 6, 7, 8]','jbani_v2_blocks');
INSERT INTO "ksd_examples" VALUES(38,1,31,'','Asan Loey Loey Bhandar II | Jo Kich Paya So Eka Var II | Kar Kar Veykhei Sirjanhaar II | Nanak Sachay Ki Sachi Kar II | Kar- deed','','[{"roman": "asan", "literal": "Трон,", "ksd_meta": ""}, {"roman": "loey loey", "literal": "просветлённые (мысли)", "ksd_meta": ""}, {"roman": "bhandar", "literal": "Сокровище, коллекция", "ksd_meta": ""}, {"roman": "jo kich", "literal": "всё это, целиком", "ksd_meta": ""}, {"roman": "paya", "literal": "достигнуто, получено (на мой “тронный” разум)", "ksd_meta": ""}, {"roman": "so", "literal": "местоимение для Jo Kich", "ksd_meta": ""}, {"roman": "eka var", "literal": "одно полное представление", "ksd_meta": ""}, {"roman": "kar kar", "literal": "через такое “делание”, через такие действия, в акте какого-либо действия", "ksd_meta": ""}, {"roman": "veykhei", "literal": "(Lit) видеть, оценивать, реализовывать", "ksd_meta": ""}, {"roman": "sirjanhaar", "literal": "Создатель", "ksd_meta": ""}, {"roman": "sachay ki", "literal": "относящийся к Создателю", "ksd_meta": ""}, {"roman": "sachi", "literal": "Связанный с Создателем, к Создателю, принадлежащий Создателю", "ksd_meta": ""}, {"roman": "kar", "literal": "deed", "ksd_meta": ""}]','Сокровища божественных добродетелей царят в моём просветлённом разуме. | Всё сокровище божественных добродетелей воцарилось в моем уме в качестве результата одного полного подчинения (разума). | Посредством (акта) такого подчинения, Создатель реализуется внутри | Нанак, мой акт подчинения относится к Творцу, и непосредственно связан с самим Творцом.','','[1, 2, 3, 4, 5, 6, 7, 8]','jbani_v2_blocks');
INSERT INTO "ksd_examples" VALUES(39,1,32,'','Ek Du Jebhau Lakh Hohe Lakh Hovey Lakh Vees II | Lakh Lakh Gera Aakhyeah Ekh Naam Jugdees II | Eyt Rah Putt Pavreeah Chareeah Hoye Ekees II | Sun Gallan Akaas Kee Keeta Aiyee Rees II | Nanak Nadree Payeah Kooree Korey Thees II 32 II','','[{"roman": "ek", "literal": "один", "ksd_meta": ""}, {"roman": "du", "literal": "из (из одного)", "ksd_meta": ""}, {"roman": "jebhau", "literal": "Язык", "ksd_meta": ""}, {"roman": "lakh hohe", "literal": "Станет Лакхом", "ksd_meta": ""}, {"roman": "lakh hovey", "literal": "Возьмёт своё происхождение из Лакха, из одного лакха станет…", "ksd_meta": ""}, {"roman": "lakh vees", "literal": "Двадцать Лакхов", "ksd_meta": ""}, {"roman": "lakh lakh", "literal": "Лакх раз", "ksd_meta": ""}, {"roman": "gera", "literal": "цикличный, повторный (что имеет циклическую природу)", "ksd_meta": ""}, {"roman": "aakhyeah", "literal": "говорить, произносить", "ksd_meta": "чантить"}, {"roman": "ek (w/aungkar)", "literal": "Один единственный", "ksd_meta": ""}, {"roman": "naam (w/aungkar)", "literal": "именительное существительное для Jagdees, Имя", "ksd_meta": ""}, {"roman": "jugdees", "literal": "Создатель", "ksd_meta": ""}, {"roman": "eyt", "literal": "конкретный (the)", "ksd_meta": ""}, {"roman": "rah", "literal": "путь", "ksd_meta": ""}, {"roman": "putt", "literal": "от Pati", "ksd_meta": "Lit Муж, Лорд, Мастер; Создатель"}, {"roman": "pavreeah", "literal": "(Lit) лестница, ступени, перекладина (как паури)", "ksd_meta": ""}, {"roman": "chareeah", "literal": "(Lit) подняться (по лестнице)", "ksd_meta": ""}, {"roman": "hoye", "literal": "стать", "ksd_meta": ""}, {"roman": "ekees", "literal": "один, союз, реализовать  (в словаре Гурбани)", "ksd_meta": ""}, {"roman": "sun", "literal": "слышать", "ksd_meta": ""}]','Если чей-то язык станет одним лакхом (в длине), из одного лакха этот лакх превратится в двадцать лакхов… | …и если этими 20 лакхами языков повторять одно и то же (предпочтительное) имя Бога лакх раз… | Чтобы стать Единым с Творцом (осознать его) нужно поднимать свою совесть (духовность) ступень за ступенью. | Услышав рассказ о возвышенной совести (духовности), низкоуровневая духовность начинает подражать ей. | Нанак, осознание Творца внтури себя происходит через милость просветления, имитируемые пути фальшивых людей лишены Реализации II32II','','[1, 2, 3, 4, 5, 6, 7, 8]','jbani_v2_blocks');
INSERT INTO "ksd_examples" VALUES(40,1,33,'','Akhunn Jor Chupey Neh Jor II | Jor Na Mangann Denn Na Jor II | Jor Na Raj Mal Mun Sor II | Jor Na Surtee Gyan Vichar II | Jor Na Jugtee Chutey Sansar II | Jis Hath Jor Kar Veykhey Soey II | Nanak Utam Nich Na Koey II 33 II | Pauree 34- Dharam Khand','','[{"roman": "akhunn", "literal": "высказывания, поговорки", "ksd_meta": ""}, {"roman": "jor", "literal": "вынужденные обстоятельства, обязательные действия, обязательные дела, форсированные действия", "ksd_meta": ""}, {"roman": "chupey", "literal": "тишина", "ksd_meta": ""}, {"roman": "neh", "literal": "отрицание, “ни”", "ksd_meta": ""}, {"roman": "jor", "literal": "вынужденные обстоятельства, обязательные действия, обязательные дела, форсированные действия", "ksd_meta": ""}, {"roman": "neh", "literal": "отрицание, “ни”", "ksd_meta": ""}, {"roman": "mangann", "literal": "просьбы, требования, молитвы", "ksd_meta": ""}, {"roman": "denn", "literal": "Предложения", "ksd_meta": ""}, {"roman": "jivann", "literal": "Жизнь", "ksd_meta": ""}, {"roman": "marann", "literal": "Смерть", "ksd_meta": ""}, {"roman": "raj", "literal": "Сила, авторитет", "ksd_meta": ""}, {"roman": "mal", "literal": "материальное", "ksd_meta": ""}, {"roman": "mun", "literal": "ум, фокус", "ksd_meta": ""}, {"roman": "sor", "literal": "шум, претензии, требования (в связке с mal)", "ksd_meta": ""}, {"roman": "surtee", "literal": "Созерцание", "ksd_meta": "фокус"}, {"roman": "gyan", "literal": "знание", "ksd_meta": ""}, {"roman": "vichar", "literal": "дискурс", "ksd_meta": ""}, {"roman": "jugtee", "literal": "метод, техника", "ksd_meta": ""}, {"roman": "chutey", "literal": "свободный от, освобождать", "ksd_meta": ""}, {"roman": "sansar", "literal": "(Lit) мир", "ksd_meta": "временной"}]','Милость Творца не реализуется через форсированные (вынужденные / принудительные) акты произношения (мантр, чантинга) или молчания | Милость Творца не реализуется через форсированные (регламентированные) акты подношений или просьб (молитвы как просьбы) | Милость Творца не реализуется через регламентированные акты, относящиеся к жизни и смерти. | Милость Творца реализуется не через форсированные властные поступки, материально ориентированные (или целенаправленно ориентированные, когда ум в молитве/ритуале глубоко сосредоточен на цели) требования | Милость Творца не реализуется посредством форсированных действий созерцания, сосредоточения, познания или дискурса | Милость Творца не реализуется посредством форсированных действий или техник, связанных с отречением от временного (мирского) | Те, кто использует форсированные действия для получения Милости Творца, оценили их. | Нанак, оценка (наблюдение) заключается в том, что беря контроль на себя, или совершая форсированное (принудительное) действие - такое действие не делает человека достойным или недостойным Милости Творца II33II','','[1, 2, 3, 4, 5, 6, 7, 8]','jbani_v2_blocks');
INSERT INTO "ksd_examples" VALUES(41,1,37,'','Pauree 37- Karm Khand & Sach Khand | Khand- Realms/Phases of Spirituality/ Stages of Realization | Experiential Paurees of Guru Nanak of his spiritual journey | Ratee Rutee Thitee Vaar II | Pavann Panni Agni Patal II | Tis Vich Dharti Thaap Rakhee Dharam Saal II | Tis Vich Jee Jugat Kay Rang II | Tin Kay Naam Aneyk Anunt II','','[{"roman": "pauree 37", "literal": "Karm Khand & Sach Khand", "ksd_meta": ""}, {"roman": "khand", "literal": "Realms/Phases of Spirituality/ Stages of Realization", "ksd_meta": ""}, {"roman": "ratee", "literal": "Raat da ho jana, Ruttan da gerhd- циклическое течение дня, переходящее в ночь", "ksd_meta": ""}, {"roman": "rutee", "literal": "циклическое возникновение сезонов (зима, весна, лето, осень)", "ksd_meta": ""}, {"roman": "thitee", "literal": "циклическое появление периодов времени", "ksd_meta": ""}, {"roman": "var", "literal": "циклическое появление дня за днём", "ksd_meta": ""}, {"roman": "pavann", "literal": "воздух", "ksd_meta": ""}, {"roman": "panni", "literal": "вода", "ksd_meta": ""}, {"roman": "agni", "literal": "огонь", "ksd_meta": ""}, {"roman": "patal", "literal": "небеса, космос", "ksd_meta": ""}, {"roman": "tis vich", "literal": "внутри которого", "ksd_meta": ""}, {"roman": "dhartee", "literal": "земля", "ksd_meta": ""}, {"roman": "thap", "literal": "установить, создать", "ksd_meta": ""}, {"roman": "rakhi", "literal": "сохраняется в существовании, поддерживать в существовании", "ksd_meta": ""}, {"roman": "dharam", "literal": "1. правило, регулирование, порядок 2. духовность, дхарам", "ksd_meta": ""}, {"roman": "saal", "literal": "место, обитель, воплощение (paat saal - место, где дают образование)", "ksd_meta": ""}, {"roman": "dharam saal", "literal": "Разум и Совесть как обитель духовности", "ksd_meta": ""}, {"roman": "tis vich", "literal": "внутри которого", "ksd_meta": ""}, {"roman": "jee", "literal": "жизнь", "ksd_meta": "духовная жизнь"}, {"roman": "jugat", "literal": "метод, техника, манера, способ", "ksd_meta": ""}]','В пределах Хукама, относящегося к природе и творению… | …и Хукама, относящегося к элементам моего физического “я”... | (В пределах такого Хукама) Моё физическое “я” создано и поддерживается в существовании; также как поддерживается мой разум и совесть (Дхарам Сал) - в качестве воплощения духовности… | …воплощение духовности, в пределах которого -  разум и совесть моей духовной жизни (естественно) пронизаны (духовным) Путём (истинным методом)… | …Путём (Истинным Методом), насыщенным безграничными божественными добродетелями. | Путём (Истинным Методом), в котором мои дела оцениваются по (пробному камню) Милости Творца Карми - в двух разных значениях и контекстах. Одно - к деяниям, другое - к благодати. Вичар моих поступков - это когда нужно постоянно осознавать, мои поступки совершаются с целью получения милости Творца или нет. Это оценка в моём уме и совести, которые мне нужно делать на пути духовного путешествия. | Это происходит потому что сам Создатель царит в моей Совести | Где (в моей Совести) мои пять чувств принимают духовное великолепие. | Благодаря Его Милости мои дела становятся ориентированными на достижение моей духовной цели. | Моя не осознающая Творца совесть (таким образом) становится Реализующей Творца в рамках этой цели. | Нанак, я осознал Творца пройдя этот путь II34II','','[1, 2, 3, 4, 5, 6, 7, 8]','jbani_v2_blocks');
INSERT INTO "ksd_examples" VALUES(42,1,35,'','Dharam Khand Ka Eho Dharam II | Gyan Khand Ka Akho Karam II | Kaytey Pavann Panni Vaisantar Keytey Kahn Mahesh II | Kaytay Bharmey Gharrat Gharreay Roop Rang Kay Ves II | Keytia Karam Bhumi Mer Kaytay, Kaytay Dhu Updes II | Kaytay Ind Chand Soor Kaytay, Kaytay Mandal Des II | Kaytay Sidh Budh Nath Kaytay, Kaytay Devi Ves II | Kaytay Dev Danav Mun Kaytay, Kaytay Ratun Smund II','','[{"roman": "dharam", "literal": "1. Правило, регуляция, закон 2. духовность", "ksd_meta": ""}, {"roman": "khand", "literal": "сфера", "ksd_meta": ""}, {"roman": "ka", "literal": "принадлежащий чему-либо, являющийся чем-либо", "ksd_meta": ""}, {"roman": "eho", "literal": "этот, тогда, (то, что выше)", "ksd_meta": ""}, {"roman": "dharam khand", "literal": "Первая сфера Милости - Хукам (Дхарам)", "ksd_meta": ""}, {"roman": "gyan", "literal": "просветление", "ksd_meta": ""}, {"roman": "khand", "literal": "сфера", "ksd_meta": ""}, {"roman": "ka", "literal": "принадлежащий к, этот", "ksd_meta": ""}, {"roman": "akho", "literal": "повествовать, рассказывать", "ksd_meta": ""}, {"roman": "karam", "literal": "1. Поступки 2. Милость", "ksd_meta": ""}, {"roman": "keytey", "literal": "множество", "ksd_meta": ""}, {"roman": "pavann", "literal": "воздух", "ksd_meta": ""}, {"roman": "panni", "literal": "вода", "ksd_meta": ""}, {"roman": "vaisantar", "literal": "огонь", "ksd_meta": ""}, {"roman": "pavan pani vaisantar", "literal": "поэтический оборот для описания первоэлементов в творении", "ksd_meta": ""}, {"roman": "kahn", "literal": "Krishen, Кришна (?)", "ksd_meta": ""}, {"roman": "mahesh", "literal": "Шива, Шив джи", "ksd_meta": ""}, {"roman": "kahn mahesh", "literal": "поэтический оборот для выражения восприятий Творца", "ksd_meta": ""}, {"roman": "kaytay", "literal": "множество", "ksd_meta": ""}, {"roman": "bharmey", "literal": "создатели, производители, породители", "ksd_meta": ""}]','Вышесказанное является Хукамом (Законом, Дхарамом) первой сферы духовности. | Это повествование о (втором) царстве Милости - сфере Просветления (Знания) | В этом просветлении (знании) есть осознание того, что существовало множество точек зрения, поскольку в творении было множество элементов, аспектов. | И осознание того, что это множество точек зрения на эти аспекты и элементы -  было создано в разных формах, обликах, проявлениях. | И осознание того, что существовало множество ведущих утверждений, основанных на множестве низких и возвышенных поступках. | Внутри которых Просветление - это осознание существования множества могущественных и менее могущественных богов на множестве уровней просветленности и непросветленности. | И осознание того, что существовало множество искателей, множества методов и мыслей воплощенных во множестве священных мировоззрений. | И осознание того, что существовало множество мудрецов, ученых и дэвов, подобных множеству драгоценных камней в океанах. | Внутри такого рода просветления - есть осознание того, что существовало множество повествований, содержащихся во множестве источников во множестве иерархий (источники высшего порядка, низшего порядка). | Нанак, все эти множества философий и множество последователей не являются ни окончательными (будут возникать ещё и ещё), ни приводящими к финальному результату (сами собой) II35II','','[1, 2, 3, 4, 5, 6, 7, 8]','jbani_v2_blocks');
INSERT INTO "ksd_examples" VALUES(43,1,36,'','Gyan Khund Meh Gyan Parchand II | Tithey Nad Binod Kodd Anand II | Sarm Khand Ki Bani Roop II | Tithey Gharrat Gharreay Bahut Anup II | Ta Kiya Glla Kathiya Na Jahe | Jay Ko Khey Pichay Pachtaye','','[{"roman": "gyan", "literal": "Просветление", "ksd_meta": ""}, {"roman": "khund", "literal": "Царство, сфера", "ksd_meta": ""}, {"roman": "meh", "literal": "Внутри Просветления", "ksd_meta": "Реализация"}, {"roman": "parchand", "literal": "первостепенный, переопределяющий, жизненно важный", "ksd_meta": "верховный"}, {"roman": "tithey", "literal": "там где, где", "ksd_meta": ""}, {"roman": "nad", "literal": "звук, история, повествование", "ksd_meta": ""}, {"roman": "binod", "literal": "шоу , зрелище", "ksd_meta": ""}, {"roman": "kodd", "literal": "from kautak, чудо, представлени", "ksd_meta": ""}, {"roman": "anand", "literal": "удовольствия", "ksd_meta": ""}, {"roman": "sarm", "literal": "mehnat, mushakat, ghalna, - усердие, стремление, усилие", "ksd_meta": ""}, {"roman": "khand", "literal": "сфера", "ksd_meta": ""}, {"roman": "bani", "literal": "(Lit) речь", "ksd_meta": "повествование"}, {"roman": "roop", "literal": "1. Форма (которую можно воспринять зрительно) 2. Красота", "ksd_meta": ""}, {"roman": "tithey", "literal": "внутри которого", "ksd_meta": ""}, {"roman": "gharrat", "literal": "существилеьное - резьба, скульптура", "ksd_meta": ""}, {"roman": "gharreay", "literal": "глагол - предавать форму", "ksd_meta": "осуществлять резьбу, скульптурировать"}, {"roman": "bahut", "literal": "1. множества. 2 чень, очень сильно", "ksd_meta": ""}, {"roman": "anup", "literal": "экстраординарный, заметный, чудесный", "ksd_meta": ""}, {"roman": "ta kiya", "literal": "принадлежащий этому", "ksd_meta": ""}, {"roman": "glla", "literal": "говорить", "ksd_meta": "повествовать"}]','Царство Просветления (Знания) - это то, в котором Реализация является Высшей Ценностью. | Внутри которой высшая ценность - заключается в осознании того, что во множестве философий и последователей этой философии - радость заточена (только) в их повествованиях, зрелищах, выступления (это маскарад, шоу, иллюзия) | Рассказ о (третьей) сфере, а именно о духовном усердии - есть красота ума и совести. | Внутри такого Усердия Ум и Совесть превращаются в чудесную скульптуру. | Повествование об этом чуде находится за пределами описаний. | любая попытка описать это чудо была бы неадекватной при полном её анализе. | В этой сфере духовного усердия (весь) разум и (вся) совесть превращаются в экстраординарное чудо. | В таком скульптурировании Разум и Совесть должны быть направлены на чистую Божественность.','','[1, 2, 3, 4, 5, 6, 7, 8]','jbani_v2_blocks');
INSERT INTO "ksd_examples" VALUES(44,1,38,'','Jut Pahara Dhiraj Suniyar II | Ehrunn Mut Ved Hathiar II | Bhou Khala Agun Tup Tao II | Bhanda Bhao Amrit Tit Dhaal II | Ghareay Shabad Sachi Taksal II | Jin Kao Nadar Karm Tin Kar II | Nanak Nadri Nadar Nihal II 38 II | Pavann Guru Panni Pita Mata Dharat Mahut II','','[{"roman": "jut", "literal": "(Lit) мораль", "ksd_meta": "контроль над своими чувствами - согласно философии Нанака"}, {"roman": "pahara", "literal": "(Lit) рабочее место кузнеца по золоту/железу (место для изготовления ювелирных изделий)", "ksd_meta": "жизнь как рабочее место для духовности"}, {"roman": "dhiraj", "literal": "терпение, баланс, снисходительность, непоколебимость (контроль ума - совестью, это не такого рода контроль, который одно время есть, а в другое его нет)", "ksd_meta": ""}, {"roman": "suniyar", "literal": "(Lit) ювелир как мастер/создатель/источник своих творений", "ksd_meta": "источник/происхождение нашей духовностиЗдесь нам важно понять:"}, {"roman": "ehrunn", "literal": "(Lit) наковальня, опора, основание (место, где драгоценностям, изделиям, придаётся форма)", "ksd_meta": ""}, {"roman": "mut", "literal": "разум", "ksd_meta": ""}, {"roman": "ved (w/aungkar)", "literal": "единственное число - знание, просветление (если в ед. числе)", "ksd_meta": ""}, {"roman": "hathiar", "literal": "(Lit) молот", "ksd_meta": "инструмент для придания формы / отливать форму"}, {"roman": "bhou", "literal": "(Lit) страх", "ksd_meta": "благоговение - в духовном смысле Нанака, т.к. в духовности Нанака нет страха. Это Nirmal Bhou Paya Har Gun Gaya - духовность достижения добродетелей основана только, если она связана с чем-то вроде “страха мирского”;"}, {"roman": "khala", "literal": "(Lit) ревёт, раздувая огонь", "ksd_meta": "обмахивать, чтобы раздувать."}, {"roman": "agun", "literal": "(Lit) огонь", "ksd_meta": "интенсивность"}, {"roman": "tup tao", "literal": "(Lit) тает от жара", "ksd_meta": "трудиться с мощными усердиями; усердно трудиться"}, {"roman": "bhanda", "literal": "(Lit) вместилище", "ksd_meta": "разум (Bhanda Dohe - wash the container; cleansing mind)"}, {"roman": "bhao", "literal": "любовь, обожествлённость, преданность", "ksd_meta": ""}, {"roman": "amrit", "literal": "A + Mrit- (Lit) вечный, божественный, неумирающий", "ksd_meta": ""}, {"roman": "tit", "literal": "внутри этого", "ksd_meta": ""}, {"roman": "dhaal", "literal": "форма/огранка для становления", "ksd_meta": ""}, {"roman": "ghareay", "literal": "скульптура", "ksd_meta": ""}, {"roman": "sachi", "literal": "корень Sach (Создатель)", "ksd_meta": "принадлежащий Создателю"}, {"roman": "sachi taksal", "literal": "двор для  чеканки, плавки, скульптурирования", "ksd_meta": "двор Создателя; Совесть"}]','Постоянный контроль над моими (пятью) чувствами - источник моей духовной жизни | Этот устойчивый контроль над моими чувствами осуществляется моим разумом, сформированным и основанным Просветлением. | Просветление разгорается благодаря усердным трудам к почитанию Творца внутри. | Этот труд, благоговение и преданность сформировали мой разум, чтобы он стал божественным (добродетельным) | Шабд скульптурируется в моей Совести. | В результате такого скульптурирования, Создатель наградил меня своими благословениямиЗдесь идёт речь о том, чтобы мы - стали Шабдом. | Нанак, высшей радостью являются благословения Милостью Творца II38II | (Гуру) Шабд есть источник, учитель, и поддерживатель моей духовной жизни | (Гуру) Шабд является руководством для моей духовности с самого её начала, во все её времена и на всём её протяжении. | Руководство (Гуру) Шабда состоит в том, что хорошие и плохие мои дела на пути духовности должны оцениваться по пробному камню Его Хукама. | Мои собственные поступки определяют, Реализую ли я Творца внутри себя, или нет - приближаюсь к нему, или отдаляюсь. | Те, кто усердно и упорно стремится стать божественными добродетелями… | Они, о Нанак, осознающие Творца внутри (в своем духовном путешествии, преодолевая недуг Кура), становятся сияющими и освобождаются (выражая Божественные Добродетели) II1II','','[1, 2, 3, 4, 5, 6, 7, 8]','jbani_v2_blocks');
INSERT INTO "ksd_examples" VALUES(45,1,1001,'ਕਰਿ ਕਰਿ ਥਾਕੀ ਮੀਤ ਘਨੇਰੇ ॥','kar kar thākī mīt ghanērē','','[]','"Я устал заводить дружбу с многими". "Многие друзья" становятся "ворами" любви к Одному Другу, питающему сердца всего. От чего, вследствие этого, дружбы со многими тоже рушатся. Манмукх имеет сложности в том, чтобы остановиться и отвязаться от них, от двойственности. Такая привязанность к своим отражениям ума – есть Хоумэ, самососредоточенность и привязанность к собственным умопостроениям. Через такой Гурмат Вичар (самоисследование), Сикх перекраивает свою картину мира, психологию, взаимодействие с обыденным и духовным миром. Когда язык произносит бани и ум сосредоточён, то на таком языке возникает вкус бани, а в уме - понимание бани. При чтении можно давать себе наставление, что моменты чтения - это то, что моему Уму и чувствам говорит Гуру, через мой язык и мой ум. Это не "я" читаю. А Гуру учит меня. Для человека, который не является носителем языка панджаби, хорошей является следующая практика. Поскольку ввиду языка, запомнить бани на все случаи жизни - сложно и избыточного, то имеет смысл знать немного, но очень плотно. Усмирять жажду узнавать всё новые и новые бани, а скорее идти в глубину уже известных бани. Наделять их переживающим смыслом, оживлять слова внутри. Сделать так, чтобы Нирбхау, Нирвэир - стали не просто словами летящими мимо в форточку, или формальной прелюдией, а строительным фундаментом собственного мышления, эмоций, реакций, "муул" – корнем. Сач Нао Вадиа','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_example');
INSERT INTO "ksd_examples" VALUES(46,1,1002,'ਗੁਹਜ ਰਤਨ ਵਿਚਿ ਲੁਕਿ ਰਹੇ ਕੋਈ ਗੁਰਮੁਖਿ ਸੇਵਕੁ ਕਢੈ ਖੋਤਿ ॥','guhaj ratan vich luk rahē kōī guramukh sēvak kadhai khōt .','','[]','Редок тот, последователь посланий Гуру, кто может погрузиться внутрь [в свою Совесть / Сознание], и найти там послание Гуру. SGGS 309.','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_example');
INSERT INTO "ksd_examples" VALUES(47,1,1003,'ਅੰਮ੍ਰਿਤ ਬਾਣੀ ਗੁਰ ਕੀ ਮੀਠੀ ॥','Anmrith Baanee Gur Kee Meethee','','[]','Амрит Бани от Гуру - Очень Очень Сладок','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_example');
INSERT INTO "ksd_examples" VALUES(48,1,1004,'ਗੁਰਮੁਖਿ ਵਿਰਲੈ ਕਿਨੈ ਚਖਿ ਡੀਠੀ ॥','Guramukh Viralai Kinai Chakh Ddeethee','','[]','Редок тот Гурмукх, который видит [Амрит Бани] и ощущает его вкус. SGGS 113 Документ подготовил Ilia Potseluev . Контактные данные: asitanath.singh@gmail.com Ресурсы: https://t.me/sikh_panth_ru https://vk.com/sikh_panth','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_example');
INSERT INTO "ksd_examples" VALUES(49,1,1,'ੴਸਤਿ ਨਾਮੁ ਕਰਤਾ ਪੁਰਖੁ ਨਿਰਭਉ ਨਿਰਵੈਰੁ ਅਕਾਲ ਮੂਰਤਿ ਅਜੂਨੀ ਸੈਭੰ ਗੁਰ ਪ੍ਰਸਾਦਿ ॥','Ik Ooangkaar Sat Naam Karataa Purakh Nirabhau Niravair Akaal Muurat Ajuunii Saibhan Gur Prasaad .','','[{"roman": "Ik Ooangkaar Sat Naam Karataa Purakh Nirabhau Niravair Akaal Muurat Ajuunii Saibhan Gur Prasaad .", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Единый Создатель, пребывающий в Единстве со своим Творением (Ik Ooangkar)Имя Его — Присутствующий в Бытии(Sat Naam)Творец, переживающий Творение Изнутри Себя(Karta Purakh)Вне страха – нет для Него второго, кого можно бояться (Nirbhau)Вне враждебности – нет для Него второго, кому противостоять(Nirvair)За пределами Времени Его образ(Akaal Murat)Не рождающийся, за пределами форм(Ajuuni)Создающий себя – сам из Себя (Saibhan) Являющий себя как Обучающее Начало – Шабд-Гуру(Gur Prasaad)','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(50,1,2,'॥ ਜਪੁ ॥','Jap .','','[{"roman": "Jap .", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Джап.(Активируй процессы бани в Себе – осознав прочитанное)','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(51,1,3,'ਆਦਿ ਸਚੁ ਜੁਗਾਦਿ ਸਚੁ ॥','Aad Sach Jugaad Sach','','[{"roman": "Aad Sach Jugaad Sach", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Настоящий Создатель во мне с момента моего появленияНастоящий Создатель был со мной во всех моих временах','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(52,1,4,'ਹੈ ਭੀ ਸਚੁ ਨਾਨਕ ਹੋਸੀ ਭੀ ਸਚੁ ॥੧॥','Hai Bhii Sach Naanak Hoosii Bhii sach .1.','','[{"roman": "Hai Bhii Sach Naanak Hoosii Bhii sach .1.", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Настоящий Создатель со мной прямо сейчас. Настоящий Создатель пребудет со мной на протяжении всего моего существования','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(53,1,5,'ਸੋਚੈ ਸੋਚਿ ਨ ਹੋਵਈ ਜੇ ਸੋਚੀ ਲਖ ਵਾਰ ॥','Sochey Soch Na Hovayee Jey Sochee Lakh Vaar II','','[{"roman": "Sochey Soch Na Hovayee Jey Sochee Lakh Vaar II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Ритуальными очищениями и омовениями не очиститься (внутренне), даже делая это сто тысяч раз','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(54,1,6,'ਚੁਪੈ ਚੁਪ ਨ ਹੋਵਈ ਜੇ ਲਾਇ ਰਹਾ ਲਿਵ ਤਾਰ ॥','Chupey Chup Na Hovayee Jey Laye Rhaan Liv Taar II','','[{"roman": "Chupey Chup Na Hovayee Jey Laye Rhaan Liv Taar II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Практиками безмолвия с упорной концентрацией ума - не прийти к тишине','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(55,1,7,'ਭੁਖਿਆ ਭੁਖ ਨ ਉਤਰੀ ਜੇ ਬੰਨਾ ਪੁਰੀਆ ਭਾਰ ॥','Bhukiya Bhukh Na Utree Jey Banna Pureeah Bhaar II','','[{"roman": "Bhukiya Bhukh Na Utree Jey Banna Pureeah Bhaar II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Если подавить или исполнить все желания - прошлые, настоящие, и будущие, они не прекратят появляться.','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(56,1,8,'ਸਹਸ ਸਿਆਣਪਾ ਲਖ ਹੋਹਿ ਤ ਇਕ ਨ ਚਲੈ ਨਾਲਿ ॥','Sehes Sianpa Lakh Hohe Ta Ek Na Chale Naal II','','[{"roman": "Sehes Sianpa Lakh Hohe Ta Ek Na Chale Naal II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Сотни духовных знаний — и ни одно не идёт вместе со мной.','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(57,1,9,'ਕਿਵ ਸਚਿਆਰਾ ਹੋਈਐ ਕਿਵ ਕੂੜੈ ਤੁਟੈ ਪਾਲਿ ॥','Kiv Sachiara Hoyey Kiv Kooray Tootey Paal II','','[{"roman": "Kiv Sachiara Hoyey Kiv Kooray Tootey Paal II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Как стать Настоящим? Как разрушить стену фальши (внутри)?','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(58,1,10,'ਹੁਕਮਿ ਰਜਾਈ ਚਲਣਾ ਨਾਨਕ ਲਿਖਿਆ ਨਾਲਿ ॥੧॥','Hukam Rajayee Chalnaa Nanak Likhiya Naal II 1 II','','[{"roman": "Hukam Rajayee Chalnaa Nanak Likhiya Naal II 1 II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Путь к становлению Настоящим состоит в том, чтобы жить и действовать в пределах письма Хукама II1II','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(59,1,11,'ਹੁਕਮੀ ਹੋਵਨਿ ਆਕਾਰ ਹੁਕਮੁ ਨ ਕਹਿਆ ਜਾਈ ॥','Hukmee Hovan Akaar Hukam Na Khayea Jayee II','','[{"roman": "Hukmee Hovan Akaar Hukam Na Khayea Jayee II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','(Как обнаружить Хукам)Моё тело и весь физический мир основаны на Хукаме, при том что сам Хукам не ограничен ими.','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(60,1,12,'ਹੁਕਮੀ ਹੋਵਨਿ ਜੀਅ ਹੁਕਮਿ ਮਿਲੈ ਵਡਿਆਈ ॥','Hukmee Hovan Jee Hukam Miley Vadeayee II','','[{"roman": "Hukmee Hovan Jee Hukam Miley Vadeayee II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Жизнь в теле и внутри физического мира основана на Хукаме. Быть живым в теле — дар, как результат согласия с физическими законами.','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(61,1,13,'ਹੁਕਮੀ ਉਤਮੁ ਨੀਚੁ ਹੁਕਮਿ ਲਿਖਿ ਦੁਖ ਸੁਖ ਪਾਈਅਹਿ ॥','Hukmee Utam Neech Hukam Likh Dukh Sukh Payeaeh II','','[{"roman": "Hukmee Utam Neech Hukam Likh Dukh Sukh Payeaeh II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Хукам определяет, что есть высокое и низкое.Живя, я лишь раскрываю последствия (предписанного) — боль или радость — в зависимости от того, следую я этому порядку или нет.','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(62,1,14,'ਇਕਨਾ ਹੁਕਮੀ ਬਖਸੀਸ ਇਕਿ ਹੁਕਮੀ ਸਦਾ ਭਵਾਈਅਹਿ ॥','Ekna Hukmee Bakhsish Ek Hukmee Sada Bhaveayeah II','','[{"roman": "Ekna Hukmee Bakhsish Ek Hukmee Sada Bhaveayeah II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Тот, кто признаёт Хукам и следует ему,получает Бакшиш — внутреннюю ясность.Тот кто отвергает обратную связь с реальностью такого Хукама,- блуждает в потёмках,повторяя поиск там, где ответа нет.','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(63,1,15,'ਹੁਕਮੈ ਅੰਦਰਿ ਸਭੁ ਕੋ ਬਾਹਰਿ ਹੁਕਮ ਨ ਕੋਇ ॥','Hukmey Andur Sabh Ko Bahur Hukam Na Koye II','','[{"roman": "Hukmey Andur Sabh Ko Bahur Hukam Na Koye II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Источник Хукама, находится внутри каждого, Ему – подчинено всё. Никто не может осознать Настоящее миновав его Хукам.','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(64,1,16,'ਨਾਨਕ ਹੁਕਮੈ ਜੇ ਬੁਝੈ ਤ ਹਉਮੈ ਕਹੈ ਨ ਕੋਇ ॥੨॥','Nanak Hukmey Jey Bujhey Ta Haumai Kahey Na Koye II 2 II','','[{"roman": "Nanak Hukmey Jey Bujhey Ta Haumai Kahey Na Koye II 2 II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Нанак говорит: при осознании Хукама внутри, идея того что я существую вне Его Хукамаперестаёт существовать II2II','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(65,1,17,'ਗਾਵੈ ਕੋ ਤਾਣੁ ਹੋਵੈ ਕਿਸੈ ਤਾਣੁ ॥','Gavai Ko Taan Hovai Kissey Taan II','','[{"roman": "Gavai Ko Taan Hovai Kissey Taan II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','(Как воспринимают Хукам? Какие восприятия воспевают?)Многие духовные искатели воспринимают Хукам как опорную силу своего существования','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(66,1,18,'ਗਾਵੈ ਕੋ ਦਾਤਿ ਜਾਣੈ ਨੀਸਾਣੁ ॥','Gavai Ko Daat Janei Nesaan II','','[{"roman": "Gavai Ko Daat Janei Nesaan II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Многие воспринимают дары (жизни) как знаки Его Хукама - узнавая в них ответ, а не случай.','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(67,1,19,'ਗਾਵੈ ਕੋ ਗੁਣ ਵਡਿਆਈਆ ਚਾਰ ॥','Gavai Ko Gunn Vadeayeea Chaar II','','[{"roman": "Gavai Ko Gunn Vadeayeea Chaar II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Многие воспринимают Хукам как качества безмерной красоты.','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(68,1,20,'ਗਾਵੈ ਕੋ ਵਿਦਿਆ ਵਿਖਮੁ ਵੀਚਾਰੁ ॥','Gavai Ko Vidiya Vikhum Vichaar II','','[{"roman": "Gavai Ko Vidiya Vikhum Vichaar II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Многие воспринимают Хукам как Просветлённость — знание за пределами описаний','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(69,1,21,'ਗਾਵੈ ਕੋ ਸਾਜਿ ਕਰੇ ਤਨੁ ਖੇਹ ॥','Gavai Ko Saaj Karey Tunn Kheh II','','[{"roman": "Gavai Ko Saaj Karey Tunn Kheh II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Многие воспринимают Хукам как силу, из которой рождаются тела и обращаются в пепел','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(70,1,22,'ਗਾਵੈ ਕੋ ਜੀਅ ਲੈ ਫਿਰਿ ਦੇਹ ॥','Gavai Ko Jee Ley Fir Deh II','','[{"roman": "Gavai Ko Jee Ley Fir Deh II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Многие воспринимают Хукам как отнятие жизни после того, как она была дана','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(71,1,23,'ਗਾਵੈ ਕੋ ਜਾਪੈ ਦਿਸੈ ਦੂਰਿ ॥','Gavai Ko Japai Disey Duur II','','[{"roman": "Gavai Ko Japai Disey Duur II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Многие воспринимают Хукам как То, что остаётся вне досягаемого','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(72,1,24,'ਗਾਵੈ ਕੋ ਵੇਖੈ ਹਾਦਰਾ ਹਦੂਰਿ ॥','Gavai Ko Vekhey Hadraa Hadoor II','','[{"roman": "Gavai Ko Vekhey Hadraa Hadoor II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Многие воспринимают Хукам как То, что ближе ближайшего','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(73,1,25,'ਕਥਨਾ ਕਥੀ ਨ ਆਵੈ ਤੋਟਿ ॥','Kathna Kathee Na Avey Tot II','','[{"roman": "Kathna Kathee Na Avey Tot II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Рассказы о восприятиях Хукама - бесчисленны…','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(74,1,26,'ਕਥਿ ਕਥਿ ਕਥੀ ਕੋਟੀ ਕੋਟਿ ਕੋਟਿ ॥','Kath Kath Kathee Kotee Kot Kot II','','[{"roman": "Kath Kath Kathee Kotee Kot Kot II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','…своими бесчисленными способами, бесчисленными искателями, бесчисленными акцентами','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(75,1,27,'ਦੇਦਾ ਦੇ ਲੈਦੇ ਥਕਿ ਪਾਹਿ ॥','Daenda Dey Laendey Thak Pahe II','','[{"roman": "Daenda Dey Laendey Thak Pahe II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Дающий творению пути к себе – продолжает давать, в своей изобильной природеПолучащие истощаются брать не от недостатка, а… от желания большего.','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(76,1,28,'ਜੁਗਾ ਜੁਗੰਤਰਿ ਖਾਹੀ ਖਾਹਿ ॥','Jugaan Jugantar Khahee Khahey II','','[{"roman": "Jugaan Jugantar Khahee Khahey II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Эта поддержкаявлениями Себя в восприятиях искателейбеспрепятственно продолжалась в течение многих веков','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(77,1,29,'ਹੁਕਮੀ ਹੁਕਮੁ ਚਲਾਏ ਰਾਹੁ ॥','Hukmi Hukam Chalaye Rah II','','[{"roman": "Hukmi Hukam Chalaye Rah II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Хукам — это движущая сила внутри самого творения','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(78,1,30,'ਨਾਨਕ ਵਿਗਸੈ ਵੇਪਰਵਾਹੁ ॥੩॥','Nanak Vigsey Veyparvah II 3 II','','[{"roman": "Nanak Vigsey Veyparvah II 3 II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Нанак говорит: Создатель управляет своим собственным Хукамом будучи беззаботно-свободным от восприятий себя II3II','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(79,1,31,'ਸਾਚਾ ਸਾਹਿਬੁ ਸਾਚੁ ਨਾਇ ਭਾਖਿਆ ਭਾਉ ਅਪਾਰੁ ॥','Sacha Sahib Sach Naye Bhakhiya Bhau Apaar II','','[{"roman": "Sacha Sahib Sach Naye Bhakhiya Bhau Apaar II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Истинен – Мастер, Истинен – его Хукам,Его язык — Закон, произнесённый любовью.','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(80,1,32,'ਆਖਹਿ ਮੰਗਹਿ ਦੇਹਿ ਦੇਹਿ ਦਾਤਿ ਕਰੇ ਦਾਤਾਰੁ ॥','Akhey Mangey Deh Deh Daat Kare Dataar II','','[{"roman": "Akhey Mangey Deh Deh Daat Kare Dataar II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Многие вторят “дай! дай!” (яви себя), но Дающийуже и без того постоянно дарует всё, такова его природа','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(81,1,33,'ਫੇਰਿ ਕਿ ਅਗੈ ਰਖੀਐ ਜਿਤੁ ਦਿਸੈ ਦਰਬਾਰੁ ॥','Faer Ke Agey RakheayJitt Dissey Darbar II','','[{"roman": "Faer Ke Agey RakheayJitt Dissey Darbar II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Среди всего того, что он даёт в этом изобилии, Что расположить во главе всегочтобы узреть Его Истинный Двор?','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(82,1,34,'ਮੁਹੌ ਕਿ ਬੋਲਣੁ ਬੋਲੀਐ ਜਿਤੁ ਸੁਣਿ ਧਰੇ ਪਿਆਰੁ ॥','Muhon Ke Bolen Boliay Jitt Sunn Dhare Pyaar II','','[{"roman": "Muhon Ke Bolen Boliay Jitt Sunn Dhare Pyaar II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Какое слово молвить внутри,чтобы Слух ведомый за этим, удержал Любовь к его Хукаму?','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(83,1,35,'ਅੰਮ੍ਰਿਤ ਵੇਲਾ ਸਚੁ ਨਾਉ ਵਡਿਆਈ ਵੀਚਾਰੁ ॥','Amrit Vela Sach Nao Vadeayee Vichar II','','[{"roman": "Amrit Vela Sach Nao Vadeayee Vichar II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Наполни Время жизни Амритой —через исследование Словав котором живёт Закон Превышнего, Всеприсутствующего','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(84,1,36,'ਕਰਮੀ ਆਵੈ ਕਪੜਾ ਨਦਰੀ ਮੋਖੁ ਦੁਆਰੁ ॥','Karmee Avey Kapraa Nadree Mokh Duar II','','[{"roman": "Karmee Avey Kapraa Nadree Mokh Duar II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Даритель Милости достигается через Одеяние-Усердия в следовании Закону, Врата во Двор Освобождения – Это Его Милость, приходящая в ответ на усердие','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(85,1,37,'ਨਾਨਕ ਏਵੈ ਜਾਣੀਐ ਸਭੁ ਆਪੇ ਸਚਿਆਰੁ ॥੪॥','Nanak Evey Janeay Sabh Apey Sachiar II 4 II','','[{"roman": "Nanak Evey Janeay Sabh Apey Sachiar II 4 II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Нанак говорит:сказанное выше — путь становления Настоящим (Сачиарой) внутри, для всех без исключения.(Kiv Sachiara Hoyey?)I4II','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(86,1,38,'ਥਾਪਿਆ ਨ ਜਾਇ ਕੀਤਾ ਨ ਹੋਇ ॥','Thapeya Na Jaye Keeta Na Hoye II','','[{"roman": "Thapeya Na Jaye Keeta Na Hoye II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Хукам не может быть “создан” или “установлен”.Его нельзя изменить или управлять им.','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(87,1,39,'ਆਪੇ ਆਪਿ ਨਿਰੰਜਨੁ ਸੋਇ ॥','Apey Aap Niranjan Soey II','','[{"roman": "Apey Aap Niranjan Soey II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Хукам существует Сам по Себеи управляется не извне,а Им самим.Он остаётся чист —не затронут творением,','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(88,1,40,'ਜਿਨਿ ਸੇਵਿਆ ਤਿਨਿ ਪਾਇਆ ਮਾਨੁ ॥','Jin Seyweya Tinn Payea Maan II','','[{"roman": "Jin Seyweya Tinn Payea Maan II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Тот, кто служит, видя служение как следование Хукаму, обретает Настоящую Честь — как знак Союза с Настоящим.','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(89,1,41,'ਨਾਨਕ ਗਾਵੀਐ ਗੁਣੀ ਨਿਧਾਨੁ ॥','Nanak Gaveay Gunee Nidhan II','','[{"roman": "Nanak Gaveay Gunee Nidhan II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Нанак говорит: служить его Хукаму, означает воспринять Его безграничные Добродетели.','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(90,1,42,'ਗਾਵੀਐ ਸੁਣੀਐ ਮਨਿ ਰਖੀਐ ਭਾਉ ॥','Gaveay Suneay Munn Rakheay Bhao II','','[{"roman": "Gaveay Suneay Munn Rakheay Bhao II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Воспой в себе Его Хукам через восприимчивое слышание И укорени в разуме любовь к принятию и усвоению Его письма','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(91,1,43,'ਦੁਖੁ ਪਰਹਰਿ ਸੁਖੁ ਘਰਿ ਲੈ ਜਾਇ ॥','Dukh Parhar Sukh Ghar Lae Jaye II','','[{"roman": "Dukh Parhar Sukh Ghar Lae Jaye II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Благодаря восприимчивому слышанию Хукама духовная агония рассеивается И духовное блаженство поселяется в доме атмы (в теле и разуме)','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(92,1,44,'ਗੁਰਮੁਖਿ ਨਾਦੰ ਗੁਰਮੁਖਿ ਵੇਦੰ ਗੁਰਮੁਖਿ ਰਹਿਆ ਸਮਾਈ ॥','Gurmukh Nadang Gurmukh Vedang Gurmukh Raheya Samayee II','','[{"roman": "Gurmukh Nadang Gurmukh Vedang Gurmukh Raheya Samayee II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Слыша это Слово, изреченное Учителем Всего в письме его Хукама, замечаю: Слово содержит внутри - Высшее Состояние, подобное музыкальной гармонии,Высшее Знание, и окончательно растворяет в Хукаме.','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(93,1,45,'ਗੁਰੁ ਈਸਰੁ ਗੁਰੁ ਗੋਰਖੁ ਬਰਮਾ ਗੁਰੁ ਪਾਰਬਤੀ ਮਾਈ ॥','Gur Esar                                                                                                                                                                                                                       Gur Gorakh Brahma Gur Parbatee Mayee II','','[{"roman": "Gur Esar                                                                                                                                                                                                                       Gur Gorakh Brahma Gur Parbatee Mayee II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Слово Учителя Всегосодержит в себе знания: Ишвары — знания о владыке и разрушителе всего,Горакха — источника йогического знания,Брахмы — знания о процессах творения,и Парвати Маа — силы поддержки и расцвета.','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(94,1,46,'ਜੇ ਹਉ ਜਾਣਾ ਆਖਾ ਨਾਹੀ ਕਹਣਾ ਕਥਨੁ ਨ ਜਾਈ ॥','Jay Hao Jana Akhan Nahee Kehna Kathan Na Jayee II','','[{"roman": "Jay Hao Jana Akhan Nahee Kehna Kathan Na Jayee II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Когда я осознаю это слово,То не могу описать его словами.Суть Хукама — постижима,но пролегает за пределами слов.','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(95,1,47,'ਗੁਰਾ ਇਕ ਦੇਹਿ ਬੁਝਾਈ ॥','Gura Ek Deh Bujhayee II','','[{"roman": "Gura Ek Deh Bujhayee II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Слово Учителя Всего Дарует Одно Исчерпывающее Осознание.','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(96,1,48,'ਸਭਨਾ ਜੀਆ ਕਾ ਇਕੁ ਦਾਤਾ ਸੋ ਮੈ ਵਿਸਰਿ ਨ ਜਾਈ ॥੫॥','Sabhna Jeea Ka Ek Daata So Mei Viser Na Jayee II 5 II','','[{"roman": "Sabhna Jeea Ka Ek Daata So Mei Viser Na Jayee II 5 II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Есть Один Хукам — поддерживающий Всю Жизнь, и я — не исключение в его поддержке.Это не мною установленное знание. Хукам не создаётся, не управляется мною. Естественность внутри меня едина с ним, поэтому я о нём не забуду. II5II','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(97,1,49,'ਤੀਰਥਿ ਨਾਵਾ ਜੇ ਤਿਸੁ ਭਾਵਾ ਵਿਣੁ ਭਾਣੇ ਕਿ ਨਾਇ ਕਰੀ ॥','Teerath Navah Jay Tes Bhavan Vinn Bhannet Ke Nhaye Karee II','','[{"roman": "Teerath Navah Jay Tes Bhavan Vinn Bhannet Ke Nhaye Karee II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Если совершается омовение в месте паломничества,но моё сознание не омылось в сфере Хукама — тогда зачем это омовение?','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(98,1,50,'ਜੇਤੀ ਸਿਰਠਿ ਉਪਾਈ ਵੇਖਾ ਵਿਣੁ ਕਰਮਾ ਕਿ ਮਿਲੈ ਲਈ ॥','Jaytee Sireth Upayee Vekha Vinn Karma Kay Miley Layee II','','[{"roman": "Jaytee Sireth Upayee Vekha Vinn Karma Kay Miley Layee II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Во всех внешних проявлениях сферы духовных практиквнутренняя духовность не реализуется По-Настоящему без Благословения, приходящего от со-настроенности','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(99,1,51,'ਮਤਿ ਵਿਚਿ ਰਤਨ ਜਵਾਹਰ ਮਾਣਿਕ ਜੇ ਇਕ ਗੁਰ ਕੀ ਸਿਖ ਸੁਣੀ ॥','Mutt Vich Ratunn Javahar Manik Jay Ek Gur Kee Sikh Sunee II','','[{"roman": "Mutt Vich Ratunn Javahar Manik Jay Ek Gur Kee Sikh Sunee II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Прислушавшись к этому одному драгоценному наставлению Гуру - моё сознание сонастроилось с Его Сферой','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(100,1,52,'ਗੁਰਾ ਇਕ ਦੇਹਿ ਬੁਝਾਈ ॥','Gura Ek Deh Bujhayee II','','[{"roman": "Gura Ek Deh Bujhayee II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Слово Учителя Всего Дарует Одно Исчерпывающее Осознание.','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(101,1,53,'ਸਭਨਾ ਜੀਆ ਕਾ ਇਕੁ ਦਾਤਾ ਸੋ ਮੈ ਵਿਸਰਿ ਨ ਜਾਈ ॥੬॥','Sabhna Jeea Ka Ek Daata So Mein Viser Na Jayee II 6 II','','[{"roman": "Sabhna Jeea Ka Ek Daata So Mein Viser Na Jayee II 6 II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Есть Один Хукам — поддерживающий Всю Жизнь, и я — не исключение в его поддержке.Я замечаю это, когда ум внешне делает то что происходит с ним снаружи, поэтому я о нём не забуду. II6II','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(102,1,54,'ਜੇ ਜੁਗ ਚਾਰੇ ਆਰਜਾ ਹੋਰ ਦਸੂਣੀ ਹੋਇ ॥','Jay Jug Charey Aarja Hor Dasunee Hoey II','','[{"roman": "Jay Jug Charey Aarja Hor Dasunee Hoey II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Если продлить свою жизнь до четырёх Юг и ещё в десять раз больше','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(103,1,55,'ਨਵਾ ਖੰਡਾ ਵਿਚਿ ਜਾਣੀਐ ਨਾਲਿ ਚਲੈ ਸਭੁ ਕੋਇ ॥','Navaa Khndan Vich Janeay Naal Chaley Sabh Koey II','','[{"roman": "Navaa Khndan Vich Janeay Naal Chaley Sabh Koey II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','И, живя так долго,В девяти царствах * получить мировую славу сделав последователем - каждого человека','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(104,1,56,'ਚੰਗਾ ਨਾਉ ਰਖਾਇ ਕੈ ਜਸੁ ਕੀਰਤਿ ਜਗਿ ਲੇਇ ॥','Changa Nao Rakhaye Kay Juss Keerat Jugg Laye II','','[{"roman": "Changa Nao Rakhaye Kay Juss Keerat Jugg Laye II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Получив доброе имя во всём временном мире, где все меня хвалят и на меня молятся…','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(105,1,57,'ਜੇ ਤਿਸੁ ਨਦਰਿ ਨ ਆਵਈ ਤ ਵਾਤ ਨ ਪੁਛੈ ਕੇ ॥','Jay Tiss Nadar Na Aavayee Ta Vaat Na Puchey Kay II','','[{"roman": "Jay Tiss Nadar Na Aavayee Ta Vaat Na Puchey Kay II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Если Его Хвалане обретается – на пути такой мирской славы меня Никто не признаёт','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(106,1,58,'ਕੀਟਾ ਅੰਦਰਿ ਕੀਟੁ ਕਰਿ ਦੋਸੀ ਦੋਸੁ ਧਰੇ ॥','Keeta Andar Keet Kar Dosee Dose Dharey II','','[{"roman": "Keeta Andar Keet Kar Dosee Dose Dharey II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','На таком пути, я червь среди червей, виновный в своём положении','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(107,1,59,'ਨਾਨਕ ਨਿਰਗੁਣਿ ਗੁਣੁ ਕਰੇਗੁਣਵੰਤਿਆ ਗੁਣੁ ਦੇ ॥','Nanak Nirgun Gunn Karey Gunvantean Gunn Dey II','','[{"roman": "Nanak Nirgun Gunn Karey Gunvantean Gunn Dey II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Нанак говорит: Тот Кто За Пределами Качеств и Форм - создаёт Их, является их обителью и дарует свои-собственные Высшие Качества','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(108,1,60,'ਤੇਹਾ ਕੋਇ ਨ ਸੁਝਈ ਜਿ ਤਿਸੁ ਗੁਣੁ ਕੋਇ ਕਰੇ ॥੭॥','Teha Koey Na Sujhayee Jay Tiss Gunn Koey Karey II 7 II','','[{"roman": "Teha Koey Na Sujhayee Jay Tiss Gunn Koey Karey II 7 II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Нет никого такого же кроме Его Хукама, кто мог бы даровать такое II7II','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(109,1,61,'ਸੁਣਿਐ ਸਿਧ ਪੀਰ ਸੁਰਿ ਨਾਥ ॥','Suney Sidh Peer Sur Naath II','','[{"roman": "Suney Sidh Peer Sur Naath II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Сонастраиваясь* со словом Хукама,мне открывается внутренняя реальность Сидхов, Пиров, Суров, Натхов. (Прислушиваясь* далее)','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(110,1,62,'ਸੁਣਿਐ ਧਰਤਿ ਧਵਲ ਆਕਾਸ ॥','Suney Dharat Dhaval Akaas II','','[{"roman": "Suney Dharat Dhaval Akaas II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Прислушиваясь к слову Хукама,мне открывается внутренняя реальность относительно Земли, Быка поддерживающего Землю*, Небес(Законы мироздания*; Понимание мирского, духовного, и их связи)','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(111,1,63,'ਸੁਣਿਐ ਦੀਪ ਲੋਅ ਪਾਤਾਲ ॥','Suney Deep Loa Pataal II','','[{"roman": "Suney Deep Loa Pataal II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Прислушиваясь к слову Хукама, мне открывается внутренняя реальность Солнца, его Света, и подземных миров лишенных света(Солнце - Гуру; что есть его свет - Надар, и что есть Ум лишенный этого света)','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(112,1,64,'ਸੁਣਿਐ ਪੋਹਿ ਨ ਸਕੈ ਕਾਲੁ ॥','Suney Poh Na Sakey Kaal II','','[{"roman": "Suney Poh Na Sakey Kaal II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Прислушиваясь к слову Хукама, я не затронут(а) временным','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(113,1,65,'ਨਾਨਕ ਭਗਤਾ ਸਦਾ ਵਿਗਾਸੁ ॥','Nanak Bhagtan Sada Vigas II','','[{"roman": "Nanak Bhagtan Sada Vigas II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Нанак, бхакти прислушивания к шабду его Хукама - приводит меня к вечному цветению','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(114,1,66,'ਸੁਣਿਐ ਦੂਖ ਪਾਪ ਕਾ ਨਾਸੁ ॥੮॥','Suney Dookh Paap Ka Naas II 8 II','','[{"roman": "Suney Dookh Paap Ka Naas II 8 II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Сонастраивание со словом Хукама устраняет духовную агонию и порок духовной глухоты* II8II(Глухота* - от того, что наше существо остаётся нереагирующим к Хукаму)','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(115,1,67,'ਸੁਣਿਐ ਈਸਰੁ ਬਰਮਾ ਇੰਦੁ ॥','Suney Esar Bharma Ind II','','[{"roman": "Suney Esar Bharma Ind II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Прислушиваясь к слову Хукама, мне открывается внутренняя реальность Шивы, Брахмы, Индры','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(116,1,68,'ਸੁਣਿਐ ਮੁਖਿ ਸਾਲਾਹਣ ਮੰਦੁ ॥','Suney Mukh Salahan Mund II','','[{"roman": "Suney Mukh Salahan Mund II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Прислушиваясь к слову Хукама,открывается реальность внутренних уст, хвалящих пороки(отрицание Хукама превращается в его признание)','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(117,1,69,'ਸੁਣਿਐ ਜੋਗ ਜੁਗਤਿ ਤਨਿ ਭੇਦ ॥','Suney Jog Jugat Tunn Bheyd II','','[{"roman": "Suney Jog Jugat Tunn Bheyd II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Прислушиваясь к слову Хукама, открывается внутренняя реальность Йоги как Союза - процессы тела ориентируются на становление Настоящим','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(118,1,70,'ਸੁਣਿਐ ਸਾਸਤ ਸਿਮ੍ਰਿਤਿ ਵੇਦ ॥','Suney Sasat Simret Ved II','','[{"roman": "Suney Sasat Simret Ved II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Прислушиваясь к слову Хукама, открывается внутренняя реальность слов Шастр, Смрити, Вед','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(119,1,71,'ਨਾਨਕ ਭਗਤਾ ਸਦਾ ਵਿਗਾਸੁ ॥','Nanak Bhagtan Sada Vigas II','','[{"roman": "Nanak Bhagtan Sada Vigas II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Нанак, бхакти прислушивания к шабду его Хукама - приводит меня к вечному цветению','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(120,1,72,'ਸੁਣਿਐ ਦੂਖ ਪਾਪ ਕਾ ਨਾਸੁ ॥੯॥','Suney Dookh Paap Ka Naas II 9 II','','[{"roman": "Suney Dookh Paap Ka Naas II 9 II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Сонастраивание со словом Хукама устраняет духовную агонию и порок духовной глухоты* II9II','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(121,1,73,'ਸੁਣਿਐ ਸਤੁ ਸੰਤੋਖੁ ਗਿਆਨੁ ॥','Suney Sat Santokh Gyan II','','[{"roman": "Suney Sat Santokh Gyan II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Сонастраивание со словом Хукама открывает мне природу Существования, Удовлетворения, Знания (Просветления)','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(122,1,74,'ਸੁਣਿਐ ਅਠਸਠਿ ਕਾ ਇਸਨਾਨੁ ॥','Suney Athsath Ka Eshnan II','','[{"roman": "Suney Athsath Ka Eshnan II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Прислушивание к слову Хукама открывает мне внутреннюю реальность очищения в 68-ми местах духовных паломничеств.','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(123,1,75,'ਸੁਣਿਐ ਪੜਿ ਪੜਿ ਪਾਵਹਿ ਮਾਨੁ ॥','Suney Parh Parh Pavey Maan II','','[{"roman": "Suney Parh Parh Pavey Maan II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Прислушивание к слову Хукама в непрерывном чтении приносит духовную пользу (честь)','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(124,1,76,'ਸੁਣਿਐ ਲਾਗੈ ਸਹਜਿ ਧਿਆਨੁ ॥','Suney Lagey Sehaj Dhyaan II','','[{"roman": "Suney Lagey Sehaj Dhyaan II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Прислушивание к слову Хукама рождает естественный духовный фокус','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(125,1,77,'ਨਾਨਕ ਭਗਤਾ ਸਦਾ ਵਿਗਾਸੁ ॥','Nanak Bhagtan Sada Vigas II','','[{"roman": "Nanak Bhagtan Sada Vigas II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Нанак, бхакти прислушивания к шабду его Хукама - приводит меня к вечному цветению','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(126,1,78,'ਸੁਣਿਐ ਦੂਖ ਪਾਪ ਕਾ ਨਾਸੁ ॥੧੦॥','Suney Dookh Paap Ka Naas II 10 II','','[{"roman": "Suney Dookh Paap Ka Naas II 10 II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Сонастраивание со словом Хукама устраняет духовную агонию и порок духовной глухоты* II10II','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(127,1,79,'ਸੁਣਿਐ ਸਰਾ ਗੁਣਾ ਕੇ ਗਾਹ ॥','Suney Sara Gunna Kay Gah II','','[{"roman": "Suney Sara Gunna Kay Gah II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Прислушивание к слову Хукама – это стремление к океану божественных качеств','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(128,1,80,'ਸੁਣਿਐ ਸੇਖ ਪੀਰ ਪਾਤਿਸਾਹ ॥','Suney Sheikh Peer Paatshah II','','[{"roman": "Suney Sheikh Peer Paatshah II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Прислушивание к слову Хукама открывает внутреннюю реальность Шейхов, Пиров, Патишахов','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(129,1,81,'ਸੁਣਿਐ ਅੰਧੇ ਪਾਵਹਿ ਰਾਹੁ ॥','Suney Andhey Pavey Rah II','','[{"roman": "Suney Andhey Pavey Rah II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Прислушивание к слову Хукама духовно-слепого приводит на (Его) Путь','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(130,1,82,'ਸੁਣਿਐ ਹਾਥ ਹੋਵੈ ਅਸਗਾਹੁ ॥','Suney Hath Hovey Asgah II','','[{"roman": "Suney Hath Hovey Asgah II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Прислушиваясь к слову Хукамарука достигает глубины океана божественных атрибутов','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(131,1,83,'ਨਾਨਕ ਭਗਤਾ ਸਦਾ ਵਿਗਾਸੁ ॥','Nanak Bhagtan Sada Vigas II','','[{"roman": "Nanak Bhagtan Sada Vigas II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Нанак, бхакти прислушивания к шабду его Хукама - приводит меня к вечному цветению','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(132,1,84,'ਸੁਣਿਐ ਦੂਖ ਪਾਪ ਕਾ ਨਾਸੁ ॥੧੧॥','Suney Dookh Paap Ka Naas II 11 II','','[{"roman": "Suney Dookh Paap Ka Naas II 11 II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Сонастраивание со словом Хукама устраняет духовную агонию и порок духовной глухоты* II11II','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(133,1,85,'ਮੰਨੇ ਕੀ ਗਤਿ ਕਹੀ ਨ ਜਾਇ ॥','Maney Kee Gutt Kahee Na Jaye II','','[{"roman": "Maney Kee Gutt Kahee Na Jaye II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Духовное состояние вверившегося в ходе прислушивания Слову – не поддаётся описанию','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(134,1,86,'ਜੇ ਕੋ ਕਹੈ ਪਿਛੈ ਪਛੁਤਾਇ ॥','Jey Ko Kahey Pichey Pachtaye II','','[{"roman": "Jey Ko Kahey Pichey Pachtaye II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Тот кто описывает - после сожалеет','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(135,1,87,'ਕਾਗਦਿ ਕਲਮ ਨ ਲਿਖਣਹਾਰੁ ॥','Kagad Kalam Na Likhanhaar II','','[{"roman": "Kagad Kalam Na Likhanhaar II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','По бумаге водя пером - не запишется','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(136,1,88,'ਮੰਨੇ ਕਾ ਬਹਿ ਕਰਨਿ ਵੀਚਾਰੁ ॥','Manney Ka Beh Karn Vichar II','','[{"roman": "Manney Ka Beh Karn Vichar II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Достойный способ описания этоВвериться Слову – через усидчивое деятельное самоисследование ||','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(137,1,89,'ਐਸਾ ਨਾਮੁ ਨਿਰੰਜਨੁ ਹੋਇ ॥','Aisa Naam Niranjun Hoey II','','[{"roman": "Aisa Naam Niranjun Hoey II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Такова природа Имени Незапятнанного …пятнами рукотворных чернил…','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(138,1,90,'ਜੇ ਕੋ ਮੰਨਿ ਜਾਣੈ ਮਨਿ ਕੋਇ ॥੧੨॥','Jay Ko Maan Janey Maan Koey II 12 II','','[{"roman": "Jay Ko Maan Janey Maan Koey II 12 II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','…тот кто Вверяется Услышанному – Тот становится тем чему Вверился||12||','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(139,1,91,'ਮੰਨੈ ਸੁਰਤਿ ਹੋਵੈ ਮਨਿ ਬੁਧਿ ॥','Munney Surt Hovey Mun Budh II','','[{"roman": "Munney Surt Hovey Mun Budh II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Состояние Вверившегося – относится к сфере совести, ума, интеллекта','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(140,1,92,'ਮੰਨੈ ਸਗਲ ਭਵਣ ਕੀ ਸੁਧਿ ॥','Munney Sagal Bhavan Kee Sudh II','','[{"roman": "Munney Sagal Bhavan Kee Sudh II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','В таком преображении совести, ума и разумастановление Вверившимся —самая полная истина для всех духовных искателей во вселенной','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(141,1,93,'ਮੰਨੈ ਮੁਹਿ ਚੋਟਾ ਨਾ ਖਾਇ ॥','Munney Moh Chota(n) Na Khaye II','','[{"roman": "Munney Moh Chota(n) Na Khaye II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','В такой пробужденностиСостояния Вверившегося – не получишь пощёчинот всей (духовной) Вселенной','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(142,1,94,'ਮੰਨੈ ਜਮ ਕੈ ਸਾਥਿ ਨ ਜਾਇ ॥','Munney Jumm Kei Saath Na Jaye II','','[{"roman": "Munney Jumm Kei Saath Na Jaye II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Не получая по лицу ударов, В Состоянии Вверившегося – Яма (духовная смерть) тем самым не сопровождает меня','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(143,1,95,'ਐਸਾ ਨਾਮੁ ਨਿਰੰਜਨੁ ਹੋਇ ॥','Aisa Naam Niranjun Hoey II','','[{"roman": "Aisa Naam Niranjun Hoey II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Такова природа Имени Незапятнанного…||','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(144,1,96,'ਜੇ ਕੋ ਮੰਨਿ ਜਾਣੈ ਮਨਿ ਕੋਇ ॥੧੩॥','Jay Ko Maan Janey Maan Koey II 13 II','','[{"roman": "Jay Ko Maan Janey Maan Koey II 13 II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','…тот кто Вверяется Становится тем чему Вверился ||13||','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(145,1,97,'ਮੰਨੈ ਮਾਰਗਿ ਠਾਕ ਨ ਪਾਇ ॥','Munney Marag Thaak Na Paye II','','[{"roman": "Munney Marag Thaak Na Paye II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Состояние Вверившегося в Слово Хукама – путь с духовными препятствиями не сталкивающий','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(146,1,98,'ਮੰਨੈ ਪਤਿ ਸਿਉ ਪਰਗਟੁ ਜਾਇ ॥','Munney Patt Sion Pargat Jaye II','','[{"roman": "Munney Patt Sion Pargat Jaye II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Состояние Вверившегося – Путь, на котором достоинство приходит от Гуру','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(147,1,99,'ਮੰਨੈ ਮਗੁ ਨ ਚਲੈ ਪੰਥੁ ॥','Munney Mugg Na Chaley Panth II','','[{"roman": "Munney Mugg Na Chaley Panth II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Состояние Вверившегося – это Путь где достоинство приходит от Гуру (!), а не от следования рукотворным путям, где достоинство исходит из социума и предписаний','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(148,1,100,'ਮੰਨੈ ਧਰਮ ਸੇਤੀ ਸਨਬੰਧੁ ॥','Munney Dharm Seytee Sunbundh II','','[{"roman": "Munney Dharm Seytee Sunbundh II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Состояние Вверившегося – это с Законом Превышнего состояние связи','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(149,1,101,'ਐਸਾ ਨਾਮੁ ਨਿਰੰਜਨੁ ਹੋਇ ॥','Aisa Naam Niranjun Hoey II','','[{"roman": "Aisa Naam Niranjun Hoey II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Такова природа Имени Незапятнанного… ||','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(150,1,102,'ਜੇ ਕੋ ਮੰਨਿ ਜਾਣੈ ਮਨਿ ਕੋਇ ॥੧੪॥','Jay Ko Maan Janey Maan Koey II 14 II','','[{"roman": "Jay Ko Maan Janey Maan Koey II 14 II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','…тот кто Вверяется Становится тем чему Вверился ||14||','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(151,1,103,'ਮੰਨੈ ਪਾਵਹਿ ਮੋਖੁ ਦੁਆਰੁ ॥','Munney Paveh Mokh Duar II','','[{"roman": "Munney Paveh Mokh Duar II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Состояние Вверившегося –это достижение тех Врат ведущих к Освобождению (от духовных препятствий; Nadree Mokh Duar, 4 паури)','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(152,1,104,'ਮੰਨੈ ਪਰਵਾਰੈ ਸਾਧਾਰੁ ॥','Munney Parvarey Sadhaar II','','[{"roman": "Munney Parvarey Sadhaar II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Состояние Вверившегося – это семью пяти чувств укоренить в Имени – в Становлении Словом','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(153,1,105,'ਮੰਨੈ ਤਰੈ ਤਾਰੇ ਗੁਰੁ ਸਿਖ ॥','Munney Trey Tarey Gur Sikh II','','[{"roman": "Munney Trey Tarey Gur Sikh II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Cостояние Вверившегося Слову - Есть переплытие мирского океана глухоты, Это и есть “Сикхи” – учение Гуру, который является переправителем(Sikhi Sikhya Gur Veechar || Nadare Karam Laghae Paar)','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(154,1,106,'ਮੰਨੈ ਨਾਨਕ ਭਵਹਿ ਨ ਭਿਖ ॥','Munney Nanak Bhaveh Na Bhikh II','','[{"roman": "Munney Nanak Bhaveh Na Bhikh II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Cостояние Вверившегося, говорит Нанак – где блуждания нет в притворном (ложном, скитании по берегу не-становления)','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(155,1,107,'ਐਸਾ ਨਾਮੁ ਨਿਰੰਜਨੁ ਹੋਇ ॥','Aisa Naam Niranjun Hoey II','','[{"roman": "Aisa Naam Niranjun Hoey II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Такова природа Имени Незапятнанного ||','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(156,1,108,'ਜੇ ਕੋ ਮੰਨਿ ਜਾਣੈ ਮਨਿ ਕੋਇ ॥੧੫॥','Jay Ko Maan Janey Maan Koey II 15 II','','[{"roman": "Jay Ko Maan Janey Maan Koey II 15 II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Тот кто Вверяется Становится тем чему Вверился||15||','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(157,1,109,'ਪੰਚ ਪਰਵਾਣ ਪੰਚ ਪਰਧਾਨੁ ॥','Panch Parwaan Panch Pardhaan II','','[{"roman": "Panch Parwaan Panch Pardhaan II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Пять чувств Вверившегося приняты как достойные руководить духовным путешествиемПять чувств ведут в переплытии с берега прислушивания на берег становления','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(158,1,110,'ਪੰਚੇ ਪਾਵਹਿ ਦਰਗਹਿ ਮਾਨੁ ॥','Panchey Pavey Dargah Maan II','','[{"roman": "Panchey Pavey Dargah Maan II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Пять чувств Вверившегося, ориентированные на Становление его Словом, получают в Его Суде (совести) честь','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(159,1,111,'ਪੰਚੇ ਸੋਹਹਿ ਦਰਿ ਰਾਜਾਨੁ ॥','Panchey Sohey Dar Rajaan II','','[{"roman": "Panchey Sohey Dar Rajaan II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Получив честь в Его Суде,Пять чувств Вверившегося теперь изящно стоят у Врат Его Самого','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(160,1,112,'ਪੰਚਾ ਕਾ ਗੁਰੁ ਏਕੁ ਧਿਆਨੁ ॥','Panchaan Ka Gur Ek Dhiyaan II','','[{"roman": "Panchaan Ka Gur Ek Dhiyaan II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','У Пяти чувств в центре внимания – Единый Учитель, стоящий во Вратах','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(161,1,113,'ਜੇ ਕੋ ਕਹੈ ਕਰੈ ਵੀਚਾਰੁ ॥','Jay Ko Khaey Kraey Vichar II','','[{"roman": "Jay Ko Khaey Kraey Vichar II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Стоит ли кому-то повествовать об этом самоисследовании?','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(162,1,114,'ਕਰਤੇ ਕੈ ਕਰਣੈ ਨਾਹੀ ਸੁਮਾਰੁ ॥','Kartey Kaey Karney Nahi Sumaar II','','[{"roman": "Kartey Kaey Karney Nahi Sumaar II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Создаваемые духовные достижения такого состояния чувств не поддаются исчислению.','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(163,1,115,'ਧੌਲੁ ਧਰਮੁ ਦਇਆ ਕਾ ਪੂਤੁ ॥','Dhaol Dhrm Dya Ka Poot II','','[{"roman": "Dhaol Dhrm Dya Ka Poot II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Его Закон в Чистом Виде – рождён во мне от Сострадания.','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(164,1,116,'ਸੰਤੋਖੁ ਥਾਪਿ ਰਖਿਆ ਜਿਨਿ ਸੂਤਿ ॥','Santokh Thaap Rakheya Jin Soot II','','[{"roman": "Santokh Thaap Rakheya Jin Soot II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Его Закон может быть утверждён и удержан на нити удовлетворённости от реализуемого сочувствия','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(165,1,117,'ਜੇ ਕੋ ਬੁਝੈ ਹੋਵੈ ਸਚਿਆਰੁ ॥','Jay Ko Bujhey Hovey Sachiaar II','','[{"roman": "Jay Ko Bujhey Hovey Sachiaar II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Тот кто Действительно Осознал это – стал Сачиарой, Настоящим','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(166,1,118,'ਧਵਲੈ ਉਪਰਿ ਕੇਤਾ ਭਾਰੁ ॥','Dhavley Upar Keyta Bhaar II','','[{"roman": "Dhavley Upar Keyta Bhaar II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Что за ношу несёт такая чистота духовной жизни, что она требует?','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(167,1,119,'ਧਰਤੀ ਹੋਰੁ ਪਰੈ ਹੋਰੁ ਹੋਰੁ ॥','Dhartee Hor Pare Hor Hor II','','[{"roman": "Dhartee Hor Pare Hor Hor II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Земля (внутренняя опора) отходитто в одну, то в другую сторону','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(168,1,120,'ਤਿਸ ਤੇ ਭਾਰੁ ਤਲੈ ਕਵਣੁ ਜੋਰੁ ॥','Tis Tey Bhaar Taley Kavan Jor II','','[{"roman": "Tis Tey Bhaar Taley Kavan Jor II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Что является для ноши – той силой, что шатает её опору?','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(169,1,121,'ਜੀਅ ਜਾਤਿ ਰੰਗਾ ਕੇ ਨਾਵ ॥','Jee Jaat Ranga Kay Naav II','','[{"roman": "Jee Jaat Ranga Kay Naav II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Эта шаткость опоры естьСама жизнь, что проникла своими атрибутами в пять чувств','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(170,1,122,'ਸਭਨਾ ਲਿਖਿਆ ਵੁੜੀ ਕਲਾਮ ॥','Sabhna Likhiya Vuree Kalaam II','','[{"roman": "Sabhna Likhiya Vuree Kalaam II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Вся эта жизнь вокругчерез мои пять чувств Непрерывно вписывала себя внутрь менявыводя из равновесия, записывая мою судьбу','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(171,1,123,'ਏਹੁ ਲੇਖਾ ਲਿਖਿ ਜਾਣੈ ਕੋਇ ॥','Eh Lekha Likh Janey Koey II','','[{"roman": "Eh Lekha Likh Janey Koey II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Эти письма судьбоносные – если знать как писать …','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(172,1,124,'ਲੇਖਾ ਲਿਖਿਆ ਕੇਤਾ ਹੋਇ ॥','Lekha Likheya Keyta Hoey II','','[{"roman": "Lekha Likheya Keyta Hoey II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','… то как бы стоило их написать?','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(173,1,125,'ਕੇਤਾ ਤਾਣੁ ਸੁਆਲਿਹੁ ਰੂਪੁ ॥','Keyta Taan Sualeho Roop II','','[{"roman": "Keyta Taan Sualeho Roop II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Сколь велика мощь и красота в Ответе на этот вопрос?','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(174,1,126,'ਕੇਤੀ ਦਾਤਿ ਜਾਣੈ ਕੌਣੁ ਕੂਤੁ ॥','Kaytee Daat Janee Kaon Koot II','','[{"roman": "Kaytee Daat Janee Kaon Koot II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Изобилие даров, текущих из Ответа на него, были бы неоценимы','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(175,1,127,'ਕੀਤਾ ਪਸਾਉ ਏਕੋ ਕਵਾਉ ॥','Keeta Pasao Eko Kvao II','','[{"roman": "Keeta Pasao Eko Kvao II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Ответ: Когда повеление Единого действует в пространстве моей совести …','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(176,1,128,'ਤਿਸ ਤੇ ਹੋਏ ਲਖ ਦਰੀਆਉ ॥','Tis Tay Hoey Lakh Dariao II','','[{"roman": "Tis Tay Hoey Lakh Dariao II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','… Из такого пространства в мою жизнь текут сто тысяч рек добродетелей','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(177,1,129,'ਕੁਦਰਤਿ ਕਵਣ ਕਹਾ ਵੀਚਾਰੁ ॥','Kudrat Kavan Kahan Vichar II','','[{"roman": "Kudrat Kavan Kahan Vichar II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Какова способность говорить об этом самоисследовании?','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(178,1,130,'ਵਾਰਿਆ ਨ ਜਾਵਾ ਏਕ ਵਾਰ ॥','Variya Na Java Ek Vaar II','','[{"roman": "Variya Na Java Ek Vaar II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Преданность и раз не выразить в полной мере','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(179,1,131,'ਜੋ ਤੁਧੁ ਭਾਵੈ ਸਾਈ ਭਲੀ ਕਾਰ ॥','Jo Tudh Bhavey Sayee Bhalee Kaar II','','[{"roman": "Jo Tudh Bhavey Sayee Bhalee Kaar II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Всё что Тебя радует – принимаю и следую, исходя из твоих повелений в пространстве Совести','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(180,1,132,'ਤੂ ਸਦਾ ਸਲਾਮਤਿ ਨਿਰੰਕਾਰ ॥੧੬॥','Tu Sada Salaamat Nirankar II 16 II','','[{"roman": "Tu Sada Salaamat Nirankar II 16 II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Ты Вечный, Поддерживающий (мою совесть через честь), Вне Форм II16II(Пришло осознание, что Совесть - это Ты, Гуру)','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(181,1,133,'ਅਸੰਖ ਜਪ ਅਸੰਖ ਭਾਉ ॥','Asankh Jup Asankh Bhao II','','[{"roman": "Asankh Jup Asankh Bhao II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Сто тысяч рек осознаний и добродетелей:Повеление Единого Внутри Совести Создаёт Неисчислимое Осознание, Неисчислимую Любовь','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(182,1,134,'ਅਸੰਖ ਪੂਜਾ ਅਸੰਖ ਤਪ ਤਾਉ ॥','Asankh Puja Asankh Tup Tao II','','[{"roman": "Asankh Puja Asankh Tup Tao II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Повеление Единого Внутри Совести Создаёт неисчислимое почитание Его,Создаёт неисчислимую высшая аскезу','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(183,1,135,'ਅਸੰਖ ਗਰੰਥ ਮੁਖਿ ਵੇਦ ਪਾਠ ॥','Asankh Granth Mukh Ved Paath II','','[{"roman": "Asankh Granth Mukh Ved Paath II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Повеление Единого Внутри Совести Эквивалентно неисчислимому чтению и повторению грантхов, вед, духовных текстов','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(184,1,136,'ਅਸੰਖ ਜੋਗ ਮਨਿ ਰਹਹਿ ਉਦਾਸ ॥','Asankh Jog Munn Rahey Udaas II','','[{"roman": "Asankh Jog Munn Rahey Udaas II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Повеление Единого Внутри Совести Создаёт неисчислимый союз В состоянии внутреннего отречения от не-вечного.','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(185,1,137,'ਅਸੰਖ ਭਗਤ ਗੁਣ ਗਿਆਨ ਵੀਚਾਰ ॥','Asankh Bhagat Gunn Gyaan Vichaar II','','[{"roman": "Asankh Bhagat Gunn Gyaan Vichaar II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Повеление Единого Внутри Совести Подобно неисчислимым бхагтам,исследующим Божественные Атрибуты','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(186,1,138,'ਅਸੰਖ ਸਤੀ ਅਸੰਖ ਦਾਤਾਰ ॥','Asankh Satee Asankh Dataar II','','[{"roman": "Asankh Satee Asankh Dataar II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Повеление Единого Внутри Совести Есть неисчислимое удовлетворение от Его безграничной дающей способности','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(187,1,139,'ਅਸੰਖ ਸੂਰ ਮੁਹ ਭਖ ਸਾਰ ॥','Asankh Soor Muh Bhakh Saar II','','[{"roman": "Asankh Soor Muh Bhakh Saar II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Повеление Единого Внутри СовестиПодобно неисчислимым воинам, стойким от ударов железом по лицу','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(188,1,140,'ਅਸੰਖ ਮੋਨਿ ਲਿਵ ਲਾਇ ਤਾਰ ॥','Asankh Moaan Liv Laye Taar II','','[{"roman": "Asankh Moaan Liv Laye Taar II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Повеление Единого Внутри Совести Создаёт тишину с неотвлекающейся сосредоточенностью','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(189,1,141,'ਕੁਦਰਤਿ ਕਵਣ ਕਹਾ ਵੀਚਾਰੁ ॥','Kudrat Kavan Kahan Vichar II','','[{"roman": "Kudrat Kavan Kahan Vichar II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Какова способность говорить об этом (внутреннем) Исследовании?','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(190,1,142,'ਵਾਰਿਆ ਨ ਜਾਵਾ ਏਕ ਵਾਰ ॥','Variya Na Java Ek Vaar II','','[{"roman": "Variya Na Java Ek Vaar II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Преданность ни разу не выразить в полной мере ||','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(191,1,143,'ਜੋ ਤੁਧੁ ਭਾਵੈ ਸਾਈ ਭਲੀ ਕਾਰ ॥','Jo Tudh Bhavey Sayee Bhalee Kaar II','','[{"roman": "Jo Tudh Bhavey Sayee Bhalee Kaar II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Всё что Тебя радует – принимаю и следую, исходя из твоих повелений в пространстве Совести','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(192,1,144,'ਤੂ ਸਦਾ ਸਲਾਮਤਿ ਨਿਰੰਕਾਰ ॥੧੭॥','Tu Sada Salaamat Nirankar II 17 II','','[{"roman": "Tu Sada Salaamat Nirankar II 17 II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Ты Вечный, Поддерживающий мою совесть через честь, Вне Форм II17II','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(193,1,145,'ਅਸੰਖ ਮੂਰਖ ਅੰਧ ਘੋਰ ॥','Asunkh Moorakh Andh Ghoar II','','[{"roman": "Asunkh Moorakh Andh Ghoar II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Повеление Единого Внутри СовестиПробуждает осознание моей непросветлённости, глупости и абсолютной тьмы','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(194,1,146,'ਅਸੰਖ ਚੋਰ ਹਰਾਮਖੋਰ ॥','Asunkh Chor Haramkhor II','','[{"roman": "Asunkh Chor Haramkhor II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Повеление Единого Внутри СовестиПробуждает осознание моей лживости и неблагодарности','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(195,1,147,'ਅਸੰਖ ਅਮਰ ਕਰਿ ਜਾਹਿ ਜੋਰ ॥','Asunkh Amar Kar Jahe Jor II','','[{"roman": "Asunkh Amar Kar Jahe Jor II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Повеление Единого Внутри СовестиПробуждает осознание попыток быть бессмертным и командовать над другими','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(196,1,148,'ਅਸੰਖ ਗਲਵਢ ਹਤਿਆ ਕਮਾਹਿ ॥','Asunkh Gulvadh Hatiya Kamahey II','','[{"roman": "Asunkh Gulvadh Hatiya Kamahey II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Повеление Единого Внутри СовестиПробуждает осознание бесчисленных действий, которые обезглавливают меня и убивают','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(197,1,149,'ਅਸੰਖ ਪਾਪੀ ਪਾਪੁ ਕਰਿ ਜਾਹਿ ॥','Asunkh Papi Pap Kar Jahey II','','[{"roman": "Asunkh Papi Pap Kar Jahey II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Повеление Единого Внутри СовестиПробуждает осознание бесчисленных действий, совершенных моим наполненным пороками разумом, подавляющими Совесть','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(198,1,150,'ਅਸੰਖ ਕੂੜਿਆਰ ਕੂੜੇ ਫਿਰਾਹਿ ॥','Asunkh Kureeaar Kurreey Firahey II','','[{"roman": "Asunkh Kureeaar Kurreey Firahey II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Повеление Единого Внутри СовестиПробуждает осознание моих бесчисленных и повторяющихся отрицаний обратной связи','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(199,1,151,'ਅਸੰਖ ਮਲੇਛ ਮਲੁ ਭਖਿ ਖਾਹਿ ॥','Asunkh Malesh Mull Bhakh Khayey II','','[{"roman": "Asunkh Malesh Mull Bhakh Khayey II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Повеление Единого Внутри СовестиПробуждает осознание склонности к бесчисленному поеданию грязи','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(200,1,152,'ਅਸੰਖ ਨਿੰਦਕ ਸਿਰਿ ਕਰਹਿ ਭਾਰੁ ॥','Asunkh Nindak Sirr Karhe Bhaar II','','[{"roman": "Asunkh Nindak Sirr Karhe Bhaar II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Повеление Единого Внутри СовестиПробуждает осознание моих бесчисленных отрицаний обратной связи, накапливающихся грузом','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(201,1,153,'ਨਾਨਕੁ ਨੀਚੁ ਕਹੈ ਵੀਚਾਰੁ ॥','Nanak Neech Kaheay Vichaar II','','[{"roman": "Nanak Neech Kaheay Vichaar II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Нанак произносит речь скромного духовного достоинства.','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(202,1,154,'ਵਾਰਿਆ ਨ ਜਾਵਾ ਏਕ ਵਾਰ ॥','Variya Na Java Ek Vaar II','','[{"roman": "Variya Na Java Ek Vaar II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Моя неспособность такова, что я не могу ни разу выразить свою преданность','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(203,1,155,'ਜੋ ਤੁਧੁ ਭਾਵੈ ਸਾਈ ਭਲੀ ਕਾਰ ॥','Jo Tudh Bhavey Sayee Bhalee Kaar II','','[{"roman": "Jo Tudh Bhavey Sayee Bhalee Kaar II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Всё что Тебя радует – То принимаю и следую, исходя из твоих повелений в пространстве Совести','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(204,1,156,'ਤੂ ਸਦਾ ਸਲਾਮਤਿ ਨਿਰੰਕਾਰ ॥੧੮॥','Tu Sada Salaamat Nirankar II 18 II','','[{"roman": "Tu Sada Salaamat Nirankar II 18 II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Ты Вечный, Поддерживающий мою совесть через честь, Вне Форм II18II','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(205,1,157,'ਅਸੰਖ ਨਾਵ ਅਸੰਖ ਥਾਵ ॥','Asunkh Naav Asunkh Thaav II','','[{"roman": "Asunkh Naav Asunkh Thaav II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Неисчислим Хукам, неисчислимы его Места','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(206,1,158,'ਅਗੰਮ ਅਗੰਮ ਅਸੰਖ ਲੋਅ ॥','Agum Agum Asunkh Loe II','','[{"roman": "Agum Agum Asunkh Loe II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','За гранью граней, неисчислимый Свет','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(207,1,159,'ਅਸੰਖ ਕਹਹਿ ਸਿਰਿ ਭਾਰੁ ਹੋਇ ॥','Asunkh Kahey Sirr Bhaar Hoey II','','[{"roman": "Asunkh Kahey Sirr Bhaar Hoey II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Неисчислимым грузом на голову ложатся неисчислимые осознания вслед','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(208,1,160,'ਅਖਰੀ ਨਾਮੁ ਅਖਰੀ ਸਾਲਾਹ ॥','Akhree Naam Akhree Salahh II','','[{"roman": "Akhree Naam Akhree Salahh II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','В неисчислимом осознанииНерушимо Имя, И нерушима к нему Хвала','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(209,1,161,'ਅਖਰੀ ਗਿਆਨੁ ਗੀਤ ਗੁਣ ਗਾਹ ॥','Akhree Gyaan Geet Gun Gah II','','[{"roman": "Akhree Gyaan Geet Gun Gah II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Нерушима песнь мудрости океана его атрибутов','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(210,1,162,'ਅਖਰੀ ਲਿਖਣੁ ਬੋਲਣੁ ਬਾਣਿ ॥','Akhree Likhen Bolunn Baan II','','[{"roman": "Akhree Likhen Bolunn Baan II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Поэтому Нерушимы слова этой песни, что вписаны внутрь','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(211,1,163,'ਅਖਰਾ ਸਿਰਿ ਸੰਜੋਗੁ ਵਖਾਣਿ ॥','Akhra Sirr Sanjog Vkhaan II','','[{"roman": "Akhra Sirr Sanjog Vkhaan II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','И нерушим союз ума с их “произношением” через дела','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(212,1,164,'ਜਿਨਿ ਏਹਿ ਲਿਖੇ ਤਿਸੁ ਸਿਰਿ ਨਾਹਿ ॥','Jin Eh Likhey Tis Sirr Nahey II','','[{"roman": "Jin Eh Likhey Tis Sirr Nahey II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Если слова той песни вписаны – тогда голова их уже не отвергнет','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(213,1,165,'ਜਿਵ ਫੁਰਮਾਏ ਤਿਵ ਤਿਵ ਪਾਹਿ ॥','Jiv Furmaey Tiv Tiv Pahe II','','[{"roman": "Jiv Furmaey Tiv Tiv Pahe II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Как Им указано, ровно так и принято','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(214,1,166,'ਜੇਤਾ ਕੀਤਾ ਤੇਤਾ ਨਾਉ ॥','Jeyta Keeta Teyta Nao II','','[{"roman": "Jeyta Keeta Teyta Nao II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Всё что создаётся Его повелением внутри Совести – находится в пределах Хукама','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(215,1,167,'ਵਿਣੁ ਨਾਵੈ ਨਾਹੀ ਕੋ ਥਾਉ ॥','Vinn Navey Nahi Ko Thao II','','[{"roman": "Vinn Navey Nahi Ko Thao II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Нет ни одного места, что не покрывал бы его Хукам, и совесть тоже становится всепокрывающей','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(216,1,168,'ਕੁਦਰਤਿ ਕਵਣ ਕਹਾ ਵੀਚਾਰੁ ॥','Kudrat Kavan Kahan Vichar II','','[{"roman": "Kudrat Kavan Kahan Vichar II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Беседа о благочестивой совести выше моих сил','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(217,1,169,'ਵਾਰਿਆ ਨ ਜਾਵਾ ਏਕ ਵਾਰ ॥','Variya Na Java Ek Vaar II','','[{"roman": "Variya Na Java Ek Vaar II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Моя неспособность такова, что я не могу ни разу выразить свою преданность','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(218,1,170,'ਜੋ ਤੁਧੁ ਭਾਵੈ ਸਾਈ ਭਲੀ ਕਾਰ ॥','Jo Tudh Bhavey Sayee Bhalee Kaar II','','[{"roman": "Jo Tudh Bhavey Sayee Bhalee Kaar II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Всё что Тебя радует – То принимаю и следую, исходя из твоих повелений в пространстве Совести','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(219,1,171,'ਤੂ ਸਦਾ ਸਲਾਮਤਿ ਨਿਰੰਕਾਰ ॥੧੯॥','Tu Sada Salaamat Nirankar II 19 II','','[{"roman": "Tu Sada Salaamat Nirankar II 19 II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Ты Вечный, Поддерживающий (мою совесть через честь), Вне Форм II19II','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(220,1,172,'ਭਰੀਐ ਹਥੁ ਪੈਰੁ ਤਨੁ ਦੇਹ ॥','Bhareay Hath Paer Tunn Deh','','[{"roman": "Bhareay Hath Paer Tunn Deh", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Когда руки, ноги и тело запятнаны…','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(221,1,173,'ਪਾਣੀ ਧੋਤੈ ਉਤਰਸੁ ਖੇਹ ॥','Panee Dhotey Utras Kheh II','','[{"roman": "Panee Dhotey Utras Kheh II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','…вода очищает их.','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(222,1,174,'ਮੂਤ ਪਲੀਤੀ ਕਪੜੁ ਹੋਇ ॥','Moot Pleete Kaparr Hoey ||','','[{"roman": "Moot Pleete Kaparr Hoey ||", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Когда одежда становится испачкана нечистотами…','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(223,1,175,'ਦੇ ਸਾਬੂਣੁ ਲਈਐ ਓਹੁ ਧੋਇ ॥','Dey Sabun Laeay Oh Dhoey II','','[{"roman": "Dey Sabun Laeay Oh Dhoey II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','…стирка с мылом очищает её.','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(224,1,176,'ਭਰੀਐ ਮਤਿ ਪਾਪਾ ਕੈ ਸੰਗਿ ॥','Bhareay Mutt Paapa Ke Sang II','','[{"roman": "Bhareay Mutt Paapa Ke Sang II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Если разум запятнан пороками…','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(225,1,177,'ਓਹੁ ਧੋਪੈ ਨਾਵੈ ਕੈ ਰੰਗਿ ॥','Oh Dhopey Navey Kaey Rung II','','[{"roman": "Oh Dhopey Navey Kaey Rung II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','…он очищается наполнением его божественными атрибутами','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(226,1,178,'ਪੁੰਨੀ ਪਾਪੀ ਆਖਣੁ ਨਾਹਿ ॥','Punee Papi Akhan Nahe II','','[{"roman": "Punee Papi Akhan Nahe II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Благочестивый, или порочный –Не определяется словамиили бормотанием мантр, чтением шабдов','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(227,1,179,'ਕਰਿ ਕਰਿ ਕਰਣਾ ਲਿਖਿ ਲੈ ਜਾਹੁ ॥','Kar Kar Karna Likh Ley Jah II','','[{"roman": "Kar Kar Karna Likh Ley Jah II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Непрерывными действиями пишутся Истинные слова','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(228,1,180,'ਆਪੇ ਬੀਜਿ ਆਪੇ ਹੀ ਖਾਹੁ ॥','Apey Beej Apey Hee Khah II','','[{"roman": "Apey Beej Apey Hee Khah II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Это побуждает осознать:Пожинаю так, как Сею','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(229,1,181,'ਨਾਨਕ ਹੁਕਮੀ ਆਵਹੁ ਜਾਹੁ ॥੨੦॥','Nanak Hukmee Aveh Jah II 20 II','','[{"roman": "Nanak Hukmee Aveh Jah II 20 II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Нанак, пожнешь, как посеешь – это Хукам, относящийся к тому что приходит и к тому что уходитII20II','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(230,1,182,'ਤੀਰਥੁ ਤਪੁ ਦਇਆ ਦਤੁ ਦਾਨੁ ॥','Teerath Tupp Dya Dut Daan II','','[{"roman": "Teerath Tupp Dya Dut Daan II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Паломничества, аскезы, раздача милостыни в своей практике практике очищения…','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(231,1,183,'ਜੇ ਕੋ ਪਾਵੈ ਤਿਲ ਕਾ ਮਾਨੁ ॥','Jay Ko Pavey Til Ka Maan II','','[{"roman": "Jay Ko Pavey Til Ka Maan II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','…те, кто очищаются так, получают чести с кунжутное семя.','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(232,1,184,'ਸੁਣਿਆ ਮੰਨਿਆ ਮਨਿ ਕੀਤਾ ਭਾਉ ॥','Suneya Maneya Mun Keeta Bhao II','','[{"roman": "Suneya Maneya Mun Keeta Bhao II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Прививая разуму Любовь кПрислушиванию и Принятию воспринятого …','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(233,1,185,'ਅੰਤਰਗਤਿ ਤੀਰਥਿ ਮਲਿ ਨਾਉ ॥','Anturgat Teerath Mull Nao II','','[{"roman": "Anturgat Teerath Mull Nao II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','… совершается внутреннее паломничество-очищения Добродетелью','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(234,1,186,'ਸਭਿ ਗੁਣ ਤੇਰੇ ਮੈ ਨਾਹੀ ਕੋਇ ॥','Sabh Gunn Teyre Mein Nahi Koey II','','[{"roman": "Sabh Gunn Teyre Mein Nahi Koey II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Все Добродетели принадлежат Тебе, а вовсе не мне','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(235,1,187,'ਵਿਣੁ ਗੁਣ ਕੀਤੇ ਭਗਤਿ ਨ ਹੋਇ ॥','Venn Gunn Keetey Bhagat Na Hoey II','','[{"roman": "Venn Gunn Keetey Bhagat Na Hoey II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Без этих Добродетелей – Бхагти не возникает','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(236,1,188,'ਸੁਅਸਤਿ ਆਥਿ ਬਾਣੀ ਬਰਮਾਉ ॥','Suast’ AathBanni Barmau II','','[{"roman": "Suast’ AathBanni Barmau II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Эти Добродетели - место паломничества и очищения, а Бани (Слово) - броня, в которой я путешествую','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(237,1,189,'ਸਤਿ ਸੁਹਾਣੁ ਸਦਾ ਮਨਿ ਚਾਉ ॥','Sat Suhan Sada Mun Chau II','','[{"roman": "Sat Suhan Sada Mun Chau II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Достигая такого места паломничества, Красота, Радость в Уме – Становятся Вечными','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(238,1,190,'ਕਵਣੁ ਸੁ ਵੇਲਾ ਵਖਤੁ ਕਵਣੁ ਕਵਣ ਥਿਤਿ ਕਵਣੁ ਵਾਰੁ ॥','Kavann So Vela Vakhat Kavann Kavann Thit Kavann Vaar II','','[{"roman": "Kavann So Vela Vakhat Kavann Kavann Thit Kavann Vaar II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Какой период времени, какой час, какой день лунного месяца (титхи), какая неделя необходимы на пути достижения этого Вечного, не зависящего от времени?','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(239,1,191,'ਕਵਣਿ ਸਿ ਰੁਤੀ ਮਾਹੁ ਕਵਣੁ ਜਿਤੁ ਹੋਆ ਆਕਾਰੁ ॥','Kavann Sey Rutee Mah Kavann Jit Hoa Akar II','','[{"roman": "Kavann Sey Rutee Mah Kavann Jit Hoa Akar II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Какой сезон, месяц, в котором обретает внешнее проявление такое Становление?','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(240,1,192,'ਵੇਲ ਨ ਪਾਈਆ ਪੰਡਤੀ ਜਿ ਹੋਵੈ ਲੇਖੁ ਪੁਰਾਣੁ ॥','Vel Na Payea Pundtee Je Hovey Leykyh Puraan II','','[{"roman": "Vel Na Payea Pundtee Je Hovey Leykyh Puraan II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Это время вечной красоты и счастья не достигается в том, что пишут Пандиты в Пуранах','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(241,1,193,'ਵਖਤੁ ਨ ਪਾਇਓ ਕਾਦੀਆ ਜਿ ਲਿਖਨਿ ਲੇਖੁ ਕੁਰਾਣੁ ॥','Vakhat Na Payeo Kadia Je Likhen Leykh Kuran II','','[{"roman": "Vakhat Na Payeo Kadia Je Likhen Leykh Kuran II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Это время вечной красоты и счастья не достигается через знание, записанное Кадиями (исламским духовенством) в Кур''ан','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(242,1,194,'ਥਿਤਿ ਵਾਰੁ ਨਾ ਜੋਗੀ ਜਾਣੈ ਰੁਤਿ ਮਾਹੁ ਨਾ ਕੋਈ ॥','Thit Vaar Na Jogi Janney Rut Mah Na Koyee II','','[{"roman": "Thit Vaar Na Jogi Janney Rut Mah Na Koyee II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Это время вечной красоты и счастья вовсе не достигается с помощью йогических знаний, относящихся к сезону, месяцу, неделе и дню','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(243,1,195,'ਜਾ ਕਰਤਾ ਸਿਰਠੀ ਕਉ ਸਾਜੇ ਆਪੇ ਜਾਣੈ ਸੋਈ ॥','Ja Karta Sirthee Ko Sajey Apey Janney Soyee II','','[{"roman": "Ja Karta Sirthee Ko Sajey Apey Janney Soyee II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Сознание Ооангкара, создавшее во мне Состояние Вечного Блаженства Духовной Реализации, Знает это','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(244,1,196,'ਕਿਵ ਕਰਿ ਆਖਾ ਕਿਵ ਸਾਲਾਹੀ ਕਿਉ ਵਰਨੀ ਕਿਵ ਜਾਣਾ ॥','Kiv Kar Aakha Kiv Salahi Kio Varni Kev Janna II','','[{"roman": "Kiv Kar Aakha Kiv Salahi Kio Varni Kev Janna II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Как это описывать, Как восхвалять,Как рассказать О том, что за гранью Знания?','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(245,1,197,'ਨਾਨਕ ਆਖਣਿ ਸਭੁ ਕੋ ਆਖੈ ਇਕ ਦੂ ਇਕੁ ਸਿਆਣਾ ॥','Nanak, Akhunn Sabh Ko, Akheey, Ek Du Ek Sianna II','','[{"roman": "Nanak, Akhunn Sabh Ko, Akheey, Ek Du Ek Sianna II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Нанак говорит: полный рассказо состоянии Вечного Блаженства внутри меня таков (за пределами описания, повествования и восхваления),потому что каждое из моих чувств пробуждено','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(246,1,198,'ਵਡਾ ਸਾਹਿਬੁ ਵਡੀ ਨਾਈ ਕੀਤਾ ਜਾ ਕਾ ਹੋਵੈ ॥','Vada Sahib Vadee Nayee Keeta Ja Kaa Hovey II','','[{"roman": "Vada Sahib Vadee Nayee Keeta Ja Kaa Hovey II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Велик Мастер, Велики его Добродетели, что приводят к такому Становлению','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(247,1,199,'ਨਾਨਕ ਜੇ ਕੋ ਆਪੌ ਜਾਣੈ ਅਗੈ ਗਇਆ ਨ ਸੋਹੈ ॥੨੧॥','Nanak Jey Ko Apao Janney Agey Gya Na Sohey II 21 II','','[{"roman": "Nanak Jey Ko Apao Janney Agey Gya Na Sohey II 21 II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Нанак говорит:Если кто-то познаёт духовность очищения путём человеческих конструкций, то пройдя этот путь - не станет сиять от (внутренней) чистоты II21II','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(248,1,200,'ਪਾਤਾਲਾ ਪਾਤਾਲ ਲਖ ਆਗਾਸਾ ਆਗਾਸ ॥','Patala Patal Lakh, Agasa Agas II','','[{"roman": "Patala Patal Lakh, Agasa Agas II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','В таком пути человеческих конструкций есть Сотни тысяч низших подземелей (мыслей и чувств) под подземельями, как и Небес над Небесами','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(249,1,201,'ਓੜਕ ਓੜਕ ਭਾਲਿ ਥਕੇ ਵੇਦ ਕਹਨਿ ਇਕ ਵਾਤ ॥','Orruk Orruk Bhal Thakey Ved Kehen Ek Vat II','','[{"roman": "Orruk Orruk Bhal Thakey Ved Kehen Ek Vat II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Прибежищем среди прибежищ от этих изнурительных поисков является Одно ценное Знание','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(250,1,202,'ਸਹਸ ਅਠਾਰਹ ਕਹਨਿ ਕਤੇਬਾ ਅਸੁਲੂ ਇਕੁ ਧਾਤੁ ॥','Sehs Athara Kehn Kteba Aslu Ek Dhat II','','[{"roman": "Sehs Athara Kehn Kteba Aslu Ek Dhat II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Знание заключается в том, чтоСреди ~ 18 тысяч (бесчисленных) Индийских школ и Кетабов, повествующих о высшем и низшем - важнейшим является Один-Единственный Источник, не являющийся человеческой конструкцией','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(251,1,203,'ਲੇਖਾ ਹੋਇ ਤ ਲਿਖੀਐ ਲੇਖੈ ਹੋਇ ਵਿਣਾਸੁ ॥','Lekha Hoe Ta Likhiyey Leykhey Hoe Vinnas II','','[{"roman": "Lekha Hoe Ta Likhiyey Leykhey Hoe Vinnas II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Записав (внутрь) Одно Знание о Единственном-Источнике своего Прибежища – возникают дарственные счета, а Счета взыскательные - устраняются','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(252,1,204,'ਨਾਨਕ ਵਡਾ ਆਖੀਐ ਆਪੇ ਜਾਣੈ ਆਪੁ ॥੨੨॥','Nanak Vadda Akheeay Apey Janney Aap II 22 II','','[{"roman": "Nanak Vadda Akheeay Apey Janney Aap II 22 II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Нанак говорит:Высшим является то повествование,в котором “я” Знает “Я”(Подлинную Идентичность) II22II','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(253,1,205,'ਸਾਲਾਹੀ ਸਾਲਾਹਿ ਏਤੀ ਸੁਰਤਿ ਨ ਪਾਈਆ ॥','Salahi Salah Eti Surt Na Payeea II','','[{"roman": "Salahi Salah Eti Surt Na Payeea II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','То Восприятие, что выше всех Похвал, где “я” знает “Я”,Не достигается само собой','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(254,1,206,'ਨਦੀਆ ਅਤੈ ਵਾਹ ਪਵਹਿ ਸਮੁੰਦਿ ਨ ਜਾਣੀਅਹਿ ॥','Nadiya Atey Vah Pveh Samund Na Janneah II','','[{"roman": "Nadiya Atey Vah Pveh Samund Na Janneah II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Для реализации такого восприятияРеки и ручьи впали в Океан, став неразличимыми(Реки моего разума и чувств слились, чтобы очиститься в Океане)','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(255,1,207,'ਸਮੁੰਦ ਸਾਹ ਸੁਲਤਾਨ ਗਿਰਹਾ ਸੇਤੀ ਮਾਲੁ ਧਨੁ ॥','Samund Shah Sultan Girha Seytee Mal Dhan II','','[{"roman": "Samund Shah Sultan Girha Seytee Mal Dhan II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Океан – Шах, Султан, владеющий недвижимыми Горами драгоценностей и богатств','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(256,1,208,'ਕੀੜੀ ਤੁਲਿ ਨ ਹੋਵਨੀ ਜੇ ਤਿਸੁ ਮਨਹੁ ਨ ਵੀਸਰਹਿ ॥੨੩॥','Kirri Tul Na Hovni Je Tis Mnoh Na Visreh II 23 II','','[{"roman": "Kirri Tul Na Hovni Je Tis Mnoh Na Visreh II 23 II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Муравей – моё “я”, остаётся несравненнымЕсли не забывает об ЭтомII23II','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(257,1,209,'ਅੰਤੁ ਨ ਸਿਫਤੀ ਕਹਣਿ ਨ ਅੰਤੁ ॥','Aant Na Sifti Kehnn Na Aant II','','[{"roman": "Aant Na Sifti Kehnn Na Aant II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Предела нет Восхвалению,И нет предела обсуждениям о том осознании','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(258,1,210,'ਅੰਤੁ ਨ ਕਰਣੈ ਦੇਣਿ ਨ ਅੰਤੁ ॥','Aant Na Karnney Denn Na Aant II','','[{"roman": "Aant Na Karnney Denn Na Aant II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Исходящие из того восприятияНеизмеримы поступки, чей Вклад – не имеет предела','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(259,1,211,'ਅੰਤੁ ਨ ਵੇਖਣਿ ਸੁਣਣਿ ਨ ਅੰਤੁ ॥','Aant Na Vekhan Sunnen Na Aant II','','[{"roman": "Aant Na Vekhan Sunnen Na Aant II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Нет предела тому Ви́дению,Слышанию нет предела','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(260,1,212,'ਅੰਤੁ ਨ ਜਾਪੈ ਕਿਆ ਮਨਿ ਮੰਤੁ ॥','Aant Na Japey Kya Mun Munt II','','[{"roman": "Aant Na Japey Kya Mun Munt II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Нет предела тому Осознанию, Которое умом руководит','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(261,1,213,'ਅੰਤੁ ਨ ਜਾਪੈ ਕੀਤਾ ਆਕਾਰੁ ॥','Aant Na Japey Kita Akaar II','','[{"roman": "Aant Na Japey Kita Akaar II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Пределов нет способам выражения того Осознания','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(262,1,214,'ਅੰਤੁ ਨ ਜਾਪੈ ਪਾਰਾਵਾਰੁ ॥','Aant Na Japey Paravar II','','[{"roman": "Aant Na Japey Paravar II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Пределов нет у того Осознания – нет границ у выражающих его действий – совсем“Он” действует или “я” – в таком осознании нет границ между рекой и Океаном','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(263,1,215,'ਅੰਤ ਕਾਰਣਿ ਕੇਤੇ ਬਿਲਲਾਹਿ ॥','Antt Karann Keytey Bil-lahey II','','[{"roman": "Antt Karann Keytey Bil-lahey II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Из-за Пределов – множество бедствий','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(264,1,216,'ਤਾ ਕੇ ਅੰਤ ਨ ਪਾਏ ਜਾਹਿ ॥','Ta Kay Aant Na Paey Jahe II','','[{"roman": "Ta Kay Aant Na Paey Jahe II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Через такие Пределы никакого Слияния не случается','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(265,1,217,'ਏਹੁ ਅੰਤੁ ਨ ਜਾਣੈ ਕੋਇ ॥','Eh Aant Na Janney Koey II','','[{"roman": "Eh Aant Na Janney Koey II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Такого отсутствия пределов достижение – единично (редко)','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(266,1,218,'ਬਹੁਤਾ ਕਹੀਐ ਬਹੁਤਾ ਹੋਇ ॥','Bahuta Kaheay Bahuta Hoey II','','[{"roman": "Bahuta Kaheay Bahuta Hoey II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','В таком подлинном знании отсутствия пределов,Чем изобильнее мыслишь о нём – тем изобильнее Оно становится','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(267,1,219,'ਵਡਾ ਸਾਹਿਬੁ ਊਚਾ ਥਾਉ ॥','Vadda Sahib Uucha Thao II','','[{"roman": "Vadda Sahib Uucha Thao II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Возвышен Мастер – Океан, Возвышена Его Обитель','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(268,1,220,'ਊਚੇ ਉਪਰਿ ਊਚਾ ਨਾਉ ॥','Uchey Upar Ucha Nao II','','[{"roman": "Uchey Upar Ucha Nao II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Превыше всего на Возвышенности (совести) Высится Имя','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(269,1,221,'ਏਵਡੁ ਊਚਾ ਹੋਵੈ ਕੋਇ ॥','Evudd Ucha Hovey Koey II','','[{"roman": "Evudd Ucha Hovey Koey II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Через возвышение к Высокому муравей Сам становится Высоким','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(270,1,222,'ਤਿਸੁ ਊਚੇ ਕਉ ਜਾਣੈ ਸੋਇ ॥','Tis Uchey Ko Janney Soey II','','[{"roman": "Tis Uchey Ko Janney Soey II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Тот кто Возвысился таким образом – Осознаёт Истинность такого возвышения','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(271,1,223,'ਜੇਵਡੁ ਆਪਿ ਜਾਣੈ ਆਪਿ ਆਪਿ ॥','Jevudd Aap Janney Aap Aap II','','[{"roman": "Jevudd Aap Janney Aap Aap II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Муравей возвышен сам настолько насколько реализовал “Я” в “я”','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(272,1,224,'ਨਾਨਕ ਨਦਰੀ ਕਰਮੀ ਦਾਤਿ ॥੨੪॥','Nanak Nadri Karmi Daat II 24 II','','[{"roman": "Nanak Nadri Karmi Daat II 24 II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Нанак говорит: это путь дарованный Его БлагословениемII24II','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(273,1,225,'ਬਹੁਤਾ ਕਰਮੁ ਲਿਖਿਆ ਨਾ ਜਾਇ ॥','Bahuta Karam Likhiya, Na Jaye II','','[{"roman": "Bahuta Karam Likhiya, Na Jaye II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','(Нанак раскрывает природу благословений)Изобильны Благословения что пишутся внутрь, не прекращаясь(Природа Благословения - постоянность, изобилие, Духовная Сытость от них)','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(274,1,226,'ਵਡਾ ਦਾਤਾ ਤਿਲੁ ਨ ਤਮਾਇ ॥','Vadda Data Til Na Tamaye II','','[{"roman": "Vadda Data Til Na Tamaye II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','От таких благословений Великого Дающего – нет желания к кунжутным семечкам (к мирской похвале)','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(275,1,227,'ਕੇਤੇ ਮੰਗਹਿ ਜੋਧ ਅਪਾਰ ॥','Kaytey Manghey Jodh Apar II','','[{"roman": "Kaytey Manghey Jodh Apar II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','В таких благословенияхприобретено множество (внутренних) воинов ...','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(276,1,228,'ਕੇਤਿਆ ਗਣਤ ਨਹੀ ਵੀਚਾਰੁ ॥','Kaytia Gannut Nahi Vichar ||','','[{"roman": "Kaytia Gannut Nahi Vichar ||", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','… которым нет счёта и описания.','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(277,1,229,'ਕੇਤੇ ਖਪਿ ਤੁਟਹਿ ਵੇਕਾਰ ॥','Kaytey Khup Tuttey Veykar II','','[{"roman": "Kaytey Khup Tuttey Veykar II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Такими благословениями множество пороков устраняются в ходе изнурительной битвы','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(278,1,230,'ਕੇਤੇ ਲੈ ਲੈ ਮੁਕਰੁ ਪਾਹਿ ॥','Kaytey Ley Ley Mukhr Pahe II','','[{"roman": "Kaytey Ley Ley Mukhr Pahe II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','В таких благословенияхприобретается ритмично-музыкальное постоянство в устранении…','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(279,1,231,'ਕੇਤੇ ਮੂਰਖ ਖਾਹੀ ਖਾਹਿ ॥','Kaytay Murakh Khahi Khahey II','','[{"roman": "Kaytay Murakh Khahi Khahey II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','…множеств желаний, основанных на требованиях моих пороков','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(280,1,232,'ਕੇਤਿਆ ਦੂਖ ਭੂਖ ਸਦ ਮਾਰ ॥','Kaytiya Dukh Bhukh Sud Mar II','','[{"roman": "Kaytiya Dukh Bhukh Sud Mar II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Эти благословения – есть призыв избавиться от бесчисленных печалей, связанных с желаниями моих пороков','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(281,1,233,'ਏਹਿ ਭਿ ਦਾਤਿ ਤੇਰੀ ਦਾਤਾਰ ॥','Eh Bhe Dat Teri Datar II','','[{"roman": "Eh Bhe Dat Teri Datar II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','И само это призывание – также является твоим благословением для меня, Податель','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(282,1,234,'ਬੰਦਿ ਖਲਾਸੀ ਭਾਣੈ ਹੋਇ ॥','Bund Khlasi Bhanney Hoey II','','[{"roman": "Bund Khlasi Bhanney Hoey II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Освобождение от рабства желаний также происходит в указе Твоих благословений.','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(283,1,235,'ਹੋਰੁ ਆਖਿ ਨ ਸਕੈ ਕੋਇ ॥','Hor Akh Na Sakey Koey II','','[{"roman": "Hor Akh Na Sakey Koey II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Я не могу приписать это освобождение ничему, кроме Твоего Благословения.','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(284,1,236,'ਜੇ ਕੋ ਖਾਇਕੁ ਆਖਣਿ ਪਾਇ ॥','Je Ko Khayek Akhann Paye II','','[{"roman": "Je Ko Khayek Akhann Paye II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Пытаться искать это освобождение у чего-либо, кроме Твоих благословений, значит быть непросвещенным','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(285,1,237,'ਓਹੁ ਜਾਣੈ ਜੇਤੀਆ ਮੁਹਿ ਖਾਇ ॥','Oh Janney Jaytia Moh Khaye II','','[{"roman": "Oh Janney Jaytia Moh Khaye II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Думать так – какая же это пощёчина!','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(286,1,238,'ਆਪੇ ਜਾਣੈ ਆਪੇ ਦੇਇ ॥','Apey Janney Apey Dey II','','[{"roman": "Apey Janney Apey Dey II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Думавший так вдовольОтпускает такие думы…','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(287,1,239,'ਆਖਹਿ ਸਿ ਭਿ ਕੇਈ ਕੇਇ ॥','Akhey Se Bhe Keiyi Kay II','','[{"roman": "Akhey Se Bhe Keiyi Kay II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Это признают и чувства и разум, и те и эти.','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(288,1,240,'ਜਿਸ ਨੋ ਬਖਸੇ ਸਿਫਤਿ ਸਾਲਾਹ ॥','Jis No Bhaksay Sift Salah II','','[{"roman": "Jis No Bhaksay Sift Salah II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Кого ни благословишь, о Достойный Похвалы…','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(289,1,241,'ਨਾਨਕ ਪਾਤਿਸਾਹੀ ਪਾਤਿਸਾਹੁ ॥੨੫॥','Nanak Patshahi Patshah II 25 II','','[{"roman": "Nanak Patshahi Patshah II 25 II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Нанак, тот Патишах среди Патишахов II25II','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(290,1,242,'ਅਮੁਲ ਗੁਣ ਅਮੁਲ ਵਾਪਾਰ ॥','Amul Gunn Amul Vapar II','','[{"roman": "Amul Gunn Amul Vapar II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Для Патишаха среди Патишахов, стремящегося к вершине духовности,Бесценны божественные атрибуты и Бесценна торговля ими – выражением в мир','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(291,1,243,'ਅਮੁਲ ਵਾਪਾਰੀਏ ਅਮੁਲ ਭੰਡਾਰ ॥','Amul Vapareay Amul Bhandar II','','[{"roman": "Amul Vapareay Amul Bhandar II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Бесценны практикующие Божественные Атрибуты И Бесценно их накопление','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(292,1,244,'ਅਮੁਲ ਆਵਹਿ ਅਮੁਲ ਲੈ ਜਾਹਿ ॥','Amul Aveh Amul Ley Jahe II','','[{"roman": "Amul Aveh Amul Ley Jahe II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Бесценно их нисхождение, Бесценно то ритмичное-постоянство, что требует их практики','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(293,1,245,'ਅਮੁਲ ਭਾਇ ਅਮੁਲਾ ਸਮਾਹਿ ॥','Amul Bhaye Amula Smahe II','','[{"roman": "Amul Bhaye Amula Smahe II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Бесценна Любовь к Ним,И Бесценно Растворение в Них','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(294,1,246,'ਅਮੁਲੁ ਧਰਮੁ ਅਮੁਲੁ ਦੀਬਾਣੁ ॥','Amul Dharam Amul Diban II','','[{"roman": "Amul Dharam Amul Diban II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Бесценны решенияПринятые в Бесценном СудеЕго Хукама','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(295,1,247,'ਅਮੁਲੁ ਤੁਲੁ ਅਮੁਲੁ ਪਰਵਾਣੁ ॥','Amul Tul Amul Parvann II','','[{"roman": "Amul Tul Amul Parvann II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Бесценен разум подобный Весам,И Бесценен весовой камень – Хукам','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(296,1,248,'ਅਮੁਲੁ ਬਖਸੀਸ ਅਮੁਲੁ ਨੀਸਾਣੁ ॥','Amul Bakhsis Amul Nisann II','','[{"roman": "Amul Bakhsis Amul Nisann II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Бесценен Бакшиш, Полученный под Его Бесценной Авторитетностью','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(297,1,249,'ਅਮੁਲੁ ਕਰਮੁ ਅਮੁਲੁ ਫੁਰਮਾਣੁ ॥','Amul Karm Amul Furmann II','','[{"roman": "Amul Karm Amul Furmann II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Бесценна Милость, Дарованная Бесценным Распоряжением (Хукама)','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(298,1,250,'ਅਮੁਲੋ ਅਮੁਲੁ ਆਖਿਆ ਨ ਜਾਇ ॥','Amulo Amul Akhiya Na Jaye II','','[{"roman": "Amulo Amul Akhiya Na Jaye II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Бесценней Бесценного –Невыразима','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(299,1,251,'ਆਖਿ ਆਖਿ ਰਹੇ ਲਿਵ ਲਾਇ ॥','Akh Akh Rhey Liv Laye II','','[{"roman": "Akh Akh Rhey Liv Laye II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Речь всех Речей – проникнуться божественными атрибутами, их милостью','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(300,1,252,'ਆਖਹਿ ਵੇਦ ਪਾਠ ਪੁਰਾਣ ॥','Akhey Ved Path Purann II','','[{"roman": "Akhey Ved Path Purann II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Проникнувшись Милостью Настоящего, открывается внутренняя реальность речений Вед и Пуран','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(301,1,253,'ਆਖਹਿ ਪੜੇ ਕਰਹਿ ਵਖਿਆਣ ॥','Akhey Parrey Kreh Vakhiyann II','','[{"roman": "Akhey Parrey Kreh Vakhiyann II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Проникнувшись Милостью Настоящего, открывается внутренняя реальность тех, кто читает и обсуждает эти тексты','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(302,1,254,'ਆਖਹਿ ਬਰਮੇ ਆਖਹਿ ਇੰਦ ॥','Akhey Barmey Akhey Ind II','','[{"roman": "Akhey Barmey Akhey Ind II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Проникнувшись Милостью Настоящего, открывается внутренняя реальность речений, относящихся к Брахме и Индре','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(303,1,255,'ਆਖਹਿ ਗੋਪੀ ਤੈ ਗੋਵਿੰਦ ॥','Akhey Gopi Tey Govind II','','[{"roman": "Akhey Gopi Tey Govind II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Проникнувшись Милостью Настоящего, открывается внутренняя реальность речений относящихся к Гопи и их Говинду','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(304,1,256,'ਆਖਹਿ ਈਸਰ ਆਖਹਿ ਸਿਧ॥','Akhey Esar Akhey Sidh II','','[{"roman": "Akhey Esar Akhey Sidh II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Проникнувшись Милостью Настоящего, открывается внутренняя реальность речений относящихся к Ишваре, речений Сиддхов','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(305,1,257,'ਆਖਹਿ ਕੇਤੇ ਕੀਤੇ ਬੁਧ ॥','Akhey Kaytey Kitay Budh II','','[{"roman": "Akhey Kaytey Kitay Budh II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Проникнувшись Милостью Настоящего, открывается внутренняя реальность речений, содержащих множества духовных озарений','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(306,1,258,'ਆਖਹਿ ਦਾਨਵ ਆਖਹਿ ਦੇਵ॥','Akhey Danv Akhey Dev II','','[{"roman": "Akhey Danv Akhey Dev II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Проникнувшись Милостью Настоящего, открывается внутренняя реальность речений Данавов и Дэвов','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(307,1,259,'ਆਖਹਿ ਸੁਰਿ ਨਰ ਮੁਨਿ ਜਨ ਸੇਵ ॥','Akhey Sur Nar,Mun Jan, Sev II','','[{"roman": "Akhey Sur Nar,Mun Jan, Sev II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Проникнувшись Милостью Настоящего, открывается внутренняя реальность речений духовных людей, их лидеров и их последователей','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(308,1,260,'ਕੇਤੇ ਆਖਹਿ ਆਖਣਿ ਪਾਹਿ ॥','Kaytey Akhay Akhann Pahe II','','[{"roman": "Kaytey Akhay Akhann Pahe II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Проникнувшись Милостью Настоящего, открывается внутренняя реальность тех речений, что изречены очень умело','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(309,1,261,'ਕੇਤੇ ਕਹਿ ਕਹਿ ਉਠਿ ਉਠਿ ਜਾਹਿ ॥','Kaytay Keh Keh Uth Uth Jahe II','','[{"roman": "Kaytay Keh Keh Uth Uth Jahe II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Проникнувшись Милостью Настоящего, открывается внутренняя реальность изобильных, старательных, дотошных речений','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(310,1,262,'ਏਤੇ ਕੀਤੇ ਹੋਰਿ ਕਰੇਹਿ ॥','Eytey Kitey Hor Kreh II','','[{"roman": "Eytey Kitey Hor Kreh II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Должно ли ещё появиться столько же речений, что уже существуют?','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(311,1,263,'ਤਾ ਆਖਿ ਨ ਸਕਹਿ ਕੇਈ ਕੇਇ ॥','Ta Akh Na Sakhey Keiyi Kay II','','[{"roman": "Ta Akh Na Sakhey Keiyi Kay II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Появись и они, ни одно из них не изрекло бы исчерпывающе','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(312,1,264,'ਜੇਵਡੁ ਭਾਵੈ ਤੇਵਡੁ ਹੋਇ ॥','Jevud Bhavey Tevud Hoe II','','[{"roman": "Jevud Bhavey Tevud Hoe II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Милость тем Величественнее –чем Величественнее Становление…','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(313,1,265,'ਨਾਨਕ ਜਾਣੈ ਸਾਚਾ ਸੋਇ ॥','Nanak Janney Sacha Soyey II','','[{"roman": "Nanak Janney Sacha Soyey II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','…Нанак говорит: такое становление, в котором осознаётся Настоящий!','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(314,1,266,'ਜੇ ਕੋ ਆਖੈ ਬੋਲੁਵਿਗਾੜੁ ॥','Je Ko Akhey Bol Vigarr II','','[{"roman": "Je Ko Akhey Bol Vigarr II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Тот кто изрекает (внешне и мысленно) обратное…','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(315,1,267,'ਤਾ ਲਿਖੀਐ ਸਿਰਿ ਗਾਵਾਰਾ ਗਾਵਾਰੁ ॥੨੬॥','Ta Likhiya Ser Gavara Gavar II 26 II','','[{"roman": "Ta Likhiya Ser Gavara Gavar II 26 II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Тот пишет в ум абсолютную непросветленность','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(316,1,268,'ਸੋ ਦਰੁ ਕੇਹਾ ਸੋ ਘਰੁ ਕੇਹਾ ਜਿਤੁ ਬਹਿ ਸਰਬ ਸਮਾਲੇ ॥','So Dar Keha So Ghar Keha Jit Beh Sarb Smaley II','','[{"roman": "So Dar Keha So Ghar Keha Jit Beh Sarb Smaley II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Проникнувшись милостью…Как прекрасна та Дверь (врата восприятия),И как прекрасен тот Дом (обитель переживания),Где правит Высший Хозяин','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(317,1,269,'ਵਾਜੇ ਨਾਦ ਅਨੇਕ ਅਸੰਖਾ ਕੇਤੇ ਵਾਵਣਹਾਰੇ ॥','Vajey Nad Anek Asankha Kaytey Vavanhare II','','[{"roman": "Vajey Nad Anek Asankha Kaytey Vavanhare II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','В том домеМножества глубоких-мыслей, подобных сакральным музыкальным звукам, Бесчисленное множество композиторов, что их составляют','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(318,1,270,'ਕੇਤੇ ਰਾਗ ਪਰੀ ਸਿਉ ਕਹੀਅਨਿ ਕੇਤੇ ਗਾਵਣਹਾਰੇ ॥','Kaytey Rag Pri Sio Kahean Kaytay Gavanhare II','','[{"roman": "Kaytey Rag Pri Sio Kahean Kaytay Gavanhare II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','В том домеМножества возвышенных чувств, подобных раагам и тактам, и множества способов их выражения, подобных певцам что их воспевают…','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(319,1,271,'ਗਾਵਹਿ ਤੁਹਨੋ ਪਉਣੁ ਪਾਣੀ ਬੈਸੰਤਰੁ ਗਾਵੈ ਰਾਜਾ ਧਰਮੁ ਦਮੁ ਦਮੁ','Gaveh Tuhno Paon Panni Baisantar Gavei Raja Dharam Duarey II','','[{"roman": "Gaveh Tuhno Paon Panni Baisantar Gavei Raja Dharam Duarey II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','В том доме Чувства и Мысли пребывают в музыкальной-гармонии с Тобойтак же природно, как воздух, вода и огонь, которыми ты правишь.Здесь они воспевают Врата к Твоему Закону, о Радж!','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(320,1,272,'ਗਾਵਹਿ ਚਿਤੁ ਗੁਪਤੁ ਲਿਖਿ ਜਾਣਹਿ ਲਿਖਿ ਲਿਖਿ ਧਰਮੁ ਵੀਚਾਰੇ ॥','Gaveh Chit Gupt Likh Janeh Likh Likh Dharam Vicharey II','','[{"roman": "Gaveh Chit Gupt Likh Janeh Likh Likh Dharam Vicharey II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','В гармонии с таким господством,Внутренний портрет становится достойнымТвоей записи,И, все те мысли и чувства, оформляют себяв Запись Закона Превышнего','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(321,1,273,'ਗਾਵਹਿ ਈਸਰੁ ਬਰਮਾ ਦੇਵੀ ਸੋਹਨਿ ਸਦਾ ਸਵਾਰੇ ॥','Gaveh Esar Bhrama Devi Sohan Sada Svare II','','[{"roman": "Gaveh Esar Bhrama Devi Sohan Sada Svare II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Находясь в гармонии с такой записью Владыки, внутренний портрет обрёл красоту Вечности, будучи украшенным Щитом божественных атрибутов','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(322,1,274,'ਗਾਵਹਿ ਇੰਦ ਇਦਾਸਣਿ ਬੈਠੇ ਦੇਵਤਿਆ ਦਰਿ ਨਾਲੇ ॥','Gaveh Ind Indasan Baithey Devtian Dar Naley II','','[{"roman": "Gaveh Ind Indasan Baithey Devtian Dar Naley II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','В такой гармонии, Совесть, исходящаяиз Владыки-Всех-Чувств (Инд), восседает на престоле разума. Разум становится той Дверью в Высшую Обитель, воспевая божественность внутри','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(323,1,275,'ਗਾਵਹਿ ਸਿਧ ਸਮਾਧੀ ਅੰਦਰਿ ਗਾਵਨਿ ਸਾਧ ਵਿਚਾਰੇ ॥','Gaveh Sidh Smadhi Andar Gavan Sadh Vicharey II','','[{"roman": "Gaveh Sidh Smadhi Andar Gavan Sadh Vicharey II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','В такой Гармонии с Высшим Сиддхом, разум погружён в самадхи, и внутри – божественный дискурс','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(324,1,276,'ਗਾਵਨਿ ਜਤੀ ਸਤੀ ਸੰਤੋਖੀ ਗਾਵਹਿ ਵੀਰ ਕਰਾਰੇ ॥','Gavan Jati Sati Santokhi Gaveh Vir Kararay II','','[{"roman": "Gavan Jati Sati Santokhi Gaveh Vir Kararay II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','От преображения природы мышления путём такой Гармонии,разум звучит в ладу с нравственностью, чистотой добродетелей,покоем удовлетворённости,и в Гармонии с героическим мужеством.','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(325,1,277,'ਗਾਵਨਿ ਪੰਡਿਤ ਪੜਨਿ ਰਖੀਸਰ ਜੁਗੁ ਜੁਗੁ ਵੇਦਾ ਨਾਲੇ ॥','Gavan Pandit Paran Rakhisar Jug Jug Veda Naley II','','[{"roman": "Gavan Pandit Paran Rakhisar Jug Jug Veda Naley II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Мой разумподобен учёному пандиту, что находится в гармонии с обретением просветления и внутреннего знания – из (внутренних) Юги в Югу.','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(326,1,278,'ਗਾਵਹਿ ਮੋਹਣੀਆ ਮਨੁ ਮੋਹਨਿ ਸੁਰਗਾ ਮਛ ਪਇਆਲੇ ॥','Gaveh Mohnnea Mun Mohan Surga Mach Pyaley II','','[{"roman": "Gaveh Mohnnea Mun Mohan Surga Mach Pyaley II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','В своём воспеванииМой разум всегда Стоит в Красоте Настоящего,в делах духовных и делах мирских','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(327,1,279,'ਗਾਵਨਿ ਰਤਨ ਉਪਾਏ ਤੇਰੇ ਅਠਸਠਿ ਤੀਰਥ ਨਾਲੇ ॥','Gavan Ratan Upaye Teyrey Athsath Teerath Naley II','','[{"roman": "Gavan Ratan Upaye Teyrey Athsath Teerath Naley II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','В такой гармонии с Тобой, я наполнил разум-дом Твоими Драгоценностями (атрибутами),очистив его от временно́го','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(328,1,280,'ਗਾਵਹਿ ਜੋਧ ਮਹਾਬਲ ਸੂਰਾ ਗਾਵਹਿ ਖਾਣੀ ਚਾਰੇ ॥','Gaveh Jodh Mahabal Sura Gavhey Khanni Charey II','','[{"roman": "Gaveh Jodh Mahabal Sura Gavhey Khanni Charey II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Находясь в Гармонии с Ооангкар, как с Источником Великолепия, я тем самым нахожусь в гармонии с отвагой, храбростью и доблестью','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(329,1,281,'ਗਾਵਹਿ ਖੰਡ ਮੰਡਲ ਵਰਭੰਡਾ ਕਰਿ ਕਰਿ ਰਖੇ ਧਾਰੇ ॥','Gaveh Khand Mandul Varbhanda Kar Kar Rakhey Dharey II','','[{"roman": "Gaveh Khand Mandul Varbhanda Kar Kar Rakhey Dharey II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Находясь в Гармонии с Тобой, мои отдельные мысли, их формирования, и весь мой разум закрепились в Тебе как в опоре.','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(330,1,282,'ਸੇਈ ਤੁਧੁਨੋ ਗਾਵਹਿ ਜੋ ਤੁਧੁ ਭਾਵਨਿ ਰਤੇ ਤੇਰੇ ਭਗਤ ਰਸਾਲੇ ॥','Seyi Tudhno Gavhe Jo Tudh Bhavan Ratey Teyrey Bhagat Rasaley II','','[{"roman": "Seyi Tudhno Gavhe Jo Tudh Bhavan Ratey Teyrey Bhagat Rasaley II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Те, кто живут в гармонии с Тобой, Ооангкар – Хозяин Дома,проникнуты твоей Любовью, преданностью и сущностью твоих атрибутов.','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(331,1,283,'ਹੋਰਿ ਕੇਤੇ ਗਾਵਨਿ ਸੇ ਮੈ ਚਿਤਿ ਨ ਆਵਨਿ ਨਾਨਕੁ ਕਿਆ ਵੀਚਾਰੇ ॥','Hor Kaytey Gavan Sey Mey Chit Na Avan Nanak Kya Vicharey II','','[{"roman": "Hor Kaytey Gavan Sey Mey Chit Na Avan Nanak Kya Vicharey II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Нанак говорит:Находиться в гармонии с Тобой – значить открывать для себя множество новых атрибутов, разговор о которых за пределами мыслительных способностей','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(332,1,284,'ਸੋਈ ਸੋਈ ਸਦਾ ਸਚੁ ਸਾਹਿਬੁ ਸਾਚਾ ਸਾਚੀ ਨਾਈ ॥','Soi Soi Sada Sach Sahib Sacha Sachi Naie II','','[{"roman": "Soi Soi Sada Sach Sahib Sacha Sachi Naie II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Каждая из моих добродетелей(внутри моего “дома”) исходит от Вечного Мастера, который является их Домовладельцем','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(333,1,285,'ਹੈ ਭੀ ਹੋਸੀ ਜਾਇ ਨ ਜਾਸੀ ਰਚਨਾ ਜਿਨਿ ਰਚਾਈ ॥','Hai Bhi Hosi Jaye Na Jasi Rachna Jinn Rachyee II','','[{"roman": "Hai Bhi Hosi Jaye Na Jasi Rachna Jinn Rachyee II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Божественные Добродетели проявились во мне Cейчас и останутся со мной –Духовность Сикхи, которая возникла во мне, не разрушится…','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(334,1,286,'ਰੰਗੀ ਰੰਗੀ ਭਾਤੀ ਕਰਿ ਕਰਿ ਜਿਨਸੀ ਮਾਇਆ ਜਿਨਿ ਉਪਾਈ ॥','Rangi Rangi Bhati Kar Kar Jinsi Maya Jin Upayi II','','[{"roman": "Rangi Rangi Bhati Kar Kar Jinsi Maya Jin Upayi II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','…из-за разнообразия красок и множества граней иллюзий, создающихся и создающихся разумом, подобном Майе','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(335,1,287,'ਕਰਿ ਕਰਿ ਵੇਖੈ ਕੀਤਾ ਆਪਣਾ ਜਿਵ ਤਿਸ ਦੀ ਵਡਿਆਈ ॥','Kar Kar Vekhey Kita Apnna Jiv Tis Di Vaddeayi II','','[{"roman": "Kar Kar Vekhey Kita Apnna Jiv Tis Di Vaddeayi II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','И в таком само-созидании даже те иллюзии, которые были достойными само-восхваления, больше не являются достойными этого','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(336,1,288,'ਜੋ ਤਿਸੁ ਭਾਵੈ ਸੋਈ ਕਰਸੀ ਹੁਕਮੁ ਨ ਕਰਣਾ ਜਾਈ ॥','Jo Tis Bhavey Soyi Karsi Hukum Na Karna Jayi II','','[{"roman": "Jo Tis Bhavey Soyi Karsi Hukum Na Karna Jayi II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Находясь в гармонии с Тобой –мой разум, отказавшись от желания командовать, теперь берется только за то,что согласуется с Хукамом – тем что угодно Тебе','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(337,1,289,'ਸੋ ਪਾਤਿਸਾਹੁ ਸਾਹਾ ਪਾਤਿਸਾਹਿਬੁ ਨਾਨਕ ਰਹਣੁ ਰਜਾਈ ॥੨੭॥','So Patsah Saha Patsahib Nanak Rahen Rajayi II 27 II','','[{"roman": "So Patsah Saha Patsahib Nanak Rahen Rajayi II 27 II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Такова природа Патишаха, кто Патишах среди Патишахов!Нанак говорит: пребывай в потоке письма его Хукама! II27II','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(338,1,290,'ਮੁੰਦਾ ਸੰਤੋਖੁ ਸਰਮੁ ਪਤੁ ਝੋਲੀ ਧਿਆਨ ਕੀ ਕਰਹਿ ਬਿਭੂਤਿ ॥','Munda Santokh Sarm Pat Jholi Dhiyan Ki Kreh Bhebhut II','','[{"roman": "Munda Santokh Sarm Pat Jholi Dhiyan Ki Kreh Bhebhut II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Сокровищница разума в том Домезапечатана в удовлетворенности,и достоинство чувствподобных одежде,усердно сосредоточено в пополнении сокровищницы','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(339,1,291,'ਖਿੰਥਾ ਕਾਲੁ ਕੁਆਰੀ ਕਾਇਆ ਜੁਗਤਿ ਡੰਡਾ ਪਰਤੀਤਿ ॥','Khintha Kal Kuari Kaya Juget Danda Parteet II','','[{"roman": "Khintha Kal Kuari Kaya Juget Danda Parteet II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Тело и его чувства – изношенная одежда времени.Через усердиев пополнении сокровищницы разумаОно освобождается от пороков при жизни.В этом освобожденииВера в божественные атрибутыподобна посоху, на которую опирается путешественник','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(340,1,292,'ਆਈ ਪੰਥੀ ਸਗਲ ਜਮਾਤੀ ਮਨਿ ਜੀਤੈ ਜਗੁ ਜੀਤੁ ॥','Ayi Panthi Sagal Jamati Mun Jitei Jug Jeet II','','[{"roman": "Ayi Panthi Sagal Jamati Mun Jitei Jug Jeet II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Опора на божественные атрибуты, как на посох путешественникаЕсть Высший Путь (пантх)Для всего Человечества.Путь, в котором разум, подобный сокровищнице, выигрывает власть над ценностью временно́го','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(341,1,293,'ਆਦੇਸੁ ਤਿਸੈ ਆਦੇਸੁ ॥','Adeys Tisey Adeys II','','[{"roman": "Adeys Tisey Adeys II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Я подчиняюсь в знак почтения только…','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(342,1,294,'ਆਦਿ ਅਨੀਲੁ ਅਨਾਦਿ ਅਨਾਹਤਿ ਜੁਗੁ ਜੁਗੁ ਏਕੋ ਵੇਸੁ ॥੨੮॥','Aad Anil Anad Anahat Jug Jug Eko Veis II 28 II','','[{"roman": "Aad Anil Anad Anahat Jug Jug Eko Veis II 28 II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Изначальному, (что был со мной в начале меня),Безупречному, проявляющемуся безударным звуком Совести Неизменно во все мои временаII28II','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(343,1,295,'ਭੁਗਤਿ ਗਿਆਨੁ ਦਇਆ ਭੰਡਾਰਣਿ ਘਟਿ ਘਟਿ ਵਾਜਹਿ ਨਾਦ ॥','Bhugat Gyan Dya Bhandaran Ghat Ghat Vajey Nad II','','[{"roman": "Bhugat Gyan Dya Bhandaran Ghat Ghat Vajey Nad II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Мой разум наслаждается Просветлённым Знанием, рожденным от Сочувствия; Став Сокровищницей Сочувствия,он гармонично-резонирует с Повелением Создателя','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(344,1,296,'ਆਪਿ ਨਾਥੁ ਨਾਥੀ ਸਭ ਜਾ ਕੀ ਰਿਧਿ ਸਿਧਿ ਅਵਰਾ ਸਾਦ ॥','Aap Nath Nathi Sabh Ja Ke Ridh Sidh Avra Saad II','','[{"roman": "Aap Nath Nathi Sabh Ja Ke Ridh Sidh Avra Saad II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Просветленное знание Сочувствия состоит в том, что Он Сам – Владыка Владык, а поиск риддх и сиддх (сверхъестественных сил) Это попытка обойти его Хукам(Hukmey Andar Sabh Ko – Bahar Hukam Na Koeye, это тот Хукам который является причиной всего, что предшествует идее влияния и силе собственного выбора)','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(345,1,297,'ਸੰਜੋਗੁ ਵਿਜੋਗੁ ਦੁਇ ਕਾਰ ਚਲਾਵਹਿ ਲੇਖੇ ਆਵਹਿ ਭਾਗ ॥','Sanjog Vijog Doey Kar Chalaveh Lekhey Avey Bhag II','','[{"roman": "Sanjog Vijog Doey Kar Chalaveh Lekhey Avey Bhag II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Просветленное знание Сочувствия состоит в том, чтоМысли, ведущие к соединению и разделению с его Повелением, определяют написание моей духовной судьбы','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(346,1,298,'ਆਦੇਸੁ ਤਿਸੈ ਆਦੇਸੁ ॥','Adeys Tisey Adeys II','','[{"roman": "Adeys Tisey Adeys II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Я подчиняюсь в знак почтения только…','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(347,1,299,'ਆਦਿ ਅਨੀਲੁ ਅਨਾਦਿ ਅਨਾਹਤਿ ਜੁਗੁ ਜੁਗੁ ਏਕੋ ਵੇਸੁ ॥੨੯॥','Aad Anil Anad Anahat Jug Jug Eko Veis II 29 II','','[{"roman": "Aad Anil Anad Anahat Jug Jug Eko Veis II 29 II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Изначальному, (что был со мной в начале меня),Безупречному, проявляющемуся безударным звуком Совести Неизменно во все мои временаII29II','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(348,1,300,'ਏਕਾ ਮਾਈ ਜੁਗਤਿ ਵਿਆਈ ਤਿਨਿ ਚੇਲੇ ਪਰਵਾਣੁ ॥','Eka Mayi Jugt Viayi Tin Chayley Parvann II','','[{"roman": "Eka Mayi Jugt Viayi Tin Chayley Parvann II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','(Разум Единый с Создателем)Путь такого Сочувствияв моём Едином РазумеСоздаёт приемлимых для Него Спутников, что поддерживают его путешествие в потоке Хукама','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(349,1,301,'ਇਕੁ ਸੰਸਾਰੀ ਇਕੁ ਭੰਡਾਰੀ ਇਕੁ ਲਾਏ ਦੀਬਾਣੁ ॥','Ek Sansari Ek Bhandari Ek Laye Dibann II','','[{"roman": "Ek Sansari Ek Bhandari Ek Laye Dibann II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','(Спутник = Мысли, Результаты) Один спутник в разуме относится к Временно́му (Мирскому),Один спутник к Сокровищнице, (Божественному), Один спутник к занимает место в Суде, и выносит Суждение о природе порока и добродетели','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(350,1,302,'ਜਿਵ ਤਿਸੁ ਭਾਵੈ ਤਿਵੈ ਚਲਾਵੈ ਜਿਵ ਹੋਵੈ ਫੁਰਮਾਣੁ ॥','Jiv Tis Bhavey Tivei Chalavey Jiv Hovei Furmann II','','[{"roman": "Jiv Tis Bhavey Tivei Chalavey Jiv Hovei Furmann II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Такой Единый Разум с его Спутникамиследует команде своего суждения о природе порока и добродетели','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(351,1,303,'ਓਹੁ ਵੇਖੈ ਓਨਾ ਨਦਰਿ ਨ ਆਵੈ ਬਹੁਤਾ ਏਹੁ ਵਿਡਾਣੁ ॥','Oh Vekhei Una Nadar Na Avei Bhauta Eh Vidann II','','[{"roman": "Oh Vekhei Una Nadar Na Avei Bhauta Eh Vidann II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Мой разум судит: в Благодати Просветления через Сонастроенность с Ним, пороки перестают существовать, вот такого изобилия сей акт','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(352,1,304,'ਆਦੇਸੁ ਤਿਸੈ ਆਦੇਸੁ ॥','Adeys Tisey Adeys ||','','[{"roman": "Adeys Tisey Adeys ||", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Я подчиняюсь в знак почтения только…','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(353,1,305,'ਆਦਿ ਅਨੀਲੁ ਅਨਾਦਿ ਅਨਾਹਤਿ ਜੁਗੁ ਜੁਗੁ ਏਕੋ ਵੇਸੁ ॥੩੦॥','Aad Anil Anad Anahat Jug Jug Eko Veis II 30 II','','[{"roman": "Aad Anil Anad Anahat Jug Jug Eko Veis II 30 II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Изначальному, (что был со мной в начале меня),Безупречному, проявляющемуся безударным звуком Совести Неизменно во все мои временаII30II','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(354,1,306,'ਆਸਣੁ ਲੋਇ ਲੋਇ ਭੰਡਾਰ ॥','Asan Loey Loey Bhandar II','','[{"roman": "Asan Loey Loey Bhandar II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Царит в разумесияющая божественными атрибутами Сокровищница','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(355,1,307,'ਜੋ ਕਿਛੁ ਪਾਇਆ ਸੁ ਏਕਾ ਵਾਰ ॥','Jo Kich Paya So Eka Var II','','[{"roman": "Jo Kich Paya So Eka Var II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Всё Твоё сокровищевоцарилось там в результата одного полного подчинения разума.','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(356,1,308,'ਕਰਿ ਕਰਿ ਵੇਖੈ ਸਿਰਜਣਹਾਰੁ ॥','Kar Kar Veykhei Sirjanhaar II','','[{"roman": "Kar Kar Veykhei Sirjanhaar II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Таким подчинением узреешь Создателя','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(357,1,309,'ਨਾਨਕ ਸਚੇ ਕੀ ਸਾਚੀ ਕਾਰ ॥','Nanak Sachay Ki Sachi Kar II','','[{"roman": "Nanak Sachay Ki Sachi Kar II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Нанак говорит: Божественен Тот, кому подчинён Разум, И поэтому Божественно такое подчинение','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(358,1,310,'ਆਦੇਸੁ ਤਿਸੈ ਆਦੇਸੁ ॥','Adeys Tisey Adeys ||','','[{"roman": "Adeys Tisey Adeys ||", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Я подчиняюсь в знак почтения только…','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(359,1,311,'ਆਦਿ ਅਨੀਲੁ ਅਨਾਦਿ ਅਨਾਹਤਿ ਜੁਗੁ ਜੁਗੁ ਏਕੋ ਵੇਸੁ ॥੩੧॥','Aad Anil Anad Anahat Jug Jug Eko Veis II 31','','[{"roman": "Aad Anil Anad Anahat Jug Jug Eko Veis II 31", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Изначальному, (что был со мной в начале меня),Безупречному, проявляющемуся безударным звуком Совести Неизменно во все мои временаII31II','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(360,1,312,'ਇਕ ਦੂ ਜੀਭੌ ਲਖ ਹੋਹਿ ਲਖ ਹੋਵਹਿ ਲਖ ਵੀਸ ॥','Ek Du Jebhau Lakh Hohe Lakh Hovey Lakh Vees II','','[{"roman": "Ek Du Jebhau Lakh Hohe Lakh Hovey Lakh Vees II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Если один языкпревратится в сто тысяч,и каждый из этих ста тысячумножится ещё на двадцать по сто тысяч','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(361,1,313,'ਲਖੁ ਲਖੁ ਗੇੜਾ ਆਖੀਅਹਿ ਏਕੁ ਨਾਮੁ ਜਗਦੀਸ ॥','Lakh Lakh Gera Aakhyeah Ekh Naam Jugdees II','','[{"roman": "Lakh Lakh Gera Aakhyeah Ekh Naam Jugdees II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','…и если этими двадцатью сотнями тысяч языковсотни тысяч раз повторять одно-единственное Имя Создателя,— это будет не способ (33 паури – акхан джор чупэ нэх джор)','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(362,1,314,'ਏਤੁ ਰਾਹਿ ਪਤਿ ਪਵੜੀਆ ਚੜੀਐ ਹੋਇ ਇਕੀਸ ॥','Eyt Rah Putt Pavreeah Chareeah Hoye Ekees II','','[{"roman": "Eyt Rah Putt Pavreeah Chareeah Hoye Ekees II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Чтобы стать Единым с Создателем нужно возвышать свою совестьступень за ступенью.','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(363,1,315,'ਸੁਣਿ ਗਲਾ ਆਕਾਸ ਕੀ ਕੀਟਾ ਆਈ ਰੀਸ ॥','Sun Gallan Akaas Kee Keeta Aiyee Rees II','','[{"roman": "Sun Gallan Akaas Kee Keeta Aiyee Rees II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Услышав речи о небесной духовности,муравьиная духовностьначинает подражать ей, сотнями тысяч языков вторя Имя Единого.','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(364,1,316,'ਨਾਨਕ ਨਦਰੀ ਪਾਈਐ ਕੂੜੀ ਕੂੜੈ ਠੀਸ ॥੩੨॥','Nanak Nadree Payeah Kooree Korey Thees II 32 II','','[{"roman": "Nanak Nadree Payeah Kooree Korey Thees II 32 II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Нанак говорит: Через Милость от СонастроенностиДостигаются “Небеса”.Имитируемые пути фальшивых людей оставляют их на “земле” II32II (Koore Korey – 1 паури, Kiv Kooray …)','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(365,1,317,'ਆਖਣਿ ਜੋਰੁ ਚੁਪੈ ਨਹ ਜੋਰੁ ॥','Akhunn Jor Chupey Neh Jor II','','[{"roman": "Akhunn Jor Chupey Neh Jor II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Милость Создателя не обретается через натужные бормотанияили молчание(многочасовой чантинг)','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(366,1,318,'ਜੋਰੁ ਨ ਮੰਗਣਿ ਦੇਣਿ ਨ ਜੋਰੁ ॥','Jor Na Mangann Denn Na Jor II','','[{"roman": "Jor Na Mangann Denn Na Jor II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Милость Создателя не обретается через натужные молитвы, просьбыили ритуальные подношения','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(367,1,319,'ਜੋਰੁ ਨ ਜੀਵਣਿ ਮਰਣਿ ਨਹ ਜੋਰੁ ॥','Jor Na Jivann Marann Neh Jor II','','[{"roman": "Jor Na Jivann Marann Neh Jor II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Милость Создателя не обретается черезпопытки властинад жизнью и смертью','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(368,1,320,'ਜੋਰੁ ਨ ਰਾਜਿ ਮਾਲਿ ਮਨਿ ਸੋਰੁ ॥','Jor Na Raj Mal Mun Sor II','','[{"roman": "Jor Na Raj Mal Mun Sor II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Милость Создателя не обретаетсяни властным насилием, ни накоплением богатств,ни умственными потугамисосредоточенными на своих требованиях (от Создателя)','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(369,1,321,'ਜੋਰੁ ਨ ਸੁਰਤੀ ਗਿਆਨਿ ਵੀਚਾਰਿ ॥','Jor Na Surtee Gyan Vichar II','','[{"roman": "Jor Na Surtee Gyan Vichar II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Милость Создателя не обретается потужной медитацией, накоплением знаний, исследованиями и духовными дискуссиями','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(370,1,322,'ਜੋਰੁ ਨ ਜੁਗਤੀ ਛੁਟੈ ਸੰਸਾਰੁ ॥','Jor Na Jugtee Chutey Sansar II','','[{"roman": "Jor Na Jugtee Chutey Sansar II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Милость Создателя не обретается через силовое отречение от мирского (сансарического)','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(371,1,323,'ਜਿਸੁ ਹਥਿ ਜੋਰੁ ਕਰਿ ਵੇਖੈ ਸੋਇ ॥','Jis Hath Jor Kar Veykhey Soey II','','[{"roman": "Jis Hath Jor Kar Veykhey Soey II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Те, кто использует силовые действия для получения Милости Создателя, имели возможность их оценить на эффективность','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(372,1,324,'ਨਾਨਕ ਉਤਮੁ ਨੀਚੁ ਨ ਕੋਇ ॥੩੩॥','Nanak Utam Nich Na Koey II 33 II','','[{"roman": "Nanak Utam Nich Na Koey II 33 II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Нанак говорит: Оценка заключается в том, что беря контроль на себя, или совершая силовое действие для получения милости – человек не возносится к Небесам и не падает на землю к муравьям(Эти действия сами по себе не влияют на Милость)II33II','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(373,1,325,'ਰਾਤੀ ਰੁਤੀ ਥਿਤੀ ਵਾਰ ॥','Ratee Rutee Thitee Vaar II','','[{"roman": "Ratee Rutee Thitee Vaar II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','В пределах одного Хукама, сменяющего день на ночь, сменяющего сезоны,движущего периодами времени…','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(374,1,326,'ਪਵਣ ਪਾਣੀ ਅਗਨੀ ਪਾਤਾਲ ॥','Pavann Panni Agni Patal II','','[{"roman": "Pavann Panni Agni Patal II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','…правящего элементами воздуха, воды, огня, пространства…','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(375,1,327,'ਤਿਸੁ ਵਿਚਿ ਧਰਤੀ ਥਾਪਿ ਰਖੀ ਧਰਮ ਸਾਲ ॥','Tis Vich Dharti Thaap Rakhee Dharam Saal II','','[{"roman": "Tis Vich Dharti Thaap Rakhee Dharam Saal II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','…В пределах такого Хукама Земля, являющаяся моим телом, создана и удерживается в существовании; Тем же Единым Хукамом поддерживается Обитель Закона,мои разум и совесть, как Его Воплощение','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(376,1,328,'ਤਿਸੁ ਵਿਚਿ ਜੀਅ ਜੁਗਤਿ ਕੇ ਰੰਗ ॥','Tis Vich Jee Jugat Kay Rang II','','[{"roman": "Tis Vich Jee Jugat Kay Rang II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','…Воплощенный Закон в разуме и совестиДелает Жизнь естественно пронизанной Высшим Методом, Высшим Путём…','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(377,1,329,'ਤਿਨ ਕੇ ਨਾਮ ਅਨੇਕ ਅਨੰਤ ॥','Tin Kay Naam Aneyk Anunt II','','[{"roman": "Tin Kay Naam Aneyk Anunt II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','…Высшим Путём,насыщенным безграничным Наам, божественными атрибутами','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(378,1,330,'ਕਰਮੀ ਕਰਮੀ ਹੋਇ ਵੀਚਾਰੁ ॥','Karmi Karmi Hoey Vichar II','','[{"roman": "Karmi Karmi Hoey Vichar II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Высшим Путём, на котором мои дела исследуются на предмет Милости','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(379,1,331,'ਸਚਾ ਆਪਿ ਸਚਾ ਦਰਬਾਰੁ ॥','Sacha Aap Sacha Darbar II','','[{"roman": "Sacha Aap Sacha Darbar II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Путь – Высший, потому чтоCам Создатель сделал мою совесть своим Двором','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(380,1,332,'ਤਿਥੈ ਸੋਹਨਿ ਪੰਚ ਪਰਵਾਣੁ ॥','Tithey Sohan Panch Parvann II','','[{"roman": "Tithey Sohan Panch Parvann II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','В моей Совестипять чувств принимают Его духовное великолепие.','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(381,1,333,'ਨਦਰੀ ਕਰਮਿ ਪਵੈ ਨੀਸਾਣੁ ॥','Nadri Karam Pvey Nisann II','','[{"roman": "Nadri Karam Pvey Nisann II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Благодаря Его Милости мои дела ориентированы на достижение духовной цели – Наполнение Времени Жизни Амритой, через Исследование Слова, в Котором Живёт Закон','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(382,1,334,'ਕਚ ਪਕਾਈ ਓਥੈ ਪਾਇ ॥','Kach Pakayi Uthey Paye II','','[{"roman": "Kach Pakayi Uthey Paye II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Моя Совесть, подобная пробному камню Милости, отделяет спелое (милость) от неспелого (кажущаяся милость) на этом Пути','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(383,1,335,'ਨਾਨਕ ਗਇਆ ਜਾਪੈ ਜਾਇ ॥੩੪॥','Nanak Gaya Japey Jaye II 34 II','','[{"roman": "Nanak Gaya Japey Jaye II 34 II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Нанак говорит:реализовать “Джап”, стать Сачиарой –значит пройти этот путь II34II','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(384,1,336,'ਧਰਮ ਖੰਡ ਕਾ ਏਹੋ ਧਰਮੁ ॥','Dharam Khand Ka Eho Dharam II','','[{"roman": "Dharam Khand Ka Eho Dharam II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Вышесказанное является Дхарам Кхандом, Сферой Закона –Опыт Хукама и Его наблюдения,из которых рождается условиедля Истинного Знания — Гьян Кханд','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(385,1,337,'ਗਿਆਨ ਖੰਡ ਕਾ ਆਖਹੁ ਕਰਮੁ ॥','Gyan Khand Ka Akho Karam II','','[{"roman": "Gyan Khand Ka Akho Karam II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Да будет изложено повествование о втором царстве Его Милости – сфере Просветления (Знания), Гьян Кханде','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(386,1,338,'ਕੇਤੇ ਪਵਣ ਪਾਣੀ ਵੈਸੰਤਰ ਕੇਤੇ ਕਾਨ ਮਹੇਸ ॥','Kaytey Pavann Panni Vaisantar Keytey Kahn Mahesh II','','[{"roman": "Kaytey Pavann Panni Vaisantar Keytey Kahn Mahesh II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','В этом Просветленииесть осознание того, что воздух, вода и огонь —первоэлементы творения,существовали во множествах точек зрения.Кришна и Махештакже существовали во множествах точек зрения.','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(387,1,339,'ਕੇਤੇ ਬਰਮੇ ਘਾੜਤਿ ਘੜੀਅਹਿ ਰੂਪ ਰੰਗ ਕੇ ਵੇਸ ॥','Kaytay Bharmey Gharrat Gharreay Roop Rang Kay Ves II','','[{"roman": "Kaytay Bharmey Gharrat Gharreay Roop Rang Kay Ves II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','В этом Просветлении есть осознание того,что множество представлений о стихиях и силахбыло создано в различных формах,структурах, обликах и цветах,во множестве внешних проявлений','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(388,1,340,'ਕੇਤੀਆ ਕਰਮ ਭੂਮੀ ਮੇਰ ਕੇਤੇ ਕੇਤੇ ਧੂ ਉਪਦੇਸ ॥','Keytia Karam Bhumi Mer Kaytay, Kaytay Dhu Updes II','','[{"roman": "Keytia Karam Bhumi Mer Kaytay, Kaytay Dhu Updes II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','В этом Просветлении есть осознание того,что существовало множество путеводных утверждений,основанных на множестве поступков —и низких, как земля,и возвышенных, как горы','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(389,1,341,'ਕੇਤੇ ਇੰਦ ਚੰਦ ਸੂਰ ਕੇਤੇ ਕੇਤੇ ਮੰਡਲ ਦੇਸ ॥','Kaytay Ind Chand Soor Kaytay, Kaytay Mandal Des II','','[{"roman": "Kaytay Ind Chand Soor Kaytay, Kaytay Mandal Des II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','В этом Просветлении есть осознание того,что существует множество богов и мудрецов,на разных уровнях просветленности — от света Солнца до тьмы Луны,во множестве измерений и континентов','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(390,1,342,'ਕੇਤੇ ਸਿਧ ਬੁਧ ਨਾਥ ਕੇਤੇ ਕੇਤੇ ਦੇਵੀ ਵੇਸ ॥','Kaytay Sidh Budh Nath Kaytay, Kaytay Devi Ves II','','[{"roman": "Kaytay Sidh Budh Nath Kaytay, Kaytay Devi Ves II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','В этом Просветленииесть осознание того,что существовало множество искателей:сиддхи со своими методами,мыслители со своими умозаключениями,следующие за духовными лидерами,а также множество священных мыслей,воплощенных в множествесвященных мировоззрений.','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(391,1,343,'ਕੇਤੇ ਦੇਵ ਦਾਨਵ ਮੁਨਿ ਕੇਤੇ ਕੇਤੇ ਰਤਨ ਸਮੁੰਦ ॥','Kaytay Dev Danav Mun Kaytay, Kaytay Ratun Smund II','','[{"roman": "Kaytay Dev Danav Mun Kaytay, Kaytay Ratun Smund II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','В этом Просветленииесть осознание того,что существовало множество дэвов, учёных и мудрецов —словно бесчисленные драгоценные камни,раскиданные в океанах.','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(392,1,344,'ਕੇਤੀਆ ਖਾਣੀ ਕੇਤੀਆ ਬਾਣੀ ਕੇਤੇ ਪਾਤ ਨਰਿੰਦ ॥','Kaytia Khanni Kaytian Bani Kaytay Paat Nrind II','','[{"roman": "Kaytia Khanni Kaytian Bani Kaytay Paat Nrind II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','В этом Просветленииесть осознание того,что существовало множество духовных повествований,хранящихся во множестве источников,и в иерархиях — от высших до низших,от Патишах-ских до придворных.(источники высшего порядка, низшего порядка).','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(393,1,345,'ਕੇਤੀਆ ਸੁਰਤੀ ਸੇਵਕ ਕੇਤੇ ਨਾਨਕ ਅੰਤੁ ਨ ਅੰਤੁ ॥੩੫॥','Kaytia Surti Sevak Kaytay Nanak Ant Na Ant II 35 II','','[{"roman": "Kaytia Surti Sevak Kaytay Nanak Ant Na Ant II 35 II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Нанак говорит:множество философий и множество последователейне имеют конца сами по себеи не приводят к окончательной целиесли примкнуть к их потоку…II35II','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(394,1,346,'ਗਿਆਨ ਖੰਡ ਮਹਿ ਗਿਆਨੁ ਪਰਚੰਡੁ ॥','Gyan Khund Meh Gyan Parchand II','','[{"roman": "Gyan Khund Meh Gyan Parchand II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Сфера Просветления, Гьян Кханд — это то,где Реализация (Знание Знаний!) становится высшей и первостепенной ценностью.','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(395,1,347,'ਤਿਥੈ ਨਾਦ ਬਿਨੋਦ ਕੋਡ ਅਨੰਦੁ ॥','Tithey Nad Binod Kodd Anand II','','[{"roman": "Tithey Nad Binod Kodd Anand II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','И потому, у этих бесчисленных философий, множеств точек зрения, восприятий, мировоззрений и их последователей – нет конца:Вся их радость остаётся заточённой в их историях, зрелищах и чудесах —в маскараде иллюзий, что они принимают за высшую ценность.','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(396,1,348,'ਸਰਮ ਖੰਡ ਕੀ ਬਾਣੀ ਰੂਪੁ ॥','Sarm Khand Ki Bani Roop II','','[{"roman": "Sarm Khand Ki Bani Roop II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Рассказ о Царстве Усердия, Сарам Кханд – это Рассказ о Становлении Формой Бани(Слова, в Котором Живёт Закон).','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(397,1,349,'ਤਿਥੈ ਘਾੜਤਿ ਘੜੀਐ ਬਹੁਤੁ ਅਨੂਪੁ ॥','Tithey Gharrat Gharreay Bahut Anup II','','[{"roman": "Tithey Gharrat Gharreay Bahut Anup II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Внутри такого усердияум и совесть, внутренний портрет, обретают формуи становятся чудесной скульптурой','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(398,1,350,'ਤਾ ਕੀਆ ਗਲਾ ਕਥੀਆ ਨਾ ਜਾਹਿ ॥','Ta Kiya Glla Kathiya Na Jahe','','[{"roman": "Ta Kiya Glla Kathiya Na Jahe", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Повествование об этом чуде находится за пределами слов','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(399,1,351,'ਜੇ ਕੋ ਕਹੈ ਪਿਛੈ ਪਛੁਤਾਇ ॥','Jay Ko Khey Pichay Pachtaye','','[{"roman": "Jay Ko Khey Pichay Pachtaye", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Всякая попытка описать это чудо —обречена стать сожалением','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(400,1,352,'ਤਿਥੈ ਘੜੀਐ ਸੁਰਤਿ ਮਤਿ ਮਨਿ ਬੁਧਿ ॥','Tithey Gharreay Surt Mut Mun Budh ||','','[{"roman": "Tithey Gharreay Surt Mut Mun Budh ||", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','В этой сфере духовного усердиявся полнота сознания —совесть, интеллект, ум —оформляется вСлово Превышнего','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(401,1,353,'ਤਿਥੈ ਘੜੀਐ ਸੁਰਾ ਸਿਧਾ ਕੀ ਸੁਧਿ ॥੩੬॥','Tithey Gharreay Sura Sidha Ki Sudh ||','','[{"roman": "Tithey Gharreay Sura Sidha Ki Sudh ||", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','В таком скульптурированииразум и совесть должны быть отчеканеныпо подобию чистой Божественности.','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(402,1,354,'ਕਰਮ ਖੰਡ ਕੀ ਬਾਣੀ ਜੋਰੁ ॥','Karm Khund Ki Banni Jor ||','','[{"roman": "Karm Khund Ki Banni Jor ||", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Рассказ о Царстве Милости, Сфере Его Ответа на Усердия,Карам Кханд –Это повествование о Силе того Слова,в которое вылеплены разум и совесть','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(403,1,355,'ਤਿਥੈ ਹੋਰੁ ਨ ਕੋਈ ਹੋਰੁ ॥','Tithey Hor Na Koi Hor ||','','[{"roman": "Tithey Hor Na Koi Hor ||", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','В пределах этой сферыПросветление исходит не от кого иного,как от Ооангкара','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(404,1,356,'ਤਿਥੈ ਜੋਧ ਮਹਾਬਲ ਸੂਰ ॥','Tithey Jodh Mahabl Soor ||','','[{"roman": "Tithey Jodh Mahabl Soor ||", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','В этой сфере разум и совесть, преображённые Милостью,озаряются отвагой и сияют великой непоколебимой силой.','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(405,1,357,'ਤਿਨ ਮਹਿ ਰਾਮੁ ਰਹਿਆ ਭਰਪੂਰ ॥','Tin Meh Ram Rahiya Bharpur ||','','[{"roman": "Tin Meh Ram Rahiya Bharpur ||", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Это происходит потому, что Вездесущий Раам пребывает там —во всей полноте,обильным присутствием.','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(406,1,358,'ਤਿਥੈ ਸੀਤੋ ਸੀਤਾ ਮਹਿਮਾ ਮਾਹਿ ॥','Tithey Sito Sita Mehma Mahe ||','','[{"roman": "Tithey Sito Sita Mehma Mahe ||", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Внутри этой полной реализацииразум и совесть сшиваются воедино с Раам,и становятся самим воспеванием Божественных Атрибутов','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(407,1,359,'ਤਾ ਕੇ ਰੂਪ ਨ ਕਥਨੇ ਜਾਹਿ ॥','Ta Kay Roop Na Kathnay Jahe ||','','[{"roman": "Ta Kay Roop Na Kathnay Jahe ||", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Красота этого чуда –за пределами описаний','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(408,1,360,'ਨਾ ਓਹਿ ਮਰਹਿ ਨ ਠਾਗੇ ਜਾਹਿ ॥','Na Oh Mreh Na Thagey Jahe ||','','[{"roman": "Na Oh Mreh Na Thagey Jahe ||", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Так разум и совестьостаются за пределами духовной смертии не поддаются обману','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(409,1,361,'ਜਿਨ ਕੈ ਰਾਮੁ ਵਸੈ ਮਨ ਮਾਹਿ ॥','Jin Kaey Ram Vsaey Mun Mahe ||','','[{"roman": "Jin Kaey Ram Vsaey Mun Mahe ||", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Это происходит потому, чтоВездесущий РаамПолностью пребывает внутри Разума и Совести','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(410,1,362,'ਤਿਥੈ ਭਗਤ ਵਸਹਿ ਕੇ ਲੋਅ ॥','Tithey Bhagt Vsey Kay Loa ||','','[{"roman": "Tithey Bhagt Vsey Kay Loa ||", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Внутри нихраскрывается пребывание просветлённой преданности —бхагти, что наполняет их Cветом.','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(411,1,363,'ਕਰਹਿ ਅਨੰਦੁ ਸਚਾ ਮਨਿ ਸੋਇ ॥','Krey Anand Scha Mun Soe ||','','[{"roman": "Krey Anand Scha Mun Soe ||", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Эти разум и совесть своей деятельностью вовлечены вблаженную милостьСоздателя','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(412,1,364,'ਸਚ ਖੰਡਿ ਵਸੈ ਨਿਰੰਕਾਰੁ ॥','Sach Khund Vsey Nirangkar ||','','[{"roman": "Sach Khund Vsey Nirangkar ||", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','В Сач Кханде — Обители Настоящего пребывает Тот, Кто вне форм.Эта Сфера Истинного, Вечного,за пределами времени и форм,является Реализацией Создателя внутри.(Сач Кханд – Кив Сачиара Хойе?)','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(413,1,365,'ਕਰਿ ਕਰਿ ਵੇਖੈ ਨਦਰਿ ਨਿਹਾਲ ॥','Kar Kar Vekhey Nadr Nihal ||','','[{"roman": "Kar Kar Vekhey Nadr Nihal ||", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Реализация Настоящего внутриесть возвышенный и счастливый опыт Его Милости,обретённый через прохождение сфер —Дхарам Кханд, Гьян Кханд, Сарам Кханд, Карам Кханд —и завершающийся в Сач Кханде(После достижения Сач Кханд, Нанак также говорит о царстве Милости. На это есть причина. Причина в том, что и Надар и Сач Кханд тесно переплетены друг с другом. Осознание Творца заключено в его милости. После этого он возвращается к Надар Нихал. Осознание Творца внутри себя - это благодать, а благодать - это осознание Ооангкара внутри себя. Они равны в духовности Сикхи)','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(414,1,366,'ਤਿਥੈ ਖੰਡ ਮੰਡਲ ਵਰਭੰਡ ॥','Tithey Khand Mandul Varbhund II','','[{"roman": "Tithey Khand Mandul Varbhund II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Эти сферы – являются моей Мандалойи в своей полноте – Вселенной его Милости','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(415,1,367,'ਜੇ ਕੋ ਕਥੈ ਤ ਅੰਤ ਨ ਅੰਤ ॥','Jay Ko Kathey Ta Ant Na Ant II','','[{"roman": "Jay Ko Kathey Ta Ant Na Ant II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Вселенная Милости, даже если кто-то повествует о ней, Находится за гранью повествований','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(416,1,368,'ਤਿਥੈ ਲੋਅ ਲੋਅ ਆਕਾਰ ॥','Tithey Loa Loa Akar II','','[{"roman": "Tithey Loa Loa Akar II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Внутри такой Милости Просветление (знание) –принимает физическое воплощение','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(417,1,369,'ਜਿਵ ਜਿਵ ਹੁਕਮੁ ਤਿਵੈ ਤਿਵ ਕਾਰ ॥','Jiv Jiv Hukum Tivey Tiv Kar II','','[{"roman": "Jiv Jiv Hukum Tivey Tiv Kar II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Просветление заключается в том, что всё что происходит по мере путешествия по этим пяти сферамсогласуется с Хукамом Создателя','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(418,1,370,'ਵੇਖੈ ਵਿਗਸੈ ਕਰਿ ਵੀਚਾਰੁ ॥','Vekhey Vigsey Kar Vichar II','','[{"roman": "Vekhey Vigsey Kar Vichar II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Я прошёл этот Путь, основываясь на своей оценкеи внутреннем исследовании (Тут Нанак ставит “печать одобрения” на свои открытия. Нанак говорит, я ходил, оценивал ситуацию, размышлял над ней, и именно это привело меня сюда, чтобы пройти в путь, и в итоге это привело меня в царство благодати, царство осознания Создателя внутри меня, к тому чтобы стать воплощением божественных добродетелей внутри.)','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(419,1,371,'ਨਾਨਕ ਕਥਨਾ ਕਰੜਾ ਸਾਰੁ ॥੩੭॥','Nanak Kathna Karra Sar II 37 II','','[{"roman": "Nanak Kathna Karra Sar II 37 II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Нанак говорит: Всё равно, повествование о Милости всё ещё остаётся за гранью возможного II37II','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(420,1,372,'ਜਤੁ ਪਾਹਾਰਾ ਧੀਰਜੁ ਸੁਨਿਆਰੁ ॥','Jut Pahara Dhiraj Suniyar II','','[{"roman": "Jut Pahara Dhiraj Suniyar II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Контроль над чувствами,формируемый Просветленным Разумом –это кузнечное место,на котором куётся духовная жизнь.Здесь терпение и непоколебимость — подобны ювелиру.','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(421,1,373,'ਅਹਰਣਿ ਮਤਿ ਵੇਦੁ ਹਥੀਆਰੁ ॥','Ehrunn Mut Ved Hathiar II','','[{"roman": "Ehrunn Mut Ved Hathiar II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Устойчивый контроль над чувствами — словно наковальня;а разум,подобен молоту,придающему форму.','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(422,1,374,'ਭਉ ਖਲਾ ਅਗਨਿ ਤਪ ਤਾਉ ॥','Bhou Khala Agun Tup Tao II','','[{"roman": "Bhou Khala Agun Tup Tao II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Просветление разгорается в разуме,когда благоговение раздувает огонь,и разум закаляется жаром усердного трудав почитании Создателя внутри.','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(423,1,375,'ਭਾਂਡਾ ਭਾਉ ਅੰਮ੍ਰਿਤੁ ਤਿਤੁ ਢਾਲਿ ॥','Bhanda Bhao Amrit Tit Dhaal II','','[{"roman": "Bhanda Bhao Amrit Tit Dhaal II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Через Труд, Благоговение и Любовьмой разум словно сосуд получил огранку,и стал способным удерживать Амрит','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(424,1,376,'ਘੜੀਐ ਸਬਦੁ ਸਚੀ ਟਕਸਾਲ ॥','Ghareay Shabad Sachi Taksal II','','[{"roman": "Ghareay Shabad Sachi Taksal II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Шабд скульптурируется в моей Совести,словно на монетном дворе Создателя.','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(425,1,377,'ਜਿਨ ਕਉ ਨਦਰਿ ਕਰਮੁ ਤਿਨ ਕਾਰ ॥','Jin Kao Nadar Karm Tin Kar II','','[{"roman": "Jin Kao Nadar Karm Tin Kar II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','В результате этого скульптурированияДаруется Милость и Благословение —и происходит становление Его Словом','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(426,1,378,'ਨਾਨਕ ਨਦਰੀ ਨਦਰਿ ਨਿਹਾਲ ॥੩੮॥','Nanak Nadri Nadar Nihal II 38 II','','[{"roman": "Nanak Nadri Nadar Nihal II 38 II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Нанак говорит: наивысшая радость —быть благословлённым Милостью Настоящего.II38II','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(427,1,379,'ਸਲੋਕੁ ॥','Shalok','','[{"roman": "Shalok", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Шлок:','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(428,1,380,'ਪਵਣੁ ਗੁਰੂ ਪਾਣੀ ਪਿਤਾ ਮਾਤਾ ਧਰਤਿ ਮਹਤੁ ॥','Pavann Guru Panni Pita Mata Dharat Mahut II','','[{"roman": "Pavann Guru Panni Pita Mata Dharat Mahut II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Шабд — мой Гуру,Он — источник, отец и мать,Он — воздух и вода, что поддерживают жизнь,Он — великая земля,всёохватывающее основание моей духовной жизни.','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(429,1,381,'ਦਿਵਸੁ ਰਾਤਿ ਦੁਇ ਦਾਈ ਦਾਇਆ ਖੇਲੈ ਸਗਲ ਜਗਤੁ ॥','Divas Raat Doe Dayi Daya Kheyley Sagal Jagat II','','[{"roman": "Divas Raat Doe Dayi Daya Kheyley Sagal Jagat II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Шабд — мой Гуру:Он ведёт меня с первых шагов,как наставница воспитывает ребёнка.Днём и ночью,во все времена и мгновения,Он остаётся руководством,что пронизывает всю мою жизнь.(Аад Сач Джюгад Сач Хэбхи Сач Нанак Хоси Бхи Сач – Отсылка к вводной шлоке)','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(430,1,382,'ਚੰਗਿਆਈਆ ਬੁਰਿਆਈਆ ਵਾਚੈ ਧਰਮੁ ਹਦੂਰਿ ॥','Changeayea Buriayea Vachey Dharam Hadoor II','','[{"roman": "Changeayea Buriayea Vachey Dharam Hadoor II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Руководство Шабд-Гуру в том,что мои дела – хорошие они или плохие –должны быть взвешенына пробном камне Его Закона – Хукама','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(431,1,383,'ਕਰਮੀ ਆਪੋ ਆਪਣੀ ਕੇ ਨੇੜੈ ਕੇ ਦੂਰਿ ॥','Karmi Apo Apni Kay Nerrey Kay Dur II','','[{"roman": "Karmi Apo Apni Kay Nerrey Kay Dur II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Мои собственные поступки определяют:становлюсь ли я ближе к Создателю, реализую ли Его внутри,или остаюсь далеко — вне реализации.(Ekna Hukmi Bakshish…)','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(432,1,384,'ਜਿਨੀ ਨਾਮੁ ਧਿਆਇਆ ਗਏ ਮਸਕਤਿ ਘਾਲਿ ॥','Jini Naam Dhiayia Gye Masakat Ghaal II','','[{"roman": "Jini Naam Dhiayia Gye Masakat Ghaal II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Те, кто упорно и усердносозерцают Наам так, что сами становятся Им…(Aisa Naam Niranjan Hoye, Jey Ko Man Janey Man Koey)','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_examples" VALUES(433,1,385,'ਨਾਨਕ ਤੇ ਮੁਖ ਉਜਲੇ ਕੇਤੀ ਛੁਟੀ ਨਾਲਿ ॥੧॥','Nanak Tay Mukh Ujlay Kayti Chutti Naal II 1 II','','[{"roman": "Nanak Tay Mukh Ujlay Kayti Chutti Naal II 1 II", "literal": "", "ksd_meta": "готовый русский AST-reference"}]','Нанак говорит: … Их лица сияют, будучи обращенными к Гуру, Освобожденные от стены фальши, заслоняющей Его Свет(Kooray Tutey Paal – Kaytte Chuttee Naal) II1II','','[1, 2, 3, 4, 5, 6, 7, 8]','ast_translation_line');
INSERT INTO "ksd_principles" VALUES(1,1,'буквальн','1 Урок - Переход от буквального к метафорическому Введение Понимание Гурбани, Часть 1/8: Переход через "Границу" - от буквального к духовному. Введение в методологию понимания Гурбани • Методология понимания Гурбани требует самостоятельного подхода. • Аналогия с поездкой в новое место: если полагаться на кого-то, достаточно следовать за ним; если ехать самому, нужен метод. • Методология включает принципы и структурированный процесс. Определение методологии • Методология - это структурированная процедура получения знаний. • В серии видеороликов рассматривается 10 принципов для самостоятельного понимания Гурбани. • Автор использует эту методологию уже 12 лет и делится ею с другими. Три вещи, которые вы узнаете • Инструменты для самостоятельного понимания Гурбани. • 10 принципов методологии. • Как НЕ НАДО интерп',NULL,NULL,'course_1');
INSERT INTO "ksd_principles" VALUES(2,3,'контекст','разлучен (или "были разлучены", в зависимости от контекста) ਮਾਧਉ (mādhau): Мадхав (одно из имен Бога, Господа) ਇਹੁ (ihu): эту/это ਜਨਮੁ (janamu): жизнь/рождение ਤੁਮ੍ਹਾਰੇ (tumhārē): Твоей/Тебе ਲੇਖੇ (lēkhē): посвященной/написанной (здесь в значении "посвящаю Тебе") ਕਹਿ ਰਵਿਦਾਸ ਆਸ ਲਗਿ ਜੀਵਉ ਚਿਰ ਭਇਓ ਦਰਸਨੁ ਦੇਖੇ ॥੨॥੧॥ ਕਹਿ (kah): говорит ਰਵਿਦਾਸ (ravidās): Равидас (имя святого) ਆਸ (ās): надежда ਲਗਿ (lagi): полагаясь/привязавшись ਜੀਵਉ (jīvau): живу ਚਿਰ (chir): давно/долго ਭਇਓ (bhaiō): стало/прошло ਦਰਸਨੁ (darasanu): видение/встреча (с Богом) ਦੇਖੇ (dēkhē): видя/увидев Ошибочные сообщения, к которым мы приходим, читая такой перевод: Гурбани говорит что у нас есть прошлые жизни. Гурбани говорит что у нас есть загробные жизни. Гурбани говорит что мы реинкарнируем. Чтобы описать духовную эмоцию - используется мирской язык любви. У Гурбани нет своего отдел',NULL,NULL,'course_1');
INSERT INTO "ksd_principles" VALUES(3,2,'рахао','2 Урок - Принцип “Рахао” (Паузы) Введение 1-ый принцип изложенный в предыдущем уроке - переход от буквального к духовному - важен. Если его упустить, то можно начать ходить кругами, никогда не приходя к пониманию. Это как с пропуском дорожного знака - возвращение в одно и то же место может увеличить расстояние, которое нам придётся пройти. Это может вызвать у нас непризянь и усталость по отношению к Гурбани. Для понимания смысла - авторы Гурбани придумали указатели - Рахао. Как мы уже знаем из предыдущего урока - необходимо переходить от буквального значения к метафорическому. Рахао буквально переводится как пауза. В действительности, это не только пауза. Что означает это слово? Давайте вспомним предыдущую метафору - с пересечением реки, с одного берега на другой. Представьте, вы стоите на одном берегу.',NULL,NULL,'course_2');
INSERT INTO "ksd_principles" VALUES(4,6,'здесь и сейчас','То, что было сказано в соответствии с… ਈਹਾ Iha - Здесь и Сейчас ਊਹਾ Uha - Потом, в будущем ਸਚੁ Sach - Создатель пребывающий в существовании ਹੋਵੈ Hovey - Будет в будущем Смысловой перевод: Его слуга Нанак говорит (вышесказанное) в Соответствии с волей Создателя, присутствующего в Существовании Здесь и Сейчас, каким Он (создатель) Всегда и будет (присутствующим здесь и сейчас)',NULL,NULL,'course_2');
INSERT INTO "ksd_principles" VALUES(5,4,'для себя','серии видео об осмыслении Гурбани своими силами и для себя. Мы договорились, что нам нужна методология — структурированный процесс понимания Гурбани. Мы дали этому процессу название «рамка Гурбани» (Gurbani Framework) и сказали, что эта рамка состоит из десяти принципов. В двух предыдущих видео мы рассмотрели два принципа. Первый — переход от буквального к духовному. Мы согласились, что это — базовый принцип: всё понимание Гурбани твёрдо на нём стоит. Второй принцип — Рахау. Ссылки на первые два видео — в описании ниже. В прошлом видео мы договорились, что каждая композиция в Гурбани имеет три формы: каждый текст — это (1) стихотворение, (2) музыкальная композиция и (3) носитель духовного послания. Для каждого аспекта Рахау имеет свой контекстуальный смысл: для поэзии «Рахау» — это название (тема), для музыкального компонента — припев, а',NULL,NULL,'course_3');
INSERT INTO "ksd_principles" VALUES(6,2,'рахау','ход от буквального к духовному; второй — принцип «Рахау»; третий — контекст. Ссылки на все три видео есть в описании ниже. Сегодня мы рассмотрим четвёртый принцип, который помогает понимать Гурбани самим. Он называется «духовность Я» (spirituality of the self). Это то, что я называю целевым принципом: он гарантирует, что послания Гурбани достигают своей цели — а цель эта есть Я. Источник принципа в том, что Гурбани в основном написано от первого лица. По сути, Гурбани — это рассказ о духовных стремлениях, духовных нуждах, духовных целях и духовном опыте Я. Гурбани — это рассказ о «Я» авторов — всех 35 составителей. А когда мы, читатели, читаем и понимаем бани, то оно становится рассказом о нашем «Я». То есть послания Гурбани применимы ко мне. Такова их целевая точка. Именно поэтому Гурбани написано от первого лица: это сумма переживаний ч',NULL,NULL,'course_4');
INSERT INTO "ksd_principles" VALUES(7,5,'творец внутри','три, а не «там, снаружи». Отсюда следствие: важен Творец внутри меня, а не тот, которого рисует внешний мир. Почему? Потому что «Творец снаружи» определён миром: «Он сидит там наверху и управляет раем и адом; он микроменеджит мир; он посылает бедствия и болезни; сначала даёт боль, а потом ждёт, чтобы ты пришёл умолять, чтобы он это снял». Это «бог снаружи» — бог религии. А Творец внутри меня — тот, который определён Гуру Нанаком и Гурбани: Бог духовности. Творец «снаружи» может «управлять раем и адом где-то там», но Творец внутри меня управляет мной. Он определяет, будет ли у меня райская жизнь внутри или ад внутри. Ещё следствие: важна вселенная внутри меня, а не та, которую принято считать «там, снаружи». Гуру Нанак сказал: вселенная — продолжение Творца. Если Творец внутри меня — значит и вселенная внутри меня. И именно эта вселенная и',NULL,NULL,'course_4');
INSERT INTO "ksd_principles" VALUES(8,4,'spirituality of the self','ность послания. Принцип 4: “Духовность для Меня”, Spirituality of the Self Если очень базово: Гурбани в сущности написано для “самости” читателя, для того кто читает Гурбани. Если сделать ещё “шаг назад”: Гурбани написано 35 духовно просветлёнными авторами и говорит об их духовных переживаниях. То есть это духовный опыт «Я» самих авторов. Поэтому, когда мы читаем и пытаемся понимать духовные послания, мы понимаем, что это написано для меня — а с вашей стороны вы скажете, что это написано для вас. Это не написано «для мира там» или для «третьих-четвёртых-пятых лиц». Это написано от первого лица для читателя, который тоже читает это от первого лица. Значит, все строки применимы ко мне, имеют отношение ко мне. Принцип 5: Творец – Внутри И дальше есть очень критический принцип: в наставлениях Гурбани Творец — пребывает внутри творения, вн',NULL,NULL,'ast_example');
INSERT INTO "ksd_principles" VALUES(9,7,'гурбани объясняет','вёте вы. Это ещё один важный принцип. Принцип 7: Гурбани объясняет Гурбани Внутри Гурбани есть множество концепций, которые были взяты из уже существовавших представлений. В 1469 году, когда пришёл Guru Nanak, духовный мир уже имел сотни и тысячи концепций: «служение/севā», «бог» и многие другие. Но когда эти концепции используются в Гурбани, они используются в контексте Гурбани. ВАЖНО: Мы не можем открыть внешний словарь и искать значения концепций Гурбани «снаружи». Например, возьмём простой концепт — «смерть». Откроете словарь — там будет одно объяснение. Откроете другие духовные тексты — например, Веды — там смерть объяснят иначе. Но чтобы понять, как Гурбани видит «смерть», нужно смотреть внутрь 1429 страниц и понимать, что именно Гурбани вкладывает в этот концепт. Принцип 8: Грамматика, согласованность смыслов, духовность шабда У',NULL,NULL,'ast_example');
INSERT INTO "ksd_principles" VALUES(10,8,'грамматика','на русский язык – передан смысловой эквивалент. Грамматика и язык: некоторые слова имеют персидское происхождение. Например, Karam, Karm не означают Карму, а “Карам Кханд” не означает “Царство Кармы”. Это слово персидского происхождения, означающее милость, благодать. В некоторых случаях, означающее “действие”, в зависимости от контекста и игры слов. В переводе и донесении смыслов учтена грамматика Гурбани – опытным сикхским теологом, исследователем Гурбани, сикхом с мировым именем. Холст понятий Ади Гуру Грантх Сахиб: перевод выстроен с учётом всего Ади Гуру Грантх Сахиб, а именно с учётом всех изложенных в него понятий, терминов, концепций и холстов. В отличие от большинства существующих переводах, этот перевод внимательно избегает любых противоречий с холстом понятий аутентичного Сикхи. Вовлечение читателя: Нанак написал это бани',NULL,NULL,'ast_example');
