INSERT INTO "words" VALUES(93,'','честь','это не всегда социальное понятие. Все эти переводы будут верны по отношению к тому смыслу Гурбани, который мы можем применить на практике, который не относится к неким общим высказываниям в духе “бог породил жизнь и формы”.','',NULL,'jbani_v2',0.85,NULL);
