INSERT INTO "words" VALUES(516,'','когда мы читаем джап бани и видим что','то подобное, связанное с препятствиями - нам не стоит понимать это буквально. В оригинале этот стих можно было бы перевести как тот стих, в котором воин получает удар по лицу мечом. Любой внешний удар - происходит у нас снаружи. Это метафора об обстоятельствах.','',NULL,'jbani_v2',0.85,NULL);
