INSERT INTO "words" VALUES(525,'','тот, в чьей жизни все, что имеет значение','это воля и команда Творца (Jo Vartaye Saee Jugat) это существо, Нанак описывает как Дживан Мукат (ਜੀਵਨ ਮੁਕਤਿ)  - кто достиг Мукти - Здесь и Сейчас.','',NULL,'jbani_v2',0.85,NULL);
INSERT INTO "words" VALUES(526,'','беседа о благочестивой совести','выше моих способностей.','',NULL,'jbani_v2',0.85,NULL);
INSERT INTO "words" VALUES(527,'','а творец','безграничен. Его дискурс, Вичар, разговор о его мудрости - это безграничная Реальность, выражающая этот дискурс. Поэтому, не может быть полного рассуждения об этой совести.','',NULL,'jbani_v2',0.85,NULL);
INSERT INTO "words" VALUES(528,'','твоё вечное бесформенное я','Поддерживающее Мою Совесть II17II','',NULL,'jbani_v2',0.85,NULL);
INSERT INTO "words" VALUES(529,'','неужели есть что','то или кто-то, сильнее Совести, просветленной (не сансарической) ?','',NULL,'jbani_v2',0.85,NULL);
INSERT INTO "words" VALUES(530,'','просветленная совесть','порождена Неисчислимым (Даже если это о неисчислимом, мы должны как-то это понять, получить представление о нём, как хочет от нас Гуру Нанак).','',NULL,'jbani_v2',0.85,NULL);
INSERT INTO "words" VALUES(531,'','люди, социум','вполне исчислимы.','',NULL,'jbani_v2',0.85,NULL);
INSERT INTO "words" VALUES(532,'','со','Весть - это знание, приходящее "бесконтрольно", от Творца, связанное с необходимостью реализовывать это знание, эту Весть Творца.','',NULL,'jbani_v2',0.85,NULL);
INSERT INTO "words" VALUES(533,'','команда творца, возникает из просветленной совести','потому что это говорит Творец. Совесть пришла к тому, чтобы принять Творца, пребывающего внутри. Как только эта реальность принята, тогда голос совести становится голосом Творца.','',NULL,'jbani_v2',0.85,NULL);
