INSERT INTO "words" VALUES(536,'','ghoar','Тьма','',NULL,'jbani_v2',0.85,NULL);
INSERT INTO "words" VALUES(537,'','то, что перевод был про дураков снаружи','было результатом нашей внутренней тьмы! Это простой способ справиться с проблемами. Чувства были направлены вовне. Чувства также искали духовность - вовне. Теперь - этого нет.','',NULL,'jbani_v2',0.85,NULL);
INSERT INTO "words" VALUES(538,'','моя духовная цель','Творец. Он доброжелателен ко всем. Дающий Благословление. Он океан духовного блаженства. Творец внутри меня. Моя совесть присматривает за мной. Он прислушивается к каждому слову или мысли, что происходят в моей Совести.','',NULL,'jbani_v2',0.85,NULL);
