INSERT INTO "words" VALUES(657,'','во всём гурбани','время не имеет значения. Время - придумано человеком. Нет понятия “благоприятные времена” в Гурбани. Нет понятия “бог может быть осознан в какое-то определённое время”.','',NULL,'jbani_v2',0.85,NULL);
