INSERT INTO "words" VALUES(783,'','карам','персидское слово, означающее Надар. Оно означает благодать. Надар - арабское слово, обозначающее Карам. На пенджаби это будет - Мехир. На санскрите это слово - Крипа. На урду - Бакшиш. Даат - это дар, но для человека с возвышенной совестью, это всегда Благословение.','',NULL,'jbani_v2',0.85,NULL);
INSERT INTO "words" VALUES(784,'','если внутренняя реализация','благословение Творца, и если она определяется как  становление Добродетелями, и если за это надо платить, и это должно быть сделано внутри нас самих нами самими, то мы - должны благословить себя. Всё в наших руках. Aape Aap - другое значение.','',NULL,'jbani_v2',0.85,NULL);
INSERT INTO "words" VALUES(785,'','мольбы о благословении','находятся снаружи. Нужно вернуть это внутрь. Когда мы решим благословить самих себя - это день, когда Творец благословит нас. В тот день, когда мы решим следовать совести, руководствоваться ею, в тот день произойдёт благословение.','',NULL,'jbani_v2',0.85,NULL);
