INSERT INTO "words" VALUES(886,'','повествование в джап бани ведётся не о чём','то вовне. Не о людях, находящихся снаружи, которые что-то поют, воспевают. Нам же объясняются действия людей, богов и т.д. - снаружи.','',NULL,'jbani_v2',0.85,NULL);
INSERT INTO "words" VALUES(887,'','именно за этим мы обращаемся к гурбани','для советов для себя.','',NULL,'jbani_v2',0.85,NULL);
INSERT INTO "words" VALUES(888,'','то есть, если у нас в голове','есть божественные добродетели, а у другого человека их нет в голове, то мы ничем не отличаемся от этого человека. Путешествие духовное - о становлении. От чувств, к разуму - затем в Совесть.','',NULL,'jbani_v2',0.85,NULL);
INSERT INTO "words" VALUES(889,'','dar','(Lit) дверь','разум, восприятие.',NULL,'jbani_v2',0.85,NULL);
INSERT INTO "words" VALUES(890,'','дверь','не физическая. Берем стихи из Гурбани, где используется Dar, Ghar и так далее. Dar - это двери, которые ведут во внешний мир изнутри - слух, осязание, зрение, обоняние, чувство вкуса. В Гурбани говорится о 9 дверях. 10-ая дверь - это ум, метафизическое.','',NULL,'jbani_v2',0.85,NULL);
