INSERT INTO "words" VALUES(1294,'','карми','не о карме. Не о прошлой жизни. Нанак ясно нам говорит, что мы создаём свою судьбу своими выборами основываясь на понимании последствии наших поступках.','',NULL,'jbani_v2',0.85,NULL);
