INSERT INTO "words" VALUES(1311,'','джап джи','это не "бани для начинающих", хотя это первый бани в СГГС. Первый не значит лёгкий.','',NULL,'jbani_v1',0.85,NULL);
INSERT INTO "words" VALUES(1312,'','джап бани','самый популярный, наиболее часто объясняемый, но наименее понятый. Это сложный бани, который многие объясняют, но мало кто понимает правильно. Большинство людей ошибаются в его интерпретации.','',NULL,'jbani_v1',0.85,NULL);
INSERT INTO "words" VALUES(1313,'','черты джап бани','лаконичность, краткость, идиоматичность, контекстуальность. Здесь велика вероятность неправильного толкования. Джап Бани - про нас и для нас, а не о ком-то другом. 70 лет духовной жизни Нанака сконцентрировались в этом Бани!','',NULL,'jbani_v1',0.85,NULL);
INSERT INTO "words" VALUES(1314,'','возможны интерпретационные ошибки из','за привнесения внешних философий.','',NULL,'jbani_v1',0.85,NULL);
