INSERT INTO "words" VALUES(1329,'','вахегуру','Удивительный Гуру. Великий Гуру, ты мой мантар (ты - мой духовный совет)','',NULL,'jbani_v1',0.85,NULL);
INSERT INTO "words" VALUES(1330,'','гур мантар','это не одно слово здесь. Это две разных сущности. Гур одна сущность, Мантар - другая. Мантар - это совет в Гурбани.','',NULL,'jbani_v1',0.85,NULL);
INSERT INTO "words" VALUES(1331,'','цель','внешнее изменение реальности, или достижение какого-то специального эффекта','',NULL,'jbani_v1',0.85,NULL);
INSERT INTO "words" VALUES(1332,'','применение','чантинг, повторение, на распев или не на распев.','',NULL,'jbani_v1',0.85,NULL);
INSERT INTO "words" VALUES(1333,'','бани','это духовный совет к реализации, а не к повторению','“мантра” находится внутри Шабда, находится в послании, которое должно быть усвоено и реализовано.',NULL,'jbani_v1',0.85,NULL);
INSERT INTO "words" VALUES(1334,'','бани называется','Джап ( ਜਪੁ  с аункар - что означает, что это процесс)','',NULL,'jbani_v1',0.85,NULL);
INSERT INTO "words" VALUES(1335,'','оно посвящено процессу','слушанию (восприятию), вере, принятию, усвоению, проживанию.','',NULL,'jbani_v1',0.85,NULL);
INSERT INTO "words" VALUES(1336,'','jup / jaap','знать, понимать. Под “джап” имеется в виду то, что можно было бы назвать “повторяй за мной (пройди тот же путь)”, или “воспроизведи это (в жизни)”','',NULL,'jbani_v1',0.85,NULL);
INSERT INTO "words" VALUES(1337,'','в гурбани, муул','это Бог, творец.','',NULL,'jbani_v1',0.85,NULL);
INSERT INTO "words" VALUES(1338,'','куда бы я ни посмотрел','там я нахожу корни Творца (mool)/ Творец повсеместно (т.е. Творец есть Корень всего и присутствует во всем и в каждом)','',NULL,'jbani_v1',0.85,NULL);
INSERT INTO "words" VALUES(1339,'','название задаёт определение использованию','предназначено для познания, предназначено как основа, предназначено как “якорь” божественных добродетелей в сознании Сикхов.','',NULL,'jbani_v1',0.85,NULL);
INSERT INTO "words" VALUES(1340,'','здесь важен мыслительный процесс','Бог определяется добродетелями (Наам).','',NULL,'jbani_v1',0.85,NULL);
INSERT INTO "words" VALUES(1341,'','сикхи','это знать, понимать, обсуждать, ценить, реализовывать эти добродетели (Джап).','',NULL,'jbani_v1',0.85,NULL);
INSERT INTO "words" VALUES(1342,'','сикхизм','уникален. Жить как Сикх - это жить свою жизнь Уникальным образом.','',NULL,'jbani_v1',0.85,NULL);
