INSERT INTO "words" VALUES(1417,'','хукам, как реагирующее начало внутри нас','сразу говорит нам то, что мы испытаем заранее от чего-либо. Хукам - всегда реагирует в нас, говорит внутри нас, выдавая те или иные реакции.','',NULL,'jbani_v1',0.85,NULL);
INSERT INTO "words" VALUES(1418,'','жить эту жизнь, получать опыт жизни','является почестью - в пределах Его Хукама. Его Хукам определяет, что такое честь.','',NULL,'jbani_v1',0.85,NULL);
INSERT INTO "words" VALUES(1419,'','то есть, из самого хукама в нас','приходит внутри нас "поощрение", или условное "наказание". Хукам - одновременно в нас, и одновременно за пределами нас. Мы не можем выбрать, что нам действительно нравится, а что не нравится. Мы не можем полюбить то, что мы не любим.','',NULL,'jbani_v1',0.85,NULL);
INSERT INTO "words" VALUES(1420,'','хукам, как первичное реагирующее начало','это то, в отношении чего разум и тело должны прислушиваться.','',NULL,'jbani_v1',0.85,NULL);
INSERT INTO "words" VALUES(1421,'','это реагирующее начало','источник радости, удовлетворения, чувства смысла, и много чего ещё. Его нельзя подавить разумом или телом. Оно испускает реакции.','',NULL,'jbani_v1',0.85,NULL);
INSERT INTO "words" VALUES(1422,'','от следования или не следования этому началу','зависит то, что мы испытываем. Разумом мы не можем себе внушить эту реакцию. Можем задавить это первичную реакцию, но в итоге где-то сломаемся, поскольку это Начало - независимое.','',NULL,'jbani_v1',0.85,NULL);
INSERT INTO "words" VALUES(1423,'','разум и тело','зависят от него, и прошиты им.','',NULL,'jbani_v1',0.85,NULL);
INSERT INTO "words" VALUES(1424,'','реагирующее начало','> Разум -> 5 органов чувств (внимание) -> 5 органов действий','',NULL,'jbani_v1',0.85,NULL);
INSERT INTO "words" VALUES(1425,'','то есть, во главе угла','должно стоять это "начало", и разум с чувствами должны управляться им, находиться в Suney (слушании) в отношении него.','',NULL,'jbani_v1',0.85,NULL);
INSERT INTO "words" VALUES(1426,'','или обратная комбинация, где это начало','за "стенкой" -','',NULL,'jbani_v1',0.85,NULL);
