INSERT INTO "words" VALUES(1477,'','реализация хукама','это реализация Творца (Nanak Hukmey Je Budhjey Ta Haumai Kahei Na Koi - от “я” к “ты”','монета перевернулась, и стало понятно, что другая сторона монеты - это Ты)',NULL,'jbani_v1',0.85,NULL);
INSERT INTO "words" VALUES(1478,'','всюду существующий','твой Хукам, есть руководство исходящее из уст Гуру (Твоих, Гурупарамешвар).','',NULL,'jbani_v1',0.85,NULL);
INSERT INTO "words" VALUES(1479,'','sacha','значит, неизменный, за пределами влияния причин и следствий. Как узнали? Через мудрость погружения в знание Хукама. Вода - существует в трёх формах, вода, лёд, пар. Это Хукам. Хукам - постоянен в этом плане.','',NULL,'jbani_v1',0.85,NULL);
