INSERT INTO "words" VALUES(1843,'','команда творца, возникает из просветленной совести','потому что это говорит Творец. Совесть пришла к тому, чтобы принять Творца, пребывающего внутри. Как только эта реальность принята, тогда голос совести становится голосом Творца.','',NULL,'jbani_v1',0.85,NULL);
