INSERT INTO "words" VALUES(1927,'','мы пропитываем пороки','добродетелями. Прививать пороки и рассуждать о добродетелях - не подходит. Это для того, чтобы умыть руки и сказать “всё, на этом всё, я выполнил свою часть”. Нужно прививать добродетели, а обсуждать - пороки. Вот о чём говорит Нанак.','',NULL,'jbani_v1',0.85,NULL);
