INSERT INTO "words" VALUES(1967,'','во всём гурбани','время не имеет значения. Время - придумано человеком. Нет понятия “благоприятные времена” в Гурбани. Нет понятия “бог может быть осознан в какое-то определённое время”.','',NULL,'jbani_v1',0.85,NULL);
