INSERT INTO "words" VALUES(2011,'','teerath tup dya dut dan','всему этому нет места в духовности Сикха. В этом суть послания. Это очень важные паури, которые люди применили ко внешним вещам - к сотворению вселенной и т.д.','',NULL,'jbani_v1',0.85,NULL);
INSERT INTO "words" VALUES(2012,'','главная проблема','упущение контекста.','',NULL,'jbani_v1',0.85,NULL);
INSERT INTO "words" VALUES(2013,'','сат сохан сада ман чао','это результат всего этого. Зачем же после этого говорить о мирах? В этом мало смысла. Основная причина, почему это не имеет смысла помимо вышеперечисленных - игнорирование контекста.','',NULL,'jbani_v1',0.85,NULL);
INSERT INTO "words" VALUES(2014,'','сейчас мы попытаемся вписать это в контекст','Панч Парван, Панч Пардхан. Где чувства становятся согласованными с разумом, совестью.','',NULL,'jbani_v1',0.85,NULL);
