INSERT INTO "words" VALUES(2019,'','патала патал','самый низший из низших. Это идиомы.','',NULL,'jbani_v1',0.85,NULL);
INSERT INTO "words" VALUES(2020,'','агаса агас','высшее из высших.','',NULL,'jbani_v1',0.85,NULL);
INSERT INTO "words" VALUES(2021,'','когда совесть проходит духовный путь к просветлению','в ней что-то происходит. Происходит нечто вроде колебаний маятника - от бечисленных темных мыслей и очень просветленных. Это становится очень осмысленным и реалистичным.','',NULL,'jbani_v1',0.85,NULL);
INSERT INTO "words" VALUES(2022,'','знание смысла','позволяет понять, когда поставить паузу. Если ставить паузу в неправильном смысле - будет утрата смысла. Как правило, в начале нашего духовного путешествия, “тёмных мыслей” в нашем разуме больше, чем “светлых мыслей”, в этом обоснование запятой.','',NULL,'jbani_v1',0.85,NULL);
INSERT INTO "words" VALUES(2023,'','тело','это основа дхарама (хукама - божественного закона), выражение Атмана во времени и пространстве. Внутри тела находится Свет Создателя.','',NULL,'jbani_v1',0.85,NULL);
INSERT INTO "words" VALUES(2024,'','в теле хранятся бесценные жемчужины знания','их можно обнаружить если научится погружаться глубоко в тело с помощью мудрости Гуру-Создателя.','',NULL,'jbani_v1',0.85,NULL);
INSERT INTO "words" VALUES(2025,'','patala patal lakh agasa agas','Непросветлённое сознание заставляет мой разум колебаться между бесчисленными темными мыслями и высокопросвещенными.','',NULL,'jbani_v1',0.85,NULL);
INSERT INTO "words" VALUES(2026,'','orruk','1) Конец, предел [может вспомнить про Ооанкар, согласно алфавиту Нанака, ūrai upamā tā kī kījai jā kā ant n pāiā)] 2) святилище, убежище (происхождение от слов Orr, Ord, Sharan)','',NULL,'jbani_v1',0.85,NULL);
INSERT INTO "words" VALUES(2027,'','orruk orruk','Idiomatic -Абсолютное святилище / убежище. Когда идёт битва, мы ищем убежища - до конца.','',NULL,'jbani_v1',0.85,NULL);
INSERT INTO "words" VALUES(2028,'','bhal thakey','Искать до конца','возможный поиск - в духовном смысле, окончательный поиск.',NULL,'jbani_v1',0.85,NULL);
