INSERT INTO "words" VALUES(2035,'','dhat','(Lit) Источник, сущность. В данном случае относится к совести','',NULL,'jbani_v1',0.85,NULL);
INSERT INTO "words" VALUES(2036,'','второе значение','цель духовности во время жизни в мире состоит в победе в этой битве. Иначе, счёт выйдет в “минус”. Признание победы - это счёт в плюс. Что-то вроде подсчёта очков происходит в этом стихе (в 22-м паури).','',NULL,'jbani_v1',0.85,NULL);
