INSERT INTO "words" VALUES(3116,'','и правители','Захватчики, и Управляемые ими - являются творениями Творца. Таким образом, основной вопрос заключается в следующем:','',NULL,'custom_номер_1_из_неправильно_приведенных_шабдов_с_разбором',0.85,NULL);
