INSERT INTO "words" VALUES(3121,'','у гурбани есть грамматика','многие знают, что она была обнаружена Professor Sahib Singh ji и дана нам как подарок. Мы используем грамматику, чтобы понимать множественное/единственное число, времена (будущее/настоящее), род (женский/мужской контекст) и т. д.','',NULL,'ast_example',0.85,NULL);
INSERT INTO "words" VALUES(3122,'','я хочу начать с вводной информации','с того, что я называю ошибкой новичка. Когда мы смотрим на Джап Джи, у нас часто уже есть заранее сформированное ощущение, и оно обычно возникает потому, что:','',NULL,'ast_example',0.85,NULL);
