INSERT INTO "words" VALUES(3148,'ਭਵਖੰਡਨਾ','bhavkhandana','разрушитель бытия/страха','разрушение смещённого восприятия (bhav+khandana); эпитет Создателя как того кто устраняет иллюзию',NULL,'manual_ksd',0.9,NULL);
INSERT INTO "words" VALUES(3149,'ਆਰਤੀ','arati','ритуал арати (лампадный обряд)','не ритуал, а состояние внутреннего созерцания Творца; всё творение — это арати Создателю (KSD)',NULL,'manual_ksd',0.9,NULL);
INSERT INTO "words" VALUES(3150,'ਧੂ','Dhu','путеводная звезда (Полярная звезда)','НЕ святой Дхрува. Dhu = фиксированное направление движения, то, на что ориентируются. Метафора: ведение, наставление, ориентир.','Перед ним: земля (bhumi, метафора: низкое), горы (Mer, метафора: высокое) — логическая прогрессия. Если бы Dhu = имя святого, последовательность разрушалась бы. Слово "упдеш" (nastavlenie) следует после — это ряд ориентиров, а не список людей.','Упрощенное издание + punjabi.com/dictionary',9.0,'Мейнстрим-перевод: Дхрува = великий преданный Вишну (индуистский святой). KSD: ਧੂ = путеводная звезда. Подтверждение: https://punjabi.com/dictionary/wordmeaning?search=ਧਰੂ');
INSERT INTO "words" VALUES(3151,'ਵੇਲਾ','Vela','время, момент','В СГГС ਵੇਲਾ = человеческая жизнь как возможность реализации Создателя. НЕ время суток, НЕ 3 часа ночи. Ключевые смыслы: (1) человеческая жизнь; (2) время, когда происходит реализация Гурбани/Создателя. Это время создаётся практикой, а не часами на часах.','ਵੇਲਾ (mukta) = определение/описание. ਵੇਲੇ (kenna/sihari) = указание на период времени.','СГГС 28, 20, 35, 146, 422, 435, 520, 540, 1084, 1090',10.0,'СГГС 28: ''ਓਹ ਵੇਲਾ ਹਥਿ ਨ ਆਵਈ'' — эта возможность не вернётся (= жизнь как возможность); СГГС 422: ''ਵੇਲਾ ਸਚੁ ਪਰਵਾਣੁ ਸਬਦੁ ਪਛਾਣਸੀ'' — Истинно то время, когда пробуждается к Слову; СГГС 1084: ''ਸਭੇ ਵਖਤ ਸਭੇ ਕਰਿ ਵੇਲਾ'' — каждый миг сделай временем памятования Создателя');
INSERT INTO "words" VALUES(3152,'ਅੰਮ੍ਰਿਤ','Amrit','бессмертный, нерождённый (А + Мрит = не-смерть)','ਅੰਮ੍ਰਿਤ = бессмертное, Нерождённое (Ооангкар). НЕ ''нектар'', НЕ ''предрассветные часы''. ਅੰਮ੍ਰਿਤ ਵੇਲਾ = Время/Жизнь, наполненная Нерождённым/Бессмертным = жизнь, в которой присутствует осознание и реализация Ооангкара.','Состав: ਅ (a-) + ਮ੍ਰਿਤ (мрит=смерть) → бессмертный','KSD-анализ Паури 4 Джап Бани',10.0,'Мейнстрим переводит как ''ambrosial hours before dawn'' (предрассветные часы) — это противоречит СГГС 422, 1084, 540 и другим шабдам, где ਵੇਲਾ = любой момент жизни');
