INSERT INTO "words" VALUES(3197,'','честь','это не всегда социальное понятие. Все эти переводы будут верны по отношению к тому смыслу Гурбани, который мы можем применить на практике, который не относится к неким общим высказываниям в духе “бог породил жизнь и формы”.','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(3198,'','utam neech (lit)','Высоко и низко. Хорошие и плохие дела.','',NULL,'jbani_v2_blocks',0.9,NULL);
