INSERT INTO "words" VALUES(3201,'','payeaeh','Получать','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(3202,'','это чуть детальнее раскрывает предыдущую строчку. мы можем делать внешне какие','то хорошие вещи, но внутренне - опустошаться от них. Общество может нас хвалить и считать святыми, но внутренне мы будем знать, что что-то не так. Ооангкар - это Высшая Природа. Ооангкар разговаривает в нас через нашу Совесть, через природу нашего тела, которые за пределами нашего контроля.','',NULL,'jbani_v2_blocks',0.9,NULL);
