INSERT INTO "words" VALUES(3217,'','dagrah (суд со','ВЕСТИ, см 16 паури) КАК РЕАГИРУЮЩЕЕ НАЧАЛО.','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(3218,'','выше мы разобрали перевод 2','го паури, который имеет практическую ценность. При этом, мы всё ещё можем не до конца понимать этот Хукам, или осознавать за него нечто абстрактное, размытое.','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(3219,'','хукам, как реагирующее начало внутри нас','сразу говорит нам то, что мы испытаем заранее от чего-либо. Хукам - всегда реагирует в нас, говорит внутри нас, выдавая те или иные реакции.','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(3220,'','жить эту жизнь, получать опыт жизни','является почестью - в пределах Его Хукама. Его Хукам определяет, что такое честь.','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(3221,'','то есть, из самого хукама в нас','приходит внутри нас "поощрение", или условное "наказание". Хукам - одновременно в нас, и одновременно за пределами нас. Мы не можем выбрать, что нам действительно нравится, а что не нравится. Мы не можем полюбить то, что мы не любим.','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(3222,'','моё человеческое тело и мой мир основан на его (ооангкар','а) Хукаме, при том что сам Хукам целиком - не может быть постигнут на человеческом уровне.','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(3223,'','хукам, как первичное реагирующее начало','это то, в отношении чего разум и тело должны прислушиваться.','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(3224,'','это реагирующее начало','источник радости, удовлетворения, чувства смысла, и много чего ещё. Его нельзя подавить разумом или телом. Оно испускает реакции.','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(3225,'','от следования или не следования этому началу','зависит то, что мы испытываем. Разумом мы не можем себе внушить эту реакцию. Можем задавить это первичную реакцию, но в итоге где-то сломаемся, поскольку это Начало - независимое.','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(3226,'','разум и тело','зависят от него, и прошиты им.','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(3227,'','оно (реагирующее начало)','не зависит от разума и тела.','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(3228,'','оно является основной жизнеспособности разума и тело. тело и разум','должны прислушиваться к этому Началу, а не диктовать ему что-то.','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(3229,'','каждый подвиг по отношению к решению в соответствии с этим началом','является мощным ускорителем процесса духовного и психологического роста, а также роста здоровья в нашей жизни - по очевидным причинам.','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(3230,'','реагирующее начало','> Разум -> 5 органов чувств (внимание) -> 5 органов действий','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(3231,'','то есть, во главе угла','должно стоять это "начало", и разум с чувствами должны управляться им, находиться в Suney (слушании) в отношении него.','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(3232,'','или обратная комбинация, где это начало','за "стенкой" -','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(3233,'','нанак в 1','м паури как раз и задаёт этот вопрос: "как сломать эту стену нереализованного состояния?", как вывести реагирующее начало, Хукам, за стену -','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(3234,'','такое понимание этого паури, понимание dagrah и хукама','практично. Такие абстрактные слова, как "божественная воля внутри", или как "суд правосудия (внутри) - Dagrah" - изжили себя, поскольку являются слишком перегруженными в отношении возникающих ассоциаций, размытыми, и не практичными.','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(3235,'','способ осознать творца внутри нас','Хукам. Пребывать в потоке Хукама, координироваться в отношении него. Результат 1-го паури. Всё Джап джи отвечает на этот вопрос: Кив Сачиара Хоийе, Кив Курее Тутте Паал? Всё СГГС - про Хукам Раджаи Чална. Паури 1 - координирует направление СГГС для нас. Всё - о Хукаме.','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(3236,'','затем, паури 2. там описывается природа хукама. 2','ой паури заканчивался так:','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(3237,'','паури 1,2,3,4','сводятся к концепции Хукама.','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(3238,'','тут речь идёт не о пении. а о воспевании','как о восприятии Хукама.','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(3239,'','gavai','Петь','Воспринимать Хукам Творца как что-либо.',NULL,'jbani_v2_blocks',0.9,NULL);
