INSERT INTO "words" VALUES(3277,'','na avey toat','не иначе','неограниченный',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(3278,'','множество людей воспринимают хукам множествами способов. создатель','внутри нас. Когда мы это говорим, это значит, что его Хукам внутри нас. Аад Сач. Хукам - движущая сила, управляющая всем. Мы не делаем Ардас, чтобы Хукам от нас ушел. Хукам - это Создатель.','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(3279,'','kath kath','повторяющие рассказы','',NULL,'jbani_v2_blocks',0.9,NULL);
