INSERT INTO "words" VALUES(3281,'','kot kot','Неисчислимым образом','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(3282,'','гурбани','нам дано для того, чтобы осознать Хукам. Но многие используют Гурбани для того, чтобы нарушить Хукам. Нужно не отвергать Хукам, а принять его, и позволить себе плыть в нём, чтобы он поддерживал нас.','',NULL,'jbani_v2_blocks',0.9,NULL);
