INSERT INTO "words" VALUES(3298,'','эта строчка говорит нам о том, что контекст 3','его паури - это Хукам. Разум Сикха должен осознавать эту строчку для того, чтобы приобрести Сэхадж, Сантокх, Хукам Раджаи Чална состояние ума.','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(3299,'','никто не получает удовлетворенности от вопрошания, хотя все','просят. Стоит обратиться к мудрости Хукама внутри, и обнаружить счастье через то, что в нас уже есть  - так как в этом хранятся ответы и руководство.','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(3300,'','создатель внутри нас в форме хукама. счастье, удовлетворенность','приходят из этого осознания. Нам нужно жить с этим “соседом” внутри себя, с Хукамом, который есть одновременно - мы, и нечто превосходящее нас, т.к. проистекает за пределами нас.','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(3301,'','реализация хукама','это реализация Творца (Nanak Hukmey Je Budhjey Ta Haumai Kahei Na Koi - от “я” к “ты”','монета перевернулась, и стало понятно, что другая сторона монеты - это Ты)',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(3302,'','всюду существующий','твой Хукам, есть руководство исходящее из уст Гуру (Твоих, Гурупарамешвар).','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(3303,'','sacha','значит, неизменный, за пределами влияния причин и следствий. Как узнали? Через мудрость погружения в знание Хукама. Вода - существует в трёх формах, вода, лёд, пар. Это Хукам. Хукам - постоянен в этом плане.','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(3304,'','вечна и неизменна твоя обитель. приходящее слово от тебя','Знак Тебя.','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(3305,'','karamat','чудеса. Превращение воды в огонь и так далее. Это нарушение Хукама. Огонь не должен порождать холод и т.д. Мы можем переосознать свою идентичность.','',NULL,'jbani_v2_blocks',0.9,NULL);
