INSERT INTO "words" VALUES(3350,'','пользуясь правилом','комментировать Гурбани, основываясь на самом Гурбани, попробуем понять, что же есть "Амрит" и что есть "Вела".','',NULL,'jbani_v2_blocks',0.9,NULL);
