INSERT INTO "words" VALUES(3352,'','и ответ','вставайте в "ранние часы и медитируйте над Истинным Именем Его Величия!". Якобы, это наказ Гуру Нанака.','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(3353,'','амрит','Твоё Бани (Слово, Послание, Мудрость, Духовный Совет и Духовное Наставление).','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(3354,'','амрит бани от гуру','Очень Очень Сладок','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(3355,'','амрит вела сач нао вадиаии вичар','Амрит Вела это превращение моей жизни - в жизнь наполненную Шабдом. Это превращение представляет собой Изучение и Реализацию Добродетелей Единого Творца, который есть Сач (вечный, отчего - истинный), который есть Источник Провидения (Нао = Хукмии), и который превыше всего (Вадаии).','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(3356,'','такими образом, если бы здесь было указание на время','например, на раннее утро, мы бы увидели не АМРИТ ВЕЛА, а АМРИТ ВЕЛЕЙ. Здесь же мы видим определение. Таким образом, приведено доказательство, что в самом первом упоминании Амрит Вела - не идёт указание на ранние часы.','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(3357,'','благословение быть человеком','получено, однако сознание многих не может сосредоточиться на Добродетелях Вездесущего ТрансцендентногоТворца (Хар Наам).','',NULL,'jbani_v2_blocks',0.9,NULL);
