INSERT INTO "words" VALUES(3687,'','напоминаем о том, что здесь происходит. все эти слова - не разговор с кем','то снаружи. Это внутренний дискурс. Это дискурс, который происходит внутри совести с умом, с чувствами. Это просветленная совесть, которая является главной. Которая является лошадью, что управляет повозкой. Повозка - является умом, использующим колёса. Колёса - это чувства. Это та самая совесть.','',NULL,'jbani_v2_blocks',0.9,NULL);
