INSERT INTO "words" VALUES(3697,'','тари (taar)','тот, кто дал обет молчания. От 2-х лет до 2-х десятилетий дают обет молчаний - хотят ум от отвлекающих факторов говорить. Я должен думать, говорить - это отвлечение внимание. Не нужно говорить, не нужно думать, не нужно слова в линию выстраивать. Вы не можете остановить !','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(3698,'','почему дискурс моей (или о моей) просветлённой совести','выше моих сил?','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(3699,'','потому что это дискурс творца. а творец','безграничен. Его дискурс, Вичар, разговор о его мудрости - это безграничная Реальность, выражающая этот дискурс. Поэтому, не может быть полного рассуждения об этой совести.','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(3700,'','потому что моя просветлённая совесть','Это Ты (Творец).','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(3701,'','объяснение 17','го Паури Карминдером Сингхом джи.','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(3702,'','асанкх паури','одни из самых плохо-понимаемых паури из-за соответствующих переводов.','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(3703,'','переход к 17 паури случается после 16-го паури. в 16-м паури','говорится о Сознании, 5-чувств которого сосредоточены вокруг Источника Мироздания. Беседы о таком сознании - за пределами всяких описаний (Kudrat Kavan Kahan Vichar II ).  За пределами всяких исчислений. И, после этой строчки, как раз закономерно и последовательно происходит продолжение темы.','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(3704,'','такое восприятие','тоже логично, ведь в предыдущих паури мы говорим о "становлении" божественностью. И Асанкх паури - это то, что происходит в результате такого становления.','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(3705,'','почему эта заметка','важная?','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(3706,'','потому что там не идёт речь о каком','то "комнатном переживании вселенной", о каких-то хаотичных','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(3707,'','предварительным условием освобождения является принятие с любовью и преданностью','Хукама Создателя.','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(3708,'','тот, в чьей жизни все, что имеет значение','это воля и команда Творца (Jo Vartaye Saee Jugat) это существо, Нанак описывает как Дживан Мукат (ਜੀਵਨ ਮੁਕਤਿ)  - кто достиг Мукти - Здесь и Сейчас.','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(3709,'','переживая на человеческом уровне всё то, что с нами происходит','печали и радости, к этому уровню добавляется возможность переживать запредельное, постоянное блаженство, состоящее в связи с Создателем, который есть Запредельное Блаженство, творящее всё в бытии ради своей божественной игры (Nanak Vigsey Veyparvah II 3 II).','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(3710,'','духовное состояние становления божественными добродетелями','это состояние связи с Хукамом.','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(3711,'','хукам проявляется в нашей жизни через совесть. через совесть','мы связаны с Создателем.','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(3712,'','беседа о благочестивой совести','выше моих способностей.','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(3713,'','а творец','безграничен. Его дискурс, Вичар, разговор о его мудрости - это безграничная Реальность, выражающая этот дискурс. Поэтому, не может быть полного рассуждения об этой совести.','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(3714,'','твоё вечное бесформенное я','Поддерживающее Мою Совесть II17II','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(3715,'','пришло просветление, что моя просветленная совесть это ты','Творец. Что я связан с Творцом через Со-весть.','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(3716,'','творец','полон высших качеств. Творец - запредельное блаженство, запредельное знание, запредельная творческая возможность. Исчерпывающее удовлетворение, вне желаний. Исчерпывающее всеведение - он есть всё, нет никого, кроме него. Творец есть действие, есть любой импульс, метафизический или физический.','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(3717,'','просветленная совесть (та, которая вне нашего контроля)','является тем каналом, через который в жизнь поступает награда от Творца, как изнутри нас самих, так и снаружи. Через неё поступает информация самому Творцу, если угодно так сказать.','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(3718,'','неужели есть что','то или кто-то, сильнее Совести, просветленной (не сансарической) ?','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(3719,'','поступки, духовные достижения, духовные цели, деятельность','такой совести - это Nahi Sumaar (16 паури), это Asankh (17 паури).','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(3720,'','просветленная совесть','порождена Неисчислимым (Даже если это о неисчислимом, мы должны как-то это понять, получить представление о нём, как хочет от нас Гуру Нанак).','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(3721,'','люди, социум','вполне исчислимы.','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(3722,'','со','Весть - это знание, приходящее "бесконтрольно", от Творца, связанное с необходимостью реализовывать это знание, эту Весть Творца.','',NULL,'jbani_v2_blocks',0.9,NULL);
