INSERT INTO "words" VALUES(3728,'','то, что перевод был про дураков снаружи','было результатом нашей внутренней тьмы! Это простой способ справиться с проблемами. Чувства были направлены вовне. Чувства также искали духовность - вовне. Теперь - этого нет.','',NULL,'jbani_v2_blocks',0.9,NULL);
