INSERT INTO "words" VALUES(3815,'','мы пропитываем пороки','добродетелями. Прививать пороки и рассуждать о добродетелях - не подходит. Это для того, чтобы умыть руки и сказать “всё, на этом всё, я выполнил свою часть”. Нужно прививать добродетели, а обсуждать - пороки. Вот о чём говорит Нанак.','',NULL,'jbani_v2_blocks',0.9,NULL);
