INSERT INTO "words" VALUES(3836,'','не ритуалы, не временные награды. духовные награды','вечны, не преходящи.Даже если внешний поступок ничтожен.','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(3837,'','во временном смысле, проиллюстрируем гигантское благотворительное деяние. кто','то идёт в пустой дом со всеми сбережениями, продаёт все сбережения, инвестиции, дом - жертвует всё на то, что он считает духовными целями. Это ничтожно мало. С другой стороны призрак (Кабира? ):','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(3838,'','божественная беседа со бхагтами (теми, кто следует хукаму)','безмерно ценна (Примечание: 1 гхари = 24 минуты).','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(3839,'','простой акт поднятия насекомого, кормления кошки','гораздо более благой акт. Поднятие насекомого от опасности - великое благо. Ищем мирских наград или духовных? Количество, качество, размер, видимость - это то, что важно во внешнем мире. Поэтому я продал весь дом, чтобы получить это всё.','',NULL,'jbani_v2_blocks',0.9,NULL);
