INSERT INTO "words" VALUES(3866,'','реализация','вне времени дня и искусственных внешних конструкций. Гуру Нанак отрицает эти практики здесь (3 часа утра для “амрит вела” и т.д.).','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(3867,'','во всём гурбани','время не имеет значения. Время - придумано человеком. Нет понятия “благоприятные времена” в Гурбани. Нет понятия “бог может быть осознан в какое-то определённое время”.','',NULL,'jbani_v2_blocks',0.9,NULL);
