INSERT INTO "words" VALUES(3871,'','hoa akar','Обрёл форму, возник.','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(3872,'','sat suhan sda man chao','не подчиняется определенному времени или неделе.','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(3873,'','внутри меня','темно или светло. Неважно, кто там в мире - тёмен или светел. Всё - для меня. Почему Гуру рассказывает нам о других людях и о том, что происходит снаружи? Как нам помогает знание о том, когда создана Земля? Это не прибавляет Sat Sohan Sda Man Chao.','',NULL,'jbani_v2_blocks',0.9,NULL);
