INSERT INTO "words" VALUES(3888,'','у йогов есть не столько такие писания, как пураны или как коран, сколько техники','медитации, крийи, асаны и так далее. Нанак говорит: “я понял это не оттуда”.','',NULL,'jbani_v2_blocks',0.9,NULL);
