INSERT INTO "words" VALUES(3907,'','когда разум решил это создать, 5 чувств говорят','“мы теперь просветленные”, мы получили совершенную сущность. Теперь у нас есть Сачиара, Гуру, Творец, Кив Сачиара Хоие.','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(3908,'','vadaa sahib','Великолепный создатель','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(3909,'','vadee nayee','Великолепные Достоинства','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(3910,'','ja kaa','В силу чего исход','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(3911,'','добродетели исходят не из ума. разум решает','достичь их. Но добродетели исходят не от него самого, а от Творца. Чувства пробуждены и будут следовать за разумом. И всё равно будут перенимать добродетели Творца.','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(3912,'','jey ko','Должен ли ты / Должна ли ты','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(3913,'','apao janney','Самостоятельно','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(3914,'','gya','(Lit) ходить, путешествовать','ориентироваться (в духовности)',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(3915,'','na sohey','не стоящий (себя)','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(3916,'','мы часто говорим о духовности, которая направлена на шабд. но самоуправление','это будущее. Где мы ставим нашу цель? Вот в чём смысл этого слова. Смысл не в том, чтобы всю жизнь рецитировать Гурбани. Смысл в том - чтобы его усвоить и применять.','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(3917,'','teerath tup dya dut dan','всему этому нет места в духовности Сикха. В этом суть послания. Это очень важные паури, которые люди применили ко внешним вещам - к сотворению вселенной и т.д.','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(3918,'','главная проблема','упущение контекста.','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(3919,'','сат сохан сада ман чао','это результат всего этого. Зачем же после этого говорить о мирах? В этом мало смысла. Основная причина, почему это не имеет смысла помимо вышеперечисленных - игнорирование контекста.','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(3920,'','сейчас мы попытаемся вписать это в контекст','Панч Парван, Панч Пардхан. Где чувства становятся согласованными с разумом, совестью.','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(3921,'','patal','(Lit) Внизу, очень низко','темнота',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(3922,'','patala patal','Idiomatic- самый низкий из низких','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(3923,'','agas','(Lit) Верхний, небо, выысокий','просвещенный',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(3924,'','agasa agas','Idiomatic- Высший из высоких','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(3925,'','патала патал','самый низший из низших. Это идиомы.','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(3926,'','агаса агас','высшее из высших.','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(3927,'','когда совесть проходит духовный путь к просветлению','в ней что-то происходит. Происходит нечто вроде колебаний маятника - от бечисленных темных мыслей и очень просветленных. Это становится очень осмысленным и реалистичным.','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(3928,'','знание смысла','позволяет понять, когда поставить паузу. Если ставить паузу в неправильном смысле - будет утрата смысла. Как правило, в начале нашего духовного путешествия, “тёмных мыслей” в нашем разуме больше, чем “светлых мыслей”, в этом обоснование запятой.','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(3929,'','тело','это основа дхарама (хукама - божественного закона), выражение Атмана во времени и пространстве. Внутри тела находится Свет Создателя.','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(3930,'','в теле хранятся бесценные жемчужины знания','их можно обнаружить если научится погружаться глубоко в тело с помощью мудрости Гуру-Создателя.','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(3931,'','разум и чувства','управляли нами	Теперь Совесть - ведёт нас. Нанак хотел подчеркнуть это.','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(3932,'','patala patal lakh agasa agas','Непросветлённое сознание заставляет мой разум колебаться между бесчисленными темными мыслями и высокопросвещенными.','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(3933,'','orruk','1) Конец, предел [может вспомнить про Ооанкар, согласно алфавиту Нанака, ūrai upamā tā kī kījai jā kā ant n pāiā)] 2) святилище, убежище (происхождение от слов Orr, Ord, Sharan)','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(3934,'','orruk orruk','Idiomatic -Абсолютное святилище / убежище. Когда идёт битва, мы ищем убежища - до конца.','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(3935,'','bhal thakey','Искать до конца','возможный поиск - в духовном смысле, окончательный поиск.',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(3936,'','kehn','(Lit) Говорить, произносить','стоящий',NULL,'jbani_v2_blocks',0.9,NULL);
