INSERT INTO "words" VALUES(3939,'','sehs athara','(Lit) 18 тысяч','метафора для суммирования всей индийской духовности. Идиома.',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(3940,'','kteba','(Lit) 4 духовные книги','метафора всех Авраамических религиозных книг (Abrahamic)',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(3941,'','aslu','(Lit) аутентичный, оригинальный','тот который имеет значение; корень того или иного значения / вопроса',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(3942,'','dhat','(Lit) Источник, сущность. В данном случае относится к совести','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(3943,'','второе значение','цель духовности во время жизни в мире состоит в победе в этой битве. Иначе, счёт выйдет в “минус”. Признание победы - это счёт в плюс. Что-то вроде подсчёта очков происходит в этом стихе (в 22-м паури).','',NULL,'jbani_v2_blocks',0.9,NULL);
