INSERT INTO "words" VALUES(3949,'','вспомним зеленый и синий ящик. одним руководит разум и чувства, другим','Совесть. Это о том, что происходит, когда совесть берет верх, а разум и чувства занимают следующие за ней позиции.','',NULL,'jbani_v2_blocks',0.9,NULL);
