INSERT INTO "words" VALUES(3955,'','причина колебаний в моём сознании','улажена. Когда этот “подсчёт” закончен, у вас появится определённый склад ума. Это мой образ мышления, основанный на “чувственном упадке”. Больше никаких колебаний не будет. Такой образ мышления не может быть достигнут без осознания божественных добродетелей.','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(3956,'','nadiya atey vah','(Lit) в реках и водоемах течёт вода','метафора разума и чувств, стремящихся к месту назначения. Здесь Нанак хочет усилить послание. Усилить идею о том, что разум и чувства должны двигаться в определённом направлении.',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(3957,'','pveh samund','(Lit)','впадать в океан; течь в океан божественных добродетелей; метафора становления, маннэ; река (из чувств и разума) втекает в океан (божественных добродетелей)',NULL,'jbani_v2_blocks',0.9,NULL);
