INSERT INTO "words" VALUES(3990,'','духовность нанака','это духовность неограниченного стремления, неограниченной реализации, неограниченных реализаций, неограниченного Творца в неограниченном сознании.','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(3991,'','это осознаёт один из миллиона. это и есть','real stuff. С другой стороны - это норма.  Наша духовность должна идти по этому пути.','',NULL,'jbani_v2_blocks',0.9,NULL);
