INSERT INTO "words" VALUES(3997,'','теперь','мы возвышены. Если убираем добродетели - возвышение всего сущего исчезает. Закрой глаза - сияние солнечных лучей исчезнет. Задёрни шторы, и несмотря на то, что солнце будет светить ярко, ты его не увидишь. Совесть - это здорово. Даже если добродетели не усвоены - Творец всё ещё там присутствует.','',NULL,'jbani_v2_blocks',0.9,NULL);
