INSERT INTO "words" VALUES(4005,'','karmi','Дарительница благословений','Создатель',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(4006,'','карам','персидское слово, означающее Надар. Оно означает благодать. Надар - арабское слово, обозначающее Карам. На пенджаби это будет - Мехир. На санскрите это слово - Крипа. На урду - Бакшиш. Даат - это дар, но для человека с возвышенной совестью, это всегда Благословение.','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(4007,'','если внутренняя реализация','благословение Творца, и если она определяется как  становление Добродетелями, и если за это надо платить, и это должно быть сделано внутри нас самих нами самими, то мы - должны благословить себя. Всё в наших руках. Aape Aap - другое значение.','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(4008,'','мольбы о благословении','находятся снаружи. Нужно вернуть это внутрь. Когда мы решим благословить самих себя - это день, когда Творец благословит нас. В тот день, когда мы решим следовать совести, руководствоваться ею, в тот день произойдёт благословение.','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(4009,'','на этом закончился предыдущий паури. и текущий паури объяснит','что именно является “благодатью”, характеристики и природу благодати.','',NULL,'jbani_v2_blocks',0.9,NULL);
