INSERT INTO "words" VALUES(4039,'','людям чужда концепция','когда дар это призвание к Наам, божественным добродетелям. Наши желания - это отражение мук желания к божественным добродетелям. Мы привязали благословения к временным событиям и мирским происшествиям.','',NULL,'jbani_v2_blocks',0.9,NULL);
