INSERT INTO "words" VALUES(4051,'','я не оскорбляю тебя. я не занимаю позицию того, что есть что','то другое, кроме Твоих Благословений. Что-то, что действует в рамках моего духовного успеха. Это осознание твоих Благословений заставило меня отказаться от оскорблений.','',NULL,'jbani_v2_blocks',0.9,NULL);
