INSERT INTO "words" VALUES(4072,'','любовь к божественным добродетелям, бесценна, наполнение ими','бесценно. Наполнение происходит в разуме, поэтому процессы принятия решений как для нашей мирской жизни, так и для нашей духовной жизни - будут осуществляться в соответствии с божественными добродетелями Творца.','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(4073,'','не только хукам бесценен, но и решения в моей жизни','становятся бесценными, потому что они приняты в соответствии с Хукамом.','',NULL,'jbani_v2_blocks',0.9,NULL);
