INSERT INTO "words" VALUES(4077,'','процесс вынесения суждений включает в себя два аспекта','разум и интеллект. Весы - это наш интеллект и разум. Это также имеет отношение к предыдущему стиху.','',NULL,'jbani_v2_blocks',0.9,NULL);
