INSERT INTO "words" VALUES(4084,'','благословение было определено в чём','то, что выходит за рамки бесценного повествования, которое является осознанием Творца внутри, становлением божественными добродетелями. И это - бесценно.','',NULL,'jbani_v2_blocks',0.9,NULL);
