INSERT INTO "words" VALUES(4090,'','контекст','пропитан благословениями Творца. Поэтому, Нанак начинает говорить о духовных текстах, поскольку сейчас становится возможна их оценка.','',NULL,'jbani_v2_blocks',0.9,NULL);
