INSERT INTO "words" VALUES(4118,'','этот паури появляется трижды в сггс, отчего','он крайне важен. В Джап бани, в Содар, в Аса Рааг Бани. Иногда он появляется в несколько измененной поэтической форме - в зависимости от поэтической структуры шабда, в которую он втекает.','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(4119,'','во первых, здесь нет dar','Dhar. Нет никакой “Dhar” в строчке.','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(4120,'','снова','некое “место”.','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(4121,'','вероятно, это подразумевают под ответом. ветер поёт, огонь поёт, всё поёт','и это и есть ответ, и это и есть место про место.','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(4122,'','повествование в джап бани ведётся не о чём','то вовне. Не о людях, находящихся снаружи, которые что-то поют, воспевают. Нам же объясняются действия людей, богов и т.д. - снаружи.','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(4123,'','творец находится внутри нас. творец','хозяин нашей совести. Нам важно придерживаться этого принципа.','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(4124,'','творец внутри нас','не значит, что это какое-то “место”. Не значит, что это физическая локация, или метафизическая локация. Нам не нужно искать это место внутри нас. Внутри нас - происходит процесс реализации, становления божественными добродетелями. Совесть - становится божественными добродетелями.','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(4125,'','то есть, если у нас в голове','есть божественные добродетели, а у другого человека их нет в голове, то мы ничем не отличаемся от этого человека. Путешествие духовное - о становлении. От чувств, к разуму - затем в Совесть.','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(4126,'','dar','(Lit) дверь','разум, восприятие.',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(4127,'','дверь','не физическая. Берем стихи из Гурбани, где используется Dar, Ghar и так далее. Dar - это двери, которые ведут во внешний мир изнутри - слух, осязание, зрение, обоняние, чувство вкуса. В Гурбани говорится о 9 дверях. 10-ая дверь - это ум, метафизическое.','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(4128,'','внутри нас (ghar)','покой. Мы что-то воспринимаем через Dar, и что-то выводит нас из себя. Наша задача - поставить охранников на наши двери. “Я хочу узнать все новости, все сплетни мира и т.д.” - нам нужен охранник. Что такое Совесть? Она диктует - что должно входить, а что должно оставаться снаружи.','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(4129,'','keha','(Lit) Что','(восклицание!) (“Какой у тебя голос! Какая замечательная идея!”)',NULL,'jbani_v2_blocks',0.9,NULL);
