INSERT INTO "words" VALUES(4142,'','допустим, у нас 100 метафор из гурбани. мы можем сказать, что 40 метафор','относятся к одной категории, 40 - ко второй, и 20 - ко всем остальным.','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(4143,'','мы хотим, чтобы кто','то другой занимался посевом, уходом, сбором урожая, и снабжал нам полученным продуктом - это аутсорсинг. Мы не можем весь сельскохозяйственный бизнес передать на аутсорсинг. Поэтому, это - метафора. Духовность самого себя - для самого себя - самим собой.','',NULL,'jbani_v2_blocks',0.9,NULL);
