INSERT INTO "words" VALUES(4156,'','каждый раз, когда мы оказываемся в чьем-то присутствии, у нас возникает какое','то чувство. У нас есть “внешний” портрет кого-то, и при этом, “внутренний портрет” кого-то - у нас может быть иным. Таким образом, существует две разных вещи. Нас волнует внутренний портрет. Нам нужно мужество, чтобы сделать внутренний портрет самих себя - достойным.','',NULL,'jbani_v2_blocks',0.9,NULL);
