INSERT INTO "words" VALUES(4177,'','мужество','быть в гармонии с Творцом, моралью, чувством удовлетворенности, с добродетелями. Это теперь задача для нашей совести - привести её в такое состояние.','',NULL,'jbani_v2_blocks',0.9,NULL);
