INSERT INTO "words" VALUES(4184,'','veda','знание','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(4185,'','проблема обретения просветления и внутреннего знания','находится в поиске постоянного состояния среди сменяющихся состояний. Для достижения этой цели - So Dar Keha Do Ghar Keha … Samaley - разум должен иметь верх над нашими чувствами в таком случае. В ином случае, ни один из этих процессов не может произойти.','',NULL,'jbani_v2_blocks',0.9,NULL);
