INSERT INTO "words" VALUES(4246,'','мы пришли к принципу в предыдущих паури, что гурбани','о нас, о нашем духовном прогрессе и путешествии. Гурбани исходит из сокровенных тайников Гуру Нанака, из его сознания и совести. Это его духовный опыт. Это для нас - для последователей Сикхи, Гурмат, которые пытаются проходить путь, проложенный Нанаком.','',NULL,'jbani_v2_blocks',0.9,NULL);
