INSERT INTO "words" VALUES(4301,'','одни и те же заключительные стихи для 4','х паури - они принадлежат к одному и тому же потоку духовной мысли. Они об одном контексте - из 26 паури. Ум подчиненный Совести, чтобы управлять Чувствами, Контролировать их. Далее, с 26-го паури - мы развиваем тот тип ума, это головоломка по одной и той же сюжетной линии.','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(4302,'','если разум общается с совестью таким образом','то совесть не замолчит. Совесть не останется без внимания. Она будет восприниматься как голос Создателя. В этот момент Сознание наделяется силой Совести, следовательно Сознание (разум) становится ответственным за контроль 5 чувств - Творец управляет 5-ю чувствами теперь.','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(4303,'','в этом нет никакой ценности для нашего духовного путешествия','это не Гурмат.','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(4304,'','этот стих считает гурмат','вершной не-просветления. В Гурмат - один и тот же Творец, а не множество разных божеств. От Сикхов не ожидается принятие троицы.','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(4305,'','sansari','это не Создатель. Sansar - это мир. Sansari относится к миру, мирскому (wordly). Bhandari это не “поддерживатель / сохранитель”, а владелец того или иного хранилища. Laye Diban - относится к “суду”, “сидеть в суде”, а не к разрушению.','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(4306,'','даже если это относится к критике этого паури','это всё так же вне контекста. Откуда бы критика “трёх божеств” пришла в этот паури, какие предпосылки говорить об этом?','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(4307,'','об этом уже было сказано в 5','м паури.','',NULL,'jbani_v2_blocks',0.9,NULL);
