INSERT INTO "words" VALUES(4376,'','мы должны достичь этой духовности в качестве просветления','развить наше сознание, совесть, восприятие. Об этом говорит Нанак. Метод песнопений - Нанак говорит Koore Korey Thees - это будет подражанием, имитацией. Совесть не может быть возвышена через Лакх Лакх Гера Акхие, Putt Pavreeah Chareeah Hoye Ekees - через это может.','',NULL,'jbani_v2_blocks',0.9,NULL);
