INSERT INTO "words" VALUES(4465,'','знание','находится за пределами всех мировоззрений, описаний, философий. Милость Творца - критический элемент в духовности Нанака. Поэтому, в Гьян Кханд Нанак говорит нам выйти за пределы этого. Что ведёт к Милости, что её приносит? И что приносит Реализацию Творца?','',NULL,'jbani_v2_blocks',0.9,NULL);
