INSERT INTO "words" VALUES(4528,'','в 34 паури - рати рути тхити вар. дхарам кханд. но откровение об этом','что это именно Дхарам Кханд, происходит в 35-м паури. Что намекает нам на это. Это наводит на мысль об этом потоке, и о разнице между 34 и 35 сторонами. Директива не заканчивается на Дхарам Кханде. Всё вышесказанное - повествование о Дхарам Кханде.','',NULL,'jbani_v2_blocks',0.9,NULL);
