INSERT INTO "words" VALUES(4564,'','наиболее распространён такой перевод','но он не особо помогает нам в нашей духовной задаче. Посмотрим внимательнее. Гуру - это субъект, подлежащее. Pavan - это определяющее прилагательное, определитель. Гуру - это то, Гуру это другое. Далее мы говорим, что Вода - наш отец. Если Пита - это субъект, то у нас есть Мата - дхарт махат.','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(4565,'','на самом деле, здесь одно подлежащее, один субъект. всё остальное','определяющие факторы.','',NULL,'jbani_v2_blocks',0.9,NULL);
