INSERT INTO "words" VALUES(4587,'','причина, по которой мы не стали божественными','то, потому что мы ищем творца за пределами “4-х направлений” - снаружи, а не внутри себя. Тут не говорится о поступках прошлой жизни, говорится о поступках текущей жизни.','',NULL,'jbani_v2_blocks',0.9,NULL);
