INSERT INTO "words" VALUES(4597,'','a.karmi apo apni','первое доказательство, “Мои собственные поступки определяют, Реализую ли я Творца внутри себя, или нет - приближаюсь к нему, или отдаляюсь”','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(4598,'','b.apey beej apey hee kha','что я сею, то и пожинаю','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(4599,'','c.jeha beejey so lunnay','духовная жизнь похожа на поле, где жнётся урожай. фермер знает, что когда он сам сажает семя, а потом сеет. Он не ожидает, что он сеет заклинание в землю, и потом из земли вырастает то или иное дерево. Мы также не можем направить свой посев на чужую жатву - это невозможно.','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(4600,'','a.kaytee это единственное число','так что это не может быть про “многих других”. Глагол во множественном числе требует наречия во множественном числе, существительное во множественном числе требует прилгатательное во множественном числе, и т.д.','',NULL,'jbani_v2_blocks',0.9,NULL);
INSERT INTO "words" VALUES(4601,'','kayteeya chutti naal (женский) или kaytay chutay naal (мужской)','здесь же ни то, ни другое','',NULL,'jbani_v2_blocks',0.9,NULL);
