INSERT INTO "words" VALUES(4609,'','духовность для жизни после смерти	духовность','здесь и сейчас, повсеместно, в любом внутреннем и внешнем акте (посмертие - тоже будет здесь и сейчас)','',NULL,'jbani_v1',0.85,NULL);
INSERT INTO "words" VALUES(4610,'','духовность ритуалов','духовное переживается только во время ритуала	Духовность просветления - духовность проживается постоянно, сама жизнь является её “ритуалом”','',NULL,'jbani_v1',0.85,NULL);
INSERT INTO "words" VALUES(4611,'','разум и чувства','управляли нами	Теперь Совесть - ведёт нас. Нанак хотел подчеркнуть это.','',NULL,'jbani_v1',0.85,NULL);
INSERT INTO "words" VALUES(4612,'','добродетель','Наам, божественное качество, божественный атрибут, божественной свойство; Virtue;','Люди дают божественности имена, согласно тем свойствам, которые она им открывает. Эти имена есть “Наам”. Добродетель, Наам заключается в том, что она берет своё начало не из самого человека, а из Присутствия Создателя (Ооангкара) внутри человека. Например, Nirabhau (вне страха). Это бесстрашие, связанное с реализацией своего Единства с Тем, по отношению к Которому нет второй сущности. Это не некая отвага или мужество в привычном смысле, где сама отвага имеет некую мирскую природу, где эта отвага мотивирована какими-то интересами, и имеет тень в виде “смелости / мужества”. Абсолютные ценности побуждают к Абсолютному Бесстрашию. Такому бесстрашию, которое не становится ниже или выше, в зависимости от обстоятельств временного мира. Это духовное бесстрашие. Оно проникнуто различающим, проницательным видением. Относительные ценности, связанные с мирскими вещами, побуждают к Относительному бесстрашию. Если обстоятельства временного мира изменятся (или обещания “рая”, относящиеся к исполнению желаний относящихся к мирскому), то вместе с этим изменится и бесстрашие. Такому бесстрашию часто не достаёт различающего видения и проницательности. В этом ключевое отличие мирского бесстрашия и духовного – и критерий божественных атрибутов.',NULL,'ast_example',0.88,NULL);
INSERT INTO "words" VALUES(4613,'','совесть','Просветленная Совесть, “Реагирующее Начало”, Внутренний “Суд Совести”, “пробный камень милости”; Conscience','Совесть - внутри человека, берущая своё начало из Бесконечной сущности (Ооангкар), а не сущности, имеющей предел, сторону и так далее. В этом состоит “просветлённость”. Это духовная совесть, а не мирская, социальная.Эту совесть можно понять и определить внутри как “реагирующее начало”. В каждом из нас - есть "реагирующее начало". Это те глубинные реакции возникающие в нас, которые предшествуют нашей мыслительной обработке. Тот первичный уровень, энергия, чувство направления, которое приходит к нам, которое мы не можем выбрать, в отношении которого мы строим свою жизнь и считаем это “самой глубинной глубиной” себя.',NULL,'ast_example',0.88,NULL);
INSERT INTO "words" VALUES(4614,'','милость','Надар, Бакшиш, Шактипат, Баракят, Благодать, Ануграха','Переживание, где Ооангкар раскрывает человеку себя, проявляет себя в нём, уплотняет себя в нём; и раскрывает знание об обыденной и высшей реальности, которые оказываются Достоверными, Надёжными, выдерживающими проверку реальностью.',NULL,'ast_example',0.88,NULL);
INSERT INTO "words" VALUES(4615,'','настоящее, настоящий','Вечное, Сач, Настоящий, Создатель, Вечный Создатель','То, что стоит над нами, то, что присутствует здесь и теперь.«На» — предлог, указывающий на местоположение, близость.«Стоящее» — от глагола стоять, т.е. то, что стоит, пребывает, имеет устойчивое присутствие.В древнерусском и старославянском это слово могло означать нечто происходящее прямо сейчас, находящееся в непосредственной близости, буквально стоящее перед глазами, перед умом.Со временем оно приобрело абстрактное значение «текущий момент времени» — то, что есть, в отличие от того, что было (прошлое) и того, что будет (будущее).',NULL,'ast_example',0.88,NULL);
INSERT INTO "words" VALUES(4616,'','сачиара','Богореализованное существо','Как стать Сачиарой – описывает Джап джи',NULL,'ast_example',0.88,NULL);
INSERT INTO "words" VALUES(4617,'','хукам','Божественная Воля, Живой Закон, Закон Природы, Дхарам','Твой Наам – это Хукам Принцип Закона – начинающегося с законов природы, боли или удовольствия, учитывания или игнорирования обратной связи от реальности; начинающийся со здравого смысла, физических вещей. И, путешествуя по следам этого Закона, можно найти Закон Божественный, с той же отчетливой силой Его Реализма, которая присутствует и в законах обыденной реальности.',NULL,'ast_example',0.88,NULL);
INSERT INTO "words" VALUES(4618,'','слово','Шабд','Письмо потока Хукама, живого закона; Гурбани, божественная речь',NULL,'ast_example',0.88,NULL);
INSERT INTO "words" VALUES(4619,'ਸਿਮਰਨ','simran','памятование, вспоминание; держать в уме','созерцательное восприятие Творца через удерживание Наам внутри ума',NULL,'manual_ksd_user_terms',0.96,NULL);
INSERT INTO "words" VALUES(4620,'ਨਾਮ','naam','имя; добродетель; божественное присутствие','принцип самопроявления Творца; Наам Единого есть Хукам, внутренний закон существования',NULL,'manual_ksd_user_terms',0.96,NULL);
INSERT INTO "words" VALUES(4621,'ਸਿਖੀ','sikhi','учение; ученичество','учение, обретаемое через опытное исследование Гуру / Слова Гуру',NULL,'manual_ksd_user_terms',0.94,NULL);
INSERT INTO "words" VALUES(4622,'ਗੁਰੂ','guru','Гуру; наставляющее начало','Бани как наставляющее Божественное Слово; обучающий принцип Хукама, ведущий от невежества к Свету',NULL,'manual_ksd_user_terms',0.96,NULL);
INSERT INTO "words" VALUES(4623,'ਵੀਚਾਰ','vichar','размышление, исследование, осмысление','деятельное исследование Бога, Наам и Хукама в собственной жизни через различающий опыт',NULL,'manual_ksd_user_terms',0.94,NULL);
INSERT INTO "words" VALUES(4624,'ਸਤਿ ਨਾਮੁ','sat naam','Сат Наам; в существовании пребывающий Наам','Единый Бог, пребывающий в Едином Существовании через Свой Наам; Наам как Хукам внутри существования',NULL,'manual_ksd_user_terms',0.96,NULL);
INSERT INTO "words" VALUES(4625,'ਓਅੰਕਾਰ','ooangkar','Ооангкар; имя Творца','Мастер без пределов, Причина всего, непрерывно осуществляющий всё во всём; Невыразимый через буквы',NULL,'manual_ksd_user_terms',0.94,NULL);
INSERT INTO "words" VALUES(4626,'ੴ','ik ooangkar','Единый Ооангкар','Единый Создатель, присутствующий в своём творении и пронизывающий человеческую природу своим Хукамом',NULL,'manual_ksd_user_terms',0.95,NULL);
INSERT INTO "words" VALUES(4627,'ਈਸਰੁ','isar','Ишар / Шива','не духовный статус; пураническая фигура, реальность которой Гурбани раскрывает и демифологизирует через слышание Шабда',NULL,'manual_ksd_user_terms',0.95,NULL);
INSERT INTO "words" VALUES(4628,'ਬਰਮਾ','brahma','Брахма','не духовный статус; ограниченная пураническая фигура, не образец реализации Единого',NULL,'manual_ksd_user_terms',0.95,NULL);
INSERT INTO "words" VALUES(4629,'ਇੰਦੁ','ind','Индра','не духовный статус; в Гурбани раскрывается как нравственно загрязнённая/мифологизированная фигура, а не духовная цель',NULL,'manual_ksd_user_terms',0.95,NULL);
INSERT INTO "words" VALUES(4630,'ਦੇਵ','dev','дэв, бог','не божественная сущность в смысле Сикхи; пураническая/социально-историческая категория, которую Гурбани демифологизирует',NULL,'manual_ksd_user_terms',0.93,NULL);
INSERT INTO "words" VALUES(4631,'ਅਵਤਾਰੀ','avtar','аватар, воплощение','цари и властители объявляли себя аватарами; Гурбани не принимает это как постижение предела Творца',NULL,'manual_ksd_user_terms',0.93,NULL);
INSERT INTO "words" VALUES(4632,'ਸੁਣਿਐ ਈਸਰੁ ਬਰਮਾ ਇੰਦੁ','suniai isar brahma ind','через слышание — Ишар, Брахма, Индра','через подлинное слышание Шабда раскрывается реальность этих так называемых богов; это не получение их статуса',NULL,'manual_ksd_user_terms',0.97,NULL);
